#!/usr/bin/env python3
"""
Studio IVR — Launcher Unificado
================================
Combina el servidor Flask (servidor.py) con la app Studio IVR embebida.
Corre en http://localhost:8080/ y se abre automáticamente en el navegador.

Índice del archivo (busca «# N.» en comentarios):
  1 App + jobs clásicos  2 Matching guión/Whisper  3 Pipeline Modal
  4 Grok  5 Whisk  6 Guion n8n/OpenRouter  7 Proyectos  8 Render FFmpeg
  9 Voz  10 Guion/audio en disco  ·  ARRANQUE al final

Compilar a .app (Mac):
    pyinstaller --windowed --name "Studio IVR" launcher.py
"""

import sys, os
from dotenv import load_dotenv
import shutil
import platform
import hashlib

