# Deshabilitar advertencias de Unicode en Windows
if sys.platform == 'win32':
    import warnings
    warnings.filterwarnings('ignore', category=UnicodeWarning)
    
    # Configurar codificación UTF-8 para la consola
    try:
        sys.stdout.reconfigure(encoding='utf-8', errors='replace')
    except:
        pass

# ============================================
#  CARPETAS DE DATOS (AppData)
# ============================================

def get_app_data_folder():
    if platform.system() == "Windows":
        appdata = os.environ.get('APPDATA', os.path.expanduser('~\\AppData\\Roaming'))
        return os.path.join(appdata, 'VideoForge')
    else:
        home = os.path.expanduser('~')
        return os.path.join(home, 'Library', 'Application Support', 'VideoForge')

# USAR SIEMPRE ESTO
APP_DATA = get_app_data_folder()
ENV_PATH = os.path.join(APP_DATA, '.env')
JOBS_FOLDER = os.path.join(APP_DATA, 'jobs')
COOKIES_FOLDER = os.path.join(APP_DATA, 'cookies')
WHISK_DOWNLOADS = os.path.join(APP_DATA, 'whisk_downloads')
FLOW_EXTENSION_FOLDER = os.path.join(APP_DATA, 'flow_extension')

# Crear carpetas si no existen
for folder in [JOBS_FOLDER, COOKIES_FOLDER, WHISK_DOWNLOADS, FLOW_EXTENSION_FOLDER]:
    os.makedirs(folder, exist_ok=True)

# Crear archivo .env si no existe
if not os.path.exists(ENV_PATH):
    with open(ENV_PATH, 'w') as f:
        f.write('')

print(f"[OK] AppData: {APP_DATA}")
print(f"[OK] Jobs: {JOBS_FOLDER}")
print(f"[OK] Cookies: {COOKIES_FOLDER}")
print(f"[OK] Whisk: {WHISK_DOWNLOADS}")
print(f"[OK] Flow Extension: {FLOW_EXTENSION_FOLDER}")


# ── PyInstaller: sys.executable es el .exe, NO python.exe. No se puede hacer
#    Popen([exe, "grok_multi.py", ...]) — eso arranca OTRO Studio IVR y rompe el puerto.
#    Los hijos entran aquí, ejecutan grok_multi con runpy y salen sin cargar Flask.
if getattr(sys, "frozen", False) and len(sys.argv) >= 2 and sys.argv[1] == "--vf-grok-worker":
    import runpy
    from pathlib import Path as _Path_grok

    _grok_script = _Path_grok(sys.argv[2]).resolve()
    if not _grok_script.is_file():
        print("ERROR: No se encuentra grok_multi:", _grok_script, file=sys.stderr)
        raise SystemExit(2)
    os.chdir(str(_grok_script.parent))
    sys.argv = [str(_grok_script)] + sys.argv[3:]
    runpy.run_path(str(_grok_script), run_name="__main__")
    raise SystemExit(0)

import threading, webbrowser, time, base64, asyncio, json, hashlib

import tkinter as tk
import requests as _req
import tempfile, subprocess

# ── Stdout unicode-safe (Windows compiled exe usa charmap/CP1252 por defecto,
#    que no puede encodar emoji ni muchos caracteres Unicode).
#    Intentamos en orden: reconfigure --> wrap buffer --> SetConsoleOutputCP(UTF-8)
#    para que ningún print() pueda crashear el proceso. ─────────────────────────
import io as _io
if sys.platform == "win32":
    try:
        import ctypes as _ct
        _ct.windll.kernel32.SetConsoleOutputCP(65001)  # UTF-8 code page
    except Exception:
        pass
for _std_name in ("stdout", "stderr"):
    try:
        _std = getattr(sys, _std_name, None)
        if _std is None:
            continue
        # Intento 1: reconfigure (Python 3.7+ nativo)
        try:
            _std.reconfigure(encoding="utf-8", errors="replace")
            continue
        except Exception:
            pass
        # Intento 2: wrap buffer (streams normales)
        if hasattr(_std, "buffer"):
            setattr(sys, _std_name,
                    _io.TextIOWrapper(_std.buffer,
                                      encoding="utf-8",
                                      errors="replace",
                                      line_buffering=True))
    except Exception:
        pass


APP_VERSION = "2.2"
VERSION_URL = "https://raw.githubusercontent.com/codedeveloper14/VideoForge/main/version.json"




def _mostrar_splash():
    splash = tk.Tk()
    splash.title("Studio IVR")
    splash.geometry("420x220")
    splash.resizable(False, False)
    splash.configure(bg="#0f0f0f")
    splash.overrideredirect(True)
    splash.update_idletasks()
    w = splash.winfo_screenwidth()
    h = splash.winfo_screenheight()
    x = (w // 2) - 210
    y = (h // 2) - 110
    splash.geometry(f"420x220+{x}+{y}")
    tk.Label(splash, text="🎬 Studio IVR", font=("Segoe UI", 22, "bold"),
             bg="#0f0f0f", fg="#ffffff").pack(pady=(30, 4))
    tk.Label(splash, text=f"v{APP_VERSION}", font=("Segoe UI", 10),
             bg="#0f0f0f", fg="#666666").pack()
    status_var = tk.StringVar(value="Verificando actualizaciones...")
    tk.Label(splash, textvariable=status_var, font=("Segoe UI", 11),
             bg="#0f0f0f", fg="#aaaaaa").pack(pady=(24, 6))
    progress_frame = tk.Frame(splash, bg="#1e1e1e", width=340, height=6)
    progress_frame.pack()
    progress_bar = tk.Frame(progress_frame, bg="#4f8ef7", width=0, height=6)
    progress_bar.place(x=0, y=0)

    def set_progress(pct):
        progress_bar.config(width=int(340 * pct / 100))
        splash.update_idletasks()

    def set_status(msg):
        status_var.set(msg)
        splash.update_idletasks()

    def _update_task():
        try:
            set_progress(15)
            r = _req.get(VERSION_URL, timeout=8)
            set_progress(30)
            if r.status_code != 200:
                set_status("No se pudo verificar. Iniciando...")
                set_progress(100)
                splash.after(1200, _arrancar)
                return
            data = r.json()
            remote_version = data.get("version", "0.0.0")
            download_url = data.get("download_url", "")
            def _ver(v): return tuple(int(x) for x in v.split("."))
            if _ver(remote_version) <= _ver(APP_VERSION):
                set_status("✓ Todo al día. Iniciando Studio IVR...")
                set_progress(100)
                splash.after(1000, _arrancar)
                return
            set_status(f"📦 Descargando actualización {remote_version}...")
            set_progress(40)
            tmp_path = os.path.join(tempfile.gettempdir(), f"StudioIVR_Setup_{remote_version}.exe")
            with _req.get(download_url, stream=True, timeout=180) as resp:
                resp.raise_for_status()
                total = int(resp.headers.get("content-length", 0))
                descargado = 0
                with open(tmp_path, "wb") as f:
                    for chunk in resp.iter_content(chunk_size=65536):
                        f.write(chunk)
                        descargado += len(chunk)
                        if total:
                            pct = 40 + int((descargado / total) * 50)
                            set_progress(pct)
            set_status("⚙️  Instalando actualización...")
            set_progress(95)
            splash.after(600, lambda p=tmp_path: _instalar(p))
        except Exception as e:
            _emsg = str(e).lower()
            if any(x in _emsg for x in ('nameresolution', 'connection', 'timeout', 'network', 'socket', 'gaierror')):
                set_status("Sin conexión — iniciando Studio IVR...")
            else:
                set_status("No se pudo verificar versión. Iniciando...")
            set_progress(100)
            splash.after(1500, _arrancar)

    def _instalar(tmp_path):
        set_status("[OK] Instalando actualización...")
        set_progress(100)
        bat_path = os.path.join(tempfile.gettempdir(), "vf_update.bat")
        with open(bat_path, "w") as bat:
            bat.write(
                "@echo off\r\n"
                "timeout /t 2 /nobreak > nul\r\n"
                "taskkill /F /IM StudioIVR.exe > nul 2>&1\r\n"
                "taskkill /F /IM StudioIVR.exe > nul 2>&1\r\n"
                "timeout /t 2 /nobreak > nul\r\n"
                f"start \"\" \"{tmp_path}\" /VERYSILENT /NORESTART /FORCECLOSEAPPLICATIONS\r\n"
                "timeout /t 20 /nobreak > nul\r\n"
                f"start \"\" \"{sys.executable}\"\r\n"
                "del \"%~f0\"\r\n"
            )
        subprocess.Popen(["cmd.exe", "/c", bat_path], creationflags=subprocess.CREATE_NO_WINDOW)
        splash.after(500, lambda: sys.exit(0))

    def _arrancar():
        splash.destroy()

    threading.Thread(target=_update_task, daemon=True).start()
    splash.mainloop()

