    _localappdata = os.environ.get("LOCALAPPDATA", "")
    _py313_site = os.path.join(_localappdata, "Programs", "Python", "Python313", "Lib", "site-packages")
    if os.path.isdir(_py313_site) and _py313_site not in sys.path:
        sys.path.insert(0, _py313_site)
    _torch_lib = os.path.join(_py313_site, "torch", "lib")
    _torch_bin = os.path.join(_py313_site, "torch", "bin")
