        "var _E=['\U0001f3ac','\U0001f4fd️','\U0001f39e️','\U0001f3a5','✨','\U0001f31f','\U0001f3ad','\U0001f4fa'];"
        "var _syncing=false;"
        "function _vfSyncFS(cb){"
        "  fetch('/api/proyectos/listar')"
        "  .then(function(r){return r.json();})"
        "  .then(function(list){"
        "    if(!Array.isArray(list)){cb&&cb();return;}"
        "    var ex=PM.getAll();"
        "    var names=ex.map(function(p){return(p.name||'').toLowerCase();});"
        "    var changed=false;"
        "    list.forEach(function(p){"
        "      var n=(p.nombre||p.name||'').trim();"
        "      if(!n||names.indexOf(n.toLowerCase())>=0)return;"
        "      var ts=p.creado?new Date(p.creado*1000).toISOString():new Date().toISOString();"
        "      ex.push({"
        "        id:'proj_'+Date.now()+'_'+Math.random().toString(36).slice(2,6),"
        "        name:n,"
        "        color:_C[ex.length%_C.length],"
        "        emoji:_E[ex.length%_E.length],"
        "        createdAt:ts,updatedAt:ts,"
        "        guion:{texto:'',escenas:[],prompts:[]},"
        "        voz:{modelo:'elevenlabs'},"
        "        imagen:{modelo:'flow'},"
        "        video:{modelo:'grok'},"
        "        render:{motion:'kenburns',transition:'crossfade'}"
        "      });"
        "      names.push(n.toLowerCase());"
        "      changed=true;"
        "    });"
        "    if(changed)PM.save(ex);"
        # After syncing, re-check load_project param — may not have been in localStorage yet
        "    var _lp2=new URLSearchParams(window.location.search).get('load_project');"
        "    if(_lp2&&!PM.getActive()){"
        "      var _all2=PM.getAll();"
        "      var _fp2=_all2.find(function(p){return(p.name||p.nombre||'')===_lp2;});"
        "      if(_fp2){"
        "        PM.setActive(_fp2.id);"
        "        setTimeout(function(){if(typeof navigate==='function')navigate('guion');},180);"
        "      }"
        "    }"
        "    cb&&cb();"
        "  }).catch(function(){cb&&cb();});}"
        # Rellena todos los <select class="proj-select"> con los proyectos actuales de PM.
        # Se llama después del sync FS para que el select aparezca poblado aunque el app
        # haya corrido su lógica de init antes de que el sync terminara.
        "function _vfFillProjSelects(){"
        "  try{"
        "    var all=PM.getAll();"
        "    var active=PM.getActive&&PM.getActive();"
        "    document.querySelectorAll('select.proj-select').forEach(function(sel){"
        "      var prev=sel.value;"
        "      while(sel.options.length>1)sel.remove(1);"
        "      all.forEach(function(p){"
        "        var opt=document.createElement('option');"
        "        opt.value=p.id;"
        "        opt.textContent=(p.name||p.nombre||'').trim()||p.id;"
        "        if(p.id===prev||(prev===''&&p.id===active))opt.selected=true;"
        "        sel.appendChild(opt);"
        "      });"
        "      if(!sel.value&&active){"
        "        for(var i=0;i<sel.options.length;i++){"
        "          if(sel.options[i].value===active){sel.selectedIndex=i;break;}"
        "        }"
        "      }"
        "    });"
        "  }catch(e){}"
