        "function pollWhisk(){"
        " var kind='imagenes';"
        " var s=_VFP[kind]; if(!s||!s.open) return;"
        " if(!s._wskSeen) s._wskSeen=false;"
        " fetch('/api/whisk/status').then(function(r){return r.json();}).then(function(j){"
        "  var s=_VFP[kind]; if(!s||!s.open) return;"
        "  if(j&&j.running) s._wskSeen=true;"
        "  var logs=[];"
        "  if(j&&j.last_log&&j.last_log.length) logs=j.last_log;"
