        "  if(logs.length) logs.forEach(function(l){s.lines.push(String(l));});"
        "  var tot=+(j&&j.total!=null?j.total:0)||0, pr=+(j&&j.progress!=null?j.progress:0)||0, saved=+(j&&j.images_saved!=null?j.images_saved:0)||0;"
        "  if(tot>0){ s.pct=Math.min(99,Math.round(pr/Math.max(1,tot)*100)); s.phase='Imagenes en cola: '+pr+' / '+tot+' · guardadas '+saved; }"
