            '  margin:0 4px;font-family:inherit\n'
            '}\n'
            '#xtab-add:hover{background:rgba(124,106,255,.15);color:#a78bfa;border-color:rgba(124,106,255,.55)}\n'

            '/* Tab dropdown menu */\n'
            '#xtab-menu{\n'
            '  position:fixed;top:50px;\n'
            '  background:#0d0d1c;border:1px solid rgba(255,255,255,.1);\n'
            '  border-radius:10px;padding:5px;min-width:160px;\n'
            '  box-shadow:0 8px 28px rgba(0,0,0,.65);z-index:960;\n'
            '  display:none\n'
            '}\n'
            '#xtab-menu.xopen{display:block}\n'
            '.xtab-mi{\n'
            '  display:flex;align-items:center;gap:9px;\n'
            '  padding:7px 11px;border-radius:7px;cursor:pointer;\n'
            '  font-size:12.5px;font-weight:500;color:#7a7a96;\n'
            '  background:none;border:none;width:100%;text-align:left;\n'
            '  transition:background .13s,color .13s;font-family:inherit\n'
            '}\n'
            '.xtab-mi:hover{background:rgba(255,255,255,.06);color:#eeeef5}\n'
            '.xtab-mi.xon{color:#a78bfa;font-weight:600}\n'

            '/* Project selector in topbar */\n'
            '#xproj-wrap{\n'
            '  display:flex;align-items:center;gap:7px;\n'
            '  padding:5px 10px;border-radius:7px;flex-shrink:0;\n'
            '  background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.08);\n'
            '  margin-right:6px;transition:background .13s,border-color .13s\n'
            '}\n'
            '#xproj-wrap:hover{background:rgba(255,255,255,.08);border-color:rgba(255,255,255,.14)}\n'
            '#xproj-lbl{font-size:9px;font-weight:700;letter-spacing:.12em;text-transform:uppercase;color:#4a4a63;white-space:nowrap}\n'
            '#xproj-sel{\n'
            '  background:none;border:none;color:#eeeef5;font-size:12px;\n'
            '  font-weight:600;cursor:pointer;font-family:inherit;outline:none;\n'
            '  max-width:140px\n'
            '}\n'
            '#xproj-sel option{background:#0d0d1c;color:#eeeef5}\n'

            '/* ── Browser-style tab overrides ─────────────────────────── */\n'
            '#xtabs{align-items:flex-end!important;padding:0 4px!important;gap:3px!important}\n'
            '.xtab{\n'
            '  height:36px!important;min-width:80px!important;max-width:180px!important;\n'
            '  border-radius:8px 8px 0 0!important;\n'
            '  border:1px solid rgba(255,255,255,.09)!important;\n'
            '  border-bottom:none!important;\n'
            '  border-right:none!important;\n'
            '  background:rgba(255,255,255,.04)!important;\n'
            '  padding:0 11px!important;\n'
            '  margin-bottom:-1px!important;\n'
            '  overflow:hidden!important;text-overflow:ellipsis!important\n'
            '}\n'
            '.xtab:first-child{border-left:1px solid rgba(255,255,255,.09)!important}\n'
            '.xtab:hover{background:rgba(255,255,255,.08)!important;border-color:rgba(255,255,255,.14)!important;color:#eeeef5!important}\n'
            '/* Active tab — purple top border, slightly lighter bg */\n'
            '.xtab-on{\n'
            '  color:#eeeef5!important;font-weight:600!important;\n'
            '  background:rgba(124,106,255,.15)!important;\n'
            '  border-color:rgba(124,106,255,.35)!important;\n'
            '  border-top-color:#7c6aff!important;\n'
            '  box-shadow:none!important\n'
            '}\n'
            '/* Home button — left of tab bar, distinct from tabs */\n'
            '#xtop-home{\n'
            '  display:inline-flex!important;align-items:center;justify-content:center;\n'
            '  width:34px!important;height:34px!important;border-radius:8px!important;\n'
            '  background:rgba(255,255,255,.06)!important;\n'
            '  border:1px solid rgba(255,255,255,.1)!important;\n'
            '  color:#7a7a96!important;cursor:pointer;flex-shrink:0;\n'
            '  transition:background .13s,color .13s;\n'
            '  margin-right:6px!important;align-self:flex-end!important;margin-bottom:3px!important\n'
            '}\n'
            '#xtop-home:hover{background:rgba(124,106,255,.15)!important;color:#a78bfa!important;border-color:rgba(124,106,255,.35)!important}\n'
            '/* + button inside tab bar */\n'
            '#xtab-add{\n'
            '  display:inline-flex!important;align-items:center;justify-content:center;\n'
            '  width:28px!important;height:28px!important;border-radius:7px!important;\n'
            '  background:rgba(255,255,255,.05)!important;\n'
            '  border:1.5px dashed rgba(255,255,255,.22)!important;\n'
            '  color:#7a7a96!important;cursor:pointer;font-size:15px;line-height:1;\n'
            '  transition:background .13s,color .13s,border-color .13s;\n'
            '  margin:0 3px 3px!important;font-family:inherit;flex-shrink:0\n'
            '}\n'
            '#xtab-add:hover{background:rgba(124,106,255,.15)!important;color:#a78bfa!important;border-color:rgba(124,106,255,.55)!important}\n'

            '/* Tab processing/done */\n'
            '.xtab-processing{\n'
            '  color:#f59e0b!important;\n'
            '  background:rgba(245,158,11,.1)!important;\n'
            '  border-color:rgba(245,158,11,.35)!important;\n'
            '  border-top-color:#f59e0b!important;\n'
            '  animation:xtPulse 1.4s ease-in-out infinite!important\n'
            '}\n'
            '.xtab-done{\n'
            '  color:#22d3a0!important;\n'
            '  background:rgba(34,211,160,.1)!important;\n'
            '  border-color:rgba(34,211,160,.35)!important;\n'
            '  border-top-color:#22d3a0!important\n'
            '}\n'
            '@keyframes xtPulse{0%,100%{opacity:.8}50%{opacity:1}}\n'

            '/* Tasks button status */\n'
            '.xtasks.xtask-active{background:rgba(245,158,11,.12)!important;color:#f59e0b!important;animation:xtPulse 1.4s ease-in-out infinite}\n'
            '.xtasks.xtask-done{background:rgba(34,211,160,.1)!important;color:#22d3a0!important}\n'

            '/* Pipeline sidebar */\n'
            '#xpipeline-sec{padding:12px 9px 8px;border-top:1px solid rgba(255,255,255,.06);margin-top:4px}\n'
            '#xpipeline-sec .xpipe-title{font-size:9.5px;font-weight:700;letter-spacing:.12em;color:#4a4a63;text-transform:uppercase;padding:0 1px 8px;display:block}\n'
            '.xpipe-step{\n'
            '  display:flex;align-items:center;gap:9px;\n'
            '  padding:7px 8px;border-radius:8px;cursor:pointer;\n'
            '  font-size:13px;font-weight:500;color:#5a5a7a;\n'
            '  background:none;border:none;width:100%;text-align:left;\n'
            '  transition:background .13s,color .13s;font-family:inherit\n'
            '}\n'
            '.xpipe-step:hover{background:rgba(255,255,255,.05)!important;color:#eeeef5!important}\n'
            '.xpipe-step.xpipe-on{color:#eeeef5!important;background:linear-gradient(90deg,rgba(124,106,255,.18),rgba(124,106,255,.06))!important;font-weight:600!important}\n'
            '.xpipe-num{\n'
            '  width:20px;height:20px;border-radius:6px;flex-shrink:0;\n'
            '  display:flex;align-items:center;justify-content:center;\n'
            '  font-size:11px;font-weight:700;\n'
            '  background:rgba(255,255,255,.07);color:#5a5a7a;\n'
            '  border:1px solid rgba(255,255,255,.08);\n'
            '  transition:background .13s,color .13s,border-color .13s\n'
            '}\n'
            '.xpipe-step.xpipe-on .xpipe-num{background:rgba(124,106,255,.3)!important;color:#a78bfa!important;border-color:rgba(124,106,255,.4)!important}\n'
            '.xpipe-step:hover .xpipe-num{background:rgba(255,255,255,.1);color:#eeeef5}\n'

            '/* ── Horizontal in-page pipeline nav ─────────────────────── */\n'
            '.vf-pg-nav{padding:8px 52px 0;margin-bottom:0;background:#07070e;border-bottom:1px solid rgba(255,255,255,.05)}\n'
            '.vf-pg-ey{\n'
            '  font-size:9px;font-weight:700;letter-spacing:.16em;\n'
            '  text-transform:uppercase;color:#4a4a63;margin-bottom:14px\n'
            '}\n'
            '.vf-ptabs{\n'
            '  display:flex;align-items:center;\n'
            '  border-bottom:1px solid rgba(255,255,255,.08);\n'
            '  overflow-x:auto;scrollbar-width:none\n'
            '}\n'
            '.vf-ptabs::-webkit-scrollbar{display:none}\n'
            '.vf-ptab{\n'
            '  display:inline-flex;align-items:center;gap:9px;\n'
            '  padding:10px 18px 13px;border:none;\n'
            '  border-bottom:2px solid transparent;margin-bottom:-1px;\n'
            '  cursor:pointer;font-size:13px;font-weight:500;color:#5a5a7a;\n'
            '  background:none;font-family:inherit;white-space:nowrap;\n'
            '  transition:color .13s,border-color .13s\n'
            '}\n'
            '.vf-ptab:hover{color:#c0bef5!important}\n'
            '.vf-ptab.vf-pon{color:#7c6aff!important;border-bottom-color:#7c6aff!important;font-weight:600!important}\n'
            '.vf-ptab-n{\n'
            '  width:20px;height:20px;border-radius:6px;\n'
            '  background:rgba(255,255,255,.07);border:1px solid rgba(255,255,255,.09);\n'
            '  display:inline-flex;align-items:center;justify-content:center;\n'
            '  font-size:10px;font-weight:700;flex-shrink:0;\n'
            '  transition:background .13s,color .13s,border-color .13s\n'
            '}\n'
            '.vf-ptab.vf-pon .vf-ptab-n{background:rgba(124,106,255,.22)!important;border-color:rgba(124,106,255,.4)!important;color:#a78bfa!important}\n'
            '/* Hide internal g-steps (replaced by the new pipeline nav) */\n'
            '#page-guion .g-steps{display:none!important}\n'

            '/* ── Guion page hero — compact SaaS redesign ─────────────────── */\n'
            '.gs-script-art{display:none!important}\n'
            '#page-guion .vs-hero-glow{display:none!important}\n'
            '#page-guion .vs-hero-bd{display:none!important}\n'
            '.gs-hero-full{display:block!important;padding:16px 52px 14px!important;background:linear-gradient(90deg,rgba(124,106,255,.04),rgba(192,38,211,.02))!important;border-bottom:1px solid rgba(124,106,255,.14)!important}\n'
            'body #page-guion.page-section.active .gs-hero-wrap{margin-top:0!important}\n'
            '/* New header elements */\n'
            '.vf-gs-row{display:flex;align-items:center;justify-content:space-between;gap:16px;margin-bottom:7px}\n'
            '.vf-gs-left{display:flex;align-items:center;gap:10px}\n'
            '.vf-gs-icon-wrap{width:32px;height:32px;border-radius:9px;background:linear-gradient(135deg,rgba(124,106,255,.22),rgba(192,38,211,.12));border:1px solid rgba(124,106,255,.3);display:flex;align-items:center;justify-content:center;flex-shrink:0;font-size:14px;color:#a78bfa}\n'
            '.vf-gs-meta{display:flex;flex-direction:column;gap:1px}\n'
            '.vf-gs-eyebrow{font-size:9px;font-weight:700;letter-spacing:.14em;text-transform:uppercase;color:#4a4a63}\n'
            '.vf-gs-title{font-size:19px;font-weight:700;letter-spacing:-.025em;color:#eeeef5;margin:0;line-height:1.1}\n'
            '.vf-gs-title span{background:linear-gradient(90deg,#a78bfa,#c084fc);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}\n'
            '.vf-gs-badges{display:flex;gap:6px;flex-shrink:0}\n'
            '.vf-gs-badge{font-size:9px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:#a78bfa;background:rgba(124,106,255,.1);border:1px solid rgba(124,106,255,.22);border-radius:6px;padding:3px 8px}\n'
            '.vf-gs-step-badge{font-size:9px;font-weight:600;letter-spacing:.06em;color:#4a4a63;background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.08);border-radius:6px;padding:3px 8px}\n'
            '.vf-gs-desc{font-size:12px;color:#5a5a78;line-height:1.5;margin:0 0 9px;max-width:600px}\n'
            '.vf-gs-chips{display:flex;flex-wrap:wrap;gap:5px}\n'
            '.vf-gs-chip{font-size:10px;font-weight:500;color:#5a5a78;background:rgba(255,255,255,.035);border:1px solid rgba(255,255,255,.07);border-radius:20px;padding:3px 10px;letter-spacing:.01em}\n'
            '/* Editor card polish */\n'
            '#page-guion .guion-wrap{padding:0!important}\n'
            '#page-guion .guion-wrap .g-card,#page-guion .guion-wrap .gk-card{border:none!important;background:transparent!important;box-shadow:none!important;border-radius:0!important;margin:0!important;padding:0!important}\n'
            '#page-guion .guion-wrap .g-card-header,#page-guion .guion-wrap .gk-card-head{padding:11px 15px!important;background:rgba(255,255,255,.025)!important;border-bottom:1px solid rgba(255,255,255,.06)!important;border-radius:0!important}\n'
            '#page-guion .guion-wrap .g-card-body,#page-guion .guion-wrap .gk-card-body{padding:0!important}\n'
            '#page-guion .guion-wrap .g-hint-row{padding:8px 15px!important;border-top:1px solid rgba(255,255,255,.04)!important;font-size:11px!important;color:#38384e!important}\n'
            '/* Action buttons row */\n'
            '.vf-guion-acts{display:flex;gap:7px;flex-wrap:wrap;margin-bottom:16px}\n'
            '.vf-act-btn{\n'
            '  display:inline-flex;align-items:center;gap:6px;\n'
            '  padding:7px 13px;border-radius:8px;\n'
            '  border:1px solid rgba(255,255,255,.1);\n'
            '  background:rgba(255,255,255,.05);color:#b0aed8;\n'
            '  font-size:12.5px;font-weight:500;cursor:pointer;\n'
            '  font-family:inherit;transition:background .13s,color .13s,border-color .13s\n'
            '}\n'
            '.vf-act-btn:hover{background:rgba(124,106,255,.12);border-color:rgba(124,106,255,.3);color:#eeeef5}\n'
            '.vf-act-ai{background:rgba(124,106,255,.1)!important;border-color:rgba(124,106,255,.28)!important;color:#a78bfa!important}\n'
            '/* Two-column guion layout */\n'
            '.vf-guion-wrap{display:flex;gap:20px;align-items:flex-start}\n'
            '.vf-guion-main{flex:1;min-width:0}\n'
            '.vf-guion-side{flex:0 0 260px;display:flex;flex-direction:column;gap:12px}\n'
            '/* Right cards */\n'
            '.vf-gcard{background:rgba(11,11,24,.8);border:1px solid rgba(124,106,255,.14);border-radius:12px;padding:15px 16px}\n'
            '.vf-gcard-ttl{font-size:9px;font-weight:700;letter-spacing:.14em;text-transform:uppercase;color:#4a4a63;margin-bottom:13px}\n'
            '.vf-ajuste-row{display:flex;justify-content:space-between;align-items:center;padding:8px 0;border-bottom:1px solid rgba(255,255,255,.05)}\n'
            '.vf-stat-lbl{color:#6a6a88;font-weight:500;font-size:12.5px}\n'
            '.vf-ajuste-sel{\n'
            '  background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1);\n'
            '  border-radius:6px;color:#eeeef5;font-size:12px;\n'
            '  padding:4px 8px;cursor:pointer;font-family:inherit;outline:none;max-width:138px\n'
            '}\n'
            '.vf-ajuste-sel option{background:#0d0d1c;color:#eeeef5}\n'
            '.vf-ajuste-stat{display:flex;justify-content:space-between;align-items:center;padding:8px 0;border-top:1px solid rgba(255,255,255,.05)}\n'
            '.vf-stat-val{color:#eeeef5;font-weight:600;font-size:12px}\n'
            '.vf-stat-row{display:flex;justify-content:space-between;align-items:center;padding:7px 0;border-bottom:1px solid rgba(255,255,255,.05)}\n'
            '.vf-stat-row:last-child{border-bottom:none}\n'
            '.vf-comp-right{display:flex;flex-direction:column;align-items:flex-end;gap:5px}\n'
            '.vf-comp-bar{width:72px;height:3px;background:rgba(255,255,255,.08);border-radius:2px;overflow:hidden}\n'
            '.vf-comp-fill{height:100%;background:linear-gradient(90deg,#7c6aff,#a78bfa);border-radius:2px;width:0%;transition:width .4s ease}\n'
            '/* Footer bar */\n'
            '.vf-gfooter{display:flex;align-items:center;justify-content:space-between;padding:16px 0 0;border-top:1px solid rgba(255,255,255,.06);margin-top:20px}\n'
            '.vf-gfoot-btn{padding:9px 18px;border-radius:8px;border:1px solid rgba(255,255,255,.1);background:rgba(255,255,255,.05);color:#7a7a96;font-size:13px;font-weight:500;cursor:pointer;font-family:inherit;transition:background .13s,color .13s}\n'
            '.vf-gfoot-btn:hover{background:rgba(255,255,255,.08);color:#eeeef5}\n'
            '.vf-gfoot-prim{background:rgba(124,106,255,.82)!important;border-color:transparent!important;color:#fff!important;font-weight:600!important}\n'
            '.vf-gfoot-prim:hover{background:#7c6aff!important}\n'
            '/* Procesar Guión — reveal and style the real footer button */\n'
            '#page-guion .g-footer{display:flex!important;justify-content:flex-end!important;padding:14px 0 2px!important;margin-top:6px!important;border-top:1px solid rgba(255,255,255,.05)!important}\n'
            '#page-guion #btn-submit,#page-guion .btn-submit{padding:10px 24px!important;border-radius:8px!important;background:linear-gradient(135deg,rgba(124,106,255,.9),rgba(160,130,255,.85))!important;border:1px solid rgba(124,106,255,.55)!important;color:#fff!important;font-size:13px!important;font-weight:700!important;letter-spacing:.01em!important;cursor:pointer!important;font-family:inherit!important;transition:opacity .15s,background .15s!important;box-shadow:0 2px 12px rgba(124,106,255,.25)!important}\n'
            '#page-guion #btn-submit:not(:disabled):hover,#page-guion .btn-submit:not(:disabled):hover{background:linear-gradient(135deg,rgba(140,120,255,1),rgba(175,145,255,.95))!important}\n'
            '#page-guion #btn-submit:disabled,#page-guion .btn-submit:disabled{opacity:.38!important;cursor:not-allowed!important}\n'
            '#page-guion .g-toggles{display:block!important;padding:10px 15px 13px!important;border-top:1px solid rgba(255,255,255,.05)!important;background:rgba(0,0,0,.1)!important}\n'
            '#page-guion .g-toggles label,#page-guion .g-toggle-label{font-size:12px!important;color:#7a7a96!important;cursor:pointer!important;display:inline-flex!important;align-items:center!important;gap:7px!important;margin-right:18px!important}\n'
            '#page-guion .g-toggle-row,#page-guion .g-toggles-row{display:flex!important;flex-wrap:wrap!important;gap:6px 0!important}\n'
            '#page-guion .g-toggles input[type=radio],#page-guion .g-toggles input[type=checkbox]{accent-color:#7c6aff!important}\n'

            '/* ── Line numbers editor ────────────────────────────────────── */\n'
            '.vf-editor-wrap{display:flex;overflow:hidden;border-radius:6px;background:rgba(0,0,0,.1)}\n'
            '.vf-line-nums{\n'
            '  flex:0 0 40px;padding:12px 8px 12px 4px;\n'
            '  font-family:var(--mono);font-size:12.5px;line-height:1.62;\n'
            '  color:#2e2e48;text-align:right;\n'
            '  background:rgba(0,0,0,.18);border-right:1px solid rgba(255,255,255,.04);\n'
            '  user-select:none;white-space:pre;overflow:hidden;\n'
            '  pointer-events:none\n'
            '}\n'
            '#page-guion .vf-editor-wrap textarea#guion-input{\n'
            '  flex:1!important;width:auto!important;\n'
            '  border:none!important;border-radius:0!important;\n'
            '  background:transparent!important;\n'
            '  padding:12px!important;min-height:220px!important;\n'
            '  font-family:var(--mono)!important;font-size:13px!important;\n'
            '  line-height:1.62!important;resize:vertical!important\n'
            '}\n'

            '/* ── Scene cards strip ───────────────────────────────────────── */\n'
            '.vf-scenes-hdr{display:flex;align-items:center;justify-content:space-between;padding:16px 0 10px;border-top:1px solid rgba(255,255,255,.06);margin-top:14px}\n'
            '.vf-scenes-lbl{font-size:9px;font-weight:700;letter-spacing:.14em;text-transform:uppercase;color:#38384e}\n'
            '.vf-scenes-count{font-size:10.5px;color:#4a4a63;font-weight:500}\n'
            '.vf-scenes-strip{\n'
            '  display:flex;gap:10px;overflow-x:auto;\n'
            '  padding:0 0 10px;\n'
            '  scrollbar-width:thin;scrollbar-color:rgba(124,106,255,.2) transparent\n'
            '}\n'
            '.vf-scenes-strip::-webkit-scrollbar{height:3px}\n'
            '.vf-scenes-strip::-webkit-scrollbar-track{background:transparent}\n'
            '.vf-scenes-strip::-webkit-scrollbar-thumb{background:rgba(124,106,255,.2);border-radius:2px}\n'
            '.vf-sc-card{\n'
            '  flex:0 0 162px;background:rgba(10,10,22,.85);\n'
            '  border:1px solid rgba(255,255,255,.07);border-radius:10px;\n'
            '  padding:11px 12px;cursor:pointer;\n'
            '  transition:background .13s,border-color .13s,box-shadow .13s;\n'
            '  position:relative;overflow:hidden\n'
            '}\n'
            '.vf-sc-card::after{content:"";position:absolute;top:0;left:0;right:0;height:2px;background:linear-gradient(90deg,rgba(124,106,255,.5),rgba(168,85,247,.3));opacity:0;transition:opacity .13s}\n'
            '.vf-sc-card:hover{background:rgba(124,106,255,.07)!important;border-color:rgba(124,106,255,.22)!important;box-shadow:0 4px 18px rgba(124,106,255,.1)!important}\n'
            '.vf-sc-card:hover::after{opacity:1}\n'
            '.vf-sc-hdr{display:flex;justify-content:space-between;align-items:center;margin-bottom:3px;gap:6px}\n'
            '.vf-sc-ttl{font-size:11px;font-weight:700;color:#c0bef5;white-space:nowrap}\n'
            '.vf-sc-del{color:#2e2e48;cursor:pointer;font-size:11px;opacity:.7;background:none;border:none;font-family:inherit;line-height:1;padding:0;flex-shrink:0}\n'
            '.vf-sc-del:hover{opacity:1;color:#f87171}\n'
            '.vf-sc-time{font-size:9px;color:#3a3a55;font-family:var(--mono);white-space:nowrap;display:block;margin-bottom:7px;letter-spacing:.02em}\n'
