            '.vfv-model-card:hover{background:rgba(124,106,255,.08);border-color:rgba(124,106,255,.28);color:#9090b8}\n'
            '.vfv-model-card.vfv-m-on{background:rgba(124,106,255,.14)!important;border-color:rgba(124,106,255,.45)!important;color:#a78bfa!important}\n'
            '.vfv-mini-btn{font-size:11px;color:#7a7a96;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1);border-radius:6px;padding:4px 8px;cursor:pointer;display:inline-flex;align-items:center;gap:4px;font-family:inherit;transition:all .13s;flex-shrink:0}\n'
            '.vfv-mini-btn:hover{color:#a78bfa;border-color:rgba(124,106,255,.3);background:rgba(124,106,255,.1)}\n'
