            '.vfv-footer{display:flex;align-items:center;justify-content:space-between;padding:14px 0 0;border-top:1px solid rgba(255,255,255,.06)}\n'
            '.vfv-foot-proc{background:linear-gradient(135deg,rgba(124,106,255,.9),rgba(160,130,255,.85))!important;border-color:rgba(124,106,255,.55)!important;color:#fff!important;font-weight:700!important;padding:10px 24px!important;font-size:13px!important;letter-spacing:.01em!important;box-shadow:0 2px 12px rgba(124,106,255,.26)!important}\n'
            '.vfv-foot-proc:hover{background:linear-gradient(135deg,rgba(140,120,255,1),rgba(175,145,255,.95))!important}\n'
