            '/* Provider toggle */\n'
            '.vfv-provider-row{display:flex;gap:6px;margin-bottom:14px}\n'
            '.vfv-prov-btn{flex:1;padding:7px 8px;border-radius:8px;border:1px solid rgba(255,255,255,.1);background:rgba(255,255,255,.04);color:#5a5a78;font-size:10.5px;font-weight:600;cursor:pointer;font-family:inherit;text-align:center;letter-spacing:.02em;transition:all .15s}\n'
            '.vfv-prov-btn:hover{background:rgba(124,106,255,.08);color:#9090b8}\n'
            '.vfv-prov-btn.vfv-pv-on{background:rgba(124,106,255,.16)!important;border-color:rgba(124,106,255,.45)!important;color:#a78bfa!important}\n'
            '/* XTTS zone */\n'
            '.vfv-xtts-zone{display:none;padding-top:10px;border-top:1px solid rgba(255,255,255,.06);margin-top:10px}\n'
            '.vfv-xtts-zone.on{display:block!important}\n'
            '.vfv-xtts-inp{width:100%;box-sizing:border-box;background:rgba(255,255,255,.04);border:1px solid rgba(124,106,255,.18);border-radius:8px;padding:7px 11px;color:var(--t);font-size:10.5px;font-family:var(--mono);outline:none;transition:border-color .15s}\n'
            '.vfv-xtts-inp:focus{border-color:rgba(167,139,250,.5)}\n'
            '/* XTTS progress */\n'
            '.vfv-xtts-pgwrap{display:none;margin-top:8px;padding:8px 10px;background:rgba(124,106,255,.05);border:1px solid rgba(124,106,255,.12);border-radius:8px}\n'
            '.vfv-xtts-pgwrap.on{display:block}\n'
            '.vfv-xtts-pgbar-track{height:3px;background:rgba(255,255,255,.07);border-radius:2px;overflow:hidden;margin-bottom:6px}\n'
            '.vfv-xtts-pgbar{height:100%;background:linear-gradient(90deg,#7c6aff,#a78bfa);width:0%;transition:width .4s;border-radius:2px}\n'
            '.vfv-xtts-status{font-size:10.5px;color:#4a4a63;line-height:1.4}\n'
            '/* ── Video Studio page redesign ──────────────────────────── */\n'
            '#page-video.page-section.active .g-header{padding:18px 20px 0!important;max-width:none!important;margin-bottom:16px!important}\n'
            '#page-video.page-section.active .grok-wrap{max-width:none!important;padding:0 20px 40px!important}\n'
            '#page-video.page-section.active .pg-grok{min-height:0!important}\n'
            '.vfvid-prov-row{display:flex;gap:6px;margin-bottom:18px;background:rgba(11,11,24,.85);border:1px solid rgba(124,106,255,.14);border-radius:12px;padding:5px}\n'
            '.vfvid-prov-btn{flex:1;padding:10px 8px;border-radius:8px;background:transparent;border:none;color:#5a5a75;font-size:12.5px;font-weight:600;cursor:pointer;transition:background .18s,color .18s;font-family:var(--f,-apple-system,BlinkMacSystemFont,system-ui,sans-serif);display:flex;align-items:center;justify-content:center;gap:8px}\n'
            '.vfvid-prov-btn:hover{background:rgba(255,255,255,.05);color:#eeeef5}\n'
            '.vfvid-prov-btn.vfvid-pv-on{background:rgba(124,106,255,.18)!important;color:#c0bef5!important}\n'
            '.vfvid-prov-badge{font-size:8.5px;padding:2px 7px;border-radius:5px;font-family:var(--mono,monospace);letter-spacing:.06em;font-weight:700;flex-shrink:0}\n'
            '.vfvid-badge-grok{background:rgba(23,209,108,.12);color:#4ade80;border:1px solid rgba(52,211,153,.25)}\n'
            '.vfvid-badge-meta{background:rgba(24,119,242,.15);color:#60a5fa;border:1px solid rgba(96,165,250,.25)}\n'
            '</style>\n'

            '<script id="xi-fullwidth">\n'
            '(function(){\n'

            '  /* Detect outer shell: each project opens in its own isolated iframe */\n'
            '  var _inShell=(function(){try{return window.parent!==window;}catch(e){return false;}})();\n'
            '  if(_inShell){\n'
            '    var _xics=document.createElement("style");\n'
            '    _xics.textContent=[\n'
            '      "#xtop{display:none!important;height:0!important;min-height:0!important}",\n'
            '      "body .main-content{padding-top:0!important}",\n'
            '      ".xlogo{display:none!important;height:0!important;min-height:0!important;padding:0!important;margin:0!important}",\n'
            '      ".proj-topbar{display:none!important;height:0!important;min-height:0!important;padding:0!important;margin:0!important}",\n'
            '      "body #page-guion.page-section.active .pg-guion{padding-top:4px!important}",\n'
            '      "body #page-voz.page-section.active .tool-wrap{padding-top:4px!important}",\n'
            '      "body #page-imagen.page-section.active .tool-wrap,body #page-imagen.page-section.active .pg-imagen{padding-top:4px!important}",\n'
            '      "body #page-video.page-section.active .grok-wrap,body #page-video.page-section.active .tool-wrap{padding-top:4px!important}",\n'
            '      "body #page-render.page-section.active .pg-render main{padding-top:4px!important}"\n'
            '    ].join("");\n'
            '    (document.head||document.documentElement).appendChild(_xics);\n'
            '    /* Also force via inline style to guarantee no top gap */\n'
            '    function _xiFix(){\n'
            '      var mc=document.querySelector(".main-content");\n'
            '      if(mc)mc.style.setProperty("padding-top","0","important");\n'
            '      document.querySelectorAll(".proj-topbar").forEach(function(el){\n'
            '        el.style.setProperty("display","none","important");\n'
            '      });\n'
            '    }\n'
            '    _xiFix();\n'
            '    setTimeout(_xiFix,100);\n'
            '    setTimeout(_xiFix,500);\n'
            '  }\n'

            '  /* tabs: [{id:projectId|null}] — one entry per visible tab */\n'
            '  var tabs=[{id:null}];\n'
            '  var curTabIdx=0;\n'
            '  var curPage="home";\n'
            '  var _procTabIdx=-1;\n'
            '  var _lastIsProc=false;\n'
            '  /* Dedup: prevent double-tab when openProject+selectProject both fire */\n'
            '  var _shellTabLast={url:"",t:0};\n'

            '  var PIPELINE_STEPS=[\n'
            '    {page:"guion",label:"Guión escrito"},\n'
            '    {page:"imagen",label:"Generación de imágenes"},\n'
            '    {page:"voz",label:"Generación de voz"},\n'
            '    {page:"video",label:"Generación de video"},\n'
            '    {page:"render",label:"Renderizado"}\n'
            '  ];\n'

            '  function getProjName(id){\n'
            '    try{var p=PM.get(id);return p?(p.name||p.n||id):id;}catch(e){return id;}\n'
            '  }\n'

            '  function fix(){\n'
            '    var sb=document.getElementById("xsb");\n'
            '    var sbW=sb?parseInt(getComputedStyle(sb).width)||228:0;\n'
            '    var mc=document.querySelector(".main-content");\n'
            '    if(mc){mc.style.setProperty("margin-left",sbW?"228px":"0px","important");}\n'
            '    var w=document.querySelector("#page-home .dash-wrap")||document.querySelector(".dash-wrap");\n'
            '    if(w){w.style.setProperty("max-width","none","important");\n'
            '          w.style.setProperty("width","100%","important");\n'
            '          w.style.setProperty("box-sizing","border-box","important");}\n'
            '    var g=document.getElementById("project-grid");\n'
            '    if(g){g.style.setProperty("grid-template-columns","repeat(auto-fill,minmax(230px,1fr))","important");\n'
            '          g.style.setProperty("width","100%","important");}\n'
            '    var pw=document.getElementById("xproj-wrap");\n'
            '    if(pw)pw.style.display=(curPage==="home")?"none":"flex";\n'
            '  }\n'

            '  var _HOME_SVG=\'<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9,22 9,12 15,12 15,22"/></svg>\';\n'

            '  function renderTabs(){\n'
            '    var xt=document.getElementById("xtabs");if(!xt)return;\n'
            '    xt.innerHTML="";\n'
            '    /* Tab for each entry in tabs[] */\n'
            '    tabs.forEach(function(tab,i){\n'
            '      var label=tab.id?getProjName(tab.id):"Inicio";\n'
            '      var btn=document.createElement("button");\n'
            '      btn.className="xtab"+(i===curTabIdx?" xtab-on":"");\n'
            '      btn.setAttribute("data-tab-idx",i);\n'
            '      btn.textContent=label;btn.title=label;\n'
            '      btn.onclick=(function(idx){return function(){switchTab(idx);};})(i);\n'
            '      if(tab.id!==null){\n'
            '        var x=document.createElement("span");\n'
            '        x.className="xtx";x.innerHTML="&#10005;";\n'
            '        x.onclick=(function(idx){return function(e){e.stopPropagation();closeTab(idx);};})(i);\n'
            '        btn.appendChild(x);\n'
            '      }\n'
            '      xt.appendChild(btn);\n'
            '    });\n'
            '    /* "+" new tab button — always last in tab bar */\n'
            '    var addBtn=document.createElement("button");\n'
            '    addBtn.id="xtab-add";addBtn.title="Nueva pestaña";addBtn.textContent="+";\n'
            '    addBtn.onclick=function(e){\n'
            '      e.stopPropagation();\n'
            '      tabs.push({id:null,page:null});curTabIdx=tabs.length-1;curPage="home";\n'
            '      if(typeof navigate==="function")navigate("home");\n'
            '      renderTabs();fix();\n'
            '    };\n'
            '    xt.appendChild(addBtn);\n'
            '  }\n'

            '  function switchTab(i){\n'
            '    if(i<0||i>=tabs.length)return;\n'
            '    curTabIdx=i;\n'
            '    var tab=tabs[i];\n'
            '    if(tab.id){\n'
            '      if(typeof switchProjectFromTool==="function")switchProjectFromTool(tab.id);\n'
            '      else if(typeof PM!=="undefined")PM.setActive(tab.id);\n'
            '      /* Restore the page this tab was on; default to guion */\n'
            '      var pg=tab.page||"guion";\n'
            '      curPage=pg;\n'
            '      if(typeof navigate==="function")navigate(pg);\n'
            '    }else{\n'
            '      curPage="home";\n'
            '      if(typeof navigate==="function")navigate("home");\n'
            '    }\n'
            '    renderTabs();fix();updatePipeline();setTimeout(buildPipelineNav,80);\n'
            '  }\n'

            '  function closeTab(i){\n'
            '    if(tabs.length===1){\n'
            '      tabs[0]={id:null,page:null};curTabIdx=0;curPage="home";\n'
            '      if(typeof navigate==="function")navigate("home");\n'
            '      renderTabs();fix();return;\n'
            '    }\n'
            '    tabs.splice(i,1);\n'
            '    if(curTabIdx>=tabs.length)curTabIdx=tabs.length-1;\n'
            '    switchTab(curTabIdx);\n'
            '  }\n'

            '  function openProjectInCurrentTab(id){\n'
            '    /* Inside outer shell: navigate current iframe (same tab) */\n'
            '    if(_inShell){\n'
            '      try{\n'
            '        var _pn=getProjName(id);\n'
            '        var _url="http://127.0.0.1:8080/?load_project="+encodeURIComponent(_pn);\n'
            '        var _now=Date.now();\n'
            '        if(_url===_shellTabLast.url&&_now-_shellTabLast.t<600)return;\n'
            '        _shellTabLast={url:_url,t:_now};\n'
            '        /* Fade out then navigate — softer transition */\n'
            '        document.body.style.transition="opacity .18s";\n'
            '        document.body.style.opacity="0";\n'
            '        setTimeout(function(){window.location.href=_url;},180);\n'
            '        return;\n'
            '      }catch(e){}\n'
            '    }\n'
            '    /* Standalone mode: in-page tab switch */\n'
            '    var pg=(curPage==="home"||!curPage)?"guion":(tabs[curTabIdx]&&tabs[curTabIdx].page?tabs[curTabIdx].page:curPage||"guion");\n'
            '    tabs[curTabIdx]={id:id,page:pg};\n'
            '    if(typeof switchProjectFromTool==="function")switchProjectFromTool(id);\n'
            '    else if(typeof PM!=="undefined")PM.setActive(id);\n'
            '    /* On home: stay there, just load project + update sidebar pipeline */\n'
            '    if(curPage!=="home"&&curPage){curPage=pg;if(typeof navigate==="function")navigate(pg);}\n'
            '    try{if(typeof renderDashboard==="function")renderDashboard();}catch(_re){}\n'
            '    try{if(typeof loadGuionFromProject==="function")loadGuionFromProject(id);}catch(_le){}\n'
            '    renderTabs();fix();updatePipeline();setTimeout(buildPipelineNav,80);\n'
            '  }\n'

            '  function xNav(pg){\n'
            '    curPage=pg;\n'
            '    if(tabs[curTabIdx])tabs[curTabIdx].page=pg;\n'
            '    if(typeof navigate==="function")navigate(pg);\n'
            '    fix();updatePipeline();buildPipelineNav();\n'
            '  }\n'

            '  function syncProj(){\n'
            '    var sel=document.getElementById("xproj-sel");if(!sel)return;\n'
            '    try{\n'
            '      var projects=typeof PM!=="undefined"?PM.getAll():[];\n'
            '      var active=typeof PM!=="undefined"?PM.getActive():null;\n'
            '      if(!projects.length){sel.innerHTML="<option value=\'\'>"+"Sin proyectos</option>";return;}\n'
            '      sel.innerHTML=projects.map(function(p){\n'
            '        return "<option value=\'"+p.id+"\'"+(p.id===active?" selected":"")+">"+p.name+"</option>";\n'
            '      }).join("");\n'
            '    }catch(e){}\n'
            '  }\n'

            '  function buildUI(){\n'
            '    var xtop=document.getElementById("xtop");if(!xtop)return;\n'

            '    if(!document.getElementById("xproj-wrap")){\n'
            '      var srch=document.getElementById("xsrch");\n'
            '      var wrap=document.createElement("div");wrap.id="xproj-wrap";\n'
            '      var lbl=document.createElement("span");lbl.id="xproj-lbl";lbl.textContent="PROYECTO";\n'
            '      var sel=document.createElement("select");sel.id="xproj-sel";\n'
            '      sel.onchange=function(){\n'
            '        var pid=this.value;if(!pid)return;\n'
            '        openProjectInCurrentTab(pid);\n'
            '      };\n'
            '      wrap.appendChild(lbl);wrap.appendChild(sel);\n'
            '      if(srch)srch.parentNode.insertBefore(wrap,srch);else xtop.appendChild(wrap);\n'
            '      syncProj();\n'
            '    }\n'

            '    /* Home button — outside and left of tab bar */\n'
            '    if(!document.getElementById("xtop-home")){\n'
            '      var xt2=document.getElementById("xtabs");\n'
            '      var hbtn=document.createElement("button");\n'
            '      hbtn.id="xtop-home";hbtn.title="Inicio";\n'
            '      hbtn.innerHTML=_HOME_SVG;\n'
            '      hbtn.onclick=function(){tabs[curTabIdx]={id:null,page:null};curPage="home";if(typeof navigate==="function")navigate("home");renderTabs();fix();updatePipeline();};\n'
            '      if(xt2&&xt2.parentNode)xt2.parentNode.insertBefore(hbtn,xt2);\n'
            '      else xtop.insertBefore(hbtn,xtop.firstChild);\n'
            '    }\n'

            '    /* Shell mode: sync tabs[curTabIdx].id from ?load_project= immediately */\n'
            '    if(_inShell&&tabs[curTabIdx]&&!tabs[curTabIdx].id){\n'
            '      try{\n'
            '        var _bqs=window.location.search;\n'
            '        var _bm=_bqs.match(/[?&]load_project=([^&]*)/);\n'
            '        if(_bm){\n'
            '          var _bln=decodeURIComponent(_bm[1]);\n'
            '          var _ball=typeof PM!=="undefined"&&PM.getAll?PM.getAll():[];\n'
            '          var _bfp=_ball.find(function(p){return(p.name||p.nombre||"")===_bln;});\n'
            '          if(_bfp)tabs[curTabIdx].id=_bfp.id;\n'
            '        }\n'
            '      }catch(_e){}\n'
            '    }\n'
