            '      var tStr=words>0?(String(m).padStart(2,"0")+":"+String(s).padStart(2,"0")+" min"):"\\u2014";\n'
            '      var sec2=Math.round(words/1.6);\n'
            '      var m2=Math.floor(sec2/60),s2=sec2%60;\n'
            '      var durStr=words>0?("00:"+String(m).padStart(2,"0")+" \\u2013 00:"+String(m2).padStart(2,"0")+" min"):"\\u2014";\n'
            '      var scenes=words>0?Math.max(1,Math.round(words/14)):0;\n'
            '      var comp="\\u2014",pct=0;\n'
            '      if(words>0){\n'
            '        if(avgSL<8||words<40){comp="Muy simple";pct=15;}\n'
