        "  var nf = parseInt((document.getElementById('gk-anim-n-final') || {}).value, 10) || 0;\n"
        "  var indices = [];\n"
        "  if (has('whole') || (has('half_start') && has('half_end'))) {\n"
        "    for (var i = 0; i < n; i++) indices.push(i);\n"
