        "  }\n"
        "  if (!indices.length) for (var c = 0; c < n; c++) indices.push(c);\n"
        "  var inFirst = indices.filter(function(i) { return i < mid; });\n"
        "  var inSecond = indices.filter(function(i) { return i >= mid; });\n"
        "  var keepFirst = ni > 0 ? inFirst.slice(0, Math.min(ni, inFirst.length)) : inFirst;\n"
