# ── Pool de conexiones DB: evita max_connections_per_hour en Hostinger ────────
import threading as _db_thr
import auth_module as _auth_mod

class _DBConnProxy:
    """Envuelve pymysql conn; close() hace rollback sin cerrar (conexión se reutiliza)."""
    __slots__ = ('_r',)
    def __init__(self, real):   self._r = real
    def close(self):
        try: self._r.rollback()
        except Exception: pass
    def cursor(self, *a, **kw): return self._r.cursor(*a, **kw)
    def commit(self):           self._r.commit()
    def rollback(self):         self._r.rollback()
    def ping(self, *a, **kw):   return self._r.ping(*a, **kw)
    def __enter__(self):        return self
    def __exit__(self, *a):     pass

_DB_TLS  = _db_thr.local()
_DB_ORIG = _auth_mod._get_db_connection

def _pooled_db_conn():
    real = getattr(_DB_TLS, 'conn', None)
    if real is not None:
        try:
            real.ping(reconnect=True)
            return _DBConnProxy(real)
        except Exception:
            try: real.close()
            except: pass
            _DB_TLS.conn = None
    real = _DB_ORIG()
    _DB_TLS.conn = real
    return _DBConnProxy(real)

_auth_mod._get_db_connection = _pooled_db_conn
_auth_mod.SESSION_MINUTES   = 60 * 24 * 365   # sesión permanente — expira solo al logout
