_TRACKED_ROUTES: dict = {
    "/api/guion/n8n_proxy":     ("guion",  "Generando guion y prompts..."),
    "/api/voz/generar":         ("voz_gen", "Generando voz..."),
    "/api/voz/fusionar":        ("voz_fus", "Fusionando audio..."),
    "/api/editor/analizar":     ("editor", "Analizando proyecto..."),
    "/api/guion/analyze_image": ("guion",  "Analizando imagen..."),
}

def _tasks_clean():
    now = _t_time()
    with _tasks_lock:
        old = [k for k,v in list(_tasks.items())
               if v["estado"] != "procesando" and now - v["inicio"] > 300]
        for k in old: del _tasks[k]

def _vf_start_bg_watcher(tid, tipo, proyecto, state_ref, state_lock,
                          running_key="running", progress_key="progress",
                          total_key="total", error_key="last_error",
                          step_key=None):
    """Watch a background state dict and keep _tasks[tid] up to date."""
    def _watch():
        import time as _wt
        while True:
            _wt.sleep(2.5)
            try:
                with state_lock:
                    running  = state_ref.get(running_key, False)
                    progress = state_ref.get(progress_key, 0) or 0
                    total    = max(1, state_ref.get(total_key, 1) or 1)
                    err      = state_ref.get(error_key)
                    step     = state_ref.get(step_key, "") if step_key else ""
                pct = int(100 * progress / total)
                with _tasks_lock:
                    if tid not in _tasks:
                        return
                    _tasks[tid]["progreso"] = pct
                    if step:
                        _tasks[tid]["mensaje"] = str(step)[:80]
                    if not running:
                        _tasks[tid]["estado"]  = "error" if err else "completado"
                        _tasks[tid]["progreso"] = 0 if err else 100
                        if err:
                            _tasks[tid]["mensaje"] = ("Error: " + str(err))[:80]
                        return
            except Exception:
                pass
    _thr_tasks.Thread(target=_watch, daemon=True, name=f"VF-bgw-{tid}").start()

@app.before_request
def _vf_track_start():
    for route, (tipo, msg) in _TRACKED_ROUTES.items():
        if request.path.startswith(route) and request.method == 'POST':
            import uuid as _uu2
            tid = str(_uu2.uuid4())[:6]
            try:
                body = request.get_json(silent=True, force=True) or {}
                proj = (body.get('project_name') or body.get('proyecto') or '').strip()
            except Exception:
                proj = ''
            with _tasks_lock:
                _tasks[tid] = {'id': tid, 'tipo': tipo, 'mensaje': msg,
                               'estado': 'procesando', 'inicio': _t_time(),
                               'proyecto': proj, 'progreso': 0, 'video_url': None}
            from flask import g as _fg; _fg._vf_tid = tid
            break

@app.after_request
def _vf_track_end(response):
    from flask import g as _fg
    tid = getattr(_fg, '_vf_tid', None)
    if tid:
        ok = response.status_code < 400
        with _tasks_lock:
            if tid in _tasks:
                _tasks[tid]['estado'] = 'completado' if ok else 'error'
                _tasks[tid]['progreso'] = 100 if ok else 0
    return response

# ── OpenAI (análisis de imagen en Guion, Vision, etc.) ───────────────────────
# Pega tu clave en UNA línea entre comillas. Si está vacío, se usan env / archivo / Whisper.
OPENAI_API_KEY_INLINE = os.getenv("OPENAI_API_KEY_INLINE")
OPENAI_WHISPER_KEY = os.getenv("OPENAI_WHISPER_KEY")
REPLICATE_API_KEY = os.getenv("REPLICATE_API_KEY")
REPLICATE_WHISPERX_MODEL = os.getenv("REPLICATE_WHISPERX_MODEL")


def _transcribir_whisperx_runpod(audio_path, language="es"):
    """
    Transcribe audio con WhisperX vía Replicate usando el cliente oficial.
    - Usa replicate.run() que sube el archivo local directamente sin host externo.
    - Usa victor-upmeet/whisperx-a40-large para audio largo sin OOM.
    Devuelve (segmentos, all_words) con timestamps word-level.
    """
    if not REPLICATE_API_KEY:
        raise Exception("Falta REPLICATE_API_KEY — pégala en el launcher (línea REPLICATE_API_KEY).")

    try:
        import replicate as _replicate_client
    except ImportError:
        raise Exception("Falta el paquete 'replicate'. Instálalo con: pip install replicate")

    import os as _os
    _os.environ["REPLICATE_API_TOKEN"] = REPLICATE_API_KEY

    print(f"[WhisperX Replicate] Subiendo audio y lanzando predicción ({_os.path.getsize(audio_path)//1024}KB)...")

    _input_payload = {
        "audio_file":   open(audio_path, "rb"),
        "align_output": True,
        "only_text":    False,
        "batch_size":   4,
    }
    if language:  # None = auto-detect por WhisperX
        _input_payload["language"] = language

    # replicate.run() con timeout via threading para evitar colgarse indefinidamente
    import threading as _threading
    _result_box = [None]
    _error_box  = [None]
    _TIMEOUT_SECS = 120  # 2 minutos máximo

    def _run_replicate():
        try:
            _result_box[0] = _replicate_client.run(
                "victor-upmeet/whisperx:84d2ad2d6194fe98a17d2b60bef1c7f910c46b2f6fd38996ca457afd9c8abfcb",
                input=_input_payload
            )
        except Exception as _re:
            _error_box[0] = _re

    _t = _threading.Thread(target=_run_replicate, daemon=True)
    _t.start()
    _t.join(timeout=_TIMEOUT_SECS)
    if _t.is_alive():
        raise Exception(f"WhisperX Replicate: timeout tras {_TIMEOUT_SECS}s — usando fallback local.")
    if _error_box[0]:
        raise Exception(f"WhisperX Replicate error: {_error_box[0]}")
    _output = _result_box[0]
    if not _output:
        raise Exception("WhisperX Replicate: la predicción no devolvió output.")

    print(f"[WhisperX Replicate] Predicción completada.")

    # ── Parsear output --> segmentos + all_words ────────────────────────────
    _segs_raw = (
        _output.get("segments")
        or (_output.get("results") or {}).get("segments")
        or []
    )
    all_words = []
    segmentos = []
    for _s in _segs_raw:
        _words_s = []
        for _w in (_s.get("words") or []):
            if _w.get("start") is not None:
                _wd = {"word": _w.get("word",""), "start": float(_w["start"]),
                       "end": float(_w.get("end", _w["start"]))}
                all_words.append(_wd)
                _words_s.append(_wd)
        segmentos.append({
            "start": float(_s.get("start", 0)),
            "end":   float(_s.get("end", 0)),
            "text":  _s.get("text", ""),
            "words": _words_s
        })
    return segmentos, all_words


def _vf_install_dir():
    """Carpeta del .exe (frozen) o del launcher .py."""
    if getattr(sys, "frozen", False):
        return os.path.dirname(os.path.abspath(sys.executable))
    return os.path.dirname(os.path.abspath(__file__))


def resolve_openai_api_key():
    """INLINE --> OPENAI_API_KEY (env) --> openai_api_key.txt --> OPENAI_WHISPER_KEY."""
    k = (OPENAI_API_KEY_INLINE or "").strip()
    if k:
        return k
    k = (os.environ.get("OPENAI_API_KEY") or "").strip()
    if k:
        return k
    key_path = os.path.join(_vf_install_dir(), "openai_api_key.txt")
    try:
        if os.path.isfile(key_path):
            k = open(key_path, encoding="utf-8", errors="replace").read().strip()
            if k:
                return k
    except Exception:
        pass
    return (OPENAI_WHISPER_KEY or "").strip()


