@app.route("/api/generar", methods=["POST"])
def generar_video():
    try:
        job_id  = str(uuid.uuid4())[:8]
        job_dir = os.path.join(JOBS_FOLDER, job_id)
        imgs_dir = os.path.join(job_dir, "imagenes")
        os.makedirs(imgs_dir, exist_ok=True)

        audio = request.files.get("audio")
        if not audio or audio.filename == '':
            return jsonify({"error": "Falta el archivo de audio"}), 400
        audio_path = os.path.join(job_dir, "audio.mp3")
        audio.save(audio_path)

        guion = request.form.get("guion", "").strip()
        if not guion:
            return jsonify({"error": "El guión está vacío"}), 400
        guion_path = os.path.join(job_dir, "guion.txt")
        with open(guion_path, "w", encoding="utf-8") as f:
            f.write(guion)

        imagen_keys = sorted(
            [k for k in request.files.keys() if k.startswith("imagen_")],
            key=lambda x: int(x.split("_")[1])
        )
        if not imagen_keys:
            return jsonify({"error": "No se subieron imágenes"}), 400

        for i, key in enumerate(imagen_keys):
            img_file = request.files[key]
            ct  = img_file.content_type or "image/png"
            ext = {"image/jpeg":".jpg","image/jpg":".jpg",
                   "image/png":".png","image/webp":".webp"}.get(ct, ".jpg")
            img_file.save(os.path.join(imgs_dir, f"img_{i:03d}{ext}"))

        resolucion = request.form.get("resolucion", "1920x1080")
        fade       = float(request.form.get("fade", "0"))
        modelo          = request.form.get("modelo", "base")
        whisper_backend = request.form.get("whisper_backend", "whisperx")  # "local" | "faster" | "api" | "whisperx"
        transicion = request.form.get("transicion", "none")
        movimiento = request.form.get("movimiento", "none")
        trans_dur  = float(request.form.get("trans_dur", "0.8"))
        shake      = request.form.get("shake", "false")

        jobs[job_id] = {
            "id": job_id, "estado": "procesando", "progreso": 0,
            "mensaje": "Iniciando...", "logs": [], "video_url": None,
            "inicio": time.time()
        }

        threading.Thread(
            target=procesar_video,
            args=(job_id, job_dir, audio_path, guion_path, imgs_dir,
                  resolucion, fade, modelo, transicion, movimiento, trans_dur, shake,
                  whisper_backend),
            daemon=True
        ).start()

        return jsonify({"job_id": job_id})

    except Exception as e:
        try:
            import traceback as _tb5
            print(_tb5.format_exc().encode('ascii', 'replace').decode('ascii'))
        except Exception:
            pass
        return jsonify({"error": str(e).encode('ascii', 'replace').decode('ascii')}), 500

@app.route("/api/estado/<job_id>")
def estado_job(job_id):
    if job_id not in jobs:
        return jsonify({"error": "Job no encontrado"}), 404
    return jsonify(jobs[job_id])

@app.route("/api/descargar/<job_id>")
def descargar_video(job_id):
    path = os.path.join(JOBS_FOLDER, job_id, "video_final.mp4")
    if not os.path.exists(path):
        return jsonify({"error": "Video no encontrado"}), 404
    return send_file(path, as_attachment=True,
                     download_name=f"video_{job_id}.mp4")


