    _CSS = "*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}html,body{height:100%;overflow:hidden;background:#07070e;-webkit-user-select:none;user-select:none}body{display:flex;flex-direction:column}:root{--c1:#7c6aff;--c2:#a78bfa;--c5:#22d3a0;--ce:#f59e0b;--cer:#f47286;--bg:#07070e;--s:#0e0e1a;--p:#131320;--b:#1c1c2e;--b2:#252538;--t:#eeeef5;--m:#5a5a75;--m2:#38384e;--mono:'JetBrains Mono',monospace}#tb{height:0;min-height:0;overflow:hidden;opacity:0;pointer-events:none;background:rgba(6,6,12,.92);backdrop-filter:blur(16px);-webkit-backdrop-filter:blur(16px);border-bottom:1px solid rgba(255,255,255,.06);display:flex;align-items:center;padding:0;gap:0;-webkit-app-region:drag;position:relative;z-index:100;flex-shrink:0}#mp{width:220px;min-width:220px;height:100%;-webkit-app-region:drag;flex-shrink:0;display:flex;align-items:center;padding:0 16px;gap:10px;border-right:1px solid rgba(255,255,255,.06);cursor:pointer;transition:background .13s}#mp:hover{background:rgba(255,255,255,.03)}.xlm2{width:34px;height:34px;border-radius:9px;flex-shrink:0;background:linear-gradient(145deg,#6c56ff 0%,#a855f7 55%,#c084fc 100%);display:flex;align-items:center;justify-content:center;box-shadow:0 0 0 1px rgba(168,85,247,.18),0 4px 14px rgba(124,106,255,.42)}.xln2{display:block;font-size:14px;font-weight:800;color:#eeeef5;letter-spacing:-.025em;line-height:1.2;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',system-ui,sans-serif}.xls2{display:block;font-size:8px;color:#38384e;letter-spacing:.14em;text-transform:uppercase;font-weight:600;margin-top:1px;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',system-ui,sans-serif}#tl{display:flex;align-items:center;height:100%;flex:1;overflow:hidden;padding:0 6px;gap:3px;-webkit-app-region:no-drag}.t{height:34px;min-width:96px;max-width:220px;background:rgba(255,255,255,.035);border:1px solid rgba(255,255,255,.07);border-radius:10px;display:inline-flex;align-items:center;padding:0 10px 0 9px;gap:7px;cursor:pointer;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',system-ui,sans-serif;font-size:12px;font-weight:500;color:#8a8aa3;flex-shrink:0;transition:color .15s,background .15s,border-color .15s,box-shadow .15s;-webkit-app-region:no-drag;white-space:nowrap;overflow:hidden;position:relative}.t:hover{color:rgba(238,238,245,.9);background:rgba(255,255,255,.08);border-color:rgba(255,255,255,.13)}.t.active{color:#eeeef5!important;font-weight:600!important;background:linear-gradient(135deg,rgba(124,106,255,.24),rgba(124,106,255,.10))!important;border-color:rgba(124,106,255,.5)!important;box-shadow:0 0 0 1px rgba(124,106,255,.2) inset,0 3px 14px rgba(124,106,255,.25)!important}.t.processing{color:#fbbf24!important;background:rgba(245,158,11,.10)!important;border-color:rgba(245,158,11,.38)!important;animation:tPulseO 1.4s ease-in-out infinite}.t.processing .ti{animation:tSpin 1.0s linear infinite}.t.done{color:#34d399!important;background:rgba(34,211,160,.14)!important;border-color:rgba(34,211,160,.48)!important;box-shadow:0 0 0 1px rgba(34,211,160,.14) inset,0 2px 10px rgba(34,211,160,.2)!important;animation:tPulseG 1.2s ease-in-out 3}.t.err{color:#fca5b1!important;background:rgba(244,114,134,.12)!important;border-color:rgba(244,114,134,.4)!important}@keyframes tPulseO{0%,100%{opacity:1}50%{opacity:.55}}@keyframes tPulseG{0%,100%{opacity:1}50%{opacity:.65}}@keyframes tSpin{to{transform:rotate(360deg)}}.ti{font-size:13px;flex-shrink:0;line-height:1;display:inline-block}.tn{flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-size:12px}.tx{width:17px;height:17px;border-radius:5px;background:rgba(255,255,255,.05);border:none;color:rgba(255,255,255,.4);cursor:pointer;font-size:9.5px;display:flex;align-items:center;justify-content:center;flex-shrink:0;transition:background .15s,color .15s;margin-left:1px}.tx:hover{background:rgba(244,114,134,.28);color:#f47286}#br{display:flex;align-items:center;gap:8px;margin-left:auto;padding:0 14px;-webkit-app-region:no-drag;flex-shrink:0}#xsrch2{display:flex;align-items:center;gap:8px;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.08);border-radius:8px;padding:5px 12px;cursor:pointer;min-width:150px;transition:background .13s,border-color .13s;-webkit-app-region:no-drag}#xsrch2:hover{background:rgba(255,255,255,.08);border-color:rgba(124,106,255,.25)}#xsrch2 svg{opacity:.42;flex-shrink:0}#xsrch2 span{font-size:11.5px;color:#5a5a75;flex:1}#xnew2{display:inline-flex;align-items:center;gap:7px;background:linear-gradient(135deg,#7c6aff,#a855f7);color:#fff;border:none;border-radius:8px;padding:6px 14px;font-size:12px;font-weight:600;cursor:pointer;white-space:nowrap;flex-shrink:0;box-shadow:0 4px 14px rgba(124,106,255,.38);transition:opacity .13s,box-shadow .13s,transform .13s;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',system-ui,sans-serif;-webkit-app-region:no-drag;letter-spacing:-.01em}#xnew2:hover{opacity:.88;box-shadow:0 6px 20px rgba(124,106,255,.52);transform:translateY(-1px)}#xtadd:hover{background:rgba(124,106,255,.15)!important;color:#a78bfa!important;border-color:rgba(124,106,255,.55)!important}.xib2{width:30px;height:30px;border-radius:7px;display:flex;align-items:center;justify-content:center;color:#5a5a75;cursor:pointer;background:transparent;border:none;transition:background .13s,color .13s;-webkit-app-region:no-drag;flex-shrink:0}.xib2:hover{background:rgba(255,255,255,.07);color:#eeeef5}#jb{display:flex;align-items:center;gap:6px;padding:0 12px;height:32px;border-radius:7px;font-size:12px;font-weight:500;color:#5a5a75;cursor:pointer;background:transparent;border:none;transition:background .13s,color .13s;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',system-ui,sans-serif;white-space:nowrap;-webkit-app-region:no-drag}#jb:hover{background:rgba(255,255,255,.06);color:#eeeef5}#jb.aj{color:var(--ce)}#jb.done{color:var(--c5)}.jbg{background:var(--ce);color:#07070e;border-radius:5px;padding:1px 5px;font-size:9px;font-weight:800;margin-left:2px}#fr{flex:1;position:relative;min-height:0}.fw{position:absolute;inset:0;display:none}.fw.active{display:flex;flex-direction:column}.fw iframe{flex:1;width:100%;border:none;display:block;min-height:0}.vld{position:absolute;inset:0;background:#07070e;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:0;pointer-events:none;transition:opacity .7s ease;animation:vldIn .35s ease both}.vld.out{opacity:0}.vld-eyebrow{font-family:'JetBrains Mono','Courier New',monospace;font-size:10px;font-weight:500;letter-spacing:.45em;color:rgba(124,106,255,.6);text-transform:uppercase;margin-bottom:10px}.vld-wordmark{font-family:'Segoe UI',system-ui,sans-serif;font-size:64px;font-weight:800;color:#eeeef5;letter-spacing:-3px;line-height:1;margin-bottom:40px}.vld-eq{display:flex;align-items:flex-end;gap:5px;height:28px}.vld-b{width:4px;border-radius:2px 2px 0 0;background:linear-gradient(to top,#5b4fd4,#a78bfa);animation:vldEq 1s ease-in-out infinite}.vld-b:nth-child(1){height:10px;animation-delay:0s}.vld-b:nth-child(2){height:22px;animation-delay:.12s}.vld-b:nth-child(3){height:16px;animation-delay:.24s}.vld-b:nth-child(4){height:28px;animation-delay:.06s}.vld-b:nth-child(5){height:12px;animation-delay:.18s}.vld-b:nth-child(6){height:24px;animation-delay:.3s}.vld-b:nth-child(7){height:8px;animation-delay:.09s}.vld-b:nth-child(8){height:20px;animation-delay:.21s}.vld-b:nth-child(9){height:14px;animation-delay:.15s}@keyframes vldIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:none}}@keyframes vldEq{0%,100%{transform:scaleY(.3);opacity:.5}50%{transform:scaleY(1);opacity:1}}#jp{position:fixed;top:52px;right:8px;width:370px;max-height:460px;background:var(--s);border:1px solid var(--b2);border-radius:14px;box-shadow:0 14px 48px rgba(0,0,0,.7);z-index:9999;display:none;flex-direction:column;overflow:hidden}.jph{padding:12px 14px 10px;border-bottom:1px solid var(--b);font-family:var(--mono);font-size:10px;font-weight:700;color:var(--t);letter-spacing:.1em;text-transform:uppercase;display:flex;align-items:center;gap:8px}.jph span{flex:1}.jph button{background:none;border:none;color:var(--m);cursor:pointer;font-size:15px;padding:0 2px;transition:color .12s}.jph button:hover{color:var(--t)}.jpl{overflow-y:auto;flex:1;padding:8px 10px;display:flex;flex-direction:column;gap:6px}.jpe{text-align:center;color:var(--m);font-size:11px;padding:24px 0;font-family:var(--mono)}.jpc{background:var(--p);border:1px solid var(--b);border-radius:10px;padding:10px 12px;transition:border-color .2s}.jpc.proc{border-color:rgba(245,158,11,.4)}.jpc.done{border-color:rgba(34,211,160,.35)}.jpc.err{border-color:rgba(244,114,134,.35)}.jpt{display:flex;align-items:center;gap:6px;margin-bottom:5px}.jpn{flex:1;font-size:11px;font-weight:700;color:var(--t);overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.jpk{font-size:8.5px;border-radius:4px;padding:2px 6px;font-weight:700;text-transform:uppercase;flex-shrink:0}.jpk.guion{background:rgba(124,106,255,.2);color:var(--c2)}.jpk.voz{background:rgba(244,114,134,.2);color:#f472b6}.jpk.video,.jpk.generar,.jpk.grok,.jpk.qwen,.jpk.gentube{background:rgba(34,211,160,.15);color:var(--c5)}.jpk.render,.jpk.editor{background:rgba(56,189,248,.15);color:#38bdf8}.jpk.imagen,.jpk.whisk,.jpk.flow{background:rgba(251,191,36,.15);color:var(--ce)}.jpk.tarea{background:var(--b2);color:var(--m)}.jpbar{height:3px;background:var(--b);border-radius:99px;overflow:hidden;margin-bottom:6px}.jpfill{height:100%;border-radius:99px;transition:width .4s}.jpfill.proc{background:linear-gradient(90deg,var(--ce),#f97316);animation:jpFillAnim 1.5s ease-in-out infinite}.jpfill.done{background:linear-gradient(90deg,var(--c1),var(--c5))}.jpfill.err{background:var(--cer)}@keyframes jpFillAnim{0%,100%{opacity:1}50%{opacity:.6}}.jpbot{display:flex;align-items:center;gap:5px;font-size:10px;color:var(--m)}.jpp{font-family:var(--mono);font-weight:700}.jpp.proc{color:var(--ce)}.jpp.done{color:var(--c5)}.jpp.err{color:var(--cer)}.jpmsg{flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.jpago{margin-left:auto;flex-shrink:0;color:var(--m2)}.jpdl{background:var(--c5);color:#06130f;border-radius:5px;padding:2px 8px;font-weight:700;font-size:9px;text-decoration:none}.jpdl:hover{background:#1db88a}#pm-ov{position:fixed;inset:0;background:rgba(4,4,12,.82);z-index:99999;display:none;align-items:center;justify-content:center;backdrop-filter:blur(12px) saturate(1.4)}#pm-m{background:linear-gradient(160deg,#10101f 0%,#0b0b18 100%);border:1px solid rgba(124,106,255,.22);border-radius:22px;width:540px;max-width:96vw;max-height:82vh;display:flex;flex-direction:column;overflow:hidden;box-shadow:0 32px 96px rgba(0,0,0,.9),0 0 0 1px rgba(124,106,255,.1) inset,0 1px 0 rgba(255,255,255,.04) inset}#pm-hd{padding:24px 24px 18px;background:linear-gradient(135deg,rgba(124,106,255,.1) 0%,rgba(124,106,255,.03) 100%);border-bottom:1px solid rgba(124,106,255,.12);display:flex;align-items:center;gap:14px}#pm-hd-icon{width:42px;height:42px;background:linear-gradient(135deg,rgba(124,106,255,.25),rgba(167,139,250,.15));border:1px solid rgba(124,106,255,.3);border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0}#pm-hd-info{flex:1}#pm-hd-title{font-size:15px;font-weight:700;background:linear-gradient(90deg,#eeeef5,#a78bfa);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;margin:0 0 2px}#pm-hd-sub{font-size:10.5px;color:var(--m);font-family:var(--mono);letter-spacing:.04em}#pm-hd-close{width:30px;height:30px;background:rgba(255,255,255,.05);border:1px solid var(--b2);border-radius:8px;color:var(--m);cursor:pointer;font-size:15px;display:flex;align-items:center;justify-content:center;transition:all .15s;flex-shrink:0}#pm-hd-close:hover{background:rgba(244,114,134,.15);border-color:rgba(244,114,134,.35);color:#f47286}#pm-sr{padding:14px 18px 12px;border-bottom:1px solid rgba(124,106,255,.08)}#pm-q{width:100%;background:rgba(255,255,255,.04);border:1px solid rgba(124,106,255,.18);border-radius:12px;padding:10px 14px;color:var(--t);font-size:12.5px;outline:none;transition:all .15s}#pm-q::placeholder{color:var(--m)}#pm-q:focus{border-color:var(--c1);box-shadow:0 0 0 3px rgba(124,106,255,.12);background-color:rgba(124,106,255,.05)}#pm-ls{overflow-y:auto;flex:1;padding:12px 14px;display:flex;flex-direction:column;gap:5px}.pm-c{background:rgba(255,255,255,.03);border:1px solid rgba(255,255,255,.06);border-radius:14px;padding:12px 16px;display:flex;align-items:center;gap:14px;cursor:pointer;transition:all .2s}.pm-c:hover{border-color:rgba(124,106,255,.4);background:rgba(124,106,255,.08);transform:translateY(-1px);box-shadow:0 4px 20px rgba(0,0,0,.4)}.pm-ci{display:none}.pm-av{width:44px;height:44px;min-width:44px;border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:800;flex-shrink:0;border:1px solid transparent;letter-spacing:-.01em}.pm-cf{flex:1;min-width:0}.pm-cn{font-size:13px;font-weight:700;color:var(--t);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;margin-bottom:3px}.pm-cs{font-size:10px;color:var(--m);overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.pm-arr{color:rgba(124,106,255,.4);font-size:18px;flex-shrink:0;line-height:1;transition:color .15s,transform .15s}.pm-c:hover .pm-arr{color:var(--c2);transform:translateX(4px)}#pm-ls::-webkit-scrollbar{width:4px}#pm-ls::-webkit-scrollbar-track{background:transparent}#pm-ls::-webkit-scrollbar-thumb{background:rgba(124,106,255,.2);border-radius:99px}#pm-ls::-webkit-scrollbar-thumb:hover{background:rgba(124,106,255,.4)}#pm-nf{padding:14px 18px 18px;border-top:1px solid rgba(124,106,255,.1);background:rgba(0,0,0,.25)}#pm-nf-label{font-size:9.5px;font-weight:700;color:var(--m);text-transform:uppercase;letter-spacing:.1em;font-family:var(--mono);margin-bottom:8px}#pm-ni{width:100%;background:rgba(255,255,255,.04);border:1px solid rgba(124,106,255,.18);border-radius:12px;padding:10px 14px;color:var(--t);font-size:12.5px;margin-bottom:10px;outline:none;transition:all .15s}#pm-ni:focus{border-color:var(--c1);box-shadow:0 0 0 3px rgba(124,106,255,.12)}#pm-nb{width:100%;padding:11px;background:linear-gradient(135deg,#7c6aff,#9333ea);border:none;border-radius:12px;color:#fff;font-weight:700;font-size:12.5px;cursor:pointer;transition:all .18s;letter-spacing:.02em}#pm-nb:hover{transform:translateY(-1px);box-shadow:0 6px 24px rgba(124,106,255,.45);opacity:.92}.pm-empty{text-align:center;color:var(--m);font-size:11px;padding:32px 0;font-family:var(--mono)}@keyframes vfS{to{transform:rotate(360deg)}}"
