@app.route("/shell")
def shell_view():
    return Response(_VF_SHELL_HTML.encode("utf-8"), mimetype="text/html; charset=utf-8")

@app.route("/api/multitask/jobs")
def multitask_jobs():
    """Devuelve jobs de render + actividades sincronas para el panel de tareas."""
    _tasks_clean()
    result = []
    for jdata in list(jobs.values()):
        result.append({
            "id":       jdata.get("id", ""),
            "estado":   jdata.get("estado", "?"),
            "progreso": jdata.get("progreso", 0),
            "mensaje":  jdata.get("mensaje", ""),
            "inicio":   jdata.get("inicio", 0),
            "video_url": jdata.get("video_url"),
            "tipo":     jdata.get("tipo", "render"),
            "proyecto": jdata.get("proyecto", ""),
        })
    with _tasks_lock:
        for td2 in list(_tasks.values()):
            result.append({
                "id":       td2.get("id", ""),
                "estado":   td2.get("estado", "?"),
                "progreso": td2.get("progreso", 0),
                "mensaje":  td2.get("mensaje", ""),
                "inicio":   td2.get("inicio", 0),
                "video_url": None,
                "tipo":     td2.get("tipo", "tarea"),
                "proyecto": td2.get("proyecto", ""),
            })
    result.sort(key=lambda x: x["inicio"], reverse=True)
    return jsonify(result)


# ══════════════════════════════════════════════════════════════════
# 2. MATCHING GUION ↔ TRANSCRIPCIÓN — timestamps por escena (Whisper)
# ══════════════════════════════════════════════════════════════════

def limpiar(texto):
    texto = texto.lower().strip()
    texto = re.sub(r'[¿¡.,;:!?\-–—"""\'()\[\]]', '', texto)
    texto = re.sub(r'\s+', ' ', texto)
    return texto

def contar_palabras_comunes(a, b):
    pa = set(limpiar(a).split())
    pb = set(limpiar(b).split())
    if not pa: return 0
    return len(pa & pb) / len(pa)

def asignar_timestamps(escenas, segmentos, duracion_total):
    n = len(escenas)
    if not segmentos:
        return _proporcional(escenas, duracion_total)

    asignaciones = []
    ultimo = 0
    for i, escena in enumerate(escenas):
        mejor_score, mejor_idx = -1, ultimo
        limite = min(len(segmentos), ultimo + max(5, len(segmentos) // n * 3))
        for j in range(ultimo, limite):
            st = segmentos[j].get("text", "")
            score = contar_palabras_comunes(escena, st)
            if j + 1 < len(segmentos):
                t2 = st + " " + segmentos[j+1].get("text","")
                score = max(score, contar_palabras_comunes(escena, t2) * 0.9)
            if score > mejor_score:
                mejor_score, mejor_idx = score, j
        asignaciones.append((mejor_idx, mejor_score))
        ultimo = mejor_idx

    resultado = []
    prev_fin = 0.0
    i = 0
    while i < n:
        idx, score = asignaciones[i]
        seg = segmentos[idx]

        # Detectar cuántas escenas consecutivas comparten este mismo segmento
        j = i + 1
        while j < n and asignaciones[j][0] == idx:
            j += 1
        grupo = list(range(i, j))  # índices de escenas en este segmento

        if len(grupo) == 1:
            # Caso normal: una sola escena en este segmento
            inicio = _refinar_inicio(escenas[i], seg)
            inicio = max(inicio, prev_fin)
            if i < n - 1:
                idx_sig = asignaciones[i+1][0]
                fin = _refinar_inicio(escenas[i+1], segmentos[idx_sig])
                if fin <= inicio:
                    fin = seg["end"]
            else:
                fin = duracion_total
            if fin <= inicio:
                fin = round(inicio + 0.5, 3)
            dur = max(0.5, round(fin - inicio, 3))
            fin = round(inicio + dur, 3)
            resultado.append({"inicio": round(inicio, 3), "fin": fin,
                               "duracion": dur, "seg_idx": idx, "score": round(score, 3)})
            prev_fin = fin
            i = j
        else:
            # Múltiples escenas en el mismo segmento:
            # El inicio del grupo es max(prev_fin, _refinar_inicio primera escena)
            # El fin del grupo es el inicio de la siguiente escena (segmento diferente)
            t_inicio_grupo = max(prev_fin, _refinar_inicio(escenas[grupo[0]], seg))
            if j < n:
                idx_sig = asignaciones[j][0]
                t_fin_grupo = _refinar_inicio(escenas[j], segmentos[idx_sig])
                if t_fin_grupo <= t_inicio_grupo:
                    t_fin_grupo = seg["end"]
            else:
                t_fin_grupo = duracion_total
            if t_fin_grupo <= t_inicio_grupo:
                t_fin_grupo = t_inicio_grupo + len(grupo) * 1.0

            # Dividir proporcional por palabras dentro del rango del grupo
            pesos = [max(1, len(limpiar(escenas[k]).split())) for k in grupo]
            total_p = sum(pesos)
            rango = t_fin_grupo - t_inicio_grupo
            t = t_inicio_grupo
            for ki, gi in enumerate(grupo):
                _, sc = asignaciones[gi]
                t_ini = round(t, 3)
                t_fin = round(t + rango * pesos[ki] / total_p, 3)
                if t_fin <= t_ini:
                    t_fin = round(t_ini + 0.5, 3)
                dur = max(0.5, round(t_fin - t_ini, 3))
                t_fin = round(t_ini + dur, 3)
                resultado.append({"inicio": t_ini, "fin": t_fin,
                                   "duracion": dur, "seg_idx": idx, "score": round(sc, 3)})
                t = t_fin
                prev_fin = t_fin
            i = j

    return resultado

def _refinar_inicio(escena, seg):
    """
    Devuelve el punto de corte para el inicio de la escena dentro del segmento.
    Encuentra la primera palabra clave, luego verifica si hay una pausa natural
    (>= 0.15s) en las 2 words INMEDIATAMENTE anteriores a esa palabra.
    Si la hay, corta en esa pausa (silencio entre párrafos).
    Si no, usa el start de la palabra clave.
    Esto evita que la imagen aparezca antes de que el audio diga la palabra.
    """
    words = seg.get("words", [])
    if not words: return seg["start"]
    TRIVIALES = {"el","la","los","las","un","una","de","en","a","y","o","que",
                 "se","es","su","me","te","con","por","para","si","no","ya"}

    claves = [w for w in limpiar(escena).split() if w not in TRIVIALES and len(w)>2]
    if not claves:
        claves = [w for w in limpiar(escena).split() if w]
    if not claves:
        return seg["start"]

    words_limpias = [limpiar(w.get("word","")) for w in words]

    # Encontrar índice de la primera palabra clave
    palabra_idx = None
    for clave in claves[:3]:
        for i, wl in enumerate(words_limpias):
            if wl == clave:
                palabra_idx = i
                break
        if palabra_idx is None:
            for i, wl in enumerate(words_limpias):
                if wl and (clave in wl or wl in clave) and len(wl) > 2:
                    palabra_idx = i
                    break
        if palabra_idx is not None:
            break

    if palabra_idx is None:
        return seg["start"]

    t_palabra = float(words[palabra_idx].get("start", seg["start"]))

    # Buscar pausa >= 0.15s solo en las 2 words INMEDIATAMENTE antes de la clave
    for k in range(max(0, palabra_idx - 2), palabra_idx):
        w_end  = float(words[k].get("end", words[k].get("start", 0)))
        w_next = float(words[k + 1].get("start", w_end))
        if (w_next - w_end) >= 0.15:
            return round(w_end, 3)

    return round(t_palabra, 3)

def asignar_timestamps_words(escenas, all_words, duracion_total):
    """
    Asignación word-level usando n-gram matching para evitar falsos positivos
    con palabras comunes. Busca secuencias de 2-3 palabras consecutivas del guión
    en el stream de words, avanzando secuencialmente.
    """
    if not all_words or not escenas:
        return _proporcional(escenas, duracion_total)

    words_limpias = [limpiar(w.get("word","")) for w in all_words]
    n_words = len(all_words)
    n_escenas = len(escenas)

    def _palabras_escena(texto):
        """Todas las palabras limpias de una línea de guión."""
        return [w for w in limpiar(texto).split() if len(w) > 0]

    def _buscar_ngram(palabras_guion, desde, max_ventana=600):
        """
        Busca la mejor coincidencia de n-gram (2-3 palabras consecutivas)
        del guión en el stream de words. Devuelve el índice de la primera
        word de la mejor coincidencia, o None si no encuentra.
        """
        hasta = min(n_words, desde + max_ventana)
        palabras = palabras_guion

        # Intentar con bigrams primero (más específico), luego unigrams
        for ngram_size in [3, 2, 1]:
            if len(palabras) < ngram_size:
                continue
            # Construir n-grams del guión (solo los primeros 5 para el inicio)
            ngrams_guion = []
            for j in range(min(len(palabras) - ngram_size + 1, 6)):
                ng = tuple(palabras[j:j+ngram_size])
                # Filtrar n-grams con palabras muy comunes como primer elemento
                COMUNES = {"the","a","an","in","on","at","to","of","and","or",
                           "is","it","its","be","was","are","for","as","with",
                           "but","not","this","that","they","you","your","we",
                           "i","my","me","he","she","his","her","their","our"}
                if ngram_size == 1 and ng[0] in COMUNES:
                    continue
                ngrams_guion.append((j, ng))

            best_pos = None
            best_guion_j = len(palabras)  # preferir el que aparece antes en el guión
            for guion_j, ng in ngrams_guion:
                for k in range(desde, hasta - ngram_size + 1):
                    if tuple(words_limpias[k:k+ngram_size]) == ng:
                        if guion_j < best_guion_j:
                            # Retroceder j posiciones para apuntar al inicio real de la escena
                            best_pos = max(desde, k - guion_j)
                            best_guion_j = guion_j
                        break  # primera ocurrencia de este n-gram
            if best_pos is not None:
                return best_pos

        return None

    resultado = []
    ultimo_idx = 0

    for i, escena in enumerate(escenas):
        palabras = _palabras_escena(escena)
        if not palabras:
            t_prev = resultado[-1]["fin"] if resultado else 0
            resultado.append({"inicio": t_prev, "fin": round(t_prev + 1.0, 3),
                               "duracion": 1.0, "seg_idx": ultimo_idx, "score": 0, "scene_idx": i})
            continue

        # Búsqueda estrictamente secuencial desde ultimo_idx
        # max_ventana limitado para evitar saltos falsos: si una escena tiene
        # un n-gram que aparece mucho más tarde en el stream, el algoritmo
        # preferiría esa coincidencia lejana sobre una 1-gram cercana correcta,
        # asignando cientos de segundos erróneos a una sola escena.
        first_idx = _buscar_ngram(palabras, ultimo_idx, max_ventana=800)

        if first_idx is None:
            # No encontró — interpolar proporcionalmente
            t_prev = resultado[-1]["inicio"] if resultado else 0
            t_interp = round(t_prev + (duracion_total - t_prev) / max(1, n_escenas - i), 3)
            resultado.append({"inicio": t_interp, "fin": t_interp,
                               "duracion": 0, "seg_idx": ultimo_idx, "score": 0, "scene_idx": i})
            continue

        # t_inicio: retroceder SIEMPRE al final de la palabra anterior
        # (end de first_idx-1), que es el punto exacto donde termina
        # la frase previa. Esto garantiza que la imagen cambie justo
        # al inicio del silencio/pausa, no después de la primera palabra.
        # Si no hay pausa (palabras pegadas), usar el start de la palabra.
        t_inicio = round(float(all_words[first_idx].get("start", 0)), 3)
        if first_idx > 0:
            _prev_end = float(all_words[first_idx - 1].get("end",
                              all_words[first_idx - 1].get("start", t_inicio)))
            _pausa_prev = t_inicio - _prev_end
            if _pausa_prev >= 0.08:
                # Hay pausa real — cortar al final de la palabra anterior
                # (inicio del silencio), avanzando 30ms para no cortar en seco
                t_inicio = round(_prev_end + 0.03, 3)
            # Si pausa < 0.08s las palabras están pegadas — usar start exacto

        resultado.append({"inicio": t_inicio, "fin": t_inicio,  # fin se calcula en segunda pasada
                          "duracion": 0, "seg_idx": first_idx, "score": 1.0, "scene_idx": i})
        ultimo_idx = first_idx + 1

    # ── Segunda pasada: ordenar por inicio y asignar t_fin[i] = t_inicio[i+1] ─
    resultado.sort(key=lambda x: x["inicio"])
    for i in range(len(resultado)):
        if i + 1 < len(resultado):
            t_fin = resultado[i + 1]["inicio"]
        else:
            t_fin = duracion_total
        t_inicio = resultado[i]["inicio"]
        if t_fin <= t_inicio:
            t_fin = round(t_inicio + 0.5, 3)
        dur = max(0.3, round(t_fin - t_inicio, 3))
        resultado[i]["fin"] = round(t_fin, 3)
        resultado[i]["duracion"] = dur

    # ── Tercera pasada: redistribuir bloque final de escenas mal asignadas ──
    # Con ciertas voces WhisperX agota el stream de palabras antes de cubrir
    # todas las escenas. Las escenas restantes quedan con score=0 O con score=1
    # pero duracion=0.3s (crammed en los últimos segundos del stream).
    # Se detecta el último match REAL (score>0 AND duracion>=1s) y se
    # redistribuye todo lo que venga después, proporcional al texto del guión.
    _tail_start = len(resultado)
    for _k in range(len(resultado) - 1, -1, -1):
        if resultado[_k]["score"] > 0 and resultado[_k]["duracion"] >= 1.0:
            _tail_start = _k + 1
            break

    _n_tail = len(resultado) - _tail_start
    _tail_indices = list(range(_tail_start, len(resultado)))
    # Solo redistribuir si hay escenas SIN match (score=0) en el bloque final.
    # Si todas tienen score=1 (coincidencia word-level correcta), sus timestamps
    # son válidos aunque su duración sea < 1s — no tocar nada.
    # Esta condición hace que el comportamiento sea idéntico a la versión v5
    # cuando el matching es perfecto.
    _tail_has_unmatched = any(resultado[i].get("score", 0) == 0 for i in _tail_indices)
    if _n_tail >= 5 and _tail_has_unmatched:  # solo actuar cuando hay escenas sin match
        # Base: fin del último match real
        _t0 = resultado[_tail_start - 1]["fin"] if _tail_start > 0 else 0.0
        _t_disponible = max(0.0, duracion_total - _t0)

        # Peso de cada escena por número de palabras del guión
        _pesos = [max(1, len(_palabras_escena(escenas[resultado[i].get("scene_idx", i)]))) for i in _tail_indices]
        _total_p = sum(_pesos) or 1

        # Garantizar al menos 0.5s por escena para que sea watchable.
        # Si el audio real no alcanza, el vídeo se extiende ligeramente
        # (las últimas imágenes se muestran con silencio o música de fondo).
        _dur_min = 0.5
        _t_rango = max(_t_disponible, _dur_min * _n_tail)

        _t = _t0
        for _ki, _idx in enumerate(_tail_indices):
            _t_ini = round(_t, 3)
            _dur = max(_dur_min, round(_t_rango * _pesos[_ki] / _total_p, 3))
            resultado[_idx]["inicio"]   = _t_ini
            resultado[_idx]["fin"]      = round(_t_ini + _dur, 3)
            resultado[_idx]["duracion"] = _dur
            _t = resultado[_idx]["fin"]

    return resultado


def _proporcional(escenas, duracion_total):
    dur = duracion_total / len(escenas)
    return [{"inicio":round(i*dur,3),"fin":round((i+1)*dur,3),
             "duracion":round(dur,3),"seg_idx":i,"score":0}
            for i in range(len(escenas))]

# ══════════════════════════════════════════════════════════════════
# 3. PIPELINE MODAL — MODAL_URL, procesar_video(), envío a motor remoto
# ══════════════════════════════════════════════════════════════════

MODAL_URL = "https://davidestebanbermudez14--motor-video-cpa-renderizar.modal.run"

# ── Helper: evita ventanas CMD en Windows para todos los subprocesos FFmpeg/ffprobe ──
def _vf_no_window():
    """En Windows devuelve creationflags=CREATE_NO_WINDOW para ocultar la consola.
    En otros SO devuelve {} (sin efecto)."""
    if sys.platform == "win32":
        return {"creationflags": subprocess.CREATE_NO_WINDOW}
    return {}

# ── FFmpeg: duración, mux final sin -shortest (evita cortar audio/final), GPU opcional ──
_vf_h264_encode_cache = None


def _vf_ffprobe_duration(path):
    """Duración en segundos (format.duration; si falta, stream de audio)."""
    try:
        if not path or not os.path.exists(path):
            return 0.0
        r = subprocess.run(
            [
                "ffprobe",
                "-v",
                "error",
                "-show_entries",
                "format=duration:stream=duration,codec_type",
                "-of",
                "json",
                path,
            ],
            capture_output=True,
            text=True,
            timeout=60,
            **_vf_no_window(),
        )
        if r.returncode != 0:
            return 0.0
        d = json.loads(r.stdout or "{}")
        fmt = (d.get("format") or {}).get("duration")
        if fmt is not None and float(fmt) > 0.01:
            return float(fmt)
        for s in d.get("streams") or []:
            if s.get("codec_type") == "audio" and s.get("duration"):
                return float(s["duration"])
        return 0.0
    except Exception:
        return 0.0


def _vf_libx264_encode_args_only():
    """libx264 siempre (sin caché global) — fallback fiable si GPU falla."""
    xthreads = (os.environ.get("VF_FFMPEG_X264_THREADS") or "0").strip() or "0"
    return [
        "-c:v",
        "libx264",
        "-preset",
        "ultrafast",
        "-crf",
        "28",
        "-pix_fmt",
        "yuv420p",
        "-r",
        "24",
        "-x264-params",
        f"threads={xthreads}",
    ]


def _vf_h264_encode_args():
    """
    Codificación H.264 para pasos que requieren re-encode (p. ej. tpad).
    VF_FFMPEG_VIDEO_ENCODER=auto|libx264|h264_nvenc|h264_qsv|h264_amf

    Modo auto: solo libx264 (CPU). FFmpeg suele listar nvenc/qsv/amf aunque el encoder
    falle en runtime (drivers, sandbox, GPU no disponible) — no se elige GPU por lista.
    """
    global _vf_h264_encode_cache
    if _vf_h264_encode_cache is not None:
        return list(_vf_h264_encode_cache)
    pref = (os.environ.get("VF_FFMPEG_VIDEO_ENCODER") or "auto").strip().lower()

    if pref in ("auto", "", "libx264", "x264", "cpu"):
        _vf_h264_encode_cache = _vf_libx264_encode_args_only()
        return list(_vf_h264_encode_cache)
    if pref == "h264_nvenc":
        _vf_h264_encode_cache = [
            "-c:v",
            "h264_nvenc",
            "-preset",
            "p4",
            "-rc",
            "vbr",
            "-cq",
            "28",
            "-pix_fmt",
            "yuv420p",
            "-r",
            "24",
        ]
    elif pref == "h264_qsv":
        _vf_h264_encode_cache = [
            "-c:v",
            "h264_qsv",
            "-preset",
            "veryfast",
            "-global_quality",
            "28",
            "-pix_fmt",
            "yuv420p",
            "-r",
            "24",
        ]
    elif pref == "h264_amf":
        _vf_h264_encode_cache = [
            "-c:v",
            "h264_amf",
            "-quality",
            "speed",
            "-rc",
            "cqp",
            "-qp_i",
            "28",
            "-qp_p",
            "28",
            "-pix_fmt",
            "yuv420p",
            "-r",
            "24",
        ]
    else:
        _vf_h264_encode_cache = _vf_libx264_encode_args_only()
    return list(_vf_h264_encode_cache)


def _abrir_carpeta(path):
    """Abre la carpeta indicada en el explorador de archivos del SO (cross-platform)."""
    try:
        folder = os.path.dirname(path) if os.path.isfile(path) else path
        if not os.path.isdir(folder):
            os.makedirs(folder, exist_ok=True)
        import platform as _pl
        s = _pl.system()
        if s == "Windows":
            subprocess.Popen(["explorer", os.path.normpath(folder)],
                             creationflags=subprocess.CREATE_NO_WINDOW)
        elif s == "Darwin":
            subprocess.Popen(["open", folder])
        else:
            subprocess.Popen(["xdg-open", folder])
    except Exception as _oe:
        print(f"[abrir_carpeta] {_oe}")


def _vf_final_mux_aligned(concat_out, audio_path_mix, video_final, duracion_total, log=None):
    """
    Une vídeo + audio a duracion_total (audio maestro). Sin -shortest: no recorta al stream
    más corto. Rellena vídeo (tpad) o audio (apad) y recorta (trim/atrim) si hace falta.
    """
    dt = float(duracion_total)
    v_dur = _vf_ffprobe_duration(concat_out)
    a_dur = _vf_ffprobe_duration(audio_path_mix)
    eps = 0.08
    if v_dur <= 0.05:
        raise Exception(f"Vídeo concatenado sin duración válida ({v_dur:.3f}s)")
    if a_dur <= 0.05:
        raise Exception(f"Audio final sin duración válida ({a_dur:.3f}s) — revisa audio_path_mix")

    def _lg(msg):
        if log:
            log(msg)

    # Filtro de audio: sincronizar a dt + fade out opcional
    a_parts = ["asetpts=PTS-STARTPTS"]
    if a_dur > dt + eps:
        a_parts.append(f"atrim=0:{dt:.6f}")
        a_parts.append("asetpts=PTS-STARTPTS")
    elif a_dur < dt - eps:
        a_parts.append(f"apad=pad_dur={dt - a_dur:.6f}")
    if dt > 3.0:
        st = max(0.0, dt - 1.5)
        a_parts.append(f"afade=t=out:st={st}:d=1.5")
    af = ",".join(a_parts)

    # Vídeo: si coincide con dt, copiar pista; si no, tpad o trim + re-encode
    if abs(v_dur - dt) <= eps:
        _lg(f"🎵 Mux final: vídeo≈audio ({v_dur:.2f}s≈{dt:.2f}s), copiando vídeo sin re-encode")
        cmd = [
            "ffmpeg",
            "-y",
            "-i",
            concat_out,
            "-i",
            audio_path_mix,
            "-filter_complex",
            f"[1:a]{af}[aout]",
            "-map",
            "0:v:0",
            "-map",
            "[aout]",
            "-c:v",
            "copy",
            "-c:a",
            "aac",
            "-b:a",
            "192k",
            "-movflags",
            "+faststart",
            "-t",
            f"{dt:.6f}",
            video_final,
        ]
        res = subprocess.run(cmd, capture_output=True, text=True, **_vf_no_window())
        _copy_ok = (
            res.returncode == 0
            or (os.path.exists(video_final) and os.path.getsize(video_final) > 10240)
        )
        if not _copy_ok:
            raise Exception(
                f"FFmpeg mux final (copy) falló:\n{(res.stderr or res.stdout or '')[-1200:]}"
            )
        return

    v_parts = ["setpts=PTS-STARTPTS"]
    if v_dur + eps < dt:
        gap = dt - v_dur
        v_parts.append(f"tpad=stop_mode=clone:stop_duration={gap:.6f}")
        _lg(f"🎵 Mux final: vídeo {v_dur:.2f}s < objetivo {dt:.2f}s --> tpad +{gap:.2f}s")
    elif v_dur - eps > dt:
        v_parts.append(f"trim=duration={dt:.6f}")
        v_parts.append("setpts=PTS-STARTPTS")
        _lg(f"🎵 Mux final: vídeo {v_dur:.2f}s > objetivo {dt:.2f}s --> trim")
    vf = ",".join(v_parts)
    fc = f"[0:v]{vf}[vout];[1:a]{af}[aout]"
    _lg("🎵 Mux final: re-encode de vídeo para alinear duración (libx264 ultrafast por defecto)")
    base_cmd = ["ffmpeg", "-y", "-i", concat_out, "-i", audio_path_mix, "-filter_complex", fc] + [
        "-map",
        "[vout]",
        "-map",
        "[aout]",
    ]
    tail = ["-c:a", "aac", "-b:a", "192k", "-movflags", "+faststart", "-t", f"{dt:.6f}", video_final]

    def _run_mux(enc_suffix, enc_list):
        return subprocess.run(base_cmd + enc_list + tail, capture_output=True, text=True, **_vf_no_window())

    res = _run_mux("prefer", _vf_h264_encode_args())
    if res.returncode != 0:
        err = (res.stderr or res.stdout or "")[-1400:]
        _lg(
            "[WARNING] Mux final: falló el encoder elegido (p. ej. NVENC sin GPU/driver); "
            "reintentando con libx264 (CPU)..."
        )
        res = _run_mux("fallback", _vf_libx264_encode_args_only())
        if res.returncode != 0:
            raise Exception(
                f"FFmpeg mux final (re-encode) falló también con libx264:\n"
                f"primer intento:\n{err}\n---\núltimo:\n"
                f"{(res.stderr or res.stdout or '')[-1200:]}"
            )


def _split_api_segmentos(all_words, tr_segments):
    """Divide segmentos largos de Whisper API en sub-segmentos por oración/pausa."""
    if not all_words:
        return [{"start": float(s.start), "end": float(s.end), "text": s.text, "words": []}
                for s in (tr_segments or [])]
    segmentos = []
    for _s in (tr_segments or []):
        seg_words = [w for w in all_words
                     if float(_s.start) - 0.05 <= w["start"] <= float(_s.end) + 0.05]
        if not seg_words:
            segmentos.append({"start": float(_s.start), "end": float(_s.end),
                              "text": _s.text, "words": []})
            continue
        cur = []
        for k, w in enumerate(seg_words):
            cur.append(w)
            is_last = (k == len(seg_words) - 1)
            ends_s = w.get("word","").strip().rstrip(",").endswith((".", "?", "!", ";"))
            has_pause = False
            if not is_last:
                we = float(w.get("end", w.get("start", 0)))
                ns = float(seg_words[k+1].get("start", we))
                has_pause = (ns - we) >= 0.15
            if (ends_s or has_pause or is_last) and cur:
                segmentos.append({
                    "start": float(cur[0].get("start", float(_s.start))),
                    "end":   float(cur[-1].get("end", cur[-1].get("start", float(_s.end)))),
                    "text":  " ".join(ww.get("word","").strip() for ww in cur),
                    "words": list(cur)
                })
                cur = []
    return segmentos or [{"start": float(s.start), "end": float(s.end),
                          "text": s.text, "words": []} for s in (tr_segments or [])]


def procesar_video(job_id, job_dir, audio_path, guion_path, imgs_dir,
                   resolucion, fade, modelo, transicion, movimiento, trans_dur, shake,
                   whisper_backend="local"):

    def log(msg, progreso=None):
        jobs[job_id]["logs"].append(msg)
        jobs[job_id]["mensaje"] = msg
        if progreso is not None:
            jobs[job_id]["progreso"] = progreso
        try:
            print(f"[{job_id}] {msg}", flush=True)
        except UnicodeEncodeError:
            _safe = f"[{job_id}] {msg}".encode("ascii", errors="replace").decode("ascii")
            try:
                print(_safe, flush=True)
            except Exception:
                pass

    def _write_concat_list(path, clip_paths):
        """Write ffmpeg concat list safely for Windows paths."""
        with open(path, "w", encoding="utf-8") as f:
            for p in clip_paths:
                pp = str(p).replace("\\", "/").replace("'", "'\\''")
                f.write(f"file '{pp}'\n")

    try:
        log("📄 Leyendo guión...", 5)
        with open(guion_path, "r", encoding="utf-8") as f:
            escenas = [e.strip() for e in f.read().split("\n") if e.strip()]
        log(f"✓ {len(escenas)} escenas", 10)

        log("🖼️ Cargando imágenes...", 12)
        exts = ('.jpg','.jpeg','.png','.webp')
        imagenes = sorted(
            [str(p) for p in __import__("pathlib").Path(imgs_dir).iterdir() if p.suffix.lower() in exts],
            key=lambda p: os.path.basename(p)
        )
        if not imagenes:
            raise Exception("No se encontraron imágenes")
        log(f"✓ {len(imagenes)} imágenes | {len(escenas)} escenas", 15)

        log("⏱️ Analizando audio...", 18)
        result = subprocess.run(
            ["ffprobe","-v","error","-show_entries","format=duration",
             "-of","json", audio_path],
            capture_output=True, text=True,
            **_vf_no_window()
        )
        if result.returncode != 0:
            raise Exception(f"ffprobe: {result.stderr}")
        try:
            _parsed = json.loads(result.stdout)
            _dur = (_parsed.get("format") or {}).get("duration")
            if _dur is None:
                _res2 = subprocess.run(["ffprobe","-v","error","-show_entries",
                    "stream=duration","-of","json",audio_path],capture_output=True, text=True, **_vf_no_window())
                _streams = json.loads(_res2.stdout).get("streams",[])
                _dur = next((s["duration"] for s in _streams if s.get("duration")),None)
            duracion_total = float(_dur)
        except Exception as _de:
            raise Exception(f"No se pudo leer la duración del audio: {_de}")
        log(f"✓ Audio: {duracion_total:.1f}s", 20)

        if whisper_backend == "api":
            log("🌐 Transcribiendo con Whisper API...", 22)
            from openai import OpenAI as _OAI
            _oai = _OAI(api_key=OPENAI_WHISPER_KEY)
            with open(audio_path, "rb") as _af:
                _tr = _oai.audio.transcriptions.create(
                    model="whisper-1", file=_af, language="es",
                    response_format="verbose_json",
                    timestamp_granularities=["word", "segment"]
                )
            _all_words = [{"word": _w.word, "start": float(_w.start), "end": float(_w.end)}
                          for _w in (getattr(_tr, "words", None) or [])]
            if not _all_words:
                for _s in (_tr.segments or []):
                    for _w in (getattr(_s, "words", None) or []):
                        _all_words.append({"word": _w.word, "start": float(_w.start), "end": float(_w.end)})
            segmentos = _split_api_segmentos(_all_words, _tr.segments)
            _pv_all_words = _all_words
            log(f"✓ {len(_all_words)} words --> {len(segmentos)} sub-segmentos (API)", 30)
        elif whisper_backend == "faster":
            log(f"⚡ Transcribiendo con faster-whisper ({modelo})...", 22)
            from faster_whisper import WhisperModel as _FWM
            _fwm = _FWM(modelo, device="cpu", compute_type="int8")
            _segs_raw, _ = _fwm.transcribe(audio_path, language=None,
                                            word_timestamps=True, beam_size=1, vad_filter=True)
            segmentos = [{"start": s.start, "end": s.end, "text": s.text,
                          "words": [{"word": w.word, "start": w.start, "end": w.end}
                                    for w in (s.words or [])]}
                         for s in _segs_raw]
            log(f"✓ {len(segmentos)} segmentos (faster-whisper)", 30)
        elif whisper_backend == "whisperx_local":
            log(f"🎯 Transcribiendo con WhisperX local ({modelo})...", 22)
            import whisperx as _wxl
            _wxl_device = "cpu"
            _wxl_model = _wxl.load_model(modelo, _wxl_device, compute_type="int8", language="es")
            _wxl_audio = _wxl.load_audio(audio_path)
            _wxl_result = _wxl_model.transcribe(_wxl_audio, batch_size=8, language="es")
            del _wxl_model
            _align_model, _align_meta = _wxl.load_align_model(language_code="es", device=_wxl_device)
            _wxl_aligned = _wxl.align(_wxl_result["segments"], _align_model, _align_meta,
                                       _wxl_audio, _wxl_device, return_char_alignments=False)
            del _align_model
            _pv_all_words = []
            for _s in _wxl_aligned["segments"]:
                for _w in (_s.get("words") or []):
                    if _w.get("start") is not None:
                        _pv_all_words.append({"word": _w.get("word",""),
                                              "start": float(_w["start"]),
                                              "end": float(_w.get("end", _w["start"]))})
            segmentos = [{"start": float(s["start"]), "end": float(s["end"]),
                          "text": s.get("text",""),
                          "words": [{"word": w.get("word",""), "start": float(w["start"]),
                                     "end": float(w.get("end", w["start"]))}
                                    for w in (s.get("words") or []) if w.get("start") is not None]}
                         for s in _wxl_aligned["segments"]]
            log(f"✓ {len(_pv_all_words)} words alineadas --> {len(segmentos)} segmentos (WhisperX local)", 30)
        elif whisper_backend == "whisperx":
            log("🎯 Transcribiendo con WhisperX Replicate (alineación forzada)...", 22)
            segmentos, _pv_all_words = _transcribir_whisperx_runpod(audio_path, language=None)
            log(f"✓ {len(_pv_all_words)} words alineadas --> {len(segmentos)} segmentos (WhisperX RunPod)", 30)
        else:
            log(f"🎤 Transcribiendo con Whisper ({modelo})...", 22)
            import whisper as _wh
            resultado = _wh.load_model(modelo).transcribe(
                audio_path, language=None, word_timestamps=True)
            segmentos = resultado.get("segments", [])
            log(f"✓ {len(segmentos)} segmentos transcritos", 30)

        log("🔍 Asignando timestamps...", 32)
        _pv_words_available = locals().get("_pv_all_words")
        if _pv_words_available:
            timestamps = asignar_timestamps_words(escenas, _pv_words_available, duracion_total)
            # Detección de fallo word-level (voz TTS lee números distinto al guión)
            _pv_unmatched = sum(1 for _t in timestamps if _t.get("score", 0) == 0)
            _pv_last_ok   = max((_t["fin"] for _t in timestamps if _t.get("score", 0) > 0), default=0.0)
            if (_pv_unmatched / max(1, len(timestamps)) > 0.40
                    and _pv_last_ok > duracion_total * 0.85):
                log(f"[WARNING] Word-level anómalo ({_pv_unmatched}/{len(timestamps)} sin match) "
                    f"--> segment-level fallback", 33)
                timestamps = asignar_timestamps(escenas, segmentos, duracion_total)
                log("  --> modo segment-level fallback (pronunciación distinta al guión)", 33)
            else:
                log("  --> modo word-level / alineación forzada (máxima precisión)", 33)
        else:
            timestamps = asignar_timestamps(escenas, segmentos, duracion_total)
            log("  --> modo segment-level", 33)
        log(f"✓ {len(timestamps)} timestamps listos", 35)
        log("📋 Timestamps por escena:")
        for _i, _ts in enumerate(timestamps):
            log(f"  E{_i+1:02d}: {_ts['inicio']:.2f}s --> {_ts['fin']:.2f}s  dur={_ts['duracion']:.3f}s  score={_ts.get('score',0):.2f}  seg={_ts.get('seg_idx','?')}")

        log("🚀 Codificando archivos para Modal...", 40)
        with open(audio_path, "rb") as f:
            audio_b64 = base64.b64encode(f.read()).decode("utf-8")
        # Para batch mode: usar audio silencioso en la nube y mezclar el audio real al final.
        # Evita reinicios de audio entre batches al concatenar.
        import tempfile as _tmp
        tmp_dir = _tmp.mkdtemp()
        silent_audio = os.path.join(tmp_dir, "silent.mp3")
        _sil = subprocess.run([
            "ffmpeg", "-y", "-f", "lavfi", "-i", "anullsrc=r=44100:cl=mono",
            "-t", str(max(1.0, duracion_total)), "-b:a", "32k", silent_audio
        ], capture_output=True, text=True, **_vf_no_window())
        if _sil.returncode == 0 and os.path.exists(silent_audio):
            with open(silent_audio, "rb") as f:
                batch_audio_b64 = base64.b64encode(f.read()).decode("utf-8")
        else:
            # Fallback de seguridad: si falla el silencioso, usar audio real.
            batch_audio_b64 = audio_b64

        extra = trans_dur if transicion != "none" else 0.0
        # Mapa escena-->imagen por nombre de archivo — evita desplazamiento cuando
        # Whisk falla en alguna imagen (img_00003 faltante no corre las demás)
        _pv_img_by_scene = {}
        for _ip in imagenes:
            _pv_m = re.match(r"^img_(\d+)$", os.path.splitext(os.path.basename(_ip))[0], re.IGNORECASE)
            if _pv_m:
                _pv_img_by_scene[int(_pv_m.group(1)) - 1] = _ip
        escenas_modal = []
        MAX_CHUNK = 8.0
        for i, ts in enumerate(timestamps):
            _sidx_pv = ts.get("scene_idx", i)
            _img_path_pv = _pv_img_by_scene.get(_sidx_pv) or imagenes[min(_sidx_pv, len(imagenes)-1)]
            with open(_img_path_pv, "rb") as f:
                img_b64 = base64.b64encode(f.read()).decode("utf-8")
            base_dur = ts["duracion"]
            if base_dur <= MAX_CHUNK:
                escenas_modal.append({
                    "imagen_b64": img_b64,
                    "duracion": base_dur,
                    "movimiento": movimiento
                })
            else:
                # Dividir en sub-chunks de <= 8s, sin transicion interna
                remaining = base_dur
                while remaining > 0:
                    d = min(MAX_CHUNK, remaining)
                    escenas_modal.append({
                        "imagen_b64": img_b64,
                        "duracion": d,
                        "movimiento": movimiento
                    })
                    remaining -= d

        payload = {
            "audio_b64":  audio_b64,
            "escenas":    escenas_modal,
            "resolucion": resolucion.replace("x",":"),
            "transicion": transicion,
            "trans_dur":  trans_dur,
            "fade":       fade,
            "shake":      shake
        }

        # Dividir en batches de 30 escenas para evitar payload demasiado grande (500 error)
        BATCH_SIZE = 30
        total_escenas = len(escenas_modal)
        log(f"⚡ Procesando en la nube ({total_escenas} escenas en batches de {BATCH_SIZE})...", 60)

        videos_b64 = []
        n_batches = (total_escenas + BATCH_SIZE - 1) // BATCH_SIZE
        for b_idx in range(n_batches):
            batch = escenas_modal[b_idx * BATCH_SIZE:(b_idx + 1) * BATCH_SIZE]
            batch_payload = {
                "audio_b64":  batch_audio_b64,
                "escenas":    batch,
                "resolucion": payload["resolucion"],
                "transicion": payload["transicion"],
                "trans_dur":  payload["trans_dur"],
                "fade":       payload["fade"],
                "shake":      payload["shake"],
                "batch_mode": True,
                "batch_index": b_idx,
                "batch_total": n_batches,
            }
            prog = 60 + int(30 * (b_idx + 1) / n_batches)
            log(f"  Batch {b_idx+1}/{n_batches} ({len(batch)} escenas)...", prog)
            # Reintentos con backoff para CUALQUIER fallo de Modal:
            # error HTTP, body vacío, respuesta no-JSON, success=False
            last_err = None
            d = None
            for _attempt in range(4):
                try:
                    resp = requests.post(MODAL_URL, json=batch_payload, timeout=900)
                    if resp.status_code in (500, 502, 503, 504) and _attempt < 3:
                        log(f"  [WARNING] Batch {b_idx+1}: error {resp.status_code}, reintento {_attempt+1}/3...")
                        time.sleep(10 * (_attempt + 1))
                        continue
                    resp.raise_for_status()
                    _resp_text = (resp.text or "").strip()
                    if not _resp_text:
                        raise ValueError("Modal devolvió respuesta vacía")
                    d = resp.json()
                    if not d.get("success"):
                        raise Exception(d.get("error", f"Error en Modal batch {b_idx+1}"))
                    last_err = None
                    break
                except Exception as _e:
                    last_err = _e
                    if _attempt < 3:
                        log(f"  [WARNING] Batch {b_idx+1}: {_e}, reintento {_attempt+1}/3...")
                        time.sleep(10 * (_attempt + 1))
            if last_err:
                raise Exception(f"Batch {b_idx+1} falló tras 4 intentos: {last_err}")
            video_b64 = d.get("video_b64") or d.get("video_base64")
            if not isinstance(video_b64, str) or not video_b64.strip():
                raise Exception(
                    f"Respuesta inválida en batch {b_idx+1}: falta video_b64 válido. "
                    f"Claves: {list(d.keys())[:20]}"
                )
            videos_b64.append(video_b64)

        log("📥 Descargando video final...", 90)
        video_concat = os.path.join(job_dir, "video_concat.mp4")
        video_final  = os.path.join(job_dir, "video_final.mp4")

        # Guardar todos los batches en disco y verificar duración real vs esperada
        part_files = []
        batch_dur_esperada = []
        for b in range(n_batches):
            batch = escenas_modal[b * BATCH_SIZE:(b + 1) * BATCH_SIZE]
            batch_dur_esperada.append(sum(sc["duracion"] for sc in batch))

        for i, vb64 in enumerate(videos_b64):
            part = os.path.join(tmp_dir, f"part_{i:04d}.mp4")
            with open(part, "wb") as f:
                f.write(base64.b64decode(vb64))
            # Medir duración real del batch
            try:
                _pr = subprocess.run(["ffprobe","-v","error","-show_entries",
                    "format=duration","-of","json", part],
                    capture_output=True, text=True, **_vf_no_window())
                _real = float(json.loads(_pr.stdout).get("format",{}).get("duration",0))
            except Exception:
                _real = 0
            _esp = batch_dur_esperada[i]
            _diff = _real - _esp
            log(f"  📦 Batch {i+1}: esperado={_esp:.3f}s real={_real:.3f}s Δ={_diff:+.3f}s")
            part_files.append(part)

        if len(part_files) == 1:
            # Un solo batch: re-encodear para normalizar PTS desde 0
            subprocess.run([
                "ffmpeg", "-y", "-i", part_files[0],
                "-vf", "setpts=PTS-STARTPTS",
                "-c:v", "libx264", "-preset", "ultrafast", "-crf", "18",
                "-pix_fmt", "yuv420p", "-r", "24", "-an",
                "-movflags", "+faststart", video_concat
            ], check=True, capture_output=True, **_vf_no_window())
        else:
            # Múltiples batches: filter_complex para normalizar PTS de cada batch
            # y concatenarlos sin saltos — cada batch de Modal empieza su PTS en 0,
            # filter_complex los reencadena correctamente.
            n_parts = len(part_files)
            inputs = []
            for p in part_files:
                inputs += ["-i", p]
            filter_parts = "".join(
                f"[{i}:v]setpts=PTS-STARTPTS[v{i}];" for i in range(n_parts)
            )
            concat_inputs = "".join(f"[v{i}]" for i in range(n_parts))
            filter_str = f"{filter_parts}{concat_inputs}concat=n={n_parts}:v=1:a=0[vout]"
            subprocess.run(
                ["ffmpeg", "-y"] + inputs + [
                    "-filter_complex", filter_str,
                    "-map", "[vout]",
                    "-c:v", "libx264", "-preset", "ultrafast", "-crf", "18",
                    "-pix_fmt", "yuv420p", "-r", "24", "-an",
                    "-movflags", "+faststart", video_concat
                ], check=True, capture_output=True, **_vf_no_window()
            )

        # Mezclar audio alineado a duracion_total (sin -shortest: evita cortar el final)
        _vf_final_mux_aligned(video_concat, audio_path, video_final, duracion_total, log=log)

        size_mb = os.path.getsize(video_final) / (1024*1024)
        log(f"[OK] Video listo — {size_mb:.1f} MB", 100)
        jobs[job_id].update({
            "estado": "completado",
            "video_url": f"/api/descargar/{job_id}",
            "size_mb":   round(size_mb, 1),
            "duracion":  round(duracion_total, 1),
            "escenas":   len(escenas)
        })
        _abrir_carpeta(video_final)

    except Exception as e:
        try:
            import traceback as _tb6
            print(_tb6.format_exc().encode('ascii', 'replace').decode('ascii'))
        except Exception:
            pass
        _e_safe2 = str(e).encode('ascii', 'replace').decode('ascii')
        log(f"Error: {_e_safe2}")
        jobs[job_id].update({"estado": "error", "error": _e_safe2})
    finally:
        try:
            import shutil as _sh
            _sh.rmtree(tmp_dir, ignore_errors=True)  # noqa: F821
        except Exception:
            pass


# ══════════════════════════════════════════════════════════════════
# 4. GROK — grok_multi.py, estado, helpers y todas las rutas /api/grok/*
#    (sesiones, login, iniciar/detener, videos, descarga zip, abrir carpeta)
# ══════════════════════════════════════════════════════════════════

import shutil, zipfile, signal
from pathlib import Path as FPath

# Mismo layout que launcher.py original (Mac): grok-animator2.0/grok_multi.py (v4 + pool).
# PyInstaller: el script embebido suele estar en _internal/grok_multi.py, pero grok_multi.py
# usa Path(__file__).parent para accounts/downloads/logs. Si ejecutamos desde _internal,
# las cookies quedan en _internal/accounts — distinto a python launcher.py (grok-animator2.0/accounts)
# y parece "solo falla el .exe". Solución: copiar grok_multi.py a grok-animator2.0/ junto al .exe.
if getattr(sys, "frozen", False):
    _APP_ROOT = FPath(os.path.dirname(sys.executable)).resolve()
else:
    _APP_ROOT = FPath(os.path.dirname(os.path.abspath(__file__))).resolve()

_GROK_DATA     = _APP_ROOT / "grok-animator2.0"
_GROK_V4       = _GROK_DATA / "grok_multi.py"
_INTERNAL_GROK = _APP_ROOT / "_internal" / "grok_multi.py"
_ROOT_GROK     = _APP_ROOT / "grok_multi.py"


def _iter_grok_bundle_roots():
    """Directorios donde suele estar el bundle (mismo orden: primero donde vive launcher.exe / launcher.py)."""
    seen, out = set(), []

    def _add(p):
        try:
            r = FPath(p).expanduser().resolve()
        except Exception:
            return
        if not r.is_dir():
            return
        k = str(r)
        if k in seen:
            return
        seen.add(k)
        out.append(r)

    _add(_APP_ROOT)
    lad = os.environ.get("LOCALAPPDATA", "")
    if lad:
        _add(FPath(lad) / "Studio IVR")
    _br = (os.environ.get("STUDIO_IVR_BUNDLE_ROOT") or "").strip()
    if _br:
        _add(FPath(_br))
    _add(FPath.home() / "Desktop" / "Studio IVR")
    _add(FPath.home() / "Documents" / "Studio IVR")
    return out


def _first_grok_script_in_root(root: FPath):
    for rel in (
        ("grok-animator2.0", "grok_multi.py"),
        ("_internal", "grok_multi.py"),
        ("grok_multi.py",),
    ):
        p = root.joinpath(*rel) if len(rel) > 1 else root / rel[0]
        if p.is_file():
            return p.resolve()
    return None


def _find_grok_multi_seed_source():
    """Primer grok_multi.py en alguna instalación conocida (p. ej. proyecto en Desktop mientras launcher corre desde AppData)."""
    for root in _iter_grok_bundle_roots():
        hit = _first_grok_script_in_root(root)
        if hit is not None:
            return hit
    return None


def _sync_grok_multi_into_app_animator_folder():
    """
    Deja siempre grok_multi.py en _APP_ROOT/grok-animator2.0/ cuando sea posible:
    - desde _internal local (PyInstaller / carpeta dist)
    - o desde otra copia del bundle (Desktop, etc.) si aquí no existe o está más viejo
    """
    try:
        _GROK_DATA.mkdir(parents=True, exist_ok=True)
    except Exception:
        pass

    def _copy_if_better(src: FPath):
        try:
            if not src.is_file():
                return
            sr, dr = src.resolve(), _GROK_V4.resolve()
            if sr == dr:
                return
            if not _GROK_V4.is_file() or src.stat().st_mtime > _GROK_V4.stat().st_mtime:
                shutil.copy2(str(src), str(_GROK_V4))
        except Exception as _ge:
            print(
                f"[Studio IVR] No se pudo sincronizar grok_multi --> grok-animator2.0: {_ge}",
                file=sys.stderr,
            )

    _copy_if_better(_INTERNAL_GROK)
    _seed = _find_grok_multi_seed_source()
    if _seed is not None:
        _copy_if_better(_seed)


def _resolve_grok_paths():
    """Actualiza GROK_DIR / GROK_SCRIPT; rellena grok-animator2.0 junto al launcher activo cuando falte el script."""
    global GROK_DIR, GROK_SCRIPT
    _sync_grok_multi_into_app_animator_folder()

    GROK_DIR = None
    GROK_SCRIPT = None
    _env_grok = (os.environ.get("STUDIO_IVR_GROK_ROOT") or "").strip()
    if _env_grok:
        _env_p = FPath(_env_grok).expanduser().resolve()
        _env_s = _env_p / "grok_multi.py"
        if _env_s.is_file():
            GROK_DIR, GROK_SCRIPT = _env_p, _env_s

    if GROK_SCRIPT is None:
        if _GROK_V4.is_file():
            GROK_DIR, GROK_SCRIPT = _GROK_DATA.resolve(), _GROK_V4.resolve()
        elif _INTERNAL_GROK.is_file():
            GROK_DIR, GROK_SCRIPT = _INTERNAL_GROK.parent.resolve(), _INTERNAL_GROK.resolve()
        elif _ROOT_GROK.is_file():
            GROK_DIR, GROK_SCRIPT = _APP_ROOT.resolve(), _ROOT_GROK.resolve()
        else:
            GROK_DIR, GROK_SCRIPT = _APP_ROOT.resolve(), (_APP_ROOT / "grok_multi.py").resolve()


_resolve_grok_paths()


def _grok_popen_argv(script_args):
    """Argv para grok_multi. En frozen, el .exe debe recibir --vf-grok-worker o re-lanza Flask."""
    sa = list(script_args)
    _gs = str(FPath(GROK_SCRIPT).resolve())
    if getattr(sys, "frozen", False):
        return [sys.executable, "--vf-grok-worker", _gs] + sa
    return [sys.executable, _gs] + sa


def _grok_child_env():
    """Mismo entorno UTF-8 que el proceso padre (evita diferencias solo en .exe)."""
    e = os.environ.copy()
    e.setdefault("PYTHONUTF8", "1")
    e.setdefault("PYTHONIOENCODING", "utf-8")
    return e


def _ensure_grok_accounts_setup():
    """
    Ensure GROK_DIR/accounts exists with base account folders so users can log in
    and save cookies without manual filesystem setup.
    """
    accounts_dir = GROK_DIR / "accounts"
    accounts_dir.mkdir(parents=True, exist_ok=True)

    # Si Grok vive en grok-animator2.0 pero antes usabas accounts/ en la raíz del proyecto, copiar sesiones.
    root_ac = _APP_ROOT / "accounts"
    if root_ac.resolve() != accounts_dir.resolve() and root_ac.is_dir():
        has_any = any(accounts_dir.iterdir())
        if not has_any:
            for folder in sorted(root_ac.iterdir()):
                if folder.is_dir() and (folder / "cookies_auto.json").exists():
                    dest = accounts_dir / folder.name
                    if not dest.exists():
                        shutil.copytree(folder, dest)

    # Asegurar siempre 10 carpetas de cuenta (account_1 … account_10).
    existing_nums = set()
    for d in accounts_dir.iterdir():
        if d.is_dir():
            import re as _re2
            m = _re2.match(r"account_(\d+)$", d.name)
            if m:
                existing_nums.add(int(m.group(1)))
    for i in range(1, 11):
        if i not in existing_nums:
            (accounts_dir / f"account_{i}").mkdir(parents=True, exist_ok=True)

    readme = accounts_dir / "README.txt"
    if not readme.exists():
        readme.write_text(
            "Carpetas de cuentas para Grok.\n"
            "1) Abre 'Sesiones' en la app.\n"
            "2) Inicia sesion en cada cuenta (account_1, account_2, ...).\n"
            "3) El sistema guarda cookies en cookies_auto.json dentro de cada carpeta.\n",
            encoding="utf-8"
        )
    return accounts_dir

grok_state = {
    "proc":         None,
    "log_lines":    [],
    "finished":     False,
    "project_dir":  None,   # current project FPath
    "images":       [],     # ordered list of (index, filename, FPath)
    "total":        0,
}

def _project_video_dir():
    return FPath(grok_state["project_dir"]) / "video" if grok_state["project_dir"] else None

def _tail_grok(proc):
    try:
        for line in iter(proc.stdout.readline, b""):
            decoded = line.decode("utf-8", errors="replace").rstrip()
            grok_state["log_lines"].append(decoded)
    except Exception:
        pass
    grok_state["finished"] = True

def _watch_and_copy():
    """Watch grok downloads/ and copy ONLY NEW .mp4s to project/video/"""
    grok_dl = GROK_DIR / "downloads"
    vid_dir = _project_video_dir()
    if not vid_dir:
        return
    import time
    # Snapshot existing files BEFORE the job starts — never copy these
    grok_dl.mkdir(parents=True, exist_ok=True)
    pre_existing = set(f.name for f in grok_dl.glob("*.mp4"))
    seen = set(pre_existing)  # treat pre-existing as already seen --> skip them
    while not grok_state["finished"] or (grok_state["proc"] and grok_state["proc"].poll() is None):
        try:
            for f in grok_dl.glob("*.mp4"):
                if f.name not in seen:
                    dest = vid_dir / f.name
                    try:
                        shutil.copy2(str(f), str(dest))
                        seen.add(f.name)
                    except Exception:
                        pass
        except Exception:
            pass
        time.sleep(2)
    # Final copy pass for any files missed in the loop
    try:
        for f in grok_dl.glob("*.mp4"):
            if f.name not in seen:
                shutil.copy2(str(f), str(vid_dir / f.name))
    except Exception:
        pass


# ── Rutas HTTP /api/grok/* ────────────────────────────────────────────




@app.route("/api/grok/sesiones", methods=["GET"])
def grok_sesiones():
    """List accounts in GROK_DIR/accounts/ and their session status."""
    import json as _json
    from pathlib import Path as _P
    try:
        _resolve_grok_paths()
        accounts_dir = _ensure_grok_accounts_setup()
        result = []
        for folder in sorted(accounts_dir.iterdir()):
            if not folder.is_dir(): continue
            ck_file = folder / "cookies_auto.json"
            active  = False
            user    = ""
            if ck_file.exists():
                try:
                    ck = _json.loads(ck_file.read_text())
                    ck_dict = {c["name"]: c["value"] for c in ck if isinstance(c, dict)}
                    # Grok usa cookie 'sso' como indicador de sesión válida
                    active = bool(ck_dict.get("sso"))
                    uid_cookie = ck_dict.get("x-userid", "")
                    user = uid_cookie[:20] if uid_cookie else (f"{len(ck)} ck" if active else "sin sesión")
                except Exception:
                    active = ck_file.stat().st_size > 50
            result.append({"name": folder.name, "active": active, "user": user,
                            "has_cookies": ck_file.exists()})
        return jsonify({"accounts": result})
    except Exception as e:
        return jsonify({"accounts": [], "error": str(e)})


@app.route("/api/grok/login_cuenta", methods=["POST"])
def grok_login_cuenta():
    """Open browser for a specific account to log in and save cookies."""
    data        = request.get_json() or {}
    folder_name = data.get("account", "").strip()
    if not folder_name:
        return jsonify({"error": "account name required"}), 400

    _resolve_grok_paths()
    accounts_dir = _ensure_grok_accounts_setup()
    folder       = accounts_dir / folder_name
    folder.mkdir(parents=True, exist_ok=True)

    grok_state["log_lines"].append(f"  🌐 [{folder_name}] Abriendo Chrome — inicia sesión en grok.com y cierra la ventana.")

    def _do_login():
        import shutil as _shutil
        try:
            from playwright.sync_api import sync_playwright

            # ── Perfil temporal limpio (evita estados corruptos de sesiones previas) ──
            import tempfile as _tf
            temp_profile = str(FPath(_tf.gettempdir()) / f"grok_tmp_{folder_name}")
            if FPath(temp_profile).exists():
                _shutil.rmtree(temp_profile)
            FPath(temp_profile).mkdir(parents=True, exist_ok=True)

            with sync_playwright() as pw:
                import glob as _glob
                _local = os.environ.get("LOCALAPPDATA", "")
                _posibles = _glob.glob(os.path.join(_local, "ms-playwright", "chromium-*", "chrome-win*", "chrome.exe"))
                _exe = _posibles[0] if _posibles else None
                ctx = pw.chromium.launch_persistent_context(
                    temp_profile, headless=False,
                    executable_path=_exe,
                    args=[
                        "--no-sandbox",
                        "--disable-blink-features=AutomationControlled",
                        "--no-first-run",
                    ],
                    viewport={"width": 1280, "height": 900},
                )
                page = ctx.pages[0] if ctx.pages else ctx.new_page()

                def _vf_statsig(sid):
                    if not sid or not isinstance(sid, str):
                        return False
                    sid = sid.strip()
                    if len(sid) < 8 or len(sid) > 256:
                        return False
                    sl = sid.lower()
                    for bad in (
                        "error", "undefined", "typeerror", "exception",
                        "cannot read", "null", "nan", "syntaxerror",
                    ):
                        if bad in sl:
                            return False
                    return True

                def _vf_sentry(sr):
                    if not sr or not isinstance(sr, str):
                        return False
                    sr = sr.strip()
                    if len(sr) < 8 or len(sr) > 64:
                        return False
                    return all(c in "0123456789abcdefABCDEF" for c in sr)

                session_meta_capture = {}

                def _on_req(req):
                    h = req.headers
                    sid = h.get("x-statsig-id", "")
                    if sid and _vf_statsig(sid) and not session_meta_capture.get("statsig_id"):
                        session_meta_capture["statsig_id"] = sid.strip()
                    bag = h.get("baggage", "")
                    if "sentry-release=" in bag and not session_meta_capture.get("sentry_release"):
                        for part in bag.split(","):
                            if part.strip().startswith("sentry-release="):
                                rel = part.split("=", 1)[1].strip()
                                if _vf_sentry(rel):
                                    session_meta_capture["sentry_release"] = rel

                page.on("request", _on_req)

                try:
                    page.goto("https://grok.com/imagine", timeout=30000)
                    page.wait_for_load_state("networkidle", timeout=30000)
                except Exception:
                    pass

                saved = False
                import time as _t
                deadline = _t.time() + 300
                while _t.time() < deadline:
                    try:
                        cookies = ctx.cookies("https://grok.com")
                    except Exception:
                        break

                    ck_dict = {c["name"]: c["value"] for c in cookies}
                    # Grok autentica con la cookie 'sso' (no con prefijo 'x-')
                    if ck_dict.get("sso"):
                        import json as _json
                        # Guardar con formato COMPLETO para que Playwright las cargue bien
                        cookie_list = [
                            {
                                "name":     c["name"],
                                "value":    c["value"],
                                "domain":   ".grok.com",
                                "path":     "/",
                                "httpOnly": c.get("httpOnly", False),
                                "secure":   c.get("secure", True),
                            }
                            for c in cookies
                        ]
                        (folder / "cookies_auto.json").write_text(
                            _json.dumps(cookie_list, indent=2)
                        )
                        smf = folder / "session_meta.json"
                        if session_meta_capture:
                            smf.write_text(_json.dumps(session_meta_capture, indent=2))
                        elif smf.exists():
                            smf.unlink()
                        grok_state["log_lines"].append(
                            f"  [OK] [{folder_name}] Sesión guardada "
                            f"(sso={ck_dict['sso'][:12]}… | {len(cookies)} cookies"
                            f"{' | session_meta OK' if session_meta_capture else ''})."
                        )
                        saved = True
                        _t.sleep(1)
                        try: ctx.close()
                        except Exception: pass
                        break
                    _t.sleep(2)

                if not saved:
                    try: ctx.close()
                    except Exception: pass
                    grok_state["log_lines"].append(
                        f"  [WARNING]  [{folder_name}] Browser cerrado sin guardar sesión "
                        f"(cookie 'sso' no detectada)."
                    )
        except ImportError:
            grok_state["log_lines"].append(f"  [ERROR] [{folder_name}] Playwright no instalado.")
        except Exception as e:
            grok_state["log_lines"].append(f"  [ERROR] [{folder_name}] Error: {e}")
        finally:
            # Limpiar perfil temporal siempre, incluso si hubo error
            try:
                import tempfile as _tf
                temp_profile = str(FPath(_tf.gettempdir()) / f"grok_tmp_{folder_name}")
                if FPath(temp_profile).exists():
                    _shutil.rmtree(temp_profile)
            except Exception:
                pass

    threading.Thread(target=_do_login, daemon=True).start()
    return jsonify({"ok": True, "message": f"Chrome abierto para {folder_name}"})


@app.route("/api/grok/borrar_sesion", methods=["POST"])
def grok_borrar_sesion():
    """Delete cookies for an account (reset session)."""
    import re as _re
    folder_name = (_re.sub(r"[^\w\-]","_",(request.get_json() or {}).get("account","").strip()))
    if not folder_name: return jsonify({"error":"account required"}),400
    ck_file = GROK_DIR / "accounts" / folder_name / "cookies_auto.json"
    if ck_file.exists(): ck_file.unlink()
    return jsonify({"ok": True})


@app.route("/api/grok/iniciar", methods=["POST"])
def grok_iniciar():
    # Kill any existing process
    if grok_state["proc"] and grok_state["proc"].poll() is None:
        grok_state["proc"].terminate()

    # ── Use existing project from topbar (never create a new one) ─
    import time as _time
    proj_name = request.form.get("project_name", "").strip()
    proj_name = re.sub(r"[^a-zA-Z0-9_\-]", "_", proj_name)
    if not proj_name:
        return jsonify({"error": "Selecciona un proyecto en la barra superior antes de animar."}), 400
    proj_dir  = FPath(JOBS_FOLDER) / proj_name
    _resolve_grok_paths()
    _ensure_grok_accounts_setup()
    if not GROK_SCRIPT.is_file():
        return jsonify({
            "error": (
                "No se encuentra grok_multi.py junto a este launcher. "
                "Copia la carpeta grok-animator2.0 (con grok_multi.py dentro) o la carpeta _internal "
                "desde el proyecto / instalación, o define la variable de entorno STUDIO_IVR_GROK_ROOT "
                "apuntando a la carpeta que contiene grok_multi.py."
            )
        }), 500
    # Auto-create the folder if it doesn't exist yet (PM may have created it without disk folder)
    for sub in ("imagen", "audio", "guion", "video", "video_final"):
        (proj_dir / sub).mkdir(parents=True, exist_ok=True)

    # ── Save images to proyecto/imagen/ ──────────────────────────
    img_keys = sorted(
        [k for k in request.files if k.startswith("imagen_")],
        key=lambda x: int(x.split("_")[1])
    )
    if not img_keys:
        return jsonify({"error": "No se recibieron imágenes"}), 400

    # Save uploaded images to imagen/ with their ORIGINAL filenames.
    # Never rename — videos will be named identically (same stem, .mp4 ext).
    import shutil as _sh
    img_dir = proj_dir / "imagen"
    img_dir.mkdir(parents=True, exist_ok=True)

    images_meta = []
    for i, key in enumerate(img_keys):
        f    = request.files[key]
        ext  = FPath(f.filename).suffix or ".jpg"
        name = FPath(f.filename).name          # keep original filename
        dest = img_dir / name
        if not dest.exists():                  # don't overwrite if already there
            f.save(str(dest))
        else:
            f.close()
        images_meta.append({"index": i+1, "name": name, "path": str(dest)})

    # Build a temporary stage manifest: files to animate this run
    # (only the ones just uploaded)
    stage_names = [m["name"] for m in images_meta]

    # ── Save prompt/config to proyecto/guion/ ────────────────────
    prompt       = request.form.get("prompt", "Cinematic slow zoom")
    slots        = int(request.form.get("slots", 3))
    aspect_ratio = request.form.get("aspect_ratio", "2:3")
    video_length = int(request.form.get("video_length", 6))
    resolution   = request.form.get("resolution", "480p")

    (proj_dir / "guion" / "config.txt").write_text(
        f"prompt: {prompt}\nslots: {slots}\naspect_ratio: {aspect_ratio}\n"
        f"video_length: {video_length}\nresolution: {resolution}\n"
    )

    # ── Update global state ───────────────────────────────────────
    grok_state.update({
        "log_lines":   [],
        "finished":    False,
        "project_dir": str(proj_dir),
        "images":      images_meta,
        "total":       len(images_meta),
    })

    # ── Launch grok_multi.py ──────────────────────────────────────
    # Write a temp file listing only the images to animate this run
    import json as _json
    stage_list_path = proj_dir / "guion" / "animate_this_run.json"
    stage_list_path.write_text(_json.dumps(stage_names))

    cmd = _grok_popen_argv([
        str(proj_dir / "imagen"),
        "--output-dir",   str(proj_dir / "video"),
        "--filter-file",  str(stage_list_path),
        "--slots",        str(slots),
        "--prompt",       prompt,
        "--aspect-ratio", aspect_ratio,
        "--video-length", str(video_length),
        "--resolution",   resolution,
    ])

    proc = subprocess.Popen(
        cmd,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
        cwd=str(GROK_DIR),
        env=_grok_child_env(),
        **_vf_no_window(),
    )
    grok_state["proc"] = proc

    threading.Thread(target=_tail_grok, args=(proc,), daemon=True).start()
    # _watch_and_copy is NOT started — grok_multi.py saves directly to
    # project/video/ via --output-dir, so no copy step is needed.

    return jsonify({"ok": True, "pid": proc.pid, "project_dir": str(proj_dir), "project_name": proj_name})


@app.route("/api/grok/regenerar", methods=["POST"])
def grok_regenerar():
    data       = request.get_json() or {}
    video_name = data.get("video_name", "")   # e.g. "img_00001.mp4"

    # Recuperar project_dir desde memoria o desde el parámetro del request
    proj_name_fallback = re.sub(r"[^a-zA-Z0-9_\-]", "_", data.get("project_name", "").strip())
    if grok_state["project_dir"]:
        proj_dir = FPath(grok_state["project_dir"])
    elif proj_name_fallback:
        proj_dir = FPath(JOBS_FOLDER) / proj_name_fallback
        grok_state["project_dir"] = str(proj_dir)  # restaurar estado en memoria
    else:
        return jsonify({"error": "Sin proyecto activo"}), 400

    _resolve_grok_paths()

    # Incrementar contador de regens activos
    grok_state["regen_count"] = grok_state.get("regen_count", 0) + 1
    grok_state["finished"]    = False

    vid_stem = FPath(video_name).stem
    img_dir  = proj_dir / "imagen"
    matches  = [p for p in img_dir.iterdir()
                if p.is_file() and p.stem == vid_stem
                and p.suffix.lower().lstrip(".") in {"jpg","jpeg","png","webp","gif","bmp"}]
    if not matches:
        return jsonify({"error": f"No hay imagen con stem {vid_stem}"}), 404
    img_path = matches[0]

    # Delete existing video
    old_vid = proj_dir / "video" / video_name
    if old_vid.exists():
        old_vid.unlink()

    # Run grok for just that image
    prompt    = data.get("prompt", "Cinematic slow zoom")
    slots     = 1
    aspect    = data.get("aspect_ratio", "2:3")
    dur       = int(data.get("video_length", 6))
    res       = data.get("resolution", "480p")

    # Create temp single-image folder
    import tempfile as _tmp
    tmp_dir = FPath(_tmp.mkdtemp())
    shutil.copy2(str(img_path), str(tmp_dir / img_path.name))

    cmd = _grok_popen_argv([
        str(tmp_dir),
        "--output-dir",  str(proj_dir / "video"),
        "--slots", str(slots),
        "--prompt", prompt,
        "--aspect-ratio", aspect,
        "--video-length", str(dur),
        "--resolution", res,
    ])

    def _run_regen():
        _snap_before = set(f.name for f in (proj_dir / "video").glob("*.mp4"))
        proc = subprocess.Popen(
            cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            cwd=str(GROK_DIR),
            env=_grok_child_env(),
            **_vf_no_window(),
        )
        for line in iter(proc.stdout.readline, b""):
            decoded = line.decode("utf-8", errors="replace").rstrip()
            grok_state["log_lines"].append(decoded)
        proc.wait()

        # Detectar archivos NUEVOS en project/video/ tras el proceso
        _snap_after  = set(f.name for f in (proj_dir / "video").glob("*.mp4"))
        _new_files   = _snap_after - _snap_before
        _target_name = f"{img_path.stem}.mp4"
        if _new_files:
            if _target_name not in _new_files:
                _new_f = sorted(_new_files)[0]
                _src   = proj_dir / "video" / _new_f
                _dst   = proj_dir / "video" / _target_name
                try:
                    _src.rename(_dst)
                except Exception as _re:
                    grok_state["log_lines"].append(f"[regen] rename error: {_re}")
            grok_state["log_lines"].append(f"\u2705 Regen completado: {_target_name}")
        else:
            # Fallback: buscar en downloads/ si --output-dir no funcionó
            dl_dir  = GROK_DIR / "downloads"
            dl_mps  = sorted(dl_dir.glob("*.mp4"), key=lambda f: f.stat().st_mtime)
            if dl_mps:
                shutil.copy2(str(dl_mps[-1]), str(proj_dir / "video" / _target_name))
                grok_state["log_lines"].append(f"\u2705 Regen completado (desde downloads): {_target_name}")
            else:
                grok_state["log_lines"].append(f"\u26a0\ufe0f Regen terminó pero no se encontró el video: {_target_name}")

        # Decrementar contador; solo marcar finished cuando no hay más regens activos
        grok_state["regen_count"] = max(0, grok_state.get("regen_count", 1) - 1)
        if grok_state["regen_count"] == 0:
            grok_state["finished"] = True
        shutil.rmtree(str(tmp_dir), ignore_errors=True)

    threading.Thread(target=_run_regen, daemon=True).start()
    return jsonify({"ok": True})


@app.route("/api/grok/detener", methods=["POST"])
def grok_detener():
    if grok_state["proc"] and grok_state["proc"].poll() is None:
        grok_state["proc"].terminate()
    grok_state["finished"] = True
    return jsonify({"ok": True})


@app.route("/api/grok/log")
def grok_log():
    offset   = int(request.args.get("offset", 0))
    finished = grok_state["finished"] or (
        grok_state["proc"] is not None and grok_state["proc"].poll() is not None
    )
    lines = grok_state["log_lines"][offset:]
    vdir = _project_video_dir()
    try:
        videos_done = len([f for f in vdir.glob("*.mp4")]) if vdir and vdir.is_dir() else 0
    except Exception:
        videos_done = 0
    videos_total = int(grok_state.get("total") or 0)
    return jsonify({
        "lines":       lines,
        "next_offset": offset + len(lines),
        "finished":    finished,
        "videos_done": videos_done,
        "videos_total": videos_total,
    })


@app.route("/api/grok/videos")
def grok_videos():
    proj_name = request.args.get("project", "")
    if not proj_name:
        # No project specified — return empty (never dump all videos)
        return jsonify({"videos": [], "total": 0, "done": 0, "project_dir": "", "project_name": ""})
    proj_dir = FPath(JOBS_FOLDER) / proj_name
    vid_dir  = proj_dir / "video"
    vid_dir.mkdir(parents=True, exist_ok=True)
    videos = sorted([f.name for f in vid_dir.glob("*.mp4")])
    return jsonify({
        "videos":       videos,
        "total":        len(videos),
        "done":         len(videos),
        "project_dir":  str(proj_dir),
        "project_name": proj_name,
    })


@app.route("/api/grok/video")
def grok_video():
    fname     = request.args.get("file", "")
    dl        = request.args.get("dl", "0") == "1"
    proj_name = request.args.get("project", "")
    if proj_name:
        proj_dir = FPath(JOBS_FOLDER) / proj_name
    else:
        proj_dir = FPath(grok_state["project_dir"]) if grok_state["project_dir"] else None
    vid_dir = (proj_dir / "video") if proj_dir else (GROK_DIR / "downloads")
    path    = vid_dir / fname
    if not path.exists():
        return jsonify({"error": "not found"}), 404
    return send_file(
        str(path),
        as_attachment=dl,
        download_name=fname,
        mimetype="video/mp4",
        conditional=True,
    )


@app.route("/api/grok/descargar_todas")
def grok_descargar_todas():
    proj_name = request.args.get("project", "")
    if proj_name:
        proj_dir = FPath(JOBS_FOLDER) / proj_name
    else:
        proj_dir = FPath(grok_state["project_dir"]) if grok_state["project_dir"] else None
    vid_dir  = (proj_dir / "video") if proj_dir else (GROK_DIR / "downloads")
    videos   = sorted(vid_dir.glob("*.mp4"))
    if not videos:
        return jsonify({"error": "Sin videos"}), 404

    from io import BytesIO as _BytesIO
    buf = _BytesIO()
    with zipfile.ZipFile(buf, "w", zipfile.ZIP_DEFLATED) as zf:
        for v in videos:
            zf.write(str(v), v.name)
    buf.seek(0)

    proj_name = proj_dir.name if proj_dir else "grok_videos"
    return send_file(
        buf,
        mimetype="application/zip",
        as_attachment=True,
        download_name=f"{proj_name}_videos.zip"
    )
@app.route("/api/grok/abrir_carpeta", methods=["POST"])
def grok_abrir_carpeta():
    data = request.get_json() or {}
    proj_name = data.get("project", "")
    if proj_name:
        proj_dir = FPath(JOBS_FOLDER) / proj_name
