@app.route("/api/meta/sesiones", methods=["GET"])
def meta_sesiones():
    try:
        accounts_dir = _meta_ensure_accounts()
        rows = []
        for folder in sorted(accounts_dir.iterdir()):
            if not folder.is_dir():
                continue
            active = _meta_is_authenticated(folder)
            ck = _meta_load_cookies_dict(folder)
            user_id = ck.get("c_user", "")
            rows.append({
                "name": folder.name,
                "active": active,
                "user": (f"uid:{user_id[:12]}" if user_id else ("sin sesión" if not active else "activa")),
                "has_cookies": bool(ck),
            })
        return jsonify({"accounts": rows})
    except Exception as e:
        return jsonify({"accounts": [], "error": str(e)})


@app.route("/api/meta/login_cuenta", methods=["POST"])
def meta_login_cuenta():
    data = request.get_json() or {}
    folder_name = re.sub(r"[^\w\-]", "_", (data.get("account") or "").strip())
    if not folder_name:
        return jsonify({"error": "account name required"}), 400
    folder = _meta_ensure_accounts() / folder_name
    folder.mkdir(parents=True, exist_ok=True)
    _meta_log(f"🌐 [{folder_name}] Abriendo Chrome — inicia sesión en meta.ai y cierra la ventana.")

    def _do_login():
        import shutil as _sh
        import tempfile as _tf
        import glob as _gl
        import time as _t
        import json as _json

        def _log(msg):
            """Log tanto a meta_state como a stdout del terminal Flask."""
            _meta_log(msg)
            print(f"[META-LOGIN] {msg}", flush=True)

        # Usar el MISMO perfil que usa el batch worker --> la sesión está disponible al lanzar Chromium
        _accounts_d = _meta_ensure_accounts()
        tmp_profile = str(_accounts_d / folder_name / "chromium_profile")
        # NO borrar el perfil existente — conservar sesión anterior
        FPath(tmp_profile).mkdir(parents=True, exist_ok=True)

        try:
            from playwright.sync_api import sync_playwright
        except ImportError:
            _log(f"[ERROR] [{folder_name}] Playwright no instalado.")
            return

        # Cookies capturadas desde headers Set-Cookie de respuestas HTTP
        # (más fiable que ctx.cookies() para cookies de subdominios)
        intercepted = {}  # name -> {name, value, domain, path, ...}

        def _on_response(resp):
            try:
                sc = resp.headers.get("set-cookie", "")
                if not sc:
                    return
                # Parsear nombre=valor del header Set-Cookie
                first_part = sc.split(";")[0].strip()
                if "=" not in first_part:
                    return
                name, _, value = first_part.partition("=")
                name = name.strip()
                value = value.strip()
                if name and name not in intercepted:
                    # Inferir dominio de la URL de la respuesta
                    try:
                        from urllib.parse import urlparse
                        dom = urlparse(resp.url).hostname or ".meta.ai"
                        if not dom.startswith("."):
                            dom = "." + dom
                    except Exception:
                        dom = ".meta.ai"
                    intercepted[name] = {
                        "name": name, "value": value,
                        "domain": dom, "path": "/",
                        "httpOnly": False, "secure": True, "sameSite": "None",
                    }
                    if name in ("ecto", "datr", "ps_l", "ps_n"):
                        _log(f"  📥 Cookie interceptada: {name}={value[:16]}… (dom={dom})")
            except Exception:
                pass

        try:
            # NO borrar el perfil — es persistente para conservar la sesión
            FPath(tmp_profile).mkdir(parents=True, exist_ok=True)

            with sync_playwright() as pw:
                _local = os.environ.get("LOCALAPPDATA", "")
                _bins = _gl.glob(os.path.join(
                    _local, "ms-playwright", "chromium-*", "chrome-win*", "chrome.exe"
                ))
                _exe = _bins[0] if _bins else None

                ctx = pw.chromium.launch_persistent_context(
                    tmp_profile,
                    headless=False,
                    executable_path=_exe,
                    args=[
                        "--no-sandbox",
                        "--disable-blink-features=AutomationControlled",
                        "--no-first-run",
                    ],
                    viewport={"width": 1280, "height": 900},
                )

                page = ctx.pages[0] if ctx.pages else ctx.new_page()
                # Interceptar TODAS las respuestas para capturar Set-Cookie
                page.on("response", _on_response)
                ctx.on("response", _on_response)  # también a nivel de contexto

                _log(f"🌐 [{folder_name}] Navegando a meta.ai…")
                try:
                    page.goto("https://www.meta.ai/", timeout=30000)
                    page.wait_for_load_state("domcontentloaded", timeout=20000)
                except Exception:
                    pass

                _META_DOMAINS = [
                    "https://www.meta.ai",
                    "https://meta.ai",
                    "https://auth.meta.ai",
                    "https://auth.meta.com",
                    "https://www.facebook.com",
                    "https://facebook.com",
                ]

                saved = False
                deadline = _t.time() + 300
                last_log_t = 0

                def _collect_all_cookies():
                    """Reúne cookies de ctx.cookies() + las interceptadas."""
                    pool = {}
                    # 1. Interceptadas desde Set-Cookie headers (más fiables)
                    pool.update(intercepted)
                    # 2. ctx.cookies() sin filtro
                    try:
                        for c in ctx.cookies():
                            pool.setdefault(c["name"], c)
                    except Exception:
                        pass
                    # 3. ctx.cookies() por dominio
                    for dom in _META_DOMAINS:
                        try:
                            for c in ctx.cookies(dom):
                                pool.setdefault(c["name"], c)
                        except Exception:
                            pass
                    return list(pool.values())

                while _t.time() < deadline:
                    _t.sleep(2)

                    all_cookies = _collect_all_cookies()
                    ck_dict = {c["name"]: c["value"] for c in all_cookies}

                    # Log de diagnóstico cada 15 s --> visible en el terminal Flask
                    now = _t.time()
                    if now - last_log_t > 15:
                        last_log_t = now
                        all_names = [c["name"] for c in all_cookies]
                        ecto_found = [n for n in all_names if n.startswith("ecto")]
                        _log(f"  🔍 [{folder_name}] Todos los nombres: {all_names} | ecto*={ecto_found} | intercept={list(intercepted.keys())}")

                    # La cookie de sesión se llama 'ecto_1_s...' (nombre dinámico con sufijo)
                    ecto_cookie = next((c for c in all_cookies if c["name"].startswith("ecto")), None)
                    if ecto_cookie:
                        cookie_list = [
                            {
                                "name":     c["name"],
                                "value":    c["value"],
                                "domain":   c.get("domain", ".meta.ai"),
                                "path":     c.get("path", "/"),
                                "httpOnly": c.get("httpOnly", False),
                                "secure":   c.get("secure", True),
                                "sameSite": c.get("sameSite", "None"),
                            }
                            for c in all_cookies
                        ]
                        (folder / "cookies_auto.json").write_text(_json.dumps(cookie_list, indent=2))
                        ecto_hint = ecto_cookie["value"][:16]
                        _log(f"  [OK] [{folder_name}] ¡Sesión guardada! {ecto_cookie['name']}={ecto_hint}… | {len(cookie_list)} cookies")
                        saved = True
                        _t.sleep(1)
                        try:
                            ctx.close()
                        except Exception:
                            pass
                        break

                if not saved:
                    # Intento final: volcar todo lo que tengamos
                    all_cookies_f = _collect_all_cookies()
                    ck_dict_f = {c["name"]: c["value"] for c in all_cookies_f}
                    all_names_f = [c["name"] for c in all_cookies_f]
                    ecto_names = [n for n in all_names_f if n.startswith("ecto")]
                    _log(
                        f"  [WARNING] [{folder_name}] Timeout. "
                        f"Cookies: {all_names_f} | ecto*={ecto_names} | intercept={list(intercepted.keys())}"
                    )
                    try:
                        ctx.close()
                    except Exception:
                        pass

        except Exception as e:
            _log(f"  [ERROR] [{folder_name}] Error: {e}")
        # NO hay finally con rmtree — el perfil es persistente y debe sobrevivir

    threading.Thread(target=_do_login, daemon=True).start()
    return jsonify({"ok": True, "message": f"Chrome abierto para {folder_name}"})


@app.route("/api/meta/borrar_sesion", methods=["POST"])
def meta_borrar_sesion():
    folder_name = re.sub(r"[^\w\-]", "_", (request.get_json() or {}).get("account", "").strip())
    if not folder_name:
        return jsonify({"error": "account required"}), 400
    ck_file = _meta_ensure_accounts() / folder_name / "cookies_auto.json"
    if ck_file.exists():
        ck_file.unlink()
    return jsonify({"ok": True})


@app.route("/api/meta/iniciar", methods=["POST"])
def meta_iniciar():
    proj_name = re.sub(r"[^a-zA-Z0-9_\-]", "_", (request.form.get("project_name", "") or "").strip())
    if not proj_name:
        return jsonify({"error": "Selecciona un proyecto antes de animar."}), 400
    proj_dir = FPath(JOBS_FOLDER) / proj_name
    for sub in ("imagen", "audio", "guion", "video", "video_final"):
        (proj_dir / sub).mkdir(parents=True, exist_ok=True)

    img_keys = sorted(
        [k for k in request.files if k.startswith("imagen_")],
        key=lambda x: int(x.split("_")[1]),
    )
    if not img_keys:
        return jsonify({"error": "No se recibieron imágenes"}), 400

    img_dir = proj_dir / "imagen"
    images_meta = []
    for i, key in enumerate(img_keys):
        f = request.files[key]
        name = FPath(f.filename).name
        if not name:
            name = f"{i+1:05d}.jpg"
        # Antes: dest = img_dir / name, y se saltaba el guardado si ya
        # existía un archivo con ese mismo nombre. Si dos de las imágenes
        # subidas tenían el MISMO nombre original (común: fotos/exports con
        # nombres repetidos o genéricos, ej. "image.jpg"), la segunda nunca
        # se guardaba — pero igual quedaba con "path" apuntando al archivo
        # de la PRIMERA. Resultado confirmado: dos requestId distintos (dos
        # generaciones reales en meta.ai) usando el mismo contenido de
        # imagen de entrada. Ahora cada subida se guarda en una ruta única
        # por índice, sin depender del nombre original — "name" se conserva
        # solo para derivar el nombre de salida (flow_0001.mp4, etc.).
        ext = FPath(name).suffix or ".jpg"
        dest = img_dir / f"{i+1:05d}_src{ext}"
        f.save(str(dest))
        images_meta.append({"index": i + 1, "name": name, "path": str(dest)})

    prompt = request.form.get("prompt", "Cinematic slow zoom")
    slots = int(request.form.get("slots", 1))
    # mode="http"  --> HTTP directo (default, sin extensión)
    # mode="ext"   --> extensión Chrome (modo legacy)
    mode = request.form.get("mode", "ext").strip().lower()
    # 900s = 15 min por video.
    # La extensión tiene un timeout de 10 min (600s) que empieza cuando meta.ai
    # recibe el job (no cuando el collector Python arranca). Con 49 jobs y ~8
    # despachados cada 10 s, el último batch llega a meta.ai unos 50 s después
    # de que Python empieza a esperar. Su timeout en la extensión expira a los
    # 650 s --> el colector Python necesita >650 s de paciencia --> 900 s es seguro.
    timeout_sec = int(request.form.get("timeout", 900))

    (proj_dir / "guion" / "config_meta.txt").write_text(
        f"prompt: {prompt}\nslots: {slots}\nmode: {mode}\n",
        encoding="utf-8",
    )

    # Seleccionar worker según modo
    if mode == "ext" or mode == "dom" or mode == "playwright":
        _worker_fn = _meta_batch_worker
        _mode_label = "Playwright DOM"
    else:
        _worker_fn = _meta_http_batch_worker
        _mode_label = "http (directo)"

    cancel_ev = threading.Event()
    meta_state.update({
        "running": True,
        "log_lines": [],
        "finished": False,
        "project_dir": str(proj_dir),
        "images": images_meta,
        "total": len(images_meta),
        "cancel_event": cancel_ev,
    })
    threading.Thread(
        target=_worker_fn,
        args=(proj_dir, prompt, slots, timeout_sec),
        daemon=True,
    ).start()
    return jsonify({
        "ok": True,
        "pid": f"meta-{int(time.time())}",
        "mode": _mode_label,
        "project_dir": str(proj_dir),
        "project_name": proj_name,
    })


@app.route("/api/meta/detener", methods=["POST"])
def meta_detener():
    ev = meta_state.get("cancel_event")
    if ev:
        ev.set()
    meta_state["running"]  = False
    meta_state["finished"] = True
    with _meta_ext_lock:
        cleared = len(_meta_ext_queue)
        _meta_ext_queue.clear()
        _meta_ext_inflight.clear()
        # NO disparamos los eventos: los collectors siguen vivos esperando sus resultados.
        # El cancel_ev ya fijado les da 5 min de gracia para recibir sus URLs.
    _meta_log(f"⏹ Detener recibido — cola vaciada ({cleared} items). "
              f"Descargando resultados que ya llegaron (hasta 5 min).")
    return jsonify({"ok": True})


@app.route("/api/meta/log")
def meta_log_route():
    offset = int(request.args.get("offset", 0))
    finished = bool(meta_state["finished"])
    lines = meta_state["log_lines"][offset:]
    vdir = None
    try:
        pd = meta_state.get("project_dir")
        if pd:
            vdir = FPath(pd) / "video"
    except Exception:
        vdir = None
    try:
        videos_done = len([f for f in vdir.glob("*.mp4")]) if vdir and vdir.is_dir() else 0
    except Exception:
        videos_done = 0
    return jsonify({
        "lines": lines,
        "next_offset": offset + len(lines),
        "finished": finished,
        "videos_done": videos_done,
        "videos_total": int(meta_state.get("total") or 0),
    })


