@app.route("/api/meta/descargar_todas")
def meta_descargar_todas():
    proj_name = request.args.get("project", "")
    if proj_name:
        proj_dir = FPath(JOBS_FOLDER) / proj_name
    else:
        proj_dir = FPath(meta_state["project_dir"]) if meta_state["project_dir"] else None
    if not proj_dir:
        return jsonify({"error": "Sin proyecto activo"}), 404
    vid_dir = proj_dir / "video"
    videos = sorted(vid_dir.glob("*.mp4"))
    if not videos:
        return jsonify({"error": "Sin videos"}), 404
    from io import BytesIO as _BytesIO
    buf = _BytesIO()
    with zipfile.ZipFile(buf, "w", zipfile.ZIP_DEFLATED) as zf:
        for v in videos:
            zf.write(str(v), v.name)
    buf.seek(0)
    return send_file(
        buf, mimetype="application/zip", as_attachment=True,
        download_name=f"{proj_dir.name}_videos_meta.zip",
    )


