@app.route("/api/meta/launch_chrome", methods=["POST"])
def meta_launch_chrome():
    """
    Lanza Chrome/Edge con la extensión cargada como worker permanente — estilo gentube.
    N pestañas de meta.ai/create quedan abiertas como slots.
    El usuario inicia sesión si es necesario; la extensión registra los slots
    automáticamente con /api/meta/ext-register.
    """
    data        = request.get_json() or {}
    folder_name = re.sub(r"[^\w\-]", "_", (data.get("account") or "cuenta1").strip()) or "cuenta1"
    n_slots     = max(1, min(int(data.get("slots", 3)), 10))

    # Buscar extensión que contiene meta_bridge.js específicamente
    try:
        ext_dir = _meta_find_extension_dir()
        if not os.path.isfile(os.path.join(ext_dir, "meta_bridge.js")):
            return jsonify({"error": f"meta_bridge.js no encontrado en: {ext_dir}"}), 400
    except Exception as e:
        return jsonify({"error": f"Error buscando extensión: {e}"}), 400

    try:
        exe = _flow_find_chromium_exe()
        if not exe or not os.path.isfile(exe):
            return jsonify({"error": "Chrome/Edge no encontrado. Instala Google Chrome."}), 400
    except Exception as e:
        return jsonify({"error": f"Error buscando Chrome: {e}"}), 400

    # Perfil persistente de Chromium para esta cuenta
    accounts_dir  = _meta_ensure_accounts()
    profile_dir   = str(accounts_dir / folder_name / "chromium_profile")
    os.makedirs(profile_dir, exist_ok=True)

    # Inyector de cookies si hay cookies_auto.json guardadas del login anterior
    extensions = [ext_dir]
    ck_file = accounts_dir / folder_name / "cookies_auto.json"
    if ck_file.exists() and ck_file.stat().st_size > 100:
        try:
            import json as _j2, tempfile as _tf2
            raw = _j2.loads(ck_file.read_text(encoding="utf-8"))
            meta_ck = [c for c in raw if isinstance(c, dict) and
                       ("meta.ai" in c.get("domain","") or c.get("name","") in
                        ("ecto_1_sess","datr","c_user","sb","xs","fr","ps_l","ps_n"))]
            if meta_ck:
                ci_dir = FPath(tempfile.mkdtemp(prefix="vf_ci_"))
                ci_dir.mkdir(parents=True, exist_ok=True)
                (ci_dir / "manifest.json").write_text(_j2.dumps({
                    "manifest_version": 3, "name": "VF Cookie Injector", "version": "1.0",
                    "permissions": ["cookies", "tabs"],
                    "host_permissions": ["https://*.meta.ai/*"],
                    "background": {"service_worker": "bg.js"},
                }), encoding="utf-8")
                # Espera a que TODAS las cookies estén escritas antes de recargar tabs
                (ci_dir / "bg.js").write_text(
                    "const ck=" + _j2.dumps(meta_ck, separators=(",",":")) + ";\n"
                    "var n=0;\n"
                    "function done(){n++;if(n===ck.length){\n"
                    "  chrome.tabs.query({url:'https://www.meta.ai/*'},function(ts){\n"
                    "    ts.forEach(function(t){chrome.tabs.reload(t.id);});\n"
                    "  });\n"
                    "}}\n"
                    "ck.forEach(function(c){\n"
                    "  chrome.cookies.set({\n"
                    "    url:'https://www.meta.ai',name:c.name||'',value:c.value||'',\n"
                    "    domain:c.domain||'.meta.ai',path:c.path||'/',\n"
                    "    secure:!!c.secure,httpOnly:!!c.httpOnly,\n"
                    "    sameSite:c.sameSite||'unspecified'\n"
                    "  },done);\n"
                    "});",
                    encoding="utf-8",
                )
                extensions.append(str(ci_dir))
                _meta_log(f"  🍪 Inyector de cookies ({len(meta_ck)} cookies) + recarga automática")
        except Exception:
            pass

    ext_list = ",".join(extensions)
    args = [
        exe,
        f"--user-data-dir={profile_dir}",
        f"--disable-extensions-except={ext_list}",
        f"--load-extension={ext_list}",
        "--no-first-run",
        "--no-default-browser-check",
        "--disable-blink-features=AutomationControlled",
    ]
    for _ in range(n_slots):
        args.append("https://www.meta.ai/create")

    _meta_log(f"  🌐 [{folder_name}] Lanzando Chrome · {n_slots} pestaña(s) · {os.path.basename(exe)}")

    def _monitor():
        proc = None
        try:
            import time as _t
            proc = subprocess.Popen(args, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            _meta_register_chrome_pid(proc.pid)
            _meta_log(f"  [OK] [{folder_name}] Chrome abierto · si ves login, inicia sesión en meta.ai")
            _meta_log(f"     Extensión registrará {n_slots} slot(s) automáticamente")
            _start = _t.time()
            proc.wait()
            _elapsed = _t.time() - _start
            if _elapsed < 8:
                _meta_log(f"  [WARNING]  [{folder_name}] Chrome se cerró en {_elapsed:.1f}s — posiblemente el modo de desarrollador no está activado.")
                _meta_log(f"     👉 Usa el botón '🔧 Modo Dev' para abrir chrome://extensions y activar el toggle.")
                _meta_log(f"     Luego vuelve a hacer clic en '🌐 Abrir Chrome'.")
            else:
                _meta_log(f"  ⏹ [{folder_name}] Chrome cerrado")
        except Exception as e:
            _meta_log(f"  [ERROR] [{folder_name}] Error lanzando Chrome: {e}")
        finally:
            if proc is not None:
                _meta_unregister_chrome_pid(proc.pid)

    threading.Thread(target=_monitor, daemon=True).start()
    return jsonify({"ok": True, "slots": n_slots,
                    "message": f"Chrome lanzando para {folder_name} ({n_slots} pestañas)"})


@app.route("/api/meta/open_devmode", methods=["POST"])
def meta_open_devmode():
    """
    Abre Chrome con el perfil de la cuenta pero SIN cargar la extensión,
    navegando directamente a chrome://extensions para que el usuario
    active el modo de desarrollador manualmente.
    """
    data        = request.get_json() or {}
    folder_name = re.sub(r"[^\w\-]", "_", (data.get("account") or "cuenta1").strip()) or "cuenta1"

    try:
        exe = _flow_find_chromium_exe()
        if not exe or not os.path.isfile(exe):
            return jsonify({"error": "Chrome/Edge no encontrado. Instala Google Chrome."}), 400
    except Exception as e:
        return jsonify({"error": f"Error buscando Chrome: {e}"}), 400

    accounts_dir = _meta_ensure_accounts()
    profile_dir  = str(accounts_dir / folder_name / "chromium_profile")
    os.makedirs(profile_dir, exist_ok=True)

    args = [
        exe,
        f"--user-data-dir={profile_dir}",
        "--no-first-run",
        "--no-default-browser-check",
        "chrome://extensions",
    ]

    _meta_log(f"  🔧 [{folder_name}] Abriendo Chrome en chrome://extensions (sin extensión)")
    _meta_log(f"     Activa el toggle 'Modo de desarrollador' y cierra Chrome.")
    _meta_log(f"     Luego usa '🌐 Abrir Chrome' para cargar la extensión normalmente.")

    def _run_devmode():
        try:
            proc = subprocess.Popen(args, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            proc.wait()
            _meta_log(f"  ⏹ [{folder_name}] Chrome (modo dev) cerrado")
        except Exception as e:
            _meta_log(f"  [ERROR] [{folder_name}] Error abriendo Chrome para modo dev: {e}")

    threading.Thread(target=_run_devmode, daemon=True).start()
    return jsonify({"ok": True, "message": f"Chrome abierto en chrome://extensions para {folder_name}"})


