_FLOW_GEN_URL_TPL   = "https://aisandbox-pa.googleapis.com/v1/projects/{pid}/flowMedia:batchGenerateImages"

# Token TTL en segundos antes de refrescar proactivamente
_FLOW_BEARER_TTL    = 45

_flow_batch_id = 0   # incrementado en cada Start — workers de batches viejos se auto-cancelan
_flow_state = {
    "running": False, "step": "idle", "progress": 0, "total": 0,
    "images_saved": 0, "log": [], "last_error": None, "output_dir": None,
    "accounts": [{"index": i, "ok": False, "email": None, "jobs": 0}
                 for i in range(_FLOW_NUM_ACCOUNTS)],
}
_flow_last_batch = {}  # persists full original batch params — never overwritten by retries
