# ── Sistema de rotación de cuentas ────────────────────────────────────────────
# active_slots: índices con browser abierto (arranca como [0..4])
# backup_queue: cola FIFO de respaldo (arranca como [5..9])
# Cuando una cuenta acumula rate limits persistentes: se banea 1h, se cierra
# su browser y se activa el siguiente de la cola de respaldo.
_flow_active_slots  = list(range(_FLOW_ACTIVE_SLOTS))            # [0,1,2,3,4]
_flow_backup_queue  = list(range(_FLOW_ACTIVE_SLOTS, _FLOW_NUM_ACCOUNTS))  # [5,6,7,8,9]
_flow_rotation_lock = threading.Lock()

_flow_rl_hits      = {}   # account_hash -> [timestamp, ...]
_flow_rl_lock      = threading.Lock()
_FLOW_RL_WINDOW    = 600  # ventana 10 min para contar hits
_FLOW_RL_THRESHOLD = 3    # 3 hits en la ventana = persistente

_flow_banned_until = {}   # account_hash -> epoch cuando termina el ban
_flow_banned_lock  = threading.Lock()
_FLOW_BAN_SECONDS  = 3600  # 1 hora

# Warmup: perfil recién abierto necesita ~45s antes de recibir generaciones
# para que reCAPTCHA no lo marque como automatizado con score bajo.
_flow_warmup_until_idx = {}   # account_idx -> epoch cuando termina el warmup
_flow_warmup_lock      = threading.Lock()
_FLOW_WARMUP_SECONDS   = 45
# Semáforo global de descargas: limita conexiones simultáneas al CDN
# flow-content.google cierra conexiones SSL cuando hay demasiadas a la vez
_flow_dl_sem = threading.Semaphore(8)

os.makedirs(_FLOW_COOKIES_DIR, exist_ok=True)

def _flow_log(msg: str):
    with _flow_lock:
        _flow_state["log"].append(msg)
        if len(_flow_state["log"]) > 600:
            _flow_state["log"] = _flow_state["log"][-600:]
    try:
        print(msg, flush=True)
    except UnicodeEncodeError:
        safe = msg.encode('ascii', errors='replace').decode('ascii')
        try:
            print(safe, flush=True)
        except Exception:
            pass

def _flow_playwright_installed() -> bool:
    try:
        from playwright.sync_api import sync_playwright
        return True
    except ImportError:
        return False

def _flow_account_hash(value: str) -> str:
    h = 5381
    for c in value:
        h = (h << 5) + h + ord(c) & 0xFFFFFFFF
    return format(h, "08x")

def _flow_get_session(cookie_str: str) -> dict:
    try:
        r = requests.get(
            _FLOW_SESSION_URL,
            headers={"cookie": cookie_str, "Content-Type": "application/json"},
            timeout=20
        )
        if r.status_code == 200:
            data   = r.json()
            bearer = data.get("access_token", "")
            user   = data.get("user", {})
            email  = user.get("email") or user.get("name") or ""
            return {"bearer": bearer, "email": email}
    except Exception:
        pass
    return {"bearer": "", "email": ""}

def _flow_get_bearer(cookie_str: str) -> str:
    return _flow_get_session(cookie_str).get("bearer", "")

def _flow_load_cookie(account_idx: int) -> str:
    ck_f = os.path.join(_FLOW_COOKIES_DIR, f"account_{account_idx}.txt")
    if not os.path.isfile(ck_f):
        return ""
    try:
        return open(ck_f, encoding="utf-8").read().strip()
    except Exception:
        return ""

# ══════════════════════════════════════════════════════════════════
# FLOW — Bridge HTTP + WebSocket
# ══════════════════════════════════════════════════════════════════

_FLOW_BRIDGE_PORT = 5556
_FLOW_WS_PORT     = 5557

_flow_bridge_started  = False
_flow_ws_started      = False
_flow_bridge_bind_ok  = False
_flow_ws_bind_ok      = False

_flow_bridge_queue    = []
_flow_bridge_q_lock   = threading.Lock()
_flow_bridge_results  = {}
_flow_bridge_r_lock   = threading.Lock()
_flow_bridge_r_events: dict = {}

_flow_ws_clients      = {}
_flow_ws_clients_lock = threading.Lock()

# Hashes de cuentas lanzadas por Playwright (cargadas de disco).
# Cuentas NO en este set = Chrome real del usuario.
_flow_playwright_hashes      = set()
_flow_playwright_hashes_lock = threading.Lock()

_flow_http_seen       = {}
_flow_http_seen_lock  = threading.Lock()
_FLOW_HTTP_SEEN_TTL   = 60.0   # 1 min — solo cuentas que han hecho GET /flow-generate-poll recientemente

# Bearer cache: la extension envia su bearer fresco al bridge
# { account_hash: {"bearer": "ya29...", "ts": float} }
_flow_bearer_cache      = {}
_flow_bearer_cache_lock = threading.Lock()

def _flow_get_cached_bearer(account_hash: str) -> str:
    """Devuelve el bearer mas reciente enviado por la extension para esta cuenta."""
    with _flow_bearer_cache_lock:
        entry = _flow_bearer_cache.get(account_hash)
        if entry:
            return entry["bearer"]
    return ""

def _flow_set_cached_bearer(account_hash: str, bearer: str):
    with _flow_bearer_cache_lock:
        _flow_bearer_cache[account_hash] = {"bearer": bearer, "ts": time.time()}


def _flow_get_connected_accounts() -> list:
    with _flow_ws_clients_lock:
        ws_accounts = set(_flow_ws_clients.keys())
    now = time.time()
    with _flow_http_seen_lock:
        stale = [a for a, t in _flow_http_seen.items() if now - t > _FLOW_HTTP_SEEN_TTL]
        for a in stale:
            del _flow_http_seen[a]
        http_accounts = set(_flow_http_seen.keys())
    # Incluir también cuentas con bearer reciente en caché (≤10 min):
    # Si el browser envió su bearer en los últimos 10 min, se considera conectado
    # aunque el SW haya muerto y _flow_http_seen/ws_clients ya no lo rastreen.
    with _flow_bearer_cache_lock:
        bearer_accounts = {h for h, e in _flow_bearer_cache.items()
                           if e.get("bearer") and now - e.get("ts", 0) < 600}
    return list(ws_accounts | http_accounts | bearer_accounts)


def _flow_ws_push(account_hash: str, request_data: dict) -> bool:
    with _flow_ws_clients_lock:
        ws = _flow_ws_clients.get(account_hash)
    if ws:
        try:
            import json as _json
            ws.send(_json.dumps({"type": "generate", "requests": [request_data]}))
            return True
        except Exception as e:
            with _flow_ws_clients_lock:
                if _flow_ws_clients.get(account_hash) is ws:
                    del _flow_ws_clients[account_hash]
    return False


def _flow_ws_drain_queue(account_hash: str):
    with _flow_bridge_q_lock:
        remaining, to_send = [], []
        for r in _flow_bridge_queue:
            if r.get("account_hash", "") == account_hash and len(to_send) < 10:
                to_send.append(r)
            else:
                remaining.append(r)
        _flow_bridge_queue[:] = remaining
    for req in to_send:
        _flow_ws_push(account_hash, req)


def _flow_cors_headers(handler):
    origin = handler.headers.get("Origin", "") if hasattr(handler, "headers") else ""
    allowed = ("https://labs.google", "https://aistudio.google.com", "https://gemini.google.com")
    if origin and any(origin == o or origin.endswith("." + o.split("//")[1]) for o in allowed):
        handler.send_header("Access-Control-Allow-Origin", origin)
        handler.send_header("Access-Control-Allow-Credentials", "true")
        handler.send_header("Vary", "Origin")
    else:
        handler.send_header("Access-Control-Allow-Origin", "*")
    handler.send_header("Access-Control-Allow-Methods", "GET, POST, OPTIONS")
    handler.send_header("Access-Control-Allow-Headers", "Content-Type, Access-Control-Request-Private-Network")
    handler.send_header("Access-Control-Allow-Private-Network", "true")


def _flow_is_banned(account_hash: str) -> bool:
    with _flow_banned_lock:
        return time.time() < _flow_banned_until.get(account_hash, 0.0)


def _flow_close_chromium_by_idx(account_idx: int):
    """Termina el proceso Chromium del perfil indicado via psutil."""
    profile_dir = str(_FLOW_BASE_DIR_PW / f"flow_profile_{account_idx}")
    try:
        import psutil as _psu
        for _p in _psu.process_iter(["pid", "cmdline"]):
            try:
                _cmd = " ".join(_p.info.get("cmdline") or [])
                if profile_dir in _cmd and "--type=" not in _cmd:
                    _p.terminate()
                    _flow_log(f"[Flow] 🔴 Browser perfil {account_idx+1} cerrado (PID={_p.pid})")
                    break
            except Exception:
                pass
    except ImportError:
        pass
    with _flow_chromium_lock:
        _flow_chromium_procs.pop(account_idx, None)


def _flow_open_chromium_by_idx(account_idx: int):
    """Abre Chromium para el perfil indicado si no está ya abierto."""
    with _flow_chromium_lock:
        existing = _flow_chromium_procs.get(account_idx)
        if existing is not None:
            if isinstance(existing, threading.Thread) and existing.is_alive():
                return  # ya abierto
            _flow_chromium_procs.pop(account_idx, None)

    # Marcar este hash como Playwright AHORA (cuando realmente va a abrir),
    # no en _load_account (que corre para todos los accounts de disco, Chrome real incluido)
    try:
        _ck_pw = _flow_load_cookie(account_idx)
        if _ck_pw:
            _sess_pw = _flow_get_session(_ck_pw)
            _email_pw = _sess_pw.get("email", "")
            if _email_pw:
                with _flow_playwright_hashes_lock:
                    _flow_playwright_hashes.add(_flow_account_hash(_email_pw))
    except Exception:
        pass

    def _launch():
        try:
            _flow_playwright_login(account_idx)
        except Exception as _e:
            _flow_log(f"[Flow Acc{account_idx+1}] Error auto-open: {_e}")
            with _flow_chromium_lock:
                _flow_chromium_procs.pop(account_idx, None)

    t = threading.Thread(target=_launch, daemon=True)
    with _flow_chromium_lock:
        _flow_chromium_procs[account_idx] = t
    t.start()
    # Warmup: el perfil recién abierto necesita ~45s para que reCAPTCHA
    # confíe en la sesión antes de recibir generaciones.
    with _flow_warmup_lock:
        _flow_warmup_until_idx[account_idx] = time.time() + _FLOW_WARMUP_SECONDS
    _flow_log(f"[Flow] 🟢 Abriendo browser perfil {account_idx+1} — warmup {_FLOW_WARMUP_SECONDS}s...")


def _flow_rotate_account(account_hash: str, acc_idx: int):
    """
    Ban 1h para account_hash, cierra su browser y activa el siguiente backup.
    Seguro para llamar desde múltiples workers (solo actúa la primera vez).
    """
    # Evitar doble-rotación: si ya está baneada, salir
    with _flow_banned_lock:
        if time.time() < _flow_banned_until.get(account_hash, 0.0):
            return
        _flow_banned_until[account_hash] = time.time() + _FLOW_BAN_SECONDS

    # Limpiar hits para no volver a disparar hasta que se reactive
    with _flow_rl_lock:
        _flow_rl_hits.pop(account_hash, None)

    _flow_log(f"[Flow] 🔄 ROTACIÓN — perfil {acc_idx+1} ({account_hash[:8]}) baneado 1h por rate limit persistente")

    def _do_rotate():
        # 1. Cerrar browser de la cuenta baneada
        _flow_close_chromium_by_idx(acc_idx)

        # 2. Mover el índice de active --> al final de backup
        # IMPORTANTE: NO llamar _flow_open_chromium_by_idx dentro del lock
        # (_flow_chromium_lock y _flow_rotation_lock en orden inverso = deadlock)
        next_idx = None
        with _flow_rotation_lock:
            if acc_idx in _flow_active_slots:
                _flow_active_slots.remove(acc_idx)
                _flow_backup_queue.append(acc_idx)
            if _flow_backup_queue:
                next_idx = _flow_backup_queue.pop(0)
                _flow_active_slots.append(next_idx)

        # 3. Abrir el browser de respaldo FUERA del lock
        if next_idx is not None:
            _flow_log(f"[Flow] 🔄 Activando perfil {next_idx+1} como reemplazo")
            time.sleep(1.5)
            _flow_open_chromium_by_idx(next_idx)
        else:
            _flow_log(f"[Flow] [WARNING] Sin más perfiles de respaldo disponibles")

        # 4. Programar reactivación en 1h
        def _reactivate():
            time.sleep(_FLOW_BAN_SECONDS)
            with _flow_banned_lock:
                _flow_banned_until.pop(account_hash, None)
            with _flow_rl_lock:
                _flow_rl_hits.pop(account_hash, None)
            # Mover de backup a active si hay hueco — FUERA del lock al abrir browser
            _reopen = False
            with _flow_rotation_lock:
                if acc_idx in _flow_backup_queue:
                    _flow_backup_queue.remove(acc_idx)
                if len(_flow_active_slots) < _FLOW_ACTIVE_SLOTS:
                    _flow_active_slots.append(acc_idx)
                    _reopen = True
                else:
                    _flow_backup_queue.insert(0, acc_idx)
            if _reopen:
                _flow_log(f"[Flow] [OK] Perfil {acc_idx+1} reactivado tras 1h de ban")
                _flow_open_chromium_by_idx(acc_idx)
            else:
                _flow_log(f"[Flow] ↩️ Perfil {acc_idx+1} regresa a respaldo (slots activos llenos)")

        threading.Thread(target=_reactivate, daemon=True).start()

    threading.Thread(target=_do_rotate, daemon=True).start()


_FLOW_RL_DEBOUNCE = 20  # segundos mínimos entre hits contabilizados (evita burst de workers)

def _flow_record_rl_hit(account_hash: str, acc_idx: int) -> bool:
    """
    Registra un hit de rate-limit con debounce de 60s por cuenta.
    Evita que 10 workers simultáneos registren 10 hits en milisegundos.
    Devuelve True si se activó rotación (rate limit persistente detectado).
    """
    now = time.time()
    with _flow_rl_lock:
        hits = _flow_rl_hits.setdefault(account_hash, [])
        # Debounce: ignorar si el último hit fue hace menos de _FLOW_RL_DEBOUNCE segundos
        if hits and now - hits[-1] < _FLOW_RL_DEBOUNCE:
            return False
        hits.append(now)
        # Limpiar hits fuera de la ventana de 10 minutos
        _flow_rl_hits[account_hash] = [t for t in hits if t > now - _FLOW_RL_WINDOW]
        count = len(_flow_rl_hits[account_hash])

    if count >= _FLOW_RL_THRESHOLD and not _flow_is_banned(account_hash):
        _flow_log(f"[Flow] [WARNING] Perfil {acc_idx+1}: {count} rate limits en {_FLOW_RL_WINDOW//60}min --> rotación")
        _flow_rotate_account(account_hash, acc_idx)
        return True
    return False


def _flow_auto_open_browsers():
    """
    Abre Chromium para todos los slots activos que tengan cookie.
    Si hay Chrome real conectado, no abre Playwright.
    """
    # Verificación instantánea: si Chrome real ya conectó (WS o HTTP bridge), no abrir Playwright
    _connected_all = set(_flow_get_connected_accounts())  # WS + HTTP + bearer cache
    with _flow_playwright_hashes_lock:
        _pw_h = set(_flow_playwright_hashes)
    # Cuentas activas via Chrome extensión (HTTP) son Chrome real aunque antes hayan sido
    # abiertas con Playwright — quitar del conjunto Playwright para detectarlas correctamente
    with _flow_http_seen_lock:
        _http_active_ao = set(_flow_http_seen.keys())
    _pw_h -= _http_active_ao
    _real_hashes = _connected_all - _pw_h
    if _real_hashes:
        _flow_log(f"[Flow] [OK] Chrome real conectado ({len(_real_hashes)} cuenta(s)) — Playwright no abrirá")
        return

    with _flow_rotation_lock:
        active = list(_flow_active_slots)
    opened = 0
    for idx in active:
        ck = _flow_load_cookie(idx)
        if not ck:
            continue
        with _flow_chromium_lock:
            existing = _flow_chromium_procs.get(idx)
            if existing is not None and isinstance(existing, threading.Thread) and existing.is_alive():
                continue
        _flow_open_chromium_by_idx(idx)
        opened += 1
        time.sleep(0.8)  # escalonar aperturas para no saturar el sistema
    if opened:
        _flow_log(f"[Flow] 🚀 Auto-apertura Playwright: {opened} browser(s) iniciados")


def _flow_start_ws_server():
    global _flow_ws_started, _flow_ws_bind_ok
    if _flow_ws_started:
        return
    _flow_ws_started = True
    try:
        import websockets.sync.server as _ws_sync
    except ImportError:
        _flow_log("[Flow] websockets no instalado - WebSocket desactivado.")
        return

    import json as _json

    def _ws_handler(ws):
        account_hash = None
        _flow_log("[Flow] WS: cliente conectado")
        try:
            for raw in ws:
                try:
                    msg = _json.loads(raw)
                except Exception:
                    continue
                t = msg.get("type", "")
                if t == "register":
                    account_hash = msg.get("account_hash", "")
                    if account_hash:
                        with _flow_ws_clients_lock:
                            _flow_ws_clients[account_hash] = ws
                        # Cachear bearer si la extension lo envia en el registro
                        bearer_from_ext = msg.get("bearer", "")
                        if bearer_from_ext:
                            _flow_set_cached_bearer(account_hash, bearer_from_ext)
                            _flow_log(f"[Flow] WS: cuenta registrada {account_hash} (bearer OK)")
                            _flow_ws_drain_queue(account_hash)
                        else:
                            _flow_log(f"[Flow] WS: cuenta registrada {account_hash} (sin bearer)")
                            # No drear la cola: extensión aún sin bearer, no puede procesar requests
                elif t == "result":
                    rid = msg.get("requestId", "")
                    if rid:
                        with _flow_bridge_r_lock:
                            _flow_bridge_results[rid] = msg
                            ev = _flow_bridge_r_events.get(rid)
                        if ev:
                            ev.set()
                        _flow_log(f"[Flow] WS: resultado recibido {rid[:12]}... status={msg.get('status','?')}")
                elif t == "token_ready":
                    pass
        except Exception as e:
            _flow_log(f"[Flow] WS: cliente desconectado: {e}")
        finally:
            if account_hash:
                with _flow_ws_clients_lock:
                    if _flow_ws_clients.get(account_hash) is ws:
                        del _flow_ws_clients[account_hash]
                _flow_log(f"[Flow] WS: cuenta desregistrada {account_hash}")

    def _run_ws():
        global _flow_ws_bind_ok
        try:
            server = _ws_sync.serve(_ws_handler, "0.0.0.0", _FLOW_WS_PORT, ping_interval=None)
            _flow_ws_bind_ok = True
            _flow_log(f"[Flow] WebSocket server en puerto {_FLOW_WS_PORT}")
            server.serve_forever()
        except OSError as e:
            _flow_ws_bind_ok = False
            if "address already in use" in str(e).lower() or "10048" in str(e):
                _flow_log(f"[Flow] WS puerto {_FLOW_WS_PORT} ya en uso (instancia previa activa)")
            else:
                _flow_log(f"[Flow] WS no pudo iniciar: {e}")

    threading.Thread(target=_run_ws, daemon=True).start()
    time.sleep(0.3)


def _flow_start_bridge():
    global _flow_bridge_started, _flow_bridge_bind_ok
    if _flow_bridge_started:
        return
    _flow_bridge_started = True

    from http.server import ThreadingHTTPServer, BaseHTTPRequestHandler
    import json as _json

    class _Handler(BaseHTTPRequestHandler):

        def _json_resp(self, code, data):
            body = _json.dumps(data).encode()
            self.send_response(code)
            _flow_cors_headers(self)
            self.send_header("Content-Type", "application/json")
            self.end_headers()
            self.wfile.write(body)

        def _read_body(self):
            n = int(self.headers.get("Content-Length", 0))
            return _json.loads(self.rfile.read(n)) if n else {}

        def do_OPTIONS(self):
            self.send_response(204)
            _flow_cors_headers(self)
            self.end_headers()

        def do_GET(self):
            from urllib.parse import urlparse, parse_qs
            parsed  = urlparse(self.path)
            qs      = parse_qs(parsed.query)
            account = qs.get("account", [""])[0]

            if account:
                with _flow_http_seen_lock:
                    _flow_http_seen[account] = time.time()

            if parsed.path == "/health":
                self._json_resp(200, {"ok": True})
                return

            if parsed.path.startswith("/flow-register"):
                if account:
                    with _flow_http_seen_lock:
                        _flow_http_seen[account] = time.time()
                    _flow_log(f"[Flow] Bridge: cuenta registrada via HTTP: {account}")
                self._json_resp(200, {"ok": True, "account": account})
                return

            if parsed.path in ("/flow-generate-poll", "/flow-bridge-status"):
                reqs = []
                with _flow_bridge_q_lock:
                    remaining = []
                    for r in _flow_bridge_queue:
                        if len(reqs) < 10 and (not account or r.get("account_hash", "") == account):
                            reqs.append(r)
                        else:
                            remaining.append(r)
                    _flow_bridge_queue[:] = remaining

                if parsed.path == "/flow-bridge-status":
                    with _flow_ws_clients_lock:
                        ws_conn = list(_flow_ws_clients.keys())
                    self._json_resp(200, {
                        "pending": len(reqs),
                        "ws_clients": ws_conn,
                        "bridge_port": _FLOW_BRIDGE_PORT,
                        "ws_port": _FLOW_WS_PORT,
                        "bridge_ok": _flow_bridge_bind_ok,
                        "ws_ok": _flow_ws_bind_ok,
                    })
                else:
                    self._json_resp(200, {"requests": reqs, "request": reqs[0] if reqs else None})
                return

            self._json_resp(404, {"error": "not found"})

        def do_POST(self):
            if self.path == "/flow-generate-result":
                try:
                    body = self._read_body()
                    rid  = body.get("requestId", "")
                    if rid:
                        with _flow_bridge_r_lock:
                            _flow_bridge_results[rid] = body
                            ev = _flow_bridge_r_events.get(rid)
                        if ev:
                            ev.set()
                        _flow_log(f"[Flow] Bridge: resultado recibido {rid[:12]}... status={body.get('status','?')}")
                    self._json_resp(200, {"ok": True})
                except Exception:
                    self._json_resp(400, {"ok": False})
            elif self.path == "/flow-register-bearer":
                # La extension envia su bearer fresco al registrarse
                try:
                    body    = self._read_body()
                    account = body.get("account", "")
                    bearer  = body.get("bearer", "")
                    if account and bearer:
                        _flow_set_cached_bearer(account, bearer)
                        # NO actualizar _flow_http_seen aquí — solo los GET polls activos lo actualizan.
                        # Actualizar aquí causaba que cuentas que solo usan WS (o que dejaron de
                        # hacer poll) quedaran marcadas como "HTTP activo", bloqueando requests 300s.
                        _flow_log(f"[Flow] Bearer recibido de extension: {account[:8]}...")
                    self._json_resp(200, {"ok": True})
                except Exception:
                    self._json_resp(400, {"ok": False})
            elif self.path == "/flow-reset-fingerprint":
                # Deshabilitado: borrar cookies de auth de Google causa 403 en loop.
                # Simplemente acusar recibo para que la extension no falle.
                try:
                    self._read_body()
                except Exception:
                    pass
                self._json_resp(200, {"ok": True, "reset": []})
            else:
                self._json_resp(404, {"error": "not found"})

        def log_message(self, *a):
            pass

    try:
        srv = ThreadingHTTPServer(("0.0.0.0", _FLOW_BRIDGE_PORT), _Handler)
        t   = threading.Thread(target=srv.serve_forever, daemon=True)
        t.start()
        _flow_bridge_bind_ok = True
        _flow_log(f"[Flow] Bridge HTTP en puerto {_FLOW_BRIDGE_PORT}")
    except OSError as e:
        _flow_bridge_bind_ok = False
        if "10048" in str(e) or "address already in use" in str(e).lower():
            _flow_bridge_bind_ok = True
            _flow_log(f"[Flow] Bridge HTTP ya activo en puerto {_FLOW_BRIDGE_PORT}")
        else:
            _flow_log(f"[Flow] Bridge HTTP no pudo iniciar: {e}")

    _flow_start_ws_server()


def _flow_upload_reference_image(b64_data: str, mime_type: str,
                                  bearer: str, project_id: str,
                                  account_hash: str = None,
                                  filename: str = "reference.png") -> str:
    """
    Sube imagen de referencia A TRAVES DEL BRIDGE.
    La extension ejecuta el fetch con cookies del navegador — evita 401 de bearer de disco.
    """
    import json as _json
    upload_url = "https://aisandbox-pa.googleapis.com/v1/flow/uploadImage"
    body = {
        "clientContext":  {"projectId": project_id, "tool": "PINHOLE"},
        "imageBytes":     b64_data,
        "fileName":       filename,
        "mimeType":       mime_type,
        "isHidden":       False,
        "isUserUploaded": True,
    }
    try:
        result = _flow_bridge_generate(
            _json.dumps(body), bearer, upload_url,
            account_hash=account_hash, timeout=30
        )
        if result.get("error"):
            _flow_log(f"[Flow] Upload error: {result['error']}")
            return ""
        status    = result.get("status", 0)
        resp_body = result.get("body", "")
        if status == 200:
            d = _json.loads(resp_body)
            _flow_log(f"[Flow] Upload OK — respuesta COMPLETA: {resp_body[:600]}")
            media = d.get("media") or {}
            name = (d.get("name") or media.get("name") or d.get("imageName") or d.get("imageId") or "")
            # El browser usa solo el UUID directamente en imageInputs.name
            if name:
                _flow_log(f"[Flow] Upload: name={name}")
                return name
            _flow_log(f"[Flow] Upload OK pero name no encontrado en: {list(d.keys())}")
        else:
            _flow_log(f"[Flow] Upload imagen ref HTTP {status}: {resp_body[:300]}")
    except Exception as e:
        _flow_log(f"[Flow] Upload imagen ref error: {e}")
    return ""


def _flow_bridge_generate(body_json: str, bearer: str, url: str,
                           account_hash: str = None, timeout: int = 120) -> dict:
    import uuid as _uuid
    _flow_start_bridge()

    rid = str(_uuid.uuid4())
    ev  = threading.Event()
    req = {"requestId": rid, "url": url, "bearer": bearer, "body": body_json}
    if account_hash:
        req["account_hash"] = account_hash

    with _flow_bridge_r_lock:
        _flow_bridge_r_events[rid] = ev

    # Intentar push WS — primero cuenta asignada, luego cualquier conectada
    pushed = False
    with _flow_ws_clients_lock:
        _ws_hashes = list(_flow_ws_clients.keys())

    # Si la cuenta asignada tiene HTTP polling activo pero NO WS, NO redirigir
    # a la WS de otra cuenta — eso mandaría la tarea al browser equivocado.
    # En ese caso, encolar directamente para HTTP polling de la cuenta asignada.
    # EXCEPCIÓN: si la cuenta también tiene WS activo, preferir WS (más confiable y
    # evita el problema de HTTP queue stale cuando el extension deja de hacer poll).
    _assigned_has_http = False
    if account_hash and account_hash not in _ws_hashes:
        with _flow_http_seen_lock:
            _t_seen = _flow_http_seen.get(account_hash, 0)
        _assigned_has_http = (time.time() - _t_seen) < _FLOW_HTTP_SEEN_TTL

    if _assigned_has_http:
        # Esperar hasta 5s por WS antes de caer a HTTP poll.
        # La extension suele enviar el bearer HTTP primero y conectar WS segundos después.
        # HTTP-poll para generation devuelve 403 (background SW sin cookies);
        # WS-push lo evita porque corre en el contexto del content script con cookies.
        _ws_grace = time.time() + 5
        while time.time() < _ws_grace:
            with _flow_ws_clients_lock:
                if account_hash in _flow_ws_clients:
                    _ws_hashes = list(_flow_ws_clients.keys())
                    break
            time.sleep(0.3)

        if account_hash not in _ws_hashes:
            # Sin WS tras espera: HTTP poll (último recurso)
            req["account_hash"] = account_hash
            with _flow_bridge_q_lock:
                _flow_bridge_queue.append(req)
            _flow_log(f"[Flow] Bridge: HTTP poll queue -> {account_hash[:8]} req={rid[:12]}...")
            pushed = True  # El "push" es el encolado; el polling lo recoge
        # Si WS apareció: pushed sigue False y cae al bloque de WS push abajo

    if not pushed:
        # WS push: cuenta asignada primero (si tiene WS), luego las demás
        _try_order = []
        if account_hash and account_hash in _ws_hashes:
            _try_order.append(account_hash)
        for _h in _ws_hashes:
            if _h not in _try_order and not _flow_is_banned(_h):
                _try_order.append(_h)

        for _h in _try_order:
            req["account_hash"] = _h
            # Si el fallback es una cuenta diferente a la asignada, usar SU bearer
            # para que las cookies del browser (Cuenta B) coincidan con el Authorization header.
            # Mismatch cookies/bearer es la causa principal de 403 reCAPTCHA.
            if _h != account_hash:
                _alt_bearer = _flow_get_cached_bearer(_h)
                if _alt_bearer:
                    req["bearer"] = _alt_bearer
            if _flow_ws_push(_h, req):
                pushed = True
                _flow_log(f"[Flow] WS push -> {_h[:8]} req={rid[:12]}...")
                break

        if not pushed:
            if account_hash:
                req["account_hash"] = account_hash
                req["bearer"] = bearer  # Restaurar bearer original
            with _flow_bridge_q_lock:
                _flow_bridge_queue.append(req)
            _flow_log(f"[Flow] Bridge: request encolado {rid[:12]}... cuenta={account_hash or 'any'} (HTTP polling)")

    deadline = time.time() + timeout
    while time.time() < deadline:
        ev.wait(timeout=2.0)
        ev.clear()
        with _flow_bridge_r_lock:
            if rid in _flow_bridge_results:
                _flow_bridge_r_events.pop(rid, None)
                return _flow_bridge_results.pop(rid)

    with _flow_bridge_q_lock:
        _flow_bridge_queue[:] = [r for r in _flow_bridge_queue if r.get("requestId") != rid]
    with _flow_bridge_r_lock:
        _flow_bridge_r_events.pop(rid, None)

    acct_info = f" (cuenta={account_hash})" if account_hash else ""
    raise RuntimeError(
        f"Sin respuesta del bridge{acct_info}. "
        "Asegurate de tener Chrome abierto en labs.google/fx/tools/flow "
        "con la extension activa."
    )


def _flow_run_batch(prompts: list, out_dir: str, slots: int,
                    aspect: str, model: str, retries: int,
                    ref_image: str = None, start_index: int = 0,
                    auto_open: bool = False):
    """
    Bridge-mode v4:
    - Bearer proviene de la extension (via bridge cache), no de cookies en disco
    - Semaforo por cuenta: 1 request activa a la vez — elimina 401/403 en cascada
    - slots = workers globales limitados por cuentas conectadas
    - Retry infinito por rondas hasta completar el 100%
    - 400 UNSAFE: marca el prompt como no reintentable
    """
    try:
        _flow_run_batch_inner(prompts, out_dir, slots, aspect, model, retries,
                              ref_image, start_index, auto_open=auto_open)
    except Exception as _top_exc:
        # Set running=False FIRST before any logging that could also raise
        with _flow_lock:
            _flow_state["running"] = False
            _flow_state["step"]    = "idle"
            _flow_state["last_error"] = str(_top_exc)
        try:
            _flow_log(f"[Flow] ERROR fatal en batch: {_top_exc}")
            import traceback as _tb
            _flow_log(f"[Flow] Traceback: {_tb.format_exc()[:800]}")
        except Exception:
            pass


def _flow_run_batch_inner(prompts: list, out_dir: str, slots: int,
                          aspect: str, model: str, retries: int,
                          ref_image: str = None, start_index: int = 0,
                          auto_open: bool = False):
    import uuid as _uuid, json as _json, queue as _q
    from concurrent.futures import ThreadPoolExecutor, as_completed
    import urllib3 as _u3; _u3.disable_warnings(_u3.exceptions.InsecureRequestWarning)

    global _flow_batch_id
    _flow_log(f"[Flow] ===== BATCH INNER START: {len(prompts)} prompts, out={out_dir[:60]} =====")
    _flow_stop.clear()
    # Limpiar requests pendientes del batch anterior — evita que upload espere detras de
    # generaciones viejas que la extension todavia tiene en su cola HTTP poll.
    with _flow_bridge_q_lock:
        _flow_bridge_queue.clear()
    _flow_log(f"[Flow] stop_cleared={not _flow_stop.is_set()} slots={slots} model={model}")
    os.makedirs(out_dir, exist_ok=True)
    # batch_id y running ya fueron actualizados sincrónicamente en api_flow_run.
    # Solo leemos el batch_id actual para que los workers sepan a cuál batch pertenecen.
    with _flow_lock:
        my_batch_id = _flow_batch_id

    # ── Cargar cuentas en paralelo ────────────────────────────────────────
    accounts_ok = []
    _acc_load_lock = threading.Lock()

    def _load_account(i):
        ck = _flow_load_cookie(i)
        if not ck:
            return
        sess   = _flow_get_session(ck)
        bearer = sess.get("bearer", "")
        email  = sess.get("email", "") or f"cuenta_{i}"
        if not bearer:
            return
        acc_hash = _flow_account_hash(email)
        entry = {
            "index":        i,
            "cookie":       ck,
            "bearer":       bearer,  # bearer inicial de disco (fallback)
            "bearer_lock":  threading.Lock(),
            "email":        email,
            "account_hash": acc_hash,
        }
        with _acc_load_lock:
            if any(a["account_hash"] == acc_hash for a in accounts_ok):
                _flow_log(f"[Flow Acc{i+1}] Duplicado ({email}), omitiendo")
                try: os.remove(os.path.join(_FLOW_COOKIES_DIR, f"account_{i}.txt"))
                except Exception: pass
                return
            accounts_ok.append(entry)
            with _flow_lock:
                _flow_state["accounts"][i].update({"ok": True, "email": f"{email} ok"})
        _flow_log(f"[Flow Acc{i+1}] OK Hash: {acc_hash} ({email})")

    load_threads = [threading.Thread(target=_load_account, args=(i,), daemon=True)
                    for i in range(_FLOW_NUM_ACCOUNTS)]
    for t in load_threads:
        t.start()
    for t in load_threads:
        t.join(timeout=25)

    # Agregar cuentas conectadas por WS (sin cookies) y por HTTP puro.
    # En .exe compilado websockets puede no estar disponible --> la extension
    # solo conecta por HTTP (/flow-register). Esas cuentas están en
    # _flow_http_seen y _flow_ws_clients pero no en accounts_ok todavía.
    _connected_all = _flow_get_connected_accounts()  # WS + HTTP
    with _flow_ws_clients_lock:
        _ws_now = dict(_flow_ws_clients)
    # Solo agregar cuentas HTTP-only si NO hay ninguna cuenta WS real conectada;
    # una cuenta HTTP-only sin bearer en caché simplemente bloquea workers 30s.
    _has_ws_accounts = bool(_ws_now)
    _all_connected_hashes = set(_connected_all) | set(_ws_now.keys())
    for _ch in list(_all_connected_hashes):
        if any(a["account_hash"] == _ch for a in accounts_ok):
            continue
        _src = "WS" if _ch in _ws_now else "HTTP"
        # Omitir cuentas HTTP-only si ya hay cuentas WS con bearer activo
        if _src == "HTTP" and _has_ws_accounts:
            _cached_b = _flow_get_cached_bearer(_ch)
            if not _cached_b:
                _flow_log(f"[Flow] Cuenta HTTP {_ch[:8]} omitida (sin bearer, hay cuentas WS activas)")
                continue
        _ch_email = f"{_src}_{_ch[:8]}"
        accounts_ok.append({
            "index":        len(accounts_ok),
            "cookie":       "",
            "bearer":       "",
            "bearer_lock":  threading.Lock(),
            "email":        _ch_email,
            "account_hash": _ch,
        })
        _flow_log(f"[Flow] Cuenta {_src} agregada: {_ch}")

    _flow_start_bridge()

    if auto_open:
        # Esperar hasta 3s para que Chrome real conecte antes de abrir Playwright
        # Chequea WS + HTTP bridge (Chrome registra por HTTP antes que WS)
        _ao_end = time.time() + 3
        while time.time() < _ao_end:
            _connected_ao = set(_flow_get_connected_accounts())
            with _flow_playwright_hashes_lock:
                _pw_h_ao = set(_flow_playwright_hashes)
            if _connected_ao - _pw_h_ao:  # Chrome real ya conectó (WS o HTTP)
                break
            time.sleep(0.3)
        _flow_auto_open_browsers()

    # ── Esperar conexion de la extension al bridge (via WS o HTTP polling) ───
    # La extension hace GET /flow-generate-poll cada 1s (background.js).
    # El WS se registra cuando background.js conecta al puerto 5557.
    # Esperamos max 90s para dar tiempo al browser de cargar Flow y registrar bearer.
    _flow_log(f"[Flow] Esperando conexion de extensiones al bridge (max 90s)...")
    _wait_deadline = time.time() + 90
    _last_feedback = time.time()
    _last_new_account = time.time()
    _first_ready_time = None   # when first "all known accounts ready" condition met
    while time.time() < _wait_deadline:
        # Detectar cuentas WS nuevas que conectaron DURANTE la espera
        with _flow_ws_clients_lock:
            _ws_during = dict(_flow_ws_clients)
        with _flow_bearer_cache_lock:
            _ws_active_during = {h for h, e in _flow_bearer_cache.items() if e.get("bearer")}
        _all_during = set(_ws_during.keys()) | _ws_active_during
        for _ch in list(_all_during):
            if not any(a["account_hash"] == _ch for a in accounts_ok):
                accounts_ok.append({
                    "index":        len(accounts_ok),
                    "cookie":       "",
                    "bearer":       "",
                    "bearer_lock":  threading.Lock(),
                    "email":        f"WS_{_ch[:8]}",
                    "account_hash": _ch,
                })
                _flow_log(f"[Flow] ➕ Cuenta WS detectada durante espera: {_ch[:8]}")
                _last_new_account = time.time()
                _first_ready_time = None  # reset — new account joined, recheck

        connected_check = _flow_get_connected_accounts()
        with _flow_ws_clients_lock:
            connected_check = set(connected_check) | set(_flow_ws_clients.keys())
        with _flow_bearer_cache_lock:
            connected_check = connected_check | {h for h, e in _flow_bearer_cache.items() if e.get("bearer")}
        n_check = len([a for a in accounts_ok if a["account_hash"] in connected_check])
        # ── Contar cuentas con bearer por tipo de conexión ───────────────────
        with _flow_ws_clients_lock:
            _ws_now_set = set(_flow_ws_clients.keys())
        with _flow_bearer_cache_lock:
            _bearer_now_set = {h for h, e in _flow_bearer_cache.items() if e.get("bearer")}
        with _flow_http_seen_lock:
            _http_now_set = set(_flow_http_seen.keys())
        # HTTP = extensión Chrome real; WS = Playwright/Chromium
        _n_http_bearer = sum(1 for a in accounts_ok
                             if a["account_hash"] in _http_now_set
                             and (a["account_hash"] in _bearer_now_set
                                  or bool(a.get("bearer", ""))))
        _n_ws_bearer   = sum(1 for a in accounts_ok
                             if a["account_hash"] in _ws_now_set
                             and (a["account_hash"] in _bearer_now_set
                                  or bool(a.get("bearer", ""))))

        # PRIORIDAD Chrome: si hay extensiones Chrome (HTTP) con bearer, no esperar Playwright
        if _n_http_bearer > 0:
            if _first_ready_time is None:
                _first_ready_time = time.time()
            _grace_elapsed = time.time() - _first_ready_time
            _grace_limit = 8  # 8s para que se conecten más extensiones Chrome
            if _grace_elapsed >= _grace_limit:
                _flow_log(f"[Flow] [OK] Chrome real listo ({_n_http_bearer} cuenta(s)) — iniciando")
                break
            elif time.time() - _last_feedback >= 5:
                _last_feedback = time.time()
                elapsed = int(time.time() - (_wait_deadline - 90))
                _flow_log(f"[Flow] [OK] {_n_http_bearer} Chrome OK — grace {int(_grace_limit - _grace_elapsed):.0f}s más...")
            time.sleep(0.3)
            continue

        # Sin Chrome real --> esperar WS (Playwright) como fallback
        if len(accounts_ok) > 0 and _n_ws_bearer >= len(accounts_ok):
            if _first_ready_time is None:
                _first_ready_time = time.time()
            _grace_elapsed = time.time() - _first_ready_time
            _all_disk_bearer = all(bool(a.get("bearer", "")) for a in accounts_ok)
            _grace_limit = 0 if _all_disk_bearer else 25
            if _grace_elapsed >= _grace_limit:
                _flow_log(f"[Flow] [OK] WS + bearer listo — iniciando ({_n_ws_bearer} cuenta(s))")
                break
            elif time.time() - _last_feedback >= 5:
                _last_feedback = time.time()
                elapsed = int(time.time() - (_wait_deadline - 90))
                _flow_log(f"[Flow] [OK] {_n_ws_bearer} cuenta(s) WS OK — grace {int(_grace_limit - _grace_elapsed):.0f}s más...")
            time.sleep(0.3)
            continue
        # Fallback: salir al acercarse al deadline si hay cuentas conectadas
        if n_check > 0 and time.time() > _wait_deadline - 5:
            break
        if time.time() - _last_feedback >= 5:
            _last_feedback = time.time()
            elapsed = int(time.time() - (_wait_deadline - 90))
            _ws_info = f"{_n_ws_bearer} con WS" if _n_ws_bearer else "sin WS..."
            _flow_log(f"[Flow] Esperando extensión Chrome... {elapsed}s ({n_check}/{len(accounts_ok)} conectada(s), {_ws_info})")
        time.sleep(0.3)

    connected_now = set(_flow_get_connected_accounts())
    with _flow_ws_clients_lock:
        connected_now = connected_now | set(_flow_ws_clients.keys())

    # Cuentas WS con bearer activo — aunque no coincidan con hashes de disco
    with _flow_bearer_cache_lock:
        _ws_active = {h for h, e in _flow_bearer_cache.items() if e.get("bearer")}
    connected_now = connected_now | _ws_active

    # Agregar cuentas WS activas que no estan en accounts_ok
    _existing_hashes = {a["account_hash"] for a in accounts_ok}
    for _wh in _ws_active:
        if _wh not in _existing_hashes:
            accounts_ok.append({
                "account_hash":  _wh,
                "email":         f"ws_{_wh[:8]}",
                "cookie":        "",
                "bearer_lock":   threading.Lock(),
            })
            _flow_log(f"[Flow] [OK] Cuenta WS agregada: {_wh[:8]}")

    if not accounts_ok:
        msg = "No hay cuentas Flow activas. Guarda la cookie en la seccion Flow."
        _flow_log(f"[Flow] {msg}")
        with _flow_lock:
            _flow_state.update({"running": False, "step": "idle", "last_error": msg})
        return

    n_connected = len([a for a in accounts_ok if a["account_hash"] in connected_now])
    if n_connected == 0:
        n_connected = len(accounts_ok)
        _flow_log(f"[Flow] Ninguna cuenta en bridge. Usando bearer de disco como fallback.")
        _flow_log(f"[Flow] [WARNING] Ninguna cuenta detectada en bridge. Usando todas.")
    else:
        _flow_log(f"[Flow] 🌐 {n_connected}/{len(accounts_ok)} cuenta(s) conectadas.")
    n_accs      = len(accounts_ok)
    slots_user  = max(1, min(slots, 10))
    max_workers = max(1, slots_user * max(1, (n_connected if n_connected > 0 else n_accs)))

    _flow_log(f"[Flow] [OK] {n_accs} cuenta(s) con cookie valida:")
    for _a in accounts_ok:
        _state = "conectada" if _a["account_hash"] in connected_now else "sin Chrome"
        cached_b = _flow_get_cached_bearer(_a["account_hash"])
        if cached_b:
            _a["bearer"] = cached_b
            _state += " + bearer OK"
        _flow_log(f"[Flow]   · {_a['email']} [{_state}]")
    # Recalcular con cuentas WS: limitar slots si hay multiples cuentas
    n_total_accs = len(accounts_ok)
    max_workers  = max(1, slots_user * n_total_accs)
    _flow_log(f"[Flow] 🚀 {len(prompts)} prompts · {max_workers} workers ({n_total_accs} cuenta(s) × {slots_user} slots)")
    if ref_image:
        _flow_log(f"[Flow] 🖼 Imagen de referencia incluida — subiendo al bridge...")
        # Parsear data URL
        _ref_mime = "image/jpeg"
        _ref_b64  = ref_image
        if "," in ref_image:
            _ref_header, _ref_b64 = ref_image.split(",", 1)
            if "image/png" in _ref_header:  _ref_mime = "image/png"
            elif "image/webp" in _ref_header: _ref_mime = "image/webp"
        # Orden de intento: WS primero (mas confiable), luego HTTP poll, luego cualquier cuenta
        with _flow_ws_clients_lock:
            _ws_hashes_for_upload = set(_flow_ws_clients.keys())
        _upload_order = (
            [a for a in accounts_ok if a["account_hash"] in _ws_hashes_for_upload] +
            [a for a in accounts_ok if a["account_hash"] not in _ws_hashes_for_upload
             and a["account_hash"] in connected_now] +
            [a for a in accounts_ok if a["account_hash"] not in connected_now]
        )
        _ref_name = ""
        _ref_pid  = str(__import__("uuid").uuid4())
        for _ref_acc in _upload_order:
            _ref_bearer = _flow_get_cached_bearer(_ref_acc["account_hash"]) or _ref_acc.get("bearer", "")
            _flow_log(f"[Flow] 🖼 Upload con {_ref_acc['email']}...")
            _ref_name = _flow_upload_reference_image(
                _ref_b64, _ref_mime, _ref_bearer, _ref_pid,
                account_hash=_ref_acc["account_hash"]
            )
            if _ref_name:
                _flow_log(f"[Flow] 🖼 Imagen subida — name={_ref_name} (NARWHAL + imageInputs)")
                break
            _flow_log(f"[Flow] [WARNING] Upload falló con {_ref_acc['email']}, intentando siguiente cuenta...")
        if not _ref_name:
            _flow_log(f"[Flow] [WARNING] Upload de ref image falló en todas las cuentas — generando sin referencia (NARWHAL)")
    else:
        _ref_name = None
    _flow_log(f"[Flow] ⚡ Asegurate de tener Chrome en labs.google/fx/tools/flow con la extension.")

    # ── Cooldown por cuenta (igual que Whisk) ─────────────────────────────
    _acc_cooldown      = {a["account_hash"]: 0.0 for a in accounts_ok}
    _acc_cooldown_lock = threading.Lock()
    _COOLDOWN_429      = 10.0  # segundos de pausa por cuenta tras 429

    def _mark_cooldown(account_hash: str):
        with _acc_cooldown_lock:
            _acc_cooldown[account_hash] = time.time() + _COOLDOWN_429
            email = next((a["email"] for a in accounts_ok if a["account_hash"] == account_hash), account_hash[:8])
            _flow_log(f"[Flow] ⏸ {email} en cooldown {_COOLDOWN_429:.0f}s (429)")

    def _is_available(account_hash: str) -> bool:
        with _acc_cooldown_lock:
            return time.time() >= _acc_cooldown.get(account_hash, 0.0)

    def _wait_until_available() -> dict:
        """Espera hasta que al menos una cuenta esté disponible y la devuelve.
        Chrome real tiene PRIORIDAD sobre Playwright Chromium."""
        while not _flow_stop.is_set():
            connected = _flow_get_connected_accounts()
            pool = [a for a in accounts_ok if a["account_hash"] in connected] or accounts_ok
            available = [a for a in pool if _is_available(a["account_hash"])]

            # Separar Chrome real de Playwright
            with _flow_playwright_hashes_lock:
                _pw_h = set(_flow_playwright_hashes)
            # Cuenta activa via Chrome extensión (HTTP) es Chrome real aunque haya sido
            # abierta con Playwright antes — quitar de _pw_h para priorizar correctamente
            with _flow_http_seen_lock:
                _pw_h -= set(_flow_http_seen.keys())
            real_available = [a for a in available if a["account_hash"] not in _pw_h]

            if real_available:
                # Hay Chrome real disponible — usarlo siempre
                with _rr_lock:
                    idx = _rr_counter[0] % len(real_available)
                    _rr_counter[0] += 1
                return real_available[idx]

            # ¿Chrome real conectado pero todas sus slots ocupadas?
            real_in_pool = [a for a in pool if a["account_hash"] not in _pw_h]
            if real_in_pool:
                # Chrome real existe pero está ocupado — esperar antes de usar Playwright
                time.sleep(0.2)
                continue

            # Sin Chrome real en absoluto --> Playwright como fallback
            if available:
                with _rr_lock:
                    idx = _rr_counter[0] % len(available)
                    _rr_counter[0] += 1
                return available[idx]

            # Todas en cooldown: esperar hasta la más próxima
            with _acc_cooldown_lock:
                earliest = min(_acc_cooldown.get(a["account_hash"], 0.0) for a in pool)
            wait = max(0.1, earliest - time.time())
            if wait > 1:
                _flow_log(f"[Flow] ⏳ Todas las cuentas en cooldown — esperando {wait:.0f}s...")
            time.sleep(min(wait, 2.0))
        return accounts_ok[0]  # fallback si se detiene
    # Semaforo por cuenta: max slots_user requests activas simultaneas
    # Limitar concurrencia por cuenta para evitar 429
    # Con 1 cuenta: todos los slots. Con 2+: max 3 por cuenta
    _acc_semaphores = {a["account_hash"]: threading.Semaphore(slots_user) for a in accounts_ok}

    # Para cuentas HTTP-only (sin WS): serializar a 1 request simultáneo
    # Burst de N requests simultáneos via HTTP-poll --> Google CAPTCHA 403
    # WS-push no tiene este problema porque la extension serializa internamente
    with _flow_ws_clients_lock:
        _ws_set_at_start = set(_flow_ws_clients.keys())
    for _a in accounts_ok:
        if _a["account_hash"] not in _ws_set_at_start:
            _acc_semaphores[_a["account_hash"]] = threading.Semaphore(1)
            _flow_log(f"[Flow] [WARNING] {_a['account_hash'][:8]} sin WS --> concurrencia 1 (evitar CAPTCHA por burst)")

    # Contador de 401 consecutivos por cuenta
    _acc_fails       = {a["account_hash"]: 0 for a in accounts_ok}
    _acc_fails_lock  = threading.Lock()
    _acc_skip_until  = {}

    _rr_counter = [0]
    _rr_lock    = threading.Lock()

    def _mark_fail(account_hash: str, is_timeout: bool = False):
        with _acc_fails_lock:
            _acc_fails[account_hash] = _acc_fails.get(account_hash, 0) + 1
            n = _acc_fails[account_hash]
            email = next((a["email"] for a in accounts_ok if a["account_hash"] == account_hash), account_hash[:8])
            if is_timeout:
                # Bridge timeout = browser muerto: desregistrar de WS/HTTP para sacarla del pool
                with _flow_ws_clients_lock:
                    _flow_ws_clients.pop(account_hash, None)
                with _flow_http_seen_lock:
                    _flow_http_seen.pop(account_hash, None)
                # Limpiar requests pendientes en la cola HTTP para este account
                # (evita que otros workers queden bloqueados 60s esperando que el browser muerto haga poll)
                with _flow_bridge_q_lock:
                    _flow_bridge_queue[:] = [
                        r for r in _flow_bridge_queue
                        if r.get("account_hash") != account_hash
                    ]
            if n == 3:
                _acc_skip_until[account_hash] = time.time() + 60
                _flow_log(f"[Flow] ⏸ {email} excluida 60s")
            elif n == 4:
                _acc_skip_until[account_hash] = time.time() + 120
                _flow_log(f"[Flow] ⏸ {email} excluida 2min (falla reiterada)")
            elif n >= 5:
                _acc_skip_until[account_hash] = time.time() + 600
                _flow_log(f"[Flow] ⏸ {email} excluida 10min (sin respuesta persistente)")

    def _mark_success(account_hash: str):
        with _acc_fails_lock:
            _acc_fails[account_hash] = 0
            _acc_skip_until.pop(account_hash, None)

    def _inject_new_accounts():
        """Agrega al batch cuentas que se conectaron después del inicio (ej: perfil de respaldo)."""
        with _flow_bearer_cache_lock:
            new_entries = {h: dict(e) for h, e in _flow_bearer_cache.items() if e.get("bearer")}
        existing = {a["account_hash"] for a in accounts_ok}
        # Índices Chrome ya asignados a alguna cuenta (para detectar perfiles sin hash)
        _used_indices = {a["index"] for a in accounts_ok}
        for _nh, _ne in new_entries.items():
            if _nh in existing:
                continue
            _now     = time.time()
            _new_idx = len(accounts_ok)
            # Heredar warmup: buscar perfil Chrome con warmup activo pero sin cuenta aún.
            # Cuando rotation abre perfil N --> _flow_warmup_until_idx[N] se setea, pero
            # la cuenta no está en accounts_ok hasta que conecta. Al conectar, su
            # index dinámico (len(accounts_ok)) ≠ N, así que el warmup se pierde.
            # Fix: copiar el expiry del perfil Chrome sin hash al nuevo index dinámico.
            _inherited_warmup = 0
            with _flow_warmup_lock:
                for _cidx, _exp in sorted(_flow_warmup_until_idx.items()):
                    if _now < _exp and _cidx not in _used_indices:
                        _inherited_warmup = _exp
                        break
            accounts_ok.append({
                "account_hash": _nh,
                "email":        f"ws_{_nh[:8]}",
                "cookie":       "",
                "bearer":       _ne.get("bearer", ""),
                "bearer_lock":  threading.Lock(),
                "index":        _new_idx,
            })
            with _flow_ws_clients_lock:
                _nh_has_ws = _nh in _flow_ws_clients
            _acc_semaphores[_nh] = threading.Semaphore(slots_user if _nh_has_ws else 1)
            with _acc_cooldown_lock:
                _acc_cooldown[_nh] = 0.0
            _acc_fails[_nh] = 0
            # Asignar project ID consistente — si hay imagen de referencia, usar el mismo
            # project ID del upload (funciona cross-account en Flow). Si no, UUID propio.
            _acc_project_ids[_nh] = _real_ref_pid if _ref_name else str(_uuid_mod.uuid4())
            _used_indices.add(_new_idx)  # marcar para evitar colisión con próxima cuenta
            if _inherited_warmup > 0:
                with _flow_warmup_lock:
                    _flow_warmup_until_idx[_new_idx] = _inherited_warmup
                _secs_left = int(_inherited_warmup - _now)
                _flow_log(f"[Flow] ➕ Cuenta {_nh[:8]} incorporada al batch — warmup heredado {_secs_left}s")
            else:
                # Sin warmup heredado: aplicar warmup mínimo de 25s para que el
                # content script del browser recién conectado se estabilice.
                _min_warmup = _now + 25
                with _flow_warmup_lock:
                    _flow_warmup_until_idx[_new_idx] = _min_warmup
                _flow_log(f"[Flow] ➕ Cuenta {_nh[:8]} incorporada al batch — warmup 25s para estabilizar tab")

    def _pick_account() -> dict:
        """
        Elige cuenta disponible: SOLO cuentas con browser conectado.
        Si no hay ninguna conectada, espera — nunca usa cuentas sin browser abierto.
        """
        _last_no_connected_log = [0.0]
        while not _flow_stop.is_set():
            now = time.time()
            connected = _flow_get_connected_accounts()
            # Solo cuentas con browser activo
            pool = [a for a in accounts_ok if a["account_hash"] in connected]
            if not pool:
                # Sin browser conectado: esperar. Loguear cada 10s para no saturar.
                if now - _last_no_connected_log[0] > 10:
                    _flow_log(f"[Flow] ⏳ Esperando que un browser se conecte al bridge...")
                    _last_no_connected_log[0] = now
                time.sleep(1)
                continue
            # Filtrar por cooldown 429, skip 401, ban por rotación y warmup
            _warmup_log_ts = getattr(_pick_account, "_warmup_log_ts", {})
            _pick_account._warmup_log_ts = _warmup_log_ts

            def _in_warmup(a):
                a_idx = a.get("index", 99)
                with _flow_warmup_lock:
                    until = _flow_warmup_until_idx.get(a_idx, 0)
                if now < until:
                    secs_left = int(until - now)
                    # Log máximo 1 vez cada 15s por perfil para no saturar
                    last = _warmup_log_ts.get(a_idx, 0)
                    if now - last > 15:
                        _warmup_log_ts[a_idx] = now
                        _flow_log(f"[Flow] ⏳ Perfil {a_idx+1} en warmup — {secs_left}s restantes, skip")
                    return True
                # Warmup terminado: limpiar entrada
                _warmup_log_ts.pop(a_idx, None)
                return False

            available = [a for a in pool
                         if _is_available(a["account_hash"])
                         and now > _acc_skip_until.get(a["account_hash"], 0)
                         and not _flow_is_banned(a["account_hash"])
                         and not _in_warmup(a)]
            if available:
                with _rr_lock:
                    idx = _rr_counter[0] % len(available)
                    _rr_counter[0] += 1
                return available[idx]
            # Hay cuentas conectadas pero todas en cooldown — esperar al más próximo
            with _acc_cooldown_lock:
                earliest = min((_acc_cooldown.get(a["account_hash"], 0.0) for a in pool), default=now + 2)
            wait = max(0.5, earliest - now)
            if wait > 2:
                _flow_log(f"[Flow] ⏳ Todas en cooldown — esperando {wait:.0f}s...")
            time.sleep(min(wait, 2.0))
        return accounts_ok[0]

    def _get_best_bearer(acc: dict) -> str:
        # Prioridad: bearer enviado por la extension al bridge (siempre fresco)
        cached = _flow_get_cached_bearer(acc["account_hash"])
        if cached:
            return cached
        return acc.get("bearer", "")

    def _refresh_bearer(acc: dict, bad_bearer: str = ""):
        """Intenta obtener bearer FRESCO, ignorando el bearer que acaba de fallar.
        Si la cache tiene el mismo bearer expirado retorna False para forzar pausa."""
        cached = _flow_get_cached_bearer(acc["account_hash"])
        if cached and cached != bad_bearer:
            acc["bearer"] = cached
            return True
        # Ultimo recurso: API de sesion via cookie en disco
        with acc["bearer_lock"]:
            new_b = _flow_get_session(acc["cookie"]).get("bearer", "")
            if new_b and new_b != bad_bearer:
                acc["bearer"] = new_b
                return True
        return False

    def _sanitize(p):
        import unicodedata
        for a, b in [("\u2014","-"),("\u2013","-"),("\u2018","'"),("\u2019","'"),
                     ("\u201c",'"'),("\u201d",'"'),("\u2026","..."),("\u00ab",'"'),("\u00bb",'"')]:
            p = p.replace(a, b)
        return ' '.join(''.join(c for c in p.strip()
                        if __import__('unicodedata').category(c)[0] != 'C' or c == ' ').split())[:1500]

    import uuid as _uuid_mod
    if _ref_name:
        # Extraer el project ID real asignado por el servidor (del path devuelto por el upload)
        import re as _re_refpid
        _m_refpid = _re_refpid.search(r'projects/([^/]+)', _ref_name)
        _real_ref_pid = _m_refpid.group(1) if _m_refpid else _ref_pid
        _flow_log(f"[Flow] Project ID de referencia: {_real_ref_pid}")
        _acc_project_ids = {a["account_hash"]: _real_ref_pid for a in accounts_ok}
    else:
        _acc_project_ids = {a["account_hash"]: str(_uuid_mod.uuid4()) for a in accounts_ok}

    # Timestamp del último request por cuenta — para espaciar requests mínimo 1s
    _acc_last_req    = {a["account_hash"]: 0.0 for a in accounts_ok}
    _acc_last_lock   = threading.Lock()

    # Intervalo mínimo entre requests consecutivos por cuenta
    # Con slots_user=10 y 3 cuentas --> 10 workers por cuenta
    # Necesitamos espaciarlos: si Google acepta ~1 req/2s por cuenta --> 2s de gap
    _ACC_MIN_GAP = max(1.5, slots_user * 0.2)  # 2s con slots=10

    def _wait_for_account_slot(account_hash: str):
        """Reserva el próximo slot disponible de forma atómica y espera si necesario."""
        with _acc_last_lock:
            last = _acc_last_req.get(account_hash, 0.0)
            now = time.time()
            # El próximo slot es: max(ahora, último_slot + gap)
            next_slot = max(now, last + _ACC_MIN_GAP)
            _acc_last_req[account_hash] = next_slot
            wait = next_slot - now
        if wait > 0.01:
            time.sleep(wait)

    # Cola y estado
    job_q       = _q.Queue()
    _unsafe     = set()
    saved_count = [0]
    res_lock    = threading.Lock()

    _completed      = set()   # índices ya guardados exitosamente
    _completed_lock = threading.Lock()

    def _mark_complete(task_idx: int) -> bool:
        """Retorna True solo si este worker es el primero en completar este índice."""
        with _completed_lock:
            if task_idx in _completed:
                return False
            _completed.add(task_idx)
            return True

    def _enqueue_missing():
        count = 0
        with _completed_lock:
            done = set(_completed)
        for i, p in enumerate(prompts):
            if i in _unsafe or i in done:
                continue
            fpath = os.path.join(out_dir, f"flow_{i+1:04d}.png")
            if os.path.isfile(fpath) and os.path.getsize(fpath) > 500:
                continue
            job_q.put((i, p))
            count += 1
        return count

    _enqueue_missing()

    # Fallback: si una tarea falla N veces con ref image (500), generar sin ref (NARWHAL)
    _ref_fail_count = {}   # task_idx -> int
    _ref_fail_lock  = threading.Lock()
    _REF_FAIL_LIMIT = 3

    def _worker(worker_id: int):
        label = f"[Flow W{worker_id+1}]"
        while not _flow_stop.is_set() and _flow_batch_id == my_batch_id:
            try:
                task_idx, prompt = job_q.get(timeout=1)
            except _q.Empty:
                break

            out_file = os.path.join(out_dir, f"flow_{task_idx+1:04d}.png")

            # Skip si ya fue completado por otro worker en esta sesión
            with _completed_lock:
                if task_idx in _completed:
                    continue

            # Skip si ya existe en disco (de sesiones anteriores) — marcar como completo
            if os.path.isfile(out_file) and os.path.getsize(out_file) > 500:
                if _mark_complete(task_idx):
                    with res_lock:
                        saved_count[0] += 1
                    with _flow_lock:
                        _flow_state["progress"]     = saved_count[0]
                        _flow_state["images_saved"] = saved_count[0]
                continue

            prompt = _sanitize(prompt)
            _flow_log(f"{label} [{task_idx+1}/{len(prompts)}] {prompt[:55]}...")

            success = False
            for attempt in range(8):
                if _flow_stop.is_set():
                    break

                acc = _pick_account()
                sem = _acc_semaphores[acc["account_hash"]]

                # Cuando quedan pocos items vs workers, dispersar para no saturar cuentas.
                # Ej: 2 items y 24 workers --> todos se amontonan en los mismos prompts --> reCAPTCHA.
                _n_left = job_q.qsize()
                if _n_left < max_workers // 2 and _n_left > 0:
                    import random as _rnd
                    time.sleep(_rnd.uniform(0.5, 2.5))

                # Intentar adquirir slot de la cuenta — timeout para no bloquear indefinidamente
                if not sem.acquire(timeout=2):
                    # Cuenta ocupada: devolver el trabajo a la cola y esperar un poco
                    job_q.put((task_idx, prompt))
                    import random as _rnd2
                    time.sleep(_rnd2.uniform(0.5, 1.5))  # pausa antes de volver al loop
                    break  # salir del loop de intentos y volver al while principal

                try:
                    bearer = _get_best_bearer(acc)
                    if not bearer:
                        # Esperar hasta 30s a que llegue el bearer de la extension
                        _flow_log(f"{label} Sin bearer para {acc['email'][:12]} — esperando...")
                        for _bwait in range(30):
                            time.sleep(1)
                            bearer = _flow_get_cached_bearer(acc["account_hash"])
                            if bearer:
                                acc["bearer"] = bearer
                                break
                        if not bearer:
                            # Ultimo intento: usar cookie del perfil si existe en disco
                            _idx_fb = acc.get("index", 99)
                            _ck_fb  = _flow_load_cookie(_idx_fb)
                            if _ck_fb:
                                _sess_fb = _flow_get_session(_ck_fb)
                                bearer   = _sess_fb.get("bearer", "")
                                if bearer:
                                    acc["cookie"] = _ck_fb
                                    acc["bearer"] = bearer
                                    _flow_log(f"{label} Bearer obtenido de cookie disco")
                            if not bearer:
                                _flow_log(f"{label} Sin bearer tras 30s — saltando")
                                continue

                    # Espaciar requests a la misma cuenta mínimo 1s
                    _wait_for_account_slot(acc["account_hash"])
                    if _flow_stop.is_set(): break
                    # Con imagen de referencia: usar el mismo proyecto del upload para que
                    # el servidor pueda acceder a la imagen (no hay acceso cross-project).
                    # Sin referencia: UUID fresco por request.
                    gen_pid    = _acc_project_ids.get(acc["account_hash"]) or str(_uuid.uuid4())
                    session_id = ";" + str(int(time.time() * 1000))
                    api_url    = _FLOW_GEN_URL_TPL.format(pid=gen_pid)
                    _seed      = __import__("random").randint(1, 999999)

                    prompt = prompt.strip().strip('"\'')
                    if model == "IMAGE_GENERATION_001_IMAGEN4":
                        prompt = prompt + ". Maintain same avatar style"

                    # Decidir si usar ref image para este intento de esta tarea
                    with _ref_fail_lock:
                        _task_ref_fails = _ref_fail_count.get(task_idx, 0)
                    _use_ref_now = bool(_ref_name) and _task_ref_fails < _REF_FAIL_LIMIT

                    # Build the inner request
                    _inner_req = {
                        "clientContext":    {"projectId": gen_pid, "tool": "PINHOLE", "sessionId": session_id},
                        "imageModelName":   ("NARWHAL" if model == "NANO_BANANA_2" else "NARWHAL" if model == "IMAGE_GENERATION_001_IMAGEN4" else model),
                        "imageAspectRatio": aspect,
                        "structuredPrompt": {"parts": [{"text": prompt}]},
                        "seed":             _seed,
                    }

                    # Imagen de referencia: usar solo si no ha fallado demasiado para esta tarea
                    if _use_ref_now:
                        _inner_req["imageInputs"] = [{
                            "imageInputType": "IMAGE_INPUT_TYPE_REFERENCE",
                            "name":           _ref_name,
                        }]

                    _req_body  = {
                        "clientContext":          {"projectId": gen_pid, "tool": "PINHOLE", "sessionId": session_id},
                        "mediaGenerationContext": {"batchId": str(_uuid.uuid4())},
                        "useNewMedia":            True,
                        "requests": [_inner_req],
                    }

                    _flow_log(f"{label} --> bridge_generate acc={acc['account_hash'][:8]} url={api_url[40:80]}")
                    try:
                        result = _flow_bridge_generate(
                            _json.dumps(_req_body), bearer, api_url,
                            account_hash=acc["account_hash"], timeout=300
                        )
                    except RuntimeError as _bridge_err:
                        # Bridge timeout: el browser no respondió. Desregistrar + re-encolar.
                        _flow_log(f"{label} Bridge timeout ({acc['account_hash'][:8]}) — re-encolando tarea")
                        _mark_fail(acc["account_hash"], is_timeout=True)
                        job_q.put((task_idx, prompt))
                        success = True
                        break
                finally:
                    sem.release()

                if result.get("error"):
                    _err_str = result['error'][:80]
                    _flow_log(f"{label} intento {attempt+1}: {_err_str}")
                    # tab_unreachable = browser tab aún cargando; dar más tiempo
                    _wait_err = 8 if "tab_unreachable" in _err_str else 2
                    time.sleep(_wait_err)
                    continue

                status    = result.get("status", 0)
                resp_body = result.get("body", "")

                if status == 200:
                    try:
                        data  = _json.loads(resp_body)
                        media = data.get("media", [])
                        if not media:
                            raise RuntimeError("Sin imagenes en respuesta")
                        fife_url = (media[0].get("image", {})
                                    .get("generatedImage", {}).get("fifeUrl"))
                        if not fife_url:
                            raise RuntimeError("Sin fifeUrl")
                        # Reintentar descarga hasta 4 veces con backoff
                        _dl_ok = False
                        for _dl_try in range(4):
                            try:
                                with _flow_dl_sem:
                                    import urllib3 as _u3; _u3.disable_warnings(_u3.exceptions.InsecureRequestWarning)
                                    r = requests.get(fife_url, timeout=30, verify=False)
                                r.raise_for_status()
                                with open(out_file, "wb") as fh:
                                    fh.write(r.content)
                                _dl_ok = True
                                break
                            except Exception as _dl_e:
                                if _dl_try < 3:
                                    time.sleep(0.5 + _dl_try)
                                else:
                                    raise _dl_e
                        if not _dl_ok:
                            raise RuntimeError("Descarga fallida tras 4 intentos")
                        _flow_log(f"{label} [OK] Imagen {task_idx+1}")
                        _mark_success(acc["account_hash"])
                        if _mark_complete(task_idx):
                            with res_lock:
                                saved_count[0] += 1
                            with _flow_lock:
                                _flow_state["progress"]     = saved_count[0]
                                _flow_state["images_saved"] = saved_count[0]
                        success = True
                        break
                    except Exception as e:
                        _flow_log(f"{label} intento {attempt+1} error descarga: {e}")
                        time.sleep(1)

                elif status == 401:
                    # NO contar 401 como falla de reCAPTCHA — es expiración de bearer
                    _bad_bearer = bearer  # el bearer que acaba de fallar
                    got_new = _refresh_bearer(acc, bad_bearer=_bad_bearer)
                    if got_new:
                        _flow_log(f"{label} 401 bearer renovado — reintentando en 3s")
                        time.sleep(3)  # pausa aunque sea bearer nuevo: evitar otro 401 inmediato
                    else:
                        _flow_log(f"{label} 401 sin bearer fresco para {acc['email'][:12]} — pausa 10s")
                        time.sleep(10)  # esperar a que la extension envie un bearer nuevo

                elif status == 403:
                    _mark_fail(acc["account_hash"])
                    # Cooldown compartido: bloquea TODOS los workers 30s para evitar
                    # que otros workers reintentalten inmediatamente tras el 403.
                    with _acc_cooldown_lock:
                        _acc_cooldown[acc["account_hash"]] = time.time() + 30.0
                    wait = 3 * (attempt + 1)
                    _flow_log(f"{label} 403 reCAPTCHA — cooldown 30s | body={resp_body[:300]}")
                    time.sleep(wait)

                elif status == 400:
                    if "unsafe" in resp_body.lower():
                        _flow_log(f"{label} 400 UNSAFE [{task_idx+1}] — reescribiendo prompt...")
                        _rewritten = _openrouter_whisk_sanitize_prompt(prompt)
                        if _rewritten:
                            _flow_log(f"{label} Prompt reescrito: {_rewritten[:80]}...")
                            prompt = _rewritten
                            continue
                        else:
                            _flow_log(f"{label} Reescritura fallida — prompt bloqueado")
                            _unsafe.add(task_idx)
                            success = True
                            break
                    elif "invalid_argument" in resp_body.lower():
                        _flow_log(f"{label} 400 INVALID_ARGUMENT (intento {attempt+1}) body={resp_body[:400]}")
                        if _ref_name:
                            _flow_log(f"{label} ref_name={_ref_name[:60]}")
                        # INVALID_ARGUMENT no se resuelve reintentando — marcar para no re-encolar
                        _unsafe.add(task_idx)
                        success = True
                        break
                    else:
                        _flow_log(f"{label} 400: {resp_body[:300]}")
                        break

                elif status == 429:
                    _mark_cooldown(acc["account_hash"])
                    email = acc.get("email", acc["account_hash"][:8])
                    _acc_idx_429 = acc.get("index", 0)
                    _flow_log(f"{label} 429 — {email} en cooldown 30s, reencola tarea")
                    _flow_record_rl_hit(acc["account_hash"], _acc_idx_429)
                    job_q.put((task_idx, prompt))
                    success = True
                    break

                else:
                    if status == 500 and _use_ref_now:
                        # Contar fallos con ref image para esta tarea
                        with _ref_fail_lock:
                            _ref_fail_count[task_idx] = _ref_fail_count.get(task_idx, 0) + 1
                            _fail_cnt = _ref_fail_count[task_idx]
                        _flow_log(f"{label} 500 con imagen ref (intento {attempt+1}, fallo_ref={_fail_cnt}/{_REF_FAIL_LIMIT}): {resp_body[:300]}")
                        if _fail_cnt >= _REF_FAIL_LIMIT:
                            _flow_log(f"{label} [WARNING] Ref image falla consistentemente — próximos intentos usarán NARWHAL sin referencia")
                    else:
                        _flow_log(f"{label} intento {attempt+1}: HTTP {status}")
                    time.sleep(2)

            if not success and task_idx not in _unsafe:
                job_q.put((task_idx, prompt))

    # ── Monitor de cuentas nuevas (hilo independiente) ───────────────────
    # Detecta cuentas que se conectan mid-batch (ej: perfil de respaldo activado)
    # sin depender de que los workers estén activos (funciona durante cooldowns).
    def _account_monitor():
        while not _flow_stop.is_set():
            try:
                _inject_new_accounts()
                # Actualizar bearer fresco para cuentas ya en accounts_ok
                for _a in list(accounts_ok):
                    _fresh = _flow_get_cached_bearer(_a["account_hash"])
                    if _fresh and _fresh != _a.get("bearer", ""):
                        _a["bearer"] = _fresh
            except Exception:
                pass
            time.sleep(2)

    threading.Thread(target=_account_monitor, daemon=True).start()

    # ── Rondas hasta completar todo ───────────────────────────────────────
    round_num  = 0
    max_rounds = 30

    _flow_log(f"[Flow] PRE-ROUND: stop={_flow_stop.is_set()} max_workers={max_workers} q={job_q.qsize()} accs={len(accounts_ok)}")
    while not _flow_stop.is_set() and round_num < max_rounds:
        round_num += 1
        if job_q.empty():
            break
        pending    = job_q.qsize()
        total_safe = len(prompts) - len(_unsafe)
        done       = saved_count[0]
        _flow_log(f"[Flow] Ronda {round_num}: {pending} pendientes, {done}/{total_safe} listas")

        with ThreadPoolExecutor(max_workers=max_workers) as ex:
            futs = []
            for i in range(max_workers):
                if _flow_stop.is_set(): break
                futs.append(ex.submit(_worker, i))
                time.sleep(0.05)  # micro-escalonado al lanzar workers
            for f in as_completed(futs):
                try:
                    f.result()
                except Exception as e:
                    _flow_log(f"[Flow] Worker exception: {e}")

        if not _flow_stop.is_set():
            # Vaciar cualquier re-encole de workers antes de reconstruir la cola.
            # Sin esto, cada ronda duplica los ítems (worker pone 1, _enqueue_missing pone otro)
            # causando Ronda2:8, Ronda3:12, Ronda4:16... y 30 rondas en 2 segundos.
            while not job_q.empty():
                try:
                    job_q.get_nowait()
                except Exception:
                    break
            newly = _enqueue_missing()
            if newly == 0:
                break

    with _flow_lock:
        _flow_state["step"]    = "done" if not _flow_stop.is_set() else "idle"
        _flow_state["running"] = False
    total_safe = len(prompts) - len(_unsafe)
    _flow_log(f"[Flow] \U0001f389 Listo: {saved_count[0]}/{total_safe} imagenes"
              + (f" ({len(_unsafe)} bloqueadas por Google)" if _unsafe else ""))



# Perfiles Chromium abiertos {idx: True}
_flow_chromium_procs: dict = {}
_flow_chromium_lock  = threading.Lock()
# Semáforo que serializa el arranque de Playwright: si se presionan 3 botones casi
# simultáneamente, los 3 threads compiten por sync_playwright()+launch_persistent_context().
# En Windows esto causa fallos intermitentes. El semáforo asegura que un perfil termina de
# abrir antes de que el siguiente empiece (se libera tras launch_persistent_context exitoso).
_flow_pw_start_sem   = threading.Semaphore(1)


def _flow_find_extension_dir() -> str:
    """
    Busca la carpeta de la extensión buscando manifest.json.
    Primero en la misma carpeta del launcher, luego en subcarpetas comunes.
    En PyInstaller --onedir v6+, también busca en sys._MEIPASS (_internal/).
    """
    import glob as _glob

    # Candidatos de carpetas base donde buscar la extensión
    search_bases = [str(_FLOW_BASE_DIR_PW)]
    # PyInstaller --onedir v6+ extrae archivos bundleados en _MEIPASS (_internal/)
    _meipass = getattr(sys, "_MEIPASS", None)
    if _meipass and _meipass not in search_bases:
        search_bases.append(_meipass)

    for base in search_bases:
        # 1. Misma carpeta base
        if os.path.isfile(os.path.join(base, "manifest.json")):
            return base
        # 2. Subcarpetas directas (extension/, Imperio/, chrome-extension/, etc.)
        try:
            for sub in os.listdir(base):
                sub_path = os.path.join(base, sub)
                if os.path.isdir(sub_path) and os.path.isfile(os.path.join(sub_path, "manifest.json")):
                    return sub_path
        except OSError:
            pass
        # 3. Buscar recursivamente hasta 2 niveles
        for found in _glob.glob(os.path.join(base, "*", "manifest.json")):
            return os.path.dirname(found)

    return str(_FLOW_BASE_DIR_PW)  # fallback — el usuario verá el error y puede corregir

def get_app_data_path():
    """Devuelve la ruta base de datos de la aplicación según el SO"""
    system = platform.system()
    
    if system == "Windows":
        appdata = os.environ.get('APPDATA', os.path.expanduser('~\\AppData\\Roaming'))
        return os.path.join(appdata, 'VideoForge')
    elif system == "Darwin":  # macOS
        home = os.path.expanduser('~')
        return os.path.join(home, 'Library', 'Application Support', 'VideoForge')
    else:
        return os.path.join(os.path.expanduser('~'), '.config', 'VideoForge')

def get_extension_install_path():
    return os.path.join(get_app_data_path(), 'flow_extension')

def get_extension_source_path():
    if getattr(sys, 'frozen', False):
        if hasattr(sys, '_MEIPASS'):
            src = os.path.join(sys._MEIPASS, 'flow_extension')
            if os.path.exists(src):
                return src
        exe_dir = os.path.dirname(sys.executable)
        src = os.path.join(exe_dir, 'flow_extension')
        if os.path.exists(src):
            return src
    for name in ['flow_extension', 'flow_extensions']:
        if os.path.exists(name):
            return os.path.abspath(name)
    return None

def calculate_dir_hash(path):
    if not os.path.exists(path):
        return None
    hasher = hashlib.sha256()
    for root, dirs, files in sorted(os.walk(path)):
        for file in sorted(files):
            file_path = os.path.join(root, file)
            try:
                with open(file_path, 'rb') as f:
                    for chunk in iter(lambda: f.read(65536), b''):
                        hasher.update(chunk)
            except:
                pass
    return hasher.hexdigest()

def ensure_flow_extension_installed():
    dest_path = get_extension_install_path()
    src_path = get_extension_source_path()
    
    if src_path is None or not os.path.exists(src_path):
        print("[WARNING]  No se encontró flow_extension en el paquete")
        return dest_path
    
    os.makedirs(dest_path, exist_ok=True)
    version_file = os.path.join(dest_path, '.version')
    current_hash = calculate_dir_hash(src_path)
    
    need_install = True
    if os.path.exists(version_file):
        try:
            with open(version_file, 'r') as f:
                saved_hash = f.read().strip()
            if saved_hash == current_hash:
                need_install = False
                print(f"[OK] flow_extension ya está actualizado en {dest_path}")
        except:
            pass
    
    if need_install:
        print(f"📦 Instalando flow_extension en {dest_path}")
        try:
            if os.path.exists(dest_path):
                shutil.rmtree(dest_path)
            shutil.copytree(src_path, dest_path)
            with open(version_file, 'w') as f:
                f.write(current_hash)
            print("[OK] flow_extension instalado correctamente")
        except Exception as e:
            print(f"[ERROR] Error al instalar flow_extension: {e}")
    
    return dest_path

# ============================================
# INSTALAR AL INICIO
# ============================================

FLOW_EXTENSION_PATH = ensure_flow_extension_installed()
print(f"📂 flow_extension instalado en: {FLOW_EXTENSION_PATH}")

def _meta_find_extension_dir() -> str:
    """
    Busca específicamente la carpeta de extensión que contiene meta_bridge.js.
    Hay múltiples directorios con manifest.json en Downloads; debemos encontrar
    el correcto (flow_extension/) que tiene los scripts de Meta AI.
    """
    import glob as _glob

    search_bases = [str(_FLOW_BASE_DIR_PW)]
    _meipass = getattr(sys, "_MEIPASS", None)
    if _meipass and _meipass not in search_bases:
        search_bases.append(_meipass)

    for base in search_bases:
        # 1. La misma carpeta base contiene meta_bridge.js
        if os.path.isfile(os.path.join(base, "meta_bridge.js")):
            return base
        # 2. Subcarpetas — buscar la que tenga meta_bridge.js
        try:
            for sub in sorted(os.listdir(base)):   # sorted para orden determinista
                sub_path = os.path.join(base, sub)
                if os.path.isdir(sub_path) and os.path.isfile(os.path.join(sub_path, "meta_bridge.js")):
                    return sub_path
        except OSError:
            pass
        # 3. Glob recursivo hasta 2 niveles
        for found in sorted(_glob.glob(os.path.join(base, "*", "meta_bridge.js"))):
            return os.path.dirname(found)

    # Fallback: usar el finder genérico de Flow
    return _flow_find_extension_dir()


def _flow_find_chromium_exe() -> str:
    """
    Busca Chromium/Chrome priorizando Playwright (único que acepta --load-extension sin restricciones).
    Fallback: Chromium portable junto al exe, luego Chrome del sistema.
    """
    import glob as _g
    _local = os.environ.get("LOCALAPPDATA", "") or os.path.join(os.path.expanduser("~"), "AppData", "Local")
    _home  = os.path.expanduser("~")
    _appdata = os.environ.get('APPDATA', os.path.expanduser('~\\AppData\\Roaming'))
    _prog = os.path.join(_appdata, 'VideoForge')
    _prog86 = _prog 
    _exe_dir = str(_FLOW_BASE_DIR_PW)  # carpeta del .exe (o del .py en desarrollo)

    # 1. Playwright Chromium (preferido — soporta --load-extension)
    for pat in [
        os.path.join(_local, "ms-playwright", "chromium-*", "chrome-win",   "chrome.exe"),
        os.path.join(_local, "ms-playwright", "chromium-*", "chrome-win64", "chrome.exe"),
        os.path.join(_local, "ms-playwright", "chromium-*", "chrome-win32", "chrome.exe"),
        os.path.join(_home,  "AppData", "Local", "ms-playwright", "chromium-*", "chrome-win*", "chrome.exe"),
    ]:
        found = sorted(_g.glob(pat))
        if found:
            return found[-1]

    # 2. Chromium portable junto al exe (carpeta chromium/ o chrome/ al lado del .exe)
    for rel in [
        os.path.join(_exe_dir, "chromium", "chrome.exe"),
        os.path.join(_exe_dir, "chrome", "chrome.exe"),
        os.path.join(_exe_dir, "chromium-win", "chrome.exe"),
    ]:
        if os.path.isfile(rel):
            return rel

    # 3. Chromium del sistema (soporta --load-extension en la mayoría de builds)
    for candidate in [
        os.path.join(_prog,   "Chromium", "Application", "chrome.exe"),
        os.path.join(_prog86, "Chromium", "Application", "chrome.exe"),
        os.path.join(_local,  "Chromium", "Application", "chrome.exe"),
        os.path.join(_local,  "Chromium", "chrome.exe"),
    ]:
        if os.path.isfile(candidate):
            return candidate

    # 4. Google Chrome como último recurso (puede no soportar --load-extension)
    for candidate in [
        os.path.join(_prog,   "Google", "Chrome", "Application", "chrome.exe"),
        os.path.join(_prog86, "Google", "Chrome", "Application", "chrome.exe"),
        os.path.join(_local,  "Google", "Chrome", "Application", "chrome.exe"),
    ]:
        if os.path.isfile(candidate):
            return candidate

    # 5. macOS — Playwright Chromium
    import glob as _gmac
    _mac_pw_bases = [
        os.path.expanduser("~/Library/Caches/ms-playwright"),
        os.path.expanduser("~/.cache/ms-playwright"),
    ]
    for _mpb in _mac_pw_bases:
        for _pat in [
            os.path.join(_mpb, "chromium-*", "chrome-mac", "Chromium.app", "Contents", "MacOS", "Chromium"),
            os.path.join(_mpb, "chromium-*", "chrome-mac-arm", "Chromium.app", "Contents", "MacOS", "Chromium"),
        ]:
            _hits = sorted(_gmac.glob(_pat))
            if _hits:
                return _hits[-1]

    # 6. macOS — Chrome/Chromium del sistema
    for candidate in [
        "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
        "/Applications/Chromium.app/Contents/MacOS/Chromium",
        "/Applications/Google Chrome Canary.app/Contents/MacOS/Google Chrome Canary",
        os.path.expanduser("~/Applications/Google Chrome.app/Contents/MacOS/Google Chrome"),
        os.path.expanduser("~/Applications/Chromium.app/Contents/MacOS/Chromium"),
    ]:
        if os.path.isfile(candidate):
            return candidate

    return ""


def _flow_reset_profile_fingerprint(profile_dir: str, account_idx: int = 0, reset_rate_limit: bool = False):
    """
    Resetea el fingerprint del perfil de Chromium.
    reset_rate_limit=True: ademas limpia cookies de aisandbox-pa (para 429).
    """
    import os as _os, glob as _glob, json as _json, uuid as _uuid
    _default_dir = _os.path.join(profile_dir, "Default")
    if not _os.path.isdir(_default_dir):
        return

    # Cookies SQLite
    _cookies_db = _os.path.join(_default_dir, "Network", "Cookies")
    if not _os.path.isfile(_cookies_db):
        _cookies_db = _os.path.join(_default_dir, "Cookies")
    if _os.path.isfile(_cookies_db):
        try:
            import sqlite3 as _sq3
            _conn = _sq3.connect(_cookies_db, timeout=5)
            _cur  = _conn.cursor()
            if reset_rate_limit:
                # Para 429: borrar TODAS las cookies de aisandbox-pa y apis.google
                # que son las que Google usa para trackear rate limit por sesion
                _cur.execute("""
                    DELETE FROM cookies
                    WHERE host_key LIKE '%aisandbox%'
                       OR host_key LIKE '%labs.google%'
                       OR host_key LIKE '%apis.google%'
                       OR (host_key LIKE '%google%' AND name IN (
                           'NID','SOCS','AEC','__utmz','_ga',
                           '__Secure-3PAPISID','__Secure-3PSID',
                           'HSID','SSID','APISID','SAPISID'
                       ))
                """)
            else:
                _cur.execute("""
                    DELETE FROM cookies
                    WHERE host_key LIKE '%labs.google%'
                       OR host_key LIKE '%aisandbox%'
                       OR host_key LIKE '%apis.google%'
                       OR (host_key LIKE '%google%' AND name IN ('NID','SOCS','AEC','__utmz','_ga'))
                """)
            _deleted = _cur.rowcount
            _conn.commit()
            _conn.close()
            if _deleted > 0:
                _flow_log(f"[Flow] 🔄 Perfil {account_idx}: {_deleted} cookies limpiadas ({'rate limit' if reset_rate_limit else 'reCAPTCHA'})")
        except Exception:
            pass

    # LevelDB localStorage
    _ldb_dir = _os.path.join(_default_dir, "Local Storage", "leveldb")
    if _os.path.isdir(_ldb_dir):
        for _ldb in _glob.glob(_os.path.join(_ldb_dir, "*")):
            try:
                with open(_ldb, "rb") as _f: _c = _f.read(512)
                if b"labs.google" in _c or b"aisandbox" in _c or b"GCAP" in _c or b"recaptcha" in _c:
                    _os.remove(_ldb)
            except Exception: pass

    # IndexedDB
    import shutil as _shu
    for _pat in ["*labs.google*", "*aisandbox*"]:
        for _idb in _glob.glob(_os.path.join(_default_dir, "IndexedDB", _pat)):
            try: _shu.rmtree(_idb, ignore_errors=True)
            except Exception: pass

    # Rotar ClientID
    _ls_path = _os.path.join(profile_dir, "Local State")
    _ls = {}
    if _os.path.isfile(_ls_path):
        try:
            with open(_ls_path, "r", encoding="utf-8") as _f: _ls = _json.load(_f)
        except Exception: pass
    _ls.setdefault("user_experience_metrics", {})["client_id"] = str(_uuid.uuid4())
    try:
        with open(_ls_path, "w", encoding="utf-8") as _f: _json.dump(_ls, _f)
    except Exception: pass

    # Network state
    for _nf in ["Network Persistent State", "TransportSecurity"]:
        try: _os.remove(_os.path.join(_default_dir, _nf))
        except Exception: pass


def _flow_diag_log(msg: str):
    """Escribe al log normal Y a un archivo de diagnóstico junto al exe (útil en --windowed)."""
    _flow_log(msg)
    if getattr(sys, "frozen", False):
        try:
            _dlog = os.path.join(str(_FLOW_BASE_DIR_PW), "flow_debug.log")
            with open(_dlog, "a", encoding="utf-8") as _f:
                import datetime as _dt
                _f.write(f"[{_dt.datetime.now().strftime('%H:%M:%S')}] {msg}\n")
        except Exception:
            pass


def _flow_playwright_login(account_idx: int):
    """
    Lanza Chromium via sync_playwright (igual que Grok/Whisk) — funciona en PyInstaller --windowed.
    """
    import traceback as _tb, shutil as _sh_p, json as _json, uuid as _uuid_p, glob as _gl

    _flow_start_bridge()

    ext_dir = _flow_find_extension_dir()
    _flow_diag_log(f"[Flow Acc{account_idx+1}] ext_dir={ext_dir!r}")
    if not os.path.isfile(os.path.join(ext_dir, "manifest.json")):
        _flow_diag_log(f"[Flow Acc{account_idx+1}] [ERROR] manifest.json no encontrado en: {ext_dir}")
        _flow_diag_log(f"[Flow Acc{account_idx+1}]   Pon la carpeta de la extension junto al .exe")
        with _flow_chromium_lock:
            _flow_chromium_procs.pop(account_idx, None)
        return

    exe = _flow_find_chromium_exe()
    _flow_diag_log(f"[Flow Acc{account_idx+1}] exe={exe!r}")
    if not exe:
        _flow_diag_log(f"[Flow Acc{account_idx+1}] [ERROR] No se encontro Chrome/Chromium.")
        _flow_diag_log(f"[Flow Acc{account_idx+1}]   Ejecuta: python -m playwright install chromium")
        with _flow_chromium_lock:
            _flow_chromium_procs.pop(account_idx, None)
        return

    profile_dir  = str(_FLOW_BASE_DIR_PW / f"flow_profile_{account_idx}")
    _default_dir = os.path.join(profile_dir, "Default")

    # Limpieza del perfil (no-fatal — si falla, igual se lanza Chromium)
    try:
        os.makedirs(_default_dir, exist_ok=True)
        # Eliminar SingletonLock — lo deja Chromium cuando cierra de forma forzada.
        # Si existe, el nuevo proceso delega a la "instancia anterior" (ya muerta) y cierra en <3s.
        for _sl in ["SingletonLock", "SingletonCookie", "SingletonSocket"]:
            try: os.remove(os.path.join(profile_dir, _sl))
            except Exception: pass
        # Solo eliminar archivos de sesion para evitar el banner "restore from crash".
        # NO borrar Visited Links, Trust Tokens, Session Storage, Local Storage ni IndexedDB
        # porque esos datos son necesarios para que reCAPTCHA Enterprise confíe en la sesion.
        # Borrarlos hace que el perfil parezca "fresco" --> PUBLIC_ERROR_UNUSUAL_ACTIVITY.
        for _sf in ["Last Session", "Last Tabs", "Current Session", "Current Tabs",
                    "Last Browser"]:
            try: os.remove(os.path.join(_default_dir, _sf))
            except Exception: pass
        _net_dir = os.path.join(_default_dir, "Network")
        for _f in ["Reporting and NEL", "Reporting and NEL-journal",
                   "Network Persistent State"]:
            try: os.remove(os.path.join(_net_dir, _f))
            except Exception: pass
        _ls_path = os.path.join(profile_dir, "Local State")
        if os.path.isfile(_ls_path):
            try:
                with open(_ls_path, "r", encoding="utf-8") as _f: _ls = _json.load(_f)
                _ls.setdefault("user_experience_metrics", {})["client_id"] = str(_uuid_p.uuid4())
                with open(_ls_path, "w", encoding="utf-8") as _f: _json.dump(_ls, _f)
            except Exception: pass
        _ext_folder = os.path.join(_default_dir, "Extensions")
        if os.path.isdir(_ext_folder):
            try: _sh_p.rmtree(_ext_folder, ignore_errors=True)
            except Exception: pass
        os.makedirs(os.path.join(_default_dir, "Network"), exist_ok=True)
        # Marcar perfil como cerrado limpiamente — evita el banner "restore from crash"
        # y hace que Google no detecte una sesion anormal anterior
        _prefs_path = os.path.join(_default_dir, "Preferences")
        _prefs = {}
        if os.path.isfile(_prefs_path):
            try:
                with open(_prefs_path, "r", encoding="utf-8") as _f: _prefs = _json.load(_f)
            except Exception: pass
        _prefs.setdefault("profile", {}).update({"exit_type": "Normal", "exited_cleanly": True})
        _prefs.setdefault("session", {}).update({"restore_on_startup": 4, "startup_urls": [_FLOW_URL]})
        try:
            with open(_prefs_path, "w", encoding="utf-8") as _f: _json.dump(_prefs, _f)
        except Exception: pass
    except Exception as _ce:
        _flow_diag_log(f"[Flow Acc{account_idx+1}] limpieza perfil error (no-fatal): {_ce}")

    _flow_diag_log(f"[Flow Acc{account_idx+1}] Iniciando via sync_playwright...")
    _flow_log(f"[Flow Acc{account_idx+1}] Abriendo Chromium...")

    _UA = (
        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
        "AppleWebKit/537.36 (KHTML, like Gecko) "
        "Chrome/136.0.0.0 Safari/537.36"
    )

    try:
        from playwright.sync_api import sync_playwright

        # Serializar arranque: esperar turno antes de iniciar Playwright.
        # Se libera justo después de launch_persistent_context (Chrome abierto y estable).
        _flow_pw_start_sem.acquire()
        _pw_sem_released = [False]
        def _rel_sem():
            if not _pw_sem_released[0]:
                _pw_sem_released[0] = True
                _flow_pw_start_sem.release()

        with sync_playwright() as pw:
            ctx = pw.chromium.launch_persistent_context(
                profile_dir,
                headless=False,
                executable_path=exe,
                # Quitar flags de Playwright que delatan automatizacion a Google
                ignore_default_args=["--disable-extensions", "--enable-automation"],
                args=[
                    f"--load-extension={ext_dir}",
                    f"--disable-extensions-except={ext_dir}",
                    # Anti-deteccion
                    "--disable-blink-features=AutomationControlled",
                    "--exclude-switches=enable-automation",
                    "--disable-automation",
                    f"--user-agent={_UA}",
                    # Permitir que la extension haga requests a 127.0.0.1 (bridge local).
                    # Sin estas flags, Chrome 98+ bloquea fetch/WebSocket a loopback
                    # desde https://labs.google (Private Network Access policy).
                    "--disable-features=PrivateNetworkAccessSendPreflights,"
                    "PrivateNetworkAccessRespectPreflightResults,"
                    "BlockInsecurePrivateNetworkRequests",
                    # UI y estabilidad
                    "--no-sandbox",
                    "--disable-session-crashed-bubble",
                    "--hide-crash-restore-bubble",
                    # Fuerza la salida del proceso cuando se cierra la ultima ventana.
                    # Sin esto, Chromium se queda en background y ctx.on("close") nunca dispara.
                    "--disable-background-mode",
                ],
            )
            _flow_diag_log(f"[Flow Acc{account_idx+1}] Chromium abierto OK")
            _flow_log(f"[Flow Acc{account_idx+1}] Chromium abierto")
            _rel_sem()  # Chrome lanzado y estable --> el siguiente perfil puede arrancar ya

            # Anti-detección reCAPTCHA Enterprise: ocultar webdriver y otras marcas de Playwright
            try:
                ctx.add_init_script(
                    "Object.defineProperty(navigator,'webdriver',{get:()=>undefined});"
                    "try{delete navigator.__proto__.webdriver;}catch(_){}"
                    "if(typeof window.chrome==='undefined'){"
                    "  window.chrome={runtime:{},app:{isInstalled:false},"
                    "  loadTimes:function(){},csi:function(){},cast:{}};"
                    "}"
                )
            except Exception:
                pass

            # Navegar a Flow URL
            try:
                page = ctx.pages[0] if ctx.pages else ctx.new_page()
                if _FLOW_URL not in (page.url or ""):
                    page.goto(_FLOW_URL, wait_until="domcontentloaded", timeout=30000)
            except Exception: pass

            # Esperar hasta que el usuario cierre Chromium.
            # NOTA: en exes compilados (PyInstaller), el event loop asyncio de Playwright
            # no dispara ctx.on("close") de forma fiable. ctx.pages tampoco es confiable.
            # Solucion: watchdog independiente via psutil que monitorea el PID del proceso
            # a nivel de OS — funciona en .py y en .exe compilado sin depender de Playwright.
            _closed_ev = threading.Event()
            ctx.on("close", lambda: _closed_ev.set())  # Funciona en .py, bonus en .exe

            # ── Detección temprana de PID ─────────────────────────────────────────
            # Buscar el PID del proceso Chrome AHORA, mientras Chrome definitivamente
            # está corriendo (justo después de launch_persistent_context).
            # Comparación normalizada (minúsculas + barras forward) para evitar el bug
            # de Windows donde las rutas pueden variar en casing o tipo de separador.
            _chrome_pid_found = [None]
            _prof_norm_pid = profile_dir.lower().replace('\\', '/')

            def _find_pid_early():
                try:
                    import psutil as _psu_e
                    for _tries in range(12):   # intentar hasta 12s desde el lanzamiento
                        if _closed_ev.is_set():
                            return
                        for _pp in _psu_e.process_iter(["pid", "cmdline"]):
                            try:
                                _cc = " ".join(_pp.info.get("cmdline") or [])
                                _cc_n = _cc.lower().replace('\\', '/')
                                if _prof_norm_pid in _cc_n and "--type=" not in _cc_n:
                                    _chrome_pid_found[0] = _pp.pid
                                    _flow_log(f"[Flow Acc{account_idx+1}] PID detectado: {_pp.pid}")
                                    return
                            except Exception:
                                pass
                        time.sleep(1)
                    _flow_log(f"[Flow Acc{account_idx+1}] Watchdog: PID no encontrado en 12s")
                except Exception:
                    pass

            threading.Thread(target=_find_pid_early, daemon=True).start()

            def _psutil_watchdog():
                """Espera a que Chrome cierre. Usa el PID detectado al arranque."""
                # Esperar hasta 15s a que _find_pid_early encuentre el PID
                for _w in range(30):
                    if _closed_ev.is_set():
                        return
                    if _chrome_pid_found[0]:
                        break
                    time.sleep(0.5)

                if _chrome_pid_found[0]:
                    # Camino feliz: esperar directamente por el PID conocido
                    try:
                        import psutil as _psu
                        _psu.Process(_chrome_pid_found[0]).wait()
                    except Exception:
                        pass
                    _flow_log(f"[Flow Acc{account_idx+1}] PID {_chrome_pid_found[0]} terminó.")
                    _closed_ev.set()
                else:
                    # Fallback: polling cada 3s con ruta normalizada
                    _flow_log(f"[Flow Acc{account_idx+1}] Watchdog fallback: polling cada 3s")
                    try:
                        import psutil as _psu
                        while not _closed_ev.is_set():
                            time.sleep(3)
                            _still_alive = False
                            for _p2 in _psu.process_iter(["pid", "cmdline"]):
                                try:
                                    _cmd2 = " ".join(_p2.info.get("cmdline") or [])
                                    _cmd2_n = _cmd2.lower().replace('\\', '/')
                                    if _prof_norm_pid in _cmd2_n and "--type=" not in _cmd2_n:
                                        _still_alive = True
                                        break
                                except Exception:
                                    pass
                            if not _still_alive:
                                _flow_log(f"[Flow Acc{account_idx+1}] Watchdog polling: Chrome cerrado.")
                                _closed_ev.set()
                    except ImportError:
                        pass  # psutil no disponible — depender de ctx.on("close")
                    except Exception:
                        _closed_ev.set()

            threading.Thread(target=_psutil_watchdog, daemon=True).start()

            def _pages_watcher():
                """
                Detecta cuando el usuario cierra la VENTANA aunque el proceso Chrome
                siga vivo en background (--disable-background-mode no siempre funciona).
                ctx.pages se vacía en cuanto se cierra la última ventana visible.
                """
                # Esperar a que Chrome abra al menos 1 página antes de vigilar
                for _ in range(30):
                    if _closed_ev.is_set():
                        return
                    try:
                        if ctx.pages:
                            break
                    except Exception:
                        return
                    time.sleep(0.5)
                # Monitorear: cuando pages queda vacío --> ventana cerrada
                while not _closed_ev.is_set():
                    time.sleep(1)
                    try:
                        n = len(ctx.pages)
                    except Exception:
                        # Playwright context ya cerrado
                        _closed_ev.set()
                        return
                    if n == 0:
                        # Pequeña pausa: descartar falsos positivos por navegación interna
                        time.sleep(3)
                        try:
                            if len(ctx.pages) == 0:
                                _flow_log(f"[Flow Acc{account_idx+1}] Ventana cerrada (0 páginas).")
                                _closed_ev.set()
                        except Exception:
                            _closed_ev.set()
                        return

            threading.Thread(target=_pages_watcher, daemon=True).start()
            _closed_ev.wait()  # Cualquiera de los 3 watchers dispara: ctx.on("close"), psutil, o pages

            # ACTUALIZACIÓN INMEDIATA DE ESTADO — hacer esto DENTRO del bloque
            # with sync_playwright(), ANTES de que salga y haga su cleanup (que puede
            # tardar segundos). Así el botón vuelve a "Abrir Chromium" de inmediato.
            with _flow_chromium_lock:
                _flow_chromium_procs.pop(account_idx, None)
            _flow_diag_log(f"[Flow Acc{account_idx+1}] Chromium cerrado.")
            _flow_log(f"[Flow Acc{account_idx+1}] Chromium cerrado.")
            # sync_playwright continúa su cleanup aquí (fuera de nuestro control)

    except Exception as e:
        try: _rel_sem()   # liberar semáforo si falló antes de que Chrome abriera
        except Exception: pass
        _flow_diag_log(f"[Flow Acc{account_idx+1}] EXCEPCION: {e}\n{_tb.format_exc()[:800]}")
    finally:
        with _flow_chromium_lock:
            _flow_chromium_procs.pop(account_idx, None)  # idempotente, ya se hizo arriba si llegó al wait



def _flow_chromium_status() -> list:
    """Estado de cada perfil — respuesta instantanea, sin llamadas HTTP."""
    with _flow_chromium_lock:
        # Limpiar entradas muertas: threads terminados, PIDs inexistentes, Popen finalizados
        dead = []
        for idx, p in _flow_chromium_procs.items():
            if isinstance(p, threading.Thread):
                # Caso normal: thread de Playwright — muerto = Chromium ya cerrado
                if not p.is_alive():
                    dead.append(idx)
                else:
                    # Thread vivo pero quizás Chrome se cerró y el watchdog quedó atascado.
                    # Verificar con psutil si el proceso real sigue en ejecución.
                    # GRACE PERIOD: si el thread lleva < 30s creado, Chrome probablemente
                    # aún está arrancando — NO hacer scan (evita falso positivo durante startup
                    # cuando 3 perfiles abren en secuencia y uno espera el semáforo).
                    _t_age = time.time() - getattr(p, "_flow_created_at", time.time())
                    if _t_age < 30:
                        pass  # demasiado reciente — confiar en el thread
                    else:
                        try:
                            import psutil as _psu_cs
                            _pd_check = str(_FLOW_BASE_DIR_PW / f"flow_profile_{idx}").lower().replace('\\', '/')
                            _proc_alive = any(
                                _pd_check in " ".join(_px.info.get("cmdline") or []).lower().replace('\\', '/')
                                and "--type=" not in " ".join(_px.info.get("cmdline") or [])
                                for _px in _psu_cs.process_iter(["pid", "cmdline"])
                            )
                            if not _proc_alive:
                                dead.append(idx)
                        except Exception:
                            pass  # si psutil falla, confiar en el thread
            elif isinstance(p, bool):
                # Placeholder antiguo (no deberia existir con el nuevo codigo)
                pass
            elif isinstance(p, int):
                try:
                    import psutil as _psu4
                    if not _psu4.pid_exists(p): dead.append(idx)
                except ImportError: pass
            elif hasattr(p, "poll") and p.poll() is not None:
                dead.append(idx)
        for idx in dead:
            _flow_chromium_procs.pop(idx, None)
        open_idxs = set(_flow_chromium_procs.keys())
    with _flow_ws_clients_lock:
        connected_hashes = set(_flow_ws_clients.keys())

    result = []
    for i in range(_FLOW_NUM_ACCOUNTS):
        ck = _flow_load_cookie(i)
        # Obtener email del estado en memoria (ya cargado por run/accounts)
        # o hacer parsing LOCAL de la cookie (sin HTTP)
        email = ""
        try:
            with _flow_lock:
                raw = _flow_state["accounts"][i].get("email") or ""
            email = str(raw).replace(" ok", "").strip()
        except Exception:
            pass

        acc_hash  = _flow_account_hash(email) if email else None
        connected = bool(acc_hash and acc_hash in connected_hashes)

        # Si no tenemos email en memoria pero hay cookie, mostrar placeholder
        if not email and ck:
            email = f"Perfil {i+1} (cookie guardada)"

        is_open = (i in open_idxs)

        with _flow_rotation_lock:
            slot_type = "active"  if i in _flow_active_slots  else "backup"
        with _flow_banned_lock:
            ban_until = _flow_banned_until.get(acc_hash, 0) if acc_hash else 0
        banned_secs = max(0, int(ban_until - time.time()))

        result.append({
            "index":       i,
            "open":        is_open,
            "connected":   connected,
            "email":       email or f"Perfil {i+1}",
            "has_cookie":  bool(ck),
            "ext_dir":     _flow_find_extension_dir() if i == 0 else "",
            "slot_type":   slot_type,           # "active" | "backup"
            "banned_secs": banned_secs,         # 0 si no está baneada
        })
    return result


# ── Flask routes ──────────────────────────────────────────────────────────────

def _flow_flask_cors(resp):
    resp.headers["Access-Control-Allow-Origin"]  = "*"
    resp.headers["Access-Control-Allow-Methods"] = "GET, POST, OPTIONS"
    resp.headers["Access-Control-Allow-Headers"] = "Content-Type"
    return resp


@app.route("/api/flow/save-cookie", methods=["POST", "OPTIONS"])
def api_flow_save_cookie():
    if request.method == "OPTIONS":
        return _flow_flask_cors(app.make_response("")), 204
    data  = request.get_json(force=True, silent=True) or {}
    idx   = int(data.get("account", data.get("account_id", 0)))
    idx   = max(0, min(idx, _FLOW_NUM_ACCOUNTS - 1))
    cookie = (data.get("cookie") or data.get("cookie_str") or "").strip()
    if not cookie:
        return jsonify({"error": "cookie vacio"}), 400
    os.makedirs(_FLOW_COOKIES_DIR, exist_ok=True)
    ck_path = os.path.join(_FLOW_COOKIES_DIR, f"account_{idx}.txt")
    try:
        with open(ck_path, "w", encoding="utf-8") as f:
            f.write(cookie)
        sess  = _flow_get_session(cookie)
        email = sess.get("email", "")
        ok    = bool(sess.get("bearer", ""))
        if ok:
            acc_hash = _flow_account_hash(email)
            with _flow_lock:
                _flow_state["accounts"][idx].update({"ok": True, "email": email})
            return _flow_flask_cors(jsonify({"ok": True, "email": email, "hash": acc_hash}))
        return _flow_flask_cors(jsonify({"ok": False, "error": "Cookie invalida o sesion expirada"}))
    except Exception as e:
        return _flow_flask_cors(jsonify({"error": str(e)})), 500


@app.route("/api/flow/profile-dump", methods=["GET"])
def api_flow_profile_dump():
    """Muestra los archivos del perfil actual para diagnostico."""
    import os as _os
    idx = int(request.args.get("idx", 0))
    profile_dir = str(_FLOW_BASE_DIR_PW / f"flow_profile_{idx}")
    result = {"profile_dir": profile_dir, "files": [], "local_state_keys": []}
    # List all files recursively (max 2 levels)
    for root, dirs, files in _os.walk(profile_dir):
        depth = root.replace(profile_dir, "").count(_os.sep)
        if depth > 2:
            dirs.clear()
            continue
        for f in files:
            rel = _os.path.relpath(_os.path.join(root, f), profile_dir)
            size = 0
            try: size = _os.path.getsize(_os.path.join(root, f))
            except: pass
            result["files"].append({"path": rel, "size": size})
    # Show Local State keys
    ls_path = _os.path.join(profile_dir, "Local State")
    if _os.path.isfile(ls_path):
        try:
            import json as _js
            with open(ls_path, "r", encoding="utf-8") as _f:
                ls = _js.load(_f)
            result["local_state_keys"] = list(ls.keys())
        except: pass
    return _flow_flask_cors(jsonify(result))


