@app.route("/api/flow/reset-chromium", methods=["POST"])
def api_flow_reset_chromium():
    """
    Borra DEFINITIVAMENTE todos los perfiles Chromium/Playwright:
    mata procesos, elimina carpetas de perfil y limpia estado en memoria.
    Las cookies de Chrome (extensión) no se tocan.
    """
    import shutil as _sh, psutil as _psu
    killed, deleted, errors = [], [], []

    # 1. Matar procesos Playwright activos
    _profile_base = str(_FLOW_BASE_DIR_PW)
    try:
        for _proc in _psu.process_iter(["pid", "cmdline"]):
            try:
                _cmd = " ".join(_proc.info.get("cmdline") or [])
                if "flow_profile_" in _cmd and "--type=" not in _cmd:
                    _proc.kill()
                    killed.append(_proc.info["pid"])
            except Exception:
                pass
    except Exception as _e:
        errors.append(f"psutil: {_e}")

    # 2. Limpiar estado Playwright en memoria
    with _flow_chromium_lock:
        _flow_chromium_procs.clear()
    with _flow_playwright_hashes_lock:
        _flow_playwright_hashes.clear()
    with _flow_ws_clients_lock:
        _flow_ws_clients.clear()

    # 3. Eliminar carpetas de perfil Chromium
    import os as _os
    try:
        for _item in _os.listdir(_profile_base):
            if _item.startswith("flow_profile_"):
                _p = _os.path.join(_profile_base, _item)
                try:
                    _sh.rmtree(_p)
                    deleted.append(_item)
                except Exception as _e2:
                    errors.append(f"{_item}: {_e2}")
    except Exception as _e3:
        errors.append(f"listdir: {_e3}")

    _flow_log(f"[Flow] 🗑 Reset Chromium: killed={killed} deleted={deleted} errors={errors}")
    return _flow_flask_cors(jsonify({"ok": True, "killed": killed, "deleted": deleted, "errors": errors}))


@app.route("/api/flow/reset-chromium-profile", methods=["POST"])
def api_flow_reset_chromium_profile():
    """Borra un perfil Chromium específico por índice (0-based)."""
    import shutil as _sh, psutil as _psu, os as _os
    data = request.get_json(force=True, silent=True) or {}
    idx  = int(data.get("idx", -1))
    if idx < 0 or idx >= _FLOW_NUM_ACCOUNTS:
        return jsonify({"error": "idx inválido"}), 400

    profile_dir = str(_FLOW_BASE_DIR_PW / f"flow_profile_{idx}")
    killed, errors = [], []

    # Matar proceso Playwright de este perfil
    try:
        _tag = f"flow_profile_{idx}"
        for _proc in _psu.process_iter(["pid", "cmdline"]):
            try:
                _cmd = " ".join(_proc.info.get("cmdline") or [])
                if _tag in _cmd and "--type=" not in _cmd:
                    _proc.kill()
                    killed.append(_proc.info["pid"])
            except Exception:
                pass
    except Exception as _e:
        errors.append(str(_e))

    # Limpiar estado en memoria
    with _flow_chromium_lock:
        _flow_chromium_procs.pop(idx, None)
    try:
        _ck2 = _flow_load_cookie(idx)
        if _ck2:
            _sess2 = _flow_get_session(_ck2)
            _em2   = _sess2.get("email", "")
            if _em2:
                _h2 = _flow_account_hash(_em2)
                with _flow_playwright_hashes_lock:
                    _flow_playwright_hashes.discard(_h2)
                with _flow_ws_clients_lock:
                    _flow_ws_clients.pop(_h2, None)
    except Exception as _e:
        errors.append(str(_e))

    # Borrar carpeta del perfil
    deleted = False
    if _os.path.isdir(profile_dir):
        try:
            _sh.rmtree(profile_dir)
            deleted = True
        except Exception as _e:
            errors.append(str(_e))

    _flow_log(f"[Flow] 🗑 Reset perfil {idx}: killed={killed} deleted={deleted} errors={errors}")
    return _flow_flask_cors(jsonify({"ok": True, "idx": idx, "killed": killed, "deleted": deleted, "errors": errors}))


@app.route("/api/flow/run-prompts", methods=["POST"])
def api_flow_run():
    _flow_log("[Flow] /api/flow/run-prompts recibido")
    with _flow_lock:
        is_running = _flow_state["running"]
    if is_running:
        _flow_log("[Flow] [WARNING] Ya hay generacion en curso --> 409")
        return jsonify({"error": "Ya hay una generacion en curso"}), 409
    data    = request.get_json(force=True) or {}
    prompts = data.get("prompts", [])
    if isinstance(prompts, str):
        prompts = [l.strip() for l in prompts.splitlines() if l.strip()]
    if not prompts:
        _flow_log("[Flow] [WARNING] Sin prompts --> 400")
        return jsonify({"error": "Sin prompts"}), 400
    out_dir = (data.get("output_dir") or "").strip()
    if not out_dir:
        _flow_log("[Flow] [WARNING] output_dir vacio --> 400")
        return jsonify({"error": "output_dir requerido"}), 400
    model   = data.get("model", "NANO_BANANA_2")  # NANO_BANANA_2=calidad, IMAGE_GENERATION_001_IMAGEN4=rapidez
    _default_slots = 5 if model == "IMAGE_GENERATION_001_IMAGEN4" else 2
    slots   = max(1, min(10, int(data.get("slots", _default_slots))))
    aspect  = data.get("aspect_ratio", "IMAGE_ASPECT_RATIO_LANDSCAPE")
    retries = max(1, min(5, int(data.get("max_retries", 2))))
    # Imagen de referencia: data URL "data:image/jpeg;base64,..."
    ref_image = (data.get("reference_image") or "").strip() or None
    # Imagen4 puede funcionar sin referencia (texto a imagen puro)
    if model == "IMAGE_GENERATION_001_IMAGEN4" and not ref_image:
        _flow_log("[Flow] Imagen4 sin referencia — modo texto a imagen")
    # Auto-abrir browsers si se pide (para flujo idea-a-video)
    if data.get("auto_open"):
        _flow_auto_open_browsers()
    # Marcar running=True y avanzar batch_id de forma SINCRONICA antes de retornar,
    # para que el frontend no lea el estado anterior en el primer poll y dispare
    # "completada" por race condition (batch_id viejo + _flwSeen=true del batch previo).
    global _flow_batch_id
    with _flow_lock:
        _flow_batch_id += 1
        _flow_state.update({
            "running": True, "step": "running", "progress": 0,
            "total": len(prompts), "images_saved": 0,
            "last_error": None, "output_dir": out_dir, "log": [],
            "batch_id": _flow_batch_id,
        })
    # El worker resuelve el modelo final según selector y referencia
    threading.Thread(
        target=_flow_run_batch,
        args=(prompts, out_dir, slots, aspect, model, retries, ref_image),
        daemon=True,
    ).start()
    return jsonify({"ok": True, "total": len(prompts)})


@app.route("/api/flow/stop", methods=["POST"])
def api_flow_stop():
    _flow_stop.set()
    with _flow_lock:
        _flow_state["running"] = False
        _flow_state["step"]    = "idle"
    return jsonify({"ok": True})


@app.route("/api/flow/retry", methods=["POST"])
def api_flow_retry():
    raw = request.get_data(as_text=True)
    print(f"[Retry RAW] {raw[:300]}", flush=True)
    data = request.get_json(force=True) or {}
    out_dir  = (data.get("output_dir") or "").strip()
    idx      = data.get("index")
    filename = (data.get("filename") or "").strip()
    fallback_prompts = data.get("fallback_prompts") or []

    with _flow_lock:
        last = dict(_flow_last_batch) if _flow_last_batch else None
    if not last and fallback_prompts:
        last = {"prompts": fallback_prompts, "slots": 2,
                "aspect": "IMAGE_ASPECT_RATIO_LANDSCAPE",
                "model": "NANO_BANANA_2", "retries": 2, "ref_image": None}

    lp = len(last.get("prompts", [])) if last else 0
    print(f"[Retry] outdir={repr(out_dir[:60])} idx={idx} batch_prompts={lp} fallback={len(fallback_prompts)}", flush=True)

    if not out_dir or idx is None:
        return jsonify({"error": f"Faltan parámetros out_dir={bool(out_dir)} idx={idx}"}), 400
    if not last:
        return jsonify({"error": "Sin parámetros — genera al menos una vez primero"}), 400
    prompts = last.get("prompts", [])
    if idx < 0 or idx >= len(prompts):
        return jsonify({"error": f"Índice {idx} fuera de rango (total: {len(prompts)})"}), 400

    old_path = os.path.join(out_dir, filename) if filename else None
    if old_path and os.path.exists(old_path):
        try: os.remove(old_path)
        except Exception: pass

    def _retry():
        _flow_run_batch(
            [prompts[idx]], out_dir,
            last.get("slots", 2),
            last.get("aspect", "IMAGE_ASPECT_RATIO_LANDSCAPE"),
            last.get("model", "NANO_BANANA_2"),
            last.get("retries", 2),
            last.get("ref_image"),
            start_index=idx,
        )
    threading.Thread(target=_retry, daemon=True).start()
    return jsonify({"ok": True})

