# ── Playwright browser login (background thread) ──────────────────────────────
def _whisk_playwright_login(profile_id: int):
    """Abre Chrome, usuario inicia sesión, captura cookies al detectar auth."""
    try:
        from playwright.sync_api import sync_playwright
    except ImportError:
        _whisk_log(f"  [C{profile_id}] [ERROR] Playwright no instalado. "
                   "Instala: pip install playwright && python -m playwright install chromium")
        return

    profile_dir = str(_WHISK_BASE_DIR / f"chrome_profile_{profile_id}")
    os.makedirs(profile_dir, exist_ok=True)
    _whisk_log(f"  [C{profile_id}] 🌐 Abriendo Chrome — inicia sesión y navega a labs.google/fx/tools/whisk")

    try:
        with sync_playwright() as pw:
            import glob as _glob
            _local = os.environ.get("LOCALAPPDATA", "")
            _posibles = _glob.glob(os.path.join(_local, "ms-playwright", "chromium-*", "chrome-win*", "chrome.exe"))
            _exe = _posibles[0] if _posibles else None
            ctx = pw.chromium.launch_persistent_context(
                profile_dir,
                headless=False,
                executable_path=_exe,
                args=["--no-first-run", "--disable-blink-features=AutomationControlled"],
                ignore_https_errors=True,
            )
            page = ctx.pages[0] if ctx.pages else ctx.new_page()
            try:
                page.goto("https://labs.google/fx/tools/whisk", timeout=20000)
            except Exception:
                pass

            saved = False
            while True:
                try:
                    cookies = ctx.cookies()
                except Exception:
                    break  # browser cerrado

                google_ck = [c for c in cookies
                             if any(d in c.get("domain", "")
                                    for d in ["labs.google", "google.com",
                                              "accounts.google.com", "googleapis.com"])]
                # Logged in cuando tiene >5 cookies de Google con cookie de sesión
                auth_names = {"SID", "__Secure-1PSID", "__Secure-3PSID", "SAPISID", "APISID"}
                has_auth = any(c["name"] in auth_names for c in google_ck)

                if has_auth and len(google_ck) >= 5:
                    ck_str = "; ".join(f"{c['name']}={c['value']}" for c in google_ck)
                    try:
                        r = _WhiskClient(ck_str, label=f"C{profile_id}").test_auth()
                        if r["ok"]:
                            os.makedirs(_WHISK_COOKIES_DIR, exist_ok=True)
                            with open(os.path.join(_WHISK_COOKIES_DIR,
                                                   f"account_{profile_id}.txt"),
                                      "w", encoding="utf-8") as fh:
                                fh.write(ck_str)
                            _whisk_log(f"  [C{profile_id}] [OK] Cookie guardada — {r.get('user','')}")
                            saved = True
                            threading.Thread(target=_whisk_sync_profile_rows, daemon=True).start()
                    except Exception:
                        pass

                if saved:
                    time.sleep(1)
                    try:
                        ctx.close()
                    except Exception:
                        pass
                    break

                time.sleep(2)

            if not saved:
                _whisk_log(f"  [C{profile_id}] [WARNING]  Browser cerrado sin guardar sesión")
    except Exception as e:
        _whisk_log(f"  [C{profile_id}] [ERROR] Browser error: {e}")


@app.route("/api/whisk/login", methods=["POST"])
def api_whisk_login():
    try:
        data       = request.get_json(force=True, silent=True) or {}
        profile_id = int(data.get("profile", data.get("account_id", 0)))
        profile_id = max(0, min(profile_id, _WHISK_NUM_ACCOUNTS - 1))

        # Modo directo: cookie pegada manualmente (campo "cookie")
        ck = (data.get("cookie") or "").strip()
        if ck:
            ck = _w_clean_cookie(ck)
            r  = _WhiskClient(ck, label=f"C{profile_id}").test_auth()
            if not r["ok"]:
                return jsonify(error=r.get("error", "Cookie inválida o expirada")), 400
            os.makedirs(_WHISK_COOKIES_DIR, exist_ok=True)
            with open(os.path.join(_WHISK_COOKIES_DIR, f"account_{profile_id}.txt"),
                      "w", encoding="utf-8") as fh:
                fh.write(ck)
            _whisk_log(f"  [C{profile_id}] [OK] Cookie guardada directamente")
            threading.Thread(target=_whisk_sync_profile_rows, daemon=True).start()
            return jsonify(ok=True, user=r.get("user", ""))

        # Modo browser: abre Chrome en segundo plano
        threading.Thread(
            target=_whisk_playwright_login,
            args=(profile_id,),
            daemon=True
        ).start()
        return jsonify(ok=True)

    except Exception as e:
        _whisk_log(f"  login error: {e}")
        return jsonify(error=str(e)), 500

@app.route("/api/whisk/set-subject", methods=["POST", "DELETE"])
def api_whisk_set_subject():
    # DELETE o POST vacío --> limpiar sujeto
    if request.method == "DELETE":
        _whisk_subj[0] = None
        return jsonify(ok=True, cleared=True)

    os.makedirs(_WHISK_DOWNLOAD_DIR, exist_ok=True)

    # ── Formato 1: JSON con base64 (lo que envía el HTML) ────────────────
    data = request.get_json(force=True, silent=True) or {}
    b64  = data.get("image", "").strip()
    if b64:
        ext = (data.get("ext") or ".jpg").lower().lstrip(".")
        if ext not in ("jpg", "jpeg", "png", "webp", "gif", "bmp"):
            ext = "jpg"
        try:
            raw  = base64.b64decode(b64)
            path = os.path.join(_WHISK_DOWNLOAD_DIR, f"_subject.{ext}")
            with open(path, "wb") as fh:
                fh.write(raw)
            _whisk_subj[0] = path
            _whisk_log(f"  📎 Sujeto guardado: _subject.{ext} ({len(raw)//1024} KB)")
            return jsonify(ok=True, path=path)
        except Exception as e:
            return jsonify(error=f"No se pudo decodificar la imagen: {e}"), 400

    # ── Formato 2: multipart/form-data (fallback) ─────────────────────────
    img = request.files.get("image")
    if img:
        ext  = os.path.splitext(img.filename)[1].lower() or ".jpg"
        path = os.path.join(_WHISK_DOWNLOAD_DIR, f"_subject{ext}")
        img.save(path)
        _whisk_subj[0] = path
        _whisk_log(f"  📎 Sujeto guardado (multipart): {path}")
        return jsonify(ok=True, path=path)

    # Sin datos --> limpiar
    _whisk_subj[0] = None
    return jsonify(ok=True, cleared=True)



@app.route("/api/whisk/run-prompts", methods=["POST"])
def api_whisk_run():
    import traceback
    import os
    import sys
    from datetime import datetime

    try:
        if _whisk_state["running"]:
            return jsonify(error="Ya hay una corrida en progreso"), 400

        data = request.get_json(force=True, silent=True) or {}

        # prompts puede llegar como lista (JS la split-ea) o como string
        raw = data.get("prompts") or ""
        if isinstance(raw, list):
            prompts = [str(p).strip() for p in raw if str(p).strip()]
        else:
            prompts = [p.strip() for p in str(raw).splitlines() if p.strip()]

        if not prompts:
            return jsonify(error="Sin prompts — escribe al menos uno"), 400

        slots = max(1, int(data.get("slots", 1)))
        repeat = max(1, int(data.get("repeat", 1)))
        out_dir = (data.get("output_dir") or "").strip() or _WHISK_DOWNLOAD_DIR

        # ============================================
        #  DIAGNOSTICO DE CARPETAS
        # ============================================
        print("[DIAG] === INICIO whisk_run_prompts ===")
        print(f"[DIAG] sys._MEIPASS: {getattr(sys, '_MEIPASS', 'No existe')}")
        print(f"[DIAG] out_dir: {out_dir}")
        print(f"[DIAG] out_dir existe: {os.path.exists(out_dir)}")
        
        # Verificar carpeta de cookies
        cookies_dir = os.path.join(os.path.dirname(out_dir), 'cookies')
        print(f"[DIAG] cookies_dir: {cookies_dir}")
        print(f"[DIAG] cookies_dir existe: {os.path.exists(cookies_dir)}")
        
        if os.path.exists(cookies_dir):
            try:
                cookie_files = os.listdir(cookies_dir)
                print(f"[DIAG] Archivos en cookies: {cookie_files[:10]}")
                if not cookie_files:
                    print("[ERROR] No hay archivos de cookies!")
            except Exception as e:
                print(f"[DIAG] Error listando cookies: {e}")
        
        print(f"[DIAG] prompts: {len(prompts)}")
        print(f"[DIAG] slots: {slots}")
        print(f"[DIAG] repeat: {repeat}")
        print(f"[DIAG] ================================")

        import uuid as _uuid
        raw_prompts = [p for p in prompts for _ in range(repeat)]
        all_prompts = [p + f" [v{i+1}-{_uuid.uuid4().hex[:6]}]" for i, p in enumerate(raw_prompts)]
        total = len(all_prompts)

        # Imagen de referencia es opcional
        if _whisk_subj[0] and not os.path.isfile(str(_whisk_subj[0])):
            _whisk_subj[0] = None

        # Crear carpeta de salida
        try:
            os.makedirs(out_dir, exist_ok=True)
            print(f"[DIAG] Carpeta out_dir creada/verificada: {out_dir}")
        except Exception as e:
            print(f"[ERROR] No se pudo crear out_dir: {e}")
            raise

        # Limpiar archivos img_* anteriores
        try:
            from pathlib import Path
            for f in Path(out_dir).glob("img_*"):
                try: f.unlink()
                except: pass
            print(f"[DIAG] Archivos img_* limpiados en {out_dir}")
        except Exception as e:
            print(f"[DIAG] No se pudieron limpiar archivos: {e}")

        _whisk_stop.clear()
        with _whisk_lock:
            prev = {i: {
                "logged_in": _whisk_state["accounts"][i].get("logged_in", False),
                "user": _whisk_state["accounts"][i].get("user", ""),
            } for i in range(_WHISK_NUM_ACCOUNTS)}
            _whisk_state.update({
                "running": True, "step": "running",
                "progress": 0, "total": total, "images_saved": 0,
                "log": [], "output_dir": out_dir, "last_error": None,
                "accounts": [{
                    "id": i, "status": "idle", "slots": [], "jobs": 0,
                    "logged_in": prev[i]["logged_in"],
                    "user": prev[i]["user"],
                } for i in range(_WHISK_NUM_ACCOUNTS)],
            })

        threading.Thread(
            target=_whisk_run_batch,
            args=(all_prompts, slots, _whisk_subj[0], out_dir),
            daemon=True
        ).start()

        return jsonify(ok=True, total=total,
                       message=f"{total} imagen(es) en cola · {slots} slot(s)")

    except Exception as e:
        # ============================================
        #  GUARDAR ERROR EN EL ESCRITORIO DEL USUARIO
        # ============================================
        error_texto = traceback.format_exc()
        print(f"[ERROR] whisk_run_prompts falló: {e}")
        print(error_texto)
        
        try:
            desktop = os.path.expanduser("~/Desktop")
            timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
            log_path = os.path.join(desktop, f"IVR_Whisk_Error_{timestamp}.txt")
            
            with open(log_path, "w", encoding="utf-8") as f:
                f.write("=" * 60 + "\n")
                f.write("  IVR 2.5 - ERROR EN WHISK\n")
                f.write("=" * 60 + "\n\n")
                f.write(f"Fecha: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n")
                f.write(f"Usuario: {os.getlogin()}\n")
                f.write(f"PC: {os.environ.get('COMPUTERNAME', 'desconocida')}\n\n")
                f.write("=" * 60 + "\n")
                f.write("  ERROR DETALLADO\n")
                f.write("=" * 60 + "\n\n")
                f.write(error_texto)
                f.write("\n\n" + "=" * 60 + "\n")
                f.write("  VARIABLES DE ENTORNO\n")
                f.write("=" * 60 + "\n\n")
                f.write(f"APPDATA: {os.environ.get('APPDATA', 'No existe')}\n")
                f.write(f"TEMP: {os.environ.get('TEMP', 'No existe')}\n")
                f.write(f"USERPROFILE: {os.environ.get('USERPROFILE', 'No existe')}\n")
                f.write("\n" + "=" * 60 + "\n")
                f.write("  FIN DEL REPORTE\n")
                f.write("=" * 60 + "\n")
            
            print(f"[DIAG] Error guardado en: {log_path}")
        except Exception as log_error:
            print(f"[ERROR] No se pudo guardar el log: {log_error}")

        _whisk_log(f"[ERROR] run-prompts error: {traceback.format_exc()}")
        return jsonify(error=str(e), trace=error_texto), 500


@app.route("/api/pollination/generate", methods=["POST"])
def api_pollination_generate():
    """Proxy al webhook n8n de Pollination; guarda img_* en la misma carpeta que Whisk (output_dir)."""
    try:
        data = request.get_json(force=True, silent=True) or {}
        raw_p = data.get("prompts") or []
        if isinstance(raw_p, str):
            prompts = [p.strip() for p in raw_p.splitlines() if p.strip()]
        else:
            prompts = [str(p).strip() for p in raw_p if str(p).strip()]
        if not prompts:
            return jsonify(error="Sin prompts"), 400

        ratio = (data.get("ratio") or "16:9").strip()
        try:
            w = int(data.get("width") or 1920)
            h = int(data.get("height") or 1097)
        except (TypeError, ValueError):
            w, h = 1920, 1097

        out_dir = (data.get("output_dir") or "").strip() or _WHISK_DOWNLOAD_DIR
        try:
            os.makedirs(out_dir, exist_ok=True)
        except OSError as e:
            return jsonify(error=f"No se pudo crear carpeta: {e}"), 400

        payload = {"prompts": prompts, "ratio": ratio, "width": w, "height": h}
        try:
            r = requests.post(_POLLINATION_WEBHOOK, json=payload, timeout=600)
            r.raise_for_status()
            try:
                result = r.json()
            except ValueError:
                ct = (r.headers.get("content-type") or "").lower()
                body = (r.text or "")[:400]
                return jsonify(
                    error="n8n no devolvió JSON válido",
                    status=r.status_code,
                    content_type=ct,
                    body_preview=body,
                ), 502
        except requests.exceptions.RequestException as e:
            return jsonify(error=f"n8n / red: {e}"), 502
    except Exception as e:
        # Evita que el cliente reciba HTML (y rompa con Unexpected token '<')
        return jsonify(error=f"Pollination proxy error: {e}"), 500

    if isinstance(result, dict) and "images" in result:
        images_list = result["images"]
    elif isinstance(result, list):
        images_list = result
    else:
        images_list = [result]

    def _extract_b64_mime(item):
        if not isinstance(item, dict):
            return None, None
        j = item.get("json") or {}
        b64 = item.get("base64") or j.get("base64")
        mime = item.get("mime") or j.get("mime") or "image/png"
        return b64, mime

    def _next_img_index():
        mx = 0
        if not FPath(out_dir).exists():
            return 1
        for f in FPath(out_dir).glob("img_*"):
            try:
                n = int(f.stem.split("_", 1)[1])
                mx = max(mx, n)
            except (ValueError, IndexError):
                pass
        return mx + 1

    idx = _next_img_index()
    saved = []
    for item in images_list:
        b64, mime = _extract_b64_mime(item)
        if not b64:
            continue
        b64 = "".join(str(b64).split())
        try:
            raw_img = base64.b64decode(b64, validate=False)
        except Exception:
            continue
        m = (mime or "image/png").lower()
        if "jpeg" in m or "jpg" in m:
            ext = ".jpg"
        elif "webp" in m:
            ext = ".webp"
        elif "png" in m:
            ext = ".png"
        else:
            ext = ".png"
        fname = f"img_{idx:05d}{ext}"
        path = os.path.join(out_dir, fname)
        with open(path, "wb") as fh:
            fh.write(raw_img)
        saved.append(fname)
        idx += 1

    if not saved:
        return jsonify(error="n8n no devolvió imágenes base64 válidas"), 502

    with _whisk_lock:
        _whisk_state["output_dir"] = out_dir

    return jsonify(ok=True, images=saved, count=len(saved), output_dir=out_dir)


