# GENTUBE — Playwright/Chromium automation for gentube.app
#   Mismo patrón que Whisk: hasta 5 cuentas, cookies persistidas en
#   disco, login visual con persistent context, worker por cuenta.
# ══════════════════════════════════════════════════════════════════

_GT_NUM_ACCOUNTS  = 5
_GT_BASE_DIR      = (
    FPath(sys.executable).parent
    if getattr(sys, "frozen", False) else
    FPath(os.path.abspath(__file__)).parent
)
_GT_COOKIES_DIR   = str(_GT_BASE_DIR / "gentube_cookies")
_GT_URL           = "https://www.gentube.app/create"
_GT_WS_PORT       = 5558

os.makedirs(_GT_COOKIES_DIR, exist_ok=True)

# ── WebSocket server para la extensión de Chrome ──────────────────────
import queue as _gt_ws_queue_mod
import struct as _struct

_gt_ws_clients    = {}   # account_id --> ws_socket
_gt_ws_lock       = threading.Lock()
_gt_pending       = {}   # requestId --> {"event": Event, "result": dict}
_gt_pending_lock  = threading.Lock()

def _gt_ws_server():
    """WebSocket server minimal en port 5558 para la extensión de Chrome."""
    import socket as _sock
    import hashlib as _hl
    import base64 as _b64_ws

    def _ws_handshake(conn):
        data = conn.recv(4096).decode('utf-8', errors='replace')
        key = ''
        for line in data.split('\r\n'):
            if 'Sec-WebSocket-Key' in line:
                key = line.split(': ')[1].strip()
        accept = _b64_ws.b64encode(
            _hl.sha1((key + '258EAFA5-E914-47DA-95CA-C5AB0DC85B11').encode()).digest()
        ).decode()
        response = (
            'HTTP/1.1 101 Switching Protocols\r\n'
            'Upgrade: websocket\r\n'
            'Connection: Upgrade\r\n'
            f'Sec-WebSocket-Accept: {accept}\r\n\r\n'
        )
        conn.send(response.encode())

    def _ws_recv(conn):
        try:
            header = conn.recv(2)
            if len(header) < 2: return None
            opcode = header[0] & 0x0f
            if opcode == 8: return None  # close
            masked = (header[1] & 0x80) != 0
            length = header[1] & 0x7f
            if length == 126:
                length = _struct.unpack('>H', conn.recv(2))[0]
            elif length == 127:
                length = _struct.unpack('>Q', conn.recv(8))[0]
            mask = conn.recv(4) if masked else b''
            data = conn.recv(length)
            if masked:
                data = bytes(b ^ mask[i % 4] for i, b in enumerate(data))
            return data.decode('utf-8', errors='replace')
        except Exception:
            return None

    def _ws_send(conn, msg):
        try:
            data = msg.encode('utf-8')
            n = len(data)
            if n <= 125:
                header = bytes([0x81, n])
            elif n <= 65535:
                header = bytes([0x81, 126]) + _struct.pack('>H', n)
            else:
                header = bytes([0x81, 127]) + _struct.pack('>Q', n)
            conn.send(header + data)
        except Exception:
            pass

    def _handle_client(conn, addr):
        import json as _json_ws
        try:
            _ws_handshake(conn)
            account_id = None
            while True:
                raw = _ws_recv(conn)
                if raw is None: break
                try:
                    msg = _json_ws.loads(raw)
                except Exception:
                    continue

                t = msg.get('type', '')

                if t == 'register':
                    account_id = msg.get('account', 'account_0')
                    with _gt_ws_lock:
                        _gt_ws_clients[account_id] = conn
                    _gt_log(f"  [GT-Ext] Cuenta conectada: {account_id}")

                elif t == 'heartbeat':
                    pass  # keep alive

                elif t == 'result':
                    rid = msg.get('requestId')
                    with _gt_pending_lock:
                        entry = _gt_pending.get(rid)
                    if entry:
                        entry['result'] = msg
                        entry['event'].set()

        except Exception:
            pass
        finally:
            if account_id:
                with _gt_ws_lock:
                    if _gt_ws_clients.get(account_id) is conn:
                        del _gt_ws_clients[account_id]
                _gt_log(f"  [GT-Ext] Cuenta desconectada: {account_id}")
            try: conn.close()
            except: pass

    srv = _sock.socket(_sock.AF_INET, _sock.SOCK_STREAM)
    srv.setsockopt(_sock.SOL_SOCKET, _sock.SO_REUSEADDR, 1)
    try:
        srv.bind(('127.0.0.1', _GT_WS_PORT))
        srv.listen(20)
        while True:
            conn, addr = srv.accept()
            threading.Thread(target=_handle_client, args=(conn, addr), daemon=True).start()
    except Exception as e:
        pass
    finally:
        srv.close()

# Arrancar WebSocket server en background
threading.Thread(target=_gt_ws_server, daemon=True).start()


def _gt_send_request_ws(account_id: str, request_id: str, prompt: str, ratio: str, timeout: int = 60) -> dict:
    """Envía request a la extensión — HTTP polling o WebSocket según modo."""
    with _gt_ws_lock:
        conn = _gt_ws_clients.get(account_id)

    # HTTP polling mode (conn is None = extensión HTTP)
    if account_id in _ext_tabs:
        evt = threading.Event()
        with _gt_pending_lock:
            _gt_pending[request_id] = {"event": evt, "result": None}
        with _ext_lock:
            _ext_requests[account_id] = {
                "requestId": request_id, "prompt": prompt, "ratio": ratio
            }
        evt.wait(timeout=timeout)
        with _gt_pending_lock:
            result = _gt_pending.pop(request_id, {}).get('result')
        with _ext_lock:
            _ext_requests.pop(account_id, None)
        if not result:
            return {"ok": False, "error": "timeout"}
        return result

    # WebSocket mode
    if not conn:
        return {"ok": False, "error": f"extensión no conectada para {account_id}"}

    import json as _json_ws
    evt = threading.Event()
    with _gt_pending_lock:
        _gt_pending[request_id] = {"event": evt, "result": None}

    msg = _json_ws.dumps({"type": "generate", "requestId": request_id,
                          "prompt": prompt, "ratio": ratio})
    data = msg.encode('utf-8')
    n = len(data)
    if n <= 125:
        header = bytes([0x81, n])
    elif n <= 65535:
        header = bytes([0x81, 126]) + _struct.pack('>H', n)
    else:
        header = bytes([0x81, 127]) + _struct.pack('>Q', n)
    try:
        conn.send(header + data)
    except Exception as e:
        with _gt_pending_lock:
            _gt_pending.pop(request_id, None)
        return {"ok": False, "error": str(e)}

    evt.wait(timeout=timeout)
    with _gt_pending_lock:
        result = _gt_pending.pop(request_id, {}).get('result')
    if not result:
        return {"ok": False, "error": "timeout"}
    return result

_gt_state = {
    "running": False, "step": "idle", "progress": 0, "total": 0,
    "images_saved": 0, "log": [], "output_dir": "",
    "accounts": [{"id": i, "logged_in": False, "user": "",
                  "has_cookie": False} for i in range(_GT_NUM_ACCOUNTS)],
}
_gt_lock       = threading.Lock()
_gt_stop       = threading.Event()
_gt_images_dir = ""


def _gt_log(msg: str):
    with _gt_lock:
        _gt_state["log"].append(msg)
        if len(_gt_state["log"]) > 600:
            _gt_state["log"] = _gt_state["log"][-600:]


def _gt_playwright_ok() -> bool:
    try:
        import importlib
        return importlib.util.find_spec("playwright") is not None
    except Exception:
        return False


def _gt_cookie_path(account_id: int) -> str:
    return os.path.join(_GT_COOKIES_DIR, f"account_{account_id}.txt")


def _gt_read_cookie(account_id: int) -> str:
    p = _gt_cookie_path(account_id)
    if not os.path.isfile(p):
        return ""
    try:
        return open(p, encoding="utf-8").read().strip()
    except Exception:
        return ""


def _gt_probe_session(cookie_str: str) -> dict:
    """Verifica sesión de gentube. Si tiene __session = está logueado."""
    if not cookie_str:
        return {"ok": False, "user": ""}
    # __session presente = sesión válida (igual que Whisk con SID)
    _SESSION_NAMES = {"__session", "__session_yakpvnhU"}
    parts = {p.split("=")[0].strip(): p.split("=", 1)[1].strip()
             for p in cookie_str.split(";") if "=" in p}
    has_session = any(k in _SESSION_NAMES and v for k, v in parts.items())
    if not has_session:
        return {"ok": False, "user": ""}
    # Intentar obtener email del JWT en __session (opcional)
    user = ""
    try:
        import base64 as _b64, json as _json
        for name in _SESSION_NAMES:
            val = parts.get(name, "")
            if val and "." in val:
                payload = val.split(".")[1]
                payload += "=" * (4 - len(payload) % 4)
                d = _json.loads(_b64.b64decode(payload).decode("utf-8", errors="ignore"))
                user = d.get("email") or d.get("sub") or ""
                if user:
                    break
    except Exception:
        pass
    return {"ok": True, "user": user}
def _gt_startup_sync():
    """Sincronización inicial de cuentas al arrancar (no bloquea Flask)."""
    time.sleep(1.5)
    try:
        _gt_sync_profiles()
    except Exception:
        pass

threading.Thread(target=_gt_startup_sync, daemon=True).start()


def _gt_read_session_from_profile(account_id: int) -> str:
    """Las cookies de Chromium están encriptadas en Windows (DPAPI).
    Solo podemos leerlas cuando el browser está abierto via ctx.cookies().
    Esta función no puede leer cookies encriptadas — siempre retorna vacío.
    La única fuente válida es el archivo .txt guardado durante el login."""
    return ""


def _gt_sync_profiles():
    """Lee cookies del perfil Chromium y verifica sesiones."""
    from concurrent.futures import ThreadPoolExecutor as _TPE, as_completed as _ac

    def _one(i):
        ck = _gt_read_cookie(i)
        if not ck:
            return i, {"logged_in": False, "user": ""}
        pr = _gt_probe_session(ck)
        if not pr["ok"]:
            # Cookie inválida — borrar
            try: os.remove(_gt_cookie_path(i))
            except: pass
            return i, {"logged_in": False, "user": ""}
        return i, {"logged_in": True, "user": pr.get("user", "")}

    results = {}
    try:
        with _TPE(max_workers=_GT_NUM_ACCOUNTS) as ex:
            futs = [ex.submit(_one, i) for i in range(_GT_NUM_ACCOUNTS)]
            for fut in _ac(futs, timeout=20):
                try:
                    idx, row = fut.result()
                    results[idx] = row
                except Exception:
                    pass
    except Exception:
        pass

    with _gt_lock:
        for i in range(_GT_NUM_ACCOUNTS):
            row = results.get(i, {"logged_in": False, "user": ""})
            _gt_state["accounts"][i]["logged_in"]  = row["logged_in"]
            _gt_state["accounts"][i]["user"]       = row.get("user", "")
            _gt_state["accounts"][i]["has_cookie"] = row["logged_in"]


def _gt_playwright_login(account_id: int):
    """Abre Chrome, usuario inicia sesión en gentube.app, captura __session.
    Patrón idéntico a Whisk — estable y probado."""
    try:
        from playwright.sync_api import sync_playwright
    except ImportError:
        _gt_log(f"  [C{account_id}] [ERROR] Playwright no instalado.")
        return

    profile_dir = str(_GT_BASE_DIR / f"gt_profile_{account_id}")
    os.makedirs(profile_dir, exist_ok=True)
    _gt_log(f"  [C{account_id}] 🌐 Abriendo Chrome — inicia sesión en gentube.app")

    try:
        with sync_playwright() as pw:
            import glob as _glob
            _local = os.environ.get("LOCALAPPDATA", "")
            _posibles = _glob.glob(os.path.join(_local, "ms-playwright",
                                                "chromium-*", "chrome-win*", "chrome.exe"))
            _exe = _posibles[0] if _posibles else None
            ctx = pw.chromium.launch_persistent_context(
                profile_dir,
                headless=False,
                executable_path=_exe,
                args=["--no-first-run", "--disable-blink-features=AutomationControlled"],
                ignore_https_errors=True,
            )
            page = ctx.pages[0] if ctx.pages else ctx.new_page()
            try:
                page.goto("https://www.gentube.app/create", timeout=20000)
            except Exception:
                pass

            # Cookies de sesión real de gentube (Clerk)
            _SESSION_NAMES = {"__session", "__session_yakpvnhU"}

            saved = False
            while True:
                try:
                    cookies = ctx.cookies()
                except Exception:
                    break  # browser cerrado por el usuario

                gt_ck = [c for c in cookies
                         if "gentube" in c.get("domain", "").lower()
                         or "clerk" in c.get("domain", "").lower()]

                session_ck = [c for c in gt_ck if c["name"] in _SESSION_NAMES]

                if session_ck:
                    ck_str = "; ".join(f"{c['name']}={c['value']}" for c in gt_ck)
                    pr = _gt_probe_session(ck_str)
                    if pr["ok"]:
                        with open(_gt_cookie_path(account_id), "w", encoding="utf-8") as fh:
                            fh.write(ck_str)
                        _gt_log(f"  [C{account_id}] [OK] Cookie guardada — {pr.get('user', '')}")
                        saved = True
                        threading.Thread(target=_gt_sync_profiles, daemon=True).start()

                if saved:
                    time.sleep(1)
                    try:
                        ctx.close()
                    except Exception:
                        pass
                    break

                time.sleep(2)

            if not saved:
                _gt_log(f"  [C{account_id}] [WARNING] Browser cerrado sin guardar sesión")
    except Exception as e:
        _gt_log(f"  [C{account_id}] [ERROR] Error: {e}")

def _gt_worker(prompts: list, slots: int, repeat: int,
               output_dir: str, ratio: str, quality: str):
    """
    Genera imágenes usando N slots (browsers headless) en paralelo.
    Cada slot mantiene su browser abierto y reutiliza la página entre imágenes
    para evitar el overhead de cargar gentube.app en cada prompt.
    """
    global _gt_images_dir
    _gt_images_dir = output_dir
    os.makedirs(output_dir, exist_ok=True)

    # Recopilar cookies disponibles
    cookies_list = []
    for i in range(_GT_NUM_ACCOUNTS):
        ck = _gt_read_cookie(i)
        if ck:
            cookies_list.append((i, ck))

    if not cookies_list:
        _gt_log("[ERROR] No hay cuentas configuradas. Usa 🔑 Login primero.")
        with _gt_lock:
            _gt_state.update(running=False, step="idle")
        return

    try:
        from playwright.sync_api import sync_playwright
    except ImportError:
        _gt_log("[ERROR] Playwright no instalado.")
        with _gt_lock:
            _gt_state.update(running=False, step="idle")
        return

    all_tasks  = prompts * repeat
    total      = len(all_tasks)
    effective_slots = min(slots, total)  # slots limitados solo por total de tareas

    with _gt_lock:
        _gt_state.update(running=True, step="running", progress=0,
                         total=total, images_saved=0, output_dir=output_dir)
    _gt_log(f"🚀 GenTube: {total} imágenes · {effective_slots} slots · {len(cookies_list)} cuentas")

    import glob as _glob
    _local    = os.environ.get("LOCALAPPDATA", "")
    _posibles = _glob.glob(os.path.join(_local, "ms-playwright",
                                        "chromium-*", "chrome-win*", "chrome.exe"))
    _exe      = _posibles[0] if _posibles else None

    # Cola de tareas compartida entre slots — cada tarea lleva (task_idx, prompt, retries)
    import queue as _queue
    task_q      = _queue.Queue()
    for i, p in enumerate(all_tasks):
        task_q.put((i, p, 0))

    saved_count = [0]
    done_count  = [0]
    errors      = [0]
    lock        = threading.Lock()

    def _slot_worker(slot_idx: int, acc_id: int, cookie_str: str):
        """Un slot mantiene su propio browser y procesa tareas de la cola."""
        with sync_playwright() as pw:
            browser = pw.chromium.launch(
                headless=True,
                executable_path=_exe,
                args=["--no-first-run",
                      "--disable-blink-features=AutomationControlled",
                      "--disable-dev-shm-usage",
                      "--no-sandbox"])
            ctx = browser.new_context(
                viewport={"width": 1280, "height": 800},
                user_agent="Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
            )
            # Inyectar cookies
            for ck_part in cookie_str.split(";"):
                ck_part = ck_part.strip()
                if "=" not in ck_part: continue
                name, _, val = ck_part.partition("=")
                for domain in [".gentube.app", "gentube.app", "www.gentube.app"]:
                    try:
                        ctx.add_cookies([{"name": name.strip(), "value": val.strip(),
                                          "domain": domain, "path": "/"}])
                        break
                    except Exception:
                        pass

            page = ctx.new_page()

            # Bloquear recursos innecesarios para acelerar carga
            def _block_route(route):
                url = route.request.url
                rt  = route.request.resource_type
                # Bloquear analytics, ads, fonts, imágenes del sitio (excepto las generadas)
                if (rt in ("image", "font", "media") and "cloudfront.net" not in url) or \
                   any(d in url for d in ["google-analytics", "googleads", "doubleclick",
                                          "pinterest", "axiom.co", "posthog", "ph.gentube"]):
                    route.abort()
                else:
                    route.continue_()
            page.route("**/*", _block_route)
            page_loaded = False
            pre_urls    = set()
            captured_cf = []

            def _on_resp(r):
                url = r.url; ct = r.headers.get("content-type","")
                if "cloudfront.net" in url and "image" in ct and r.status==200 and "profile_" not in url:
                    captured_cf.append(url)
            page.on("response", _on_resp)

            try:
                while not _gt_stop.is_set():
                    try:
                        task_idx, prompt, retries = task_q.get_nowait()
                    except _queue.Empty:
                        break

                    try:
                        # Cargar página solo la primera vez por slot
                        if not page_loaded:
                            page.goto(_GT_URL, timeout=60000, wait_until="domcontentloaded")
                            # Esperar a que React monte el textarea
                            try:
                                page.wait_for_selector("textarea", timeout=15000)
                            except Exception:
                                pass
                            time.sleep(0.2)
                            for img in page.query_selector_all("img"):
                                s = img.get_attribute("src") or ""
                                if s: pre_urls.add(s[:200])
                            page_loaded = True
                            _gt_log(f"  [S{slot_idx}/C{acc_id}] Página cargada")

                        _gt_log(f"  [S{slot_idx}|{task_idx+1}/{total}] {prompt[:55]}…")

                        # Una sola llamada JS que: limpia, escribe prompt, instala observer y clicka
                        del captured_cf[:]
                        result = page.evaluate(f"""
                            () => {{
                                // 1. Limpiar y escribir prompt en textarea
                                const ta = document.querySelector('textarea');
                                if (!ta) return 'no_textarea';
                                ta.focus();
                                const nativeSet = Object.getOwnPropertyDescriptor(
                                    window.HTMLTextAreaElement.prototype, 'value').set;
                                nativeSet.call(ta, {prompt!r});
                                ta.dispatchEvent(new Event('input', {{bubbles:true}}));
                                ta.dispatchEvent(new Event('change', {{bubbles:true}}));

                                // 2. Instalar MutationObserver + interval poll ANTES del click
                                window.__gt_img = null;
                                window.__gt_pre = new Set(
                                    Array.from(document.querySelectorAll('img'))
                                         .map(i => (i.src||'').substring(0,200))
                                         .filter(Boolean)
                                );
                                const _check = () => {{
                                    for (const img of document.querySelectorAll('img')) {{
                                        const s = img.src || '';
                                        if (s.startsWith('data:image') && s.length > 5000
                                                && !window.__gt_pre.has(s.substring(0,200))) {{
                                            window.__gt_img = s; return;
                                        }}
                                    }}
                                }};
                                const obs = new MutationObserver(_check);
                                obs.observe(document.body, {{subtree:true, childList:true,
                                                             attributes:true, attributeFilter:['src']}});
                                // Poll interval como backup (React puede reemplazar nodos)
                                window.__gt_poll = setInterval(_check, 150);
                                window.__gt_obs = obs;

                                // 3. Click botón generar (flecha ↗)
                                const r = ta.getBoundingClientRect();
                                const candidates = Array.from(document.querySelectorAll('button'))
                                    .filter(b => {{
                                        const br = b.getBoundingClientRect();
                                        const cls = b.className || '';
                                        return b.offsetParent !== null && !b.disabled &&
                                               b.textContent.trim() === '' &&
                                               br.y >= r.top - 20 && br.y <= r.bottom + 60 &&
                                               br.x >= r.right - 60 && !cls.includes('absolute');
                                    }});
                                candidates.sort((a,b) => {{
                                    const ar=a.getBoundingClientRect(), br=b.getBoundingClientRect();
                                    return Math.hypot(ar.x-r.right,ar.y-r.top)
                                          -Math.hypot(br.x-r.right,br.y-r.top);
                                }});
                                if (candidates.length > 0) {{ candidates[0].click(); return 'ok'; }}
                                return 'no_btn';
                            }}
                        """)

                        if result != 'ok':
                            _gt_log(f"  [S{slot_idx}] {result}, recargando...")
                            page_loaded = False
                            pre_urls.clear()
                            # Detectar si la sesión expiró (redirigió al login)
                            try:
                                cur_url = page.url
                                if 'sign-in' in cur_url or 'login' in cur_url or 'clerk' in cur_url:
                                    _gt_log(f"  [S{slot_idx}] ⚠ Sesión expirada C{acc_id} — usa 🔑 Login")
                                    ck_path = _gt_cookie_path(acc_id)
                                    if os.path.isfile(ck_path): os.remove(ck_path)
                                    threading.Thread(target=_gt_sync_profiles, daemon=True).start()
                                    # Reencolar y salir de este slot
                                    if retries < 3: task_q.put((task_idx, prompt, retries+1))
                                    with lock:
                                        done_count[0] += 1
                                        with _gt_lock: _gt_state["progress"] = min(done_count[0], total)
                                    task_q.task_done()
                                    break
                            except Exception: pass
                            if retries < 3:
                                task_q.put((task_idx, prompt, retries+1))
                            with lock:
                                done_count[0] += 1
                                with _gt_lock:
                                    _gt_state["progress"] = min(done_count[0], total)
                            task_q.task_done()
                            continue

                        # Poll window.__gt_img — se actualiza por MutationObserver al instante
                        import base64 as _b64
                        result_img = None
                        for tick in range(90):
                            time.sleep(0.2)
                            try:
                                ds = page.evaluate("() => window.__gt_img || null")
                                if ds and ds[:200] not in pre_urls:
                                    try: page.evaluate("() => { if(window.__gt_obs) window.__gt_obs.disconnect(); if(window.__gt_poll) clearInterval(window.__gt_poll); }")
                                    except: pass
                                    result_img = ('b64', ds)
                                    break
                                # CloudFront fallback
                                new_cf = [u for u in captured_cf if u not in pre_urls]
                                if new_cf:
                                    result_img = ('url', new_cf[-1])
                                    break
                            except Exception:
                                pass

                        if not result_img:
                            _gt_log(f"  [S{slot_idx}|{task_idx+1}] ⚠ Sin imagen, reintentando...")
                            page_loaded = False
                            pre_urls.clear()
                            if retries < 3:
                                task_q.put((task_idx, prompt, retries+1))
                            with lock:
                                done_count[0] += 1
                                with _gt_lock:
                                    _gt_state["progress"] = min(done_count[0], total)
                            task_q.task_done()
                            continue  # no llega al finally de abajo
                        else:
                            ts    = int(time.time() * 1000)
                            if result_img[0] == 'b64':
                                header, _, b64data = result_img[1].partition(",")
                                ext   = "webp" if "webp" in header else "png"
                                fname = f"gt_{task_idx+1:04d}_{ts}.{ext}"
                                fpath = os.path.join(output_dir, fname)
                                with open(fpath, "wb") as fh:
                                    fh.write(_b64.b64decode(b64data))
                            else:
                                import urllib.request as _ur
                                opener = _ur.build_opener()
                                opener.addheaders = [("User-Agent","Mozilla/5.0")]
                                img_data = opener.open(result_img[1], timeout=30).read()
                                ext   = "webp" if result_img[1].endswith(".webp") else "png"
                                fname = f"gt_{task_idx+1:04d}_{ts}.{ext}"
                                fpath = os.path.join(output_dir, fname)
                                with open(fpath, "wb") as fh:
                                    fh.write(img_data)

                            with lock:
                                saved_count[0] += 1
                                with _gt_lock:
                                    _gt_state["images_saved"] = saved_count[0]
                            _gt_log(f"  [OK] [S{slot_idx}|{task_idx+1}] {fname}")

                            # Registrar imagen generada en pre_urls para próxima iteración
                            if result_img[0] == 'b64':
                                pre_urls.add(result_img[1][:200])

                    except Exception as e2:
                        _gt_log(f"  [S{slot_idx}|{task_idx+1}] [ERROR] {str(e2)[:80]}")
                        page_loaded = False
                        pre_urls.clear()
                        if retries < 3:
                            task_q.put((task_idx, prompt, retries+1))
                    finally:
                        with lock:
                            done_count[0] += 1
                            with _gt_lock:
                                _gt_state["progress"] = min(done_count[0], total)
                        task_q.task_done()

            finally:
                try: browser.close()
                except Exception: pass

    # Lanzar slots en paralelo, round-robin de cuentas
    threads = []
    for slot_idx in range(effective_slots):
        acc_id, cookie_str = cookies_list[slot_idx % len(cookies_list)]
        t = threading.Thread(target=_slot_worker,
                             args=(slot_idx, acc_id, cookie_str), daemon=True)
        t.start()
        threads.append(t)

    for t in threads:
        t.join()

    _gt_log(f"🎉 Finalizado. {saved_count[0]}/{total} imágenes · {errors[0]} errores.")
    with _gt_lock:
        _gt_state.update(running=False, step="done",
                         progress=done_count[0], images_saved=saved_count[0])


@app.route("/api/gentube/status")
def gt_status():
    with _gt_lock:
        st = {
            "running":      _gt_state["running"],
            "step":         _gt_state["step"],
            "progress":     _gt_state["progress"],
            "total":        _gt_state["total"],
            "images_saved": _gt_state["images_saved"],
            "log":          list(_gt_state["log"]),
            "output_dir":   _gt_state["output_dir"],
            "accounts":     [dict(a) for a in _gt_state["accounts"]],
        }
    st["playwright_ok"] = _gt_playwright_ok()
    st["ext_connected"] = 0
    st["ext_accounts"]  = []
    return jsonify(st)

@app.route("/api/gentube/check-login")
def gt_check_login():
    try:
        _gt_sync_profiles()
    except Exception:
        pass
    with _gt_lock:
        profiles = [{"id": a["id"], "logged_in": a["logged_in"], "user": a["user"]}
                    for a in _gt_state["accounts"]]
    return jsonify(profiles=profiles)


@app.route("/api/gentube/login", methods=["POST"])
def gt_login():
    data       = request.get_json(force=True, silent=True) or {}
    account_id = max(0, min(int(data.get("profile", data.get("account_id", 0))),
                            _GT_NUM_ACCOUNTS - 1))
    # Modo cookie directa
    ck = (data.get("cookie") or "").strip()
    if ck:
        pr = _gt_probe_session(ck)
        if not pr["ok"]:
            return jsonify(error="Cookie inválida o expirada — verifica que hayas copiado la cookie correcta."), 400
        with open(_gt_cookie_path(account_id), "w", encoding="utf-8") as fh:
            fh.write(ck)
        _gt_log(f"  [C{account_id}] [OK] Cookie guardada directamente — {pr.get('user','')}")
        threading.Thread(target=_gt_sync_profiles, daemon=True).start()
        return jsonify(ok=True, user=pr.get("user", ""))
    # Modo browser
    threading.Thread(target=_gt_playwright_login, args=(account_id,), daemon=True).start()
    return jsonify(ok=True)


@app.route("/api/gentube/run-prompts", methods=["POST"])
def gt_run_prompts():
    global _gt_stop
    data       = request.get_json() or {}
    prompts    = [p for p in (data.get("prompts") or []) if str(p).strip()]
    slots      = max(1, min(8,  int(data.get("slots", 1))))
    repeat     = max(1, min(20, int(data.get("repeat", 1))))
    output_dir = (data.get("output_dir") or "").strip()
    ratio      = data.get("ratio", "1:1")
    quality    = data.get("quality", "standard")

    if not prompts:
        return jsonify({"error": "Sin prompts"}), 400
    if not output_dir:
        return jsonify({"error": "Sin output_dir"}), 400

    with _gt_lock:
        if _gt_state.get("running"):
            return jsonify({"error": "Ya hay una generación en curso"}), 409

    _gt_stop = threading.Event()
    with _gt_lock:
        _gt_state["log"] = []
        _gt_state["running"] = True
        _gt_state["step"] = "starting"
        _gt_state["progress"] = 0
        _gt_state["total"] = len(prompts) * repeat
        _gt_state["images_saved"] = 0
    threading.Thread(
        target=_gt_worker,
        args=(prompts, slots, repeat, output_dir, ratio, quality),
        daemon=True
    ).start()
    return jsonify({"ok": True, "message": f"Iniciado {len(prompts)*repeat} imágenes"})


@app.route("/api/gentube/stop", methods=["POST"])
def gt_stop():
    _gt_stop.set()
    with _gt_lock:
        _gt_state.update(running=False, step="idle", progress=0, total=0)
    return jsonify({"ok": True})

@app.route("/api/gentube/reset", methods=["POST"])
def gt_reset():
    """Fuerza reset del estado si quedó atascado."""
    global _gt_stop
    _gt_stop = threading.Event()
    _gt_stop.set()
    with _gt_lock:
        _gt_state.update(running=False, step="idle", progress=0, total=0,
                         images_saved=0, log=[])
    return jsonify({"ok": True})


@app.route("/api/gentube/images")
def gt_images():
    d = (_gt_images_dir or "").strip()
    if not d or not os.path.isdir(d):
        return jsonify({"images": [], "count": 0})
    exts = {".png", ".jpg", ".jpeg", ".webp"}
    imgs = sorted(
        [f for f in os.listdir(d) if os.path.splitext(f)[1].lower() in exts],
        key=lambda f: os.path.getmtime(os.path.join(d, f)), reverse=True
    )
    return jsonify({"images": imgs, "count": len(imgs)})


@app.route("/api/gentube/image/<path:name>")
def gt_image(name):
    from flask import send_file as _sf
    d = (_gt_images_dir or "").strip()
    if not d:
        return jsonify({"error": "no dir"}), 404
    p = os.path.join(d, os.path.basename(name))
    if not os.path.isfile(p):
        return jsonify({"error": "not found"}), 404
    return _sf(p)


@app.route("/api/gentube/clear-images", methods=["POST"])
def gt_clear_images():
    d = (_gt_images_dir or "").strip()
    if not d or not os.path.isdir(d):
        return jsonify({"ok": True})
    exts = {".png", ".jpg", ".jpeg", ".webp"}
    for f in os.listdir(d):
        if os.path.splitext(f)[1].lower() in exts:
            try: os.remove(os.path.join(d, f))
            except Exception: pass
    with _gt_lock:
        _gt_state["images_saved"] = 0
    return jsonify({"ok": True})


