# 7. PROYECTOS — /api/proyectos/* (imagen_file, crear, listar, contenido;
#    videos_final y video_final siguen tras el bloque de render local §8)
# ══════════════════════════════════════════════════════════════════

@app.route("/api/proyectos/imagen_file")
def proyecto_imagen_file():
    import re as _re
    from pathlib import Path as _P
    proj = _re.sub(r"[^\w\-]","_",request.args.get("project","").strip())
    fname = request.args.get("file","").strip()
    if not proj or not fname: return jsonify({"error":"missing"}),400
    path = _P(JOBS_FOLDER)/proj/"imagen"/fname
    if not path.exists(): return "",404
    ext  = path.suffix.lower()
    mime = {".jpg":"image/jpeg",".jpeg":"image/jpeg",".png":"image/png",
            ".webp":"image/webp",".gif":"image/gif",".bmp":"image/bmp"}.get(ext,"image/jpeg")
    resp = send_file(str(path), mimetype=mime)
    resp.headers["Cache-Control"] = "no-store, no-cache, must-revalidate"
    resp.headers["Pragma"] = "no-cache"
    return resp


@app.route("/api/proyectos/crear", methods=["POST"])
def crear_proyecto():
    data = request.get_json() or {}
    import re as _r
    name = _r.sub(r"[^\w\-]", "_", data.get("nombre","").strip())[:60]
    if not name: return jsonify({"error": "Nombre invalido"}), 400
    from pathlib import Path as _P
    proj = _P(JOBS_FOLDER) / name
    for s in ("imagen","audio","guion","video","video_final"): (proj/s).mkdir(parents=True, exist_ok=True)
    return jsonify({"ok":True, "nombre":name, "ruta":str(proj)})

@app.route("/api/proyectos/listar")
def listar_proyectos():
    from pathlib import Path as _P
    out=[]
    try:
        for d in sorted(_P(JOBS_FOLDER).iterdir()):
            if not d.is_dir() or d.name.startswith("."): continue
            subs={s.name for s in d.iterdir() if s.is_dir()}
            if not any(x in subs for x in ("imagen","audio","video")): continue
            out.append({"nombre":d.name,"ruta":str(d),
                "videos": len(list((d/"video").glob("*.mp4"))) if (d/"video").exists() else 0,
                "audios": len(list((d/"audio").glob("*")))     if (d/"audio").exists() else 0,
                "creado": d.stat().st_ctime})
    except: pass
    out.sort(key=lambda x:x["creado"],reverse=True)
    return jsonify(out)

@app.route("/api/proyectos/contenido")
def proyecto_contenido():
    """Returns matched images/videos for a project"""
    proj_name = request.args.get("project", "")
    if not proj_name:
        return jsonify({"error": "No project"}), 400
    from pathlib import Path as _P
    proj_dir = _P(JOBS_FOLDER) / proj_name
    img_dir  = proj_dir / "imagen"
    vid_dir  = proj_dir / "video"

    images   = []
    if img_dir.exists():
        for f in img_dir.iterdir():
            if f.is_file() and f.suffix.lower().lstrip('.') in {'jpg','jpeg','png','webp','gif','bmp'}:
                images.append(f)
    videos   = [f for f in vid_dir.glob("*.mp4")] if vid_dir.exists() else []

    def _ctime(p):
        st = p.stat()
        return getattr(st, "st_birthtime", None) or st.st_mtime

    # Alineado con render_inteligente: img_00001/flow_0001… por número; si no, ctime (tipo Mac).
    def _media_path_order(p):
        m = re.match(r"^(?:img|flow)_(\d+)$", p.stem, flags=re.I)
        if m:
            return (0, int(m.group(1)), p.stem.lower())
        return (1, _ctime(p), p.stem.lower())

    images.sort(key=_media_path_order)
    videos.sort(key=_media_path_order)

    # Index videos by exact stem (img_00001.mp4 ↔ img_00001.jpg)
    vid_by_stem = {v.stem: v.name for v in videos}

    seen_stems = set()
    scenes = []
    for img in images:
        seen_stems.add(img.stem)
        vid = vid_by_stem.get(img.stem)
        scenes.append({
            "index":     img.stem,
            "image":     img.name,
            "video":     vid,
            "has_video": vid is not None
        })

    for v in videos:
        if v.stem not in seen_stems:
            seen_stems.add(v.stem)
            scenes.append({
                "index":     v.stem,
                "image":     None,
                "video":     v.name,
                "has_video": True
            })

    def _scene_order(s):
        if s["image"] and (img_dir / s["image"]).exists():
            p = img_dir / s["image"]
            m = re.match(r"^(?:img|flow)_(\d+)$", p.stem, flags=re.I)
            if m:
                return (0, int(m.group(1)), "")
            return (1, _ctime(p), p.name.lower())
        if s["video"] and (vid_dir / s["video"]).exists():
            p = vid_dir / s["video"]
            m = re.match(r"^(?:img|flow)_(\d+)$", p.stem, flags=re.I)
            if m:
                return (0, int(m.group(1)), "")
            return (1, _ctime(p), p.name.lower())
        return (2, 0.0, "")
    scenes.sort(key=_scene_order)

    return jsonify({
        "scenes":      scenes,
        "total":       len(scenes),
        "with_video":  sum(1 for s in scenes if s["has_video"]),
        "images_only": sum(1 for s in scenes if not s["has_video"]),
        "debug": {
            "img_dir":    str(img_dir),
            "img_count":  len(images),
            "vid_count":  len(videos),
            "img_dir_exists": img_dir.exists(),
        }
    })


# ══════════════════════════════════════════════════════════════════
# 8. RENDER LOCAL (FFmpeg) — /api/render_inteligente, descargar_render,
#    procesar_render_inteligente (worker)
# ══════════════════════════════════════════════════════════════════

@app.route("/api/render_inteligente", methods=["POST"])
def render_inteligente():
    """Local FFmpeg render using project videos+images+audio"""
    # ── Verificar límite de videos ANTES de comenzar (server-side) ──
    _ri_user = _current_username()
    if _ri_user:
        _ri_ok, _ri_msg, _ri_extra = check_limit(_ri_user, "video", 1)
        if not _ri_ok:
            return jsonify({
                "error": _ri_msg,
                "limit_reached": True,
                "limit_type": "video",
                "extra": _ri_extra,
            }), 429

    try:
        proj_name  = request.form.get("project_name", "")
        render_mode = request.form.get("render_mode", "smart")  # images|videos|smart
        guion      = request.form.get("guion", "").strip()
        resolucion = request.form.get("resolucion", "1920x1080")
        modelo          = request.form.get("modelo", "base")
        whisper_backend = request.form.get("whisper_backend", "whisperx")  # "local" | "faster" | "api" | "whisperx"
        transicion = request.form.get("transicion", "none")
        trans_dur  = float(request.form.get("trans_dur", "0.8"))
        movimiento = request.form.get("movimiento", "none")
        shake      = request.form.get("shake", "false") == "true"
        
        if not proj_name:
            return jsonify({"error": "Proyecto requerido"}), 400
        
        from pathlib import Path as _P
        proj_dir = _P(JOBS_FOLDER) / proj_name
        img_dir  = proj_dir / "imagen"
        vid_dir  = proj_dir / "video"
        audio_dir = proj_dir / "audio"
        out_dir   = proj_dir / "video_final"
        out_dir.mkdir(parents=True, exist_ok=True)
        
        # Get audio
        audio = request.files.get("audio")
        if audio and audio.filename:
            import re as _re2
            _aext = os.path.splitext(audio.filename)[-1].lower() or ".mp3"
            _aext = _aext if _aext in {".mp3",".wav",".m4a",".aac",".ogg",".flac"} else ".mp3"
            audio_path = str(audio_dir / f"render_audio{_aext}")
            audio_dir.mkdir(parents=True, exist_ok=True)
            audio.save(audio_path)
        else:
            # Try to find existing audio in project
            audios = list(audio_dir.glob("*")) if audio_dir.exists() else []
            audio_path = str(audios[0]) if audios else None
        
        if not audio_path or not os.path.exists(audio_path):
            return jsonify({"error": "No se encontró audio"}), 400
        
        # Orden de escenas: en macOS el ctime suele coincidir con la subida; en Windows no.
        # Misma intención que launcher Comentado.py: primero img_00001, img_00002… por número;
        # si el nombre no sigue img_NNNNN, orden por ctime y nombre (comportamiento tipo Mac).
        def _ctime_r(p):
            st = p.stat()
            return getattr(st, "st_birthtime", None) or st.st_mtime

        def _render_path_order(p):
            stem = (p.stem or "")
            m = re.match(r"^(?:img|flow)_(\d+)$", stem, flags=re.I)
            if m:
                return (0, int(m.group(1)), stem.lower())
            return (1, _ctime_r(p), stem.lower())  # fallback como Mac: orden por antigüedad + nombre

        images = []
        if img_dir.exists():
            for _f in img_dir.iterdir():
                if _f.is_file() and _f.suffix.lower().lstrip('.') in {'jpg','jpeg','png','webp','gif','bmp'}:
                    images.append(_f)
            images.sort(key=_render_path_order)
        if not images and render_mode == 'images':
            return jsonify({"error": "No hay imágenes en el proyecto"}), 400

        videos = []
        if vid_dir.exists():
            for f in vid_dir.glob("*.mp4"):
                videos.append(f)
            videos.sort(key=_render_path_order)

        if not images and not videos:
            return jsonify({"error": "El proyecto no tiene imágenes ni videos para renderizar"}), 400

        vid_index = {v.stem: v for v in videos}
        
        # Save guion if provided
        guion_path = None
        if guion:
            guion_path = str(proj_dir / "guion" / "guion_render.txt")
            os.makedirs(os.path.dirname(guion_path), exist_ok=True)
            open(guion_path,"w",encoding="utf-8").write(guion)
        
        job_id = str(uuid.uuid4())[:8]
        jobs[job_id] = {"id":job_id,"estado":"procesando","progreso":0,"mensaje":"Iniciando...","logs":[],"video_url":None,"inicio":time.time()}
        
        threading.Thread(
            target=procesar_render_inteligente,
            args=(job_id, images, vid_index, audio_path, guion, resolucion, modelo,
                  transicion, trans_dur, movimiento, shake, render_mode, str(out_dir),
                  whisper_backend, guion_path, _ri_user),
            daemon=True
        ).start()

        # ── Registrar video generado en la BD ────────────────────
        if _ri_user:
            try:
                _ri_uid = (_get_user_full(_ri_user) or {}).get("id")
                if _ri_uid:
                    record_usage(_ri_uid, videos=1)
            except Exception:
                pass  # nunca bloquear el render por fallo de registro

        return jsonify({"job_id": job_id})
    except Exception as e:
        try:
            import traceback as _tb3
            print(_tb3.format_exc().encode('ascii', 'replace').decode('ascii'))
        except Exception:
            pass
        return jsonify({"error": str(e).encode('ascii', 'replace').decode('ascii')}), 500




def procesar_render_inteligente(job_id, images, vid_index, audio_path, guion,
                                 resolucion, modelo, transicion, trans_dur,
                                 movimiento, shake, render_mode, out_dir,
                                 whisper_backend="local", guion_path=None,
                                 ri_user=None):
    """Pipeline híbrido: imágenes --> Modal GPU | videos --> FFmpeg local (paralelo)."""
    import tempfile as _tmp, shutil as _sh, math as _math
    from concurrent.futures import ThreadPoolExecutor as _TPE
    import io as _io
    import random

    _MODAL_URL = "https://davidestebanbermudez14--motor-video-cpa-renderizar.modal.run"
    try:
        BATCH_SIZE = int((os.environ.get("VF_MODAL_BATCH_SIZE") or "28").strip())
    except ValueError:
        BATCH_SIZE = 28
    BATCH_SIZE = max(8, min(40, BATCH_SIZE))
    try:
        _seg_par = int((os.environ.get("VF_RENDER_SEG_PARALLEL") or "2").strip())
    except ValueError:
        _seg_par = 2
    _seg_par = max(1, min(6, _seg_par))
    try:
        _vid_clip_par = int((os.environ.get("VF_RENDER_VID_CLIP_PARALLEL") or "2").strip())
    except ValueError:
        _vid_clip_par = 2
    _vid_clip_par = max(1, min(4, _vid_clip_par))
    try:
        _modal_read_timeout = int((os.environ.get("VF_MODAL_READ_TIMEOUT_SEC") or "240").strip())
    except ValueError:
        _modal_read_timeout = 240
    _modal_read_timeout = max(60, min(1200, _modal_read_timeout))
    try:
        _modal_connect_timeout = int((os.environ.get("VF_MODAL_CONNECT_TIMEOUT_SEC") or "35").strip())
    except ValueError:
        _modal_connect_timeout = 35
    _modal_connect_timeout = max(8, min(120, _modal_connect_timeout))
    # FFmpeg local: 0 = usar todos los núcleos (mucho más rápido que threads=1 forzado)
    _ff_threads = (os.environ.get("VF_FFMPEG_THREADS") or "0").strip() or "0"
    _x264_thr = (os.environ.get("VF_FFMPEG_X264_THREADS") or "0").strip() or "0"
    try:
        _modal_max_retries = int((os.environ.get("VF_MODAL_MAX_RETRIES") or "4").strip())
    except ValueError:
        _modal_max_retries = 4
    _modal_max_retries = max(1, min(8, _modal_max_retries))
    _MAX_LOG_LINES = 800
    _modal_local = threading.local()

    def _modal_session():
        s = getattr(_modal_local, "s", None)
        if s is None:
            try:
                # Reusar pool TLS reduce SSLEOF en Windows
                s = _mk_https_session(16)
            except Exception:
                s = requests.Session()
            _modal_local.s = s
        return s

    def log(msg, pct=None):
        _logs = jobs[job_id]["logs"]
        _logs.append(msg)
        if len(_logs) > _MAX_LOG_LINES:
            del _logs[: len(_logs) - _MAX_LOG_LINES]
        jobs[job_id]["mensaje"] = msg
        if pct is not None: jobs[job_id]["progreso"] = pct
        try:
            print(f"[{job_id}] {msg}", flush=True)
        except UnicodeEncodeError:
            _safe = f"[{job_id}] {msg}".encode("ascii", errors="replace").decode("ascii")
            try:
                print(_safe, flush=True)
            except Exception:
                pass

    def _run_cmd(cmd, err_ctx):
        """Run subprocess and raise readable error on failure."""
        res = subprocess.run(cmd, capture_output=True, text=True, **_vf_no_window())
        if res.returncode != 0:
            stderr = (res.stderr or "").strip()
            # Saltar header de FFmpeg, mostrar las últimas líneas con el error real
            lines = stderr.splitlines()
            # Tomar las últimas 20 líneas que suelen contener el error real
            detail = "\n".join(lines[-20:]) if lines else "sin salida"
            raise Exception(f"{err_ctx}:\n{detail}")
        return res

    def _write_concat_list(path, clip_paths):
        """Write ffmpeg concat list safely for Windows paths."""
        with open(path, "w", encoding="utf-8") as f:
            for p in clip_paths:
                pp = str(p).replace("\\", "/").replace("'", "'\\''")
                f.write(f"file '{pp}'\n")

    tmp_dir = _tmp.mkdtemp()
    try:
        # ── Audio duration ────────────────────────────────────────────────────
        log("⏱️ Analizando audio...", 3)
        _res = _run_cmd(["ffprobe","-v","error","-show_entries","format=duration",
                         "-of","json",audio_path], "ffprobe no pudo leer audio")
        try:
            _parsed = json.loads(_res.stdout)
            _dur = (_parsed.get("format") or {}).get("duration")
            if _dur is None:
                _r2 = _run_cmd(["ffprobe","-v","error","-show_entries",
                    "stream=duration","-of","json",audio_path], "ffprobe fallback falló")
                _dur = next((s["duration"] for s in json.loads(_r2.stdout).get("streams",[])
                             if s.get("duration")), None)
            duracion_total = float(_dur)
        except Exception as _de:
            raise Exception(f"No se pudo leer la duración del audio: {_de}")
        log(f"✓ Audio: {duracion_total:.1f}s", 7)

        # ── Verificar duración máxima según plan (server-side) ───
        if ri_user:
            _dur_ok, _dur_msg = check_video_duration(ri_user, duracion_total)
            if not _dur_ok:
                log(f"⛔ {_dur_msg}")
                jobs[job_id].update({"estado": "error", "error": _dur_msg,
                                     "limit_reached": True, "limit_type": "video_duration"})
                return

        # ── Whisper timestamps ────────────────────────────────────────────────
        # Leer guión del disco con split("\n") — IDÉNTICO a procesar_video (solo imagen)
        if guion_path and os.path.exists(guion_path):
            with open(guion_path, "r", encoding="utf-8") as _gf:
                escenas_texto = [e.strip() for e in _gf.read().split("\n") if e.strip()]
        elif guion:
            escenas_texto = [e.strip() for e in guion.split("\n") if e.strip()]
        else:
            _n_items = len(images) if images else len(vid_index)
            escenas_texto = [f"Escena {i+1}" for i in range(_n_items)]
        if guion and guion.strip():
            if whisper_backend == "api":
                log("🌐 Transcribiendo con Whisper API...", 10)
                try:
                    from openai import OpenAI as _OAI
                    _oai = _OAI(api_key=OPENAI_WHISPER_KEY)
                    with open(audio_path, "rb") as _af:
                        _tr = _oai.audio.transcriptions.create(
                            model="whisper-1", file=_af, language="es",
                            response_format="verbose_json",
                            timestamp_granularities=["word", "segment"]
                        )
                    _all_words = [{"word": _w.word, "start": float(_w.start), "end": float(_w.end)}
                                  for _w in (getattr(_tr, "words", None) or [])]
                    if not _all_words:
                        for _s in (_tr.segments or []):
                            for _w in (getattr(_s, "words", None) or []):
                                _all_words.append({"word": _w.word, "start": float(_w.start), "end": float(_w.end)})
                    segmentos = _split_api_segmentos(_all_words, _tr.segments)
                    log(f"  (API: {len(_all_words)} words --> {len(segmentos)} sub-segmentos)")
                except Exception as _ae:
                    raise Exception(f"Whisper API error: {_ae}")
            elif whisper_backend == "faster":
                log(f"⚡ Transcribiendo con faster-whisper ({modelo})...", 10)
                try:
                    from faster_whisper import WhisperModel as _FWM
                    _fwm = _FWM(modelo, device="cpu", compute_type="int8")
                    _segs_raw, _ = _fwm.transcribe(
                        audio_path, language=None,
                        word_timestamps=True, beam_size=2
                    )
                    segmentos = []
                    for _s in _segs_raw:
                        segmentos.append({
                            "start": _s.start, "end": _s.end, "text": _s.text,
                            "words": [{"word": w.word, "start": w.start, "end": w.end}
                                      for w in (_s.words or [])]
                        })
                except Exception as _fe:
                    raise Exception(f"faster-whisper error: {_fe}")
            elif whisper_backend == "whisperx_local":
                log(f"🎯 Transcribiendo con WhisperX local ({modelo})...", 10)
                try:
                    import whisperx as _wxl
                    _wxl_device = "cpu"
                    _wxl_model = _wxl.load_model(modelo, _wxl_device, compute_type="int8", language="es")
                    _wxl_audio = _wxl.load_audio(audio_path)
                    _wxl_result = _wxl_model.transcribe(_wxl_audio, batch_size=8, language="es")
                    del _wxl_model
                    _align_model, _align_meta = _wxl.load_align_model(language_code="es", device=_wxl_device)
                    _wxl_aligned = _wxl.align(_wxl_result["segments"], _align_model, _align_meta,
                                               _wxl_audio, _wxl_device, return_char_alignments=False)
                    del _align_model
                    _ri_all_words = []
                    for _s in _wxl_aligned["segments"]:
                        for _w in (_s.get("words") or []):
                            if _w.get("start") is not None:
                                _ri_all_words.append({"word": _w.get("word",""),
                                                      "start": float(_w["start"]),
                                                      "end": float(_w.get("end", _w["start"]))})
                    segmentos = [{"start": float(s["start"]), "end": float(s["end"]),
                                  "text": s.get("text",""),
                                  "words": [{"word": w.get("word",""), "start": float(w["start"]),
                                             "end": float(w.get("end", w["start"]))}
                                            for w in (s.get("words") or []) if w.get("start") is not None]}
                                 for s in _wxl_aligned["segments"]]
                except Exception as _wxle:
                    raise Exception(f"WhisperX local error: {_wxle}")
            elif whisper_backend == "whisperx":
                log("🎯 Transcribiendo con WhisperX Replicate (alineación forzada)...", 10)
                try:
                    segmentos, _ri_all_words = _transcribir_whisperx_runpod(audio_path, language=None)
                except Exception as _wxe:
                    raise Exception(f"WhisperX RunPod error: {_wxe}")
            else:
                log(f"🎤 Transcribiendo con Whisper ({modelo})...", 10)
                import whisper as _whisper
                wm = _whisper.load_model(modelo)
                resultado = wm.transcribe(audio_path, language=None, word_timestamps=True)
                segmentos = resultado.get("segments", [])
            log(f"✓ {len(segmentos)} segmentos", 20)
            _ri_words = locals().get("_ri_all_words") or (
                _all_words if whisper_backend == "api" else None
            )
            if _ri_words:
                timestamps = asignar_timestamps_words(escenas_texto, _ri_words, duracion_total)

                # ── Detección de fallo en word-level ─────────────────────────
                # Con ciertas voces TTS el narrator lee números y abreviaciones
                # de forma distinta al texto del guión ("Kepler-70" --> "kepler setenta").
                # El n-gram matching exacto falla silenciosamente: encuentra coincidencias
                # en posiciones incorrectas del stream, produciendo escenas de 200-300s
                # que "absorben" decenas de escenas siguientes. Síntoma: >40% de escenas
                # sin match Y el último match está en los últimos 15% del audio.
                # En ese caso, segment-level (bag-of-words overlap) es más robusto
                # porque tolera variaciones de pronunciación en los números.
                _wl_unmatched = sum(1 for _ts in timestamps if _ts.get("score", 0) == 0)
                _wl_last_ok   = max(
                    (_ts["fin"] for _ts in timestamps if _ts.get("score", 0) > 0),
                    default=0.0
                )
                _wl_ratio  = _wl_unmatched / max(1, len(timestamps))
                _wl_late   = _wl_last_ok > duracion_total * 0.85
                _wl_failed = _wl_ratio > 0.40 and _wl_late

                if _wl_failed:
                    log(f"[WARNING] Word-level anómalo: {_wl_unmatched}/{len(timestamps)} escenas sin "
                        f"coincidencia, último match al "
                        f"{_wl_last_ok / duracion_total * 100:.0f}% del audio.", 33)
                    log("   Causa probable: voz TTS lee números/abreviaciones distinto al guión.", 33)
                    log("   Usando segment-level (más tolerante a variaciones de pronunciación)...", 33)
                    timestamps = asignar_timestamps(escenas_texto, segmentos, duracion_total)
                    log(f"✓ {len(timestamps)} timestamps (segment-level fallback)", 22)
                else:
                    log(f"✓ {len(timestamps)} timestamps (word-level / precisión máxima)", 22)
            else:
                timestamps = asignar_timestamps(escenas_texto, segmentos, duracion_total)
                log(f"✓ {len(timestamps)} timestamps (segment-level)", 22)
        else:
            dur_eq = duracion_total / max(1, len(escenas_texto))
            timestamps = [{"inicio": i*dur_eq, "fin": (i+1)*dur_eq, "duracion": dur_eq}
                          for i in range(len(escenas_texto))]
            log(f"✓ {len(timestamps)} timestamps", 22)
        log("📋 Timestamps por escena:")
        for _i, _ts in enumerate(timestamps):
            log(f"  E{_i+1:02d}: {_ts['inicio']:.2f}s --> {_ts['fin']:.2f}s  dur={_ts['duracion']:.3f}s  score={_ts.get('score',0):.2f}  seg={_ts.get('seg_idx','?')}")

        # ── Build scene list ──────────────────────────────────────────────────
        # Un timestamp por línea de guión: si hay más timestamps que imágenes (p. ej. Whisk
        # generó menos clips), reutilizar la última imagen como en procesar_video — evita
        # vídeos cortos (~solo primeras escenas) con -shortest en el mux final.
        scenes = []
        # ── Videos-only mode: build scenes directly from vid_index ──────────
        if not images and render_mode in ("smart", "videos") and vid_index:
            _vids_sorted = sorted(vid_index.values(), key=lambda p: p.name)
            n_ts, n_vids = len(timestamps), len(_vids_sorted)
            _n_total = max(n_ts, n_vids)
            if n_ts > n_vids:
                log(f"[WARNING] {n_ts} timestamps pero solo {n_vids} videos — se reutiliza el último.", 25)
            for i in range(_n_total):
                _vid = _vids_sorted[min(i, n_vids - 1)]
                _ts  = timestamps[min(i, n_ts - 1)] if timestamps else {"inicio": 0, "fin": duracion_total / max(1, n_vids), "duracion": duracion_total / max(1, n_vids)}
                _vid_path = str(_vid) if _vid.exists() else None
                scenes.append({
                    "type": "video" if _vid_path else "image",
                    "img_path": str(_vid),
                    "vid_path": _vid_path,
                    "duracion": max(0.5, float(_ts["duracion"])),
                    "inicio": float(_ts.get("inicio", 0)),
                    "fin": float(_ts.get("fin", _ts.get("inicio", 0) + _ts["duracion"])),
                    "escena_idx": i,
                })
        else:
            n_ts, n_img = len(timestamps), len(images)
            if n_ts > n_img:
                log(
                    f"[WARNING] {n_ts} timestamps (guión) pero {n_img} imágenes — "
                    f"se reutiliza la última imagen en las {n_ts - n_img} escenas finales.",
                    25,
                )
            # Mapa escena-->imagen por nombre de archivo (img_00001-->escena 0, etc.)
            # Robusto ante fallos de Whisk: si falta img_00003.png, la escena 2
            # usa el fallback pero las escenas 3,4,… siguen viendo su imagen
            # correcta — sin el desplazamiento que causaba el índice de lista.
            _img_by_scene = {}
            for _img in images:
                _mm = re.match(r"^(?:img|flow)_(\d+)$", _img.stem, re.IGNORECASE)
                if _mm:
                    _img_by_scene[int(_mm.group(1)) - 1] = _img
            if n_ts >= n_img:
                for i in range(n_ts):
                    ts = timestamps[i]
                    _sidx = ts.get("scene_idx", i)
                    img = _img_by_scene.get(_sidx) or images[min(_sidx, n_img - 1)]
                    vid = vid_index.get(img.stem) if render_mode in ("smart", "videos") else None
                    vid_path = str(vid) if vid and os.path.exists(str(vid)) else None
                    scenes.append(
                        {
                            "type": "video" if vid_path else "image",
                            "img_path": str(img),
                            "vid_path": vid_path,
                            "duracion": max(0.5, float(ts["duracion"])),
                            "inicio": float(ts.get("inicio", 0)),
                            "fin": float(ts.get("fin", ts.get("inicio", 0) + ts["duracion"])),
                            "escena_idx": i,
                        }
                    )
            else:
                _ts_by_scene = {_t.get("scene_idx", _j): _t for _j, _t in enumerate(timestamps)}
                for i, img in enumerate(images):
                    # Usar índice de escena del nombre del archivo, no posición de lista
                    _mm2 = re.match(r"^(?:img|flow)_(\d+)$", img.stem, re.IGNORECASE)
                    _sidx2 = int(_mm2.group(1)) - 1 if _mm2 else i
                    ts = _ts_by_scene.get(_sidx2, timestamps[min(i, n_ts - 1)])
                    vid = vid_index.get(img.stem) if render_mode in ("smart", "videos") else None
                    vid_path = str(vid) if vid and os.path.exists(str(vid)) else None
                    scenes.append(
                        {
                            "type": "video" if vid_path else "image",
                            "img_path": str(img),
                            "vid_path": vid_path,
                            "duracion": max(0.5, float(ts["duracion"])),
                            "escena_idx": i,
                        }
                    )
        total_vid = sum(float(s["duracion"]) for s in scenes)
        gap = float(duracion_total) - total_vid
        if gap > 0.08 and scenes:
            scenes[-1]["duracion"] = round(max(0.5, float(scenes[-1]["duracion"]) + gap), 3)
            log(
                f"📏 Ajuste fin de línea: +{gap:.2f}s en última escena "
                f"(suma escenas {total_vid:.1f}s --> audio {duracion_total:.1f}s).",
                26,
            )
        n_vid = sum(1 for s in scenes if s["type"] == "video")
        log(f"📋 {len(scenes)} escenas — {n_vid} video · {len(scenes) - n_vid} imagen", 25)

        # ── Resolution ───────────────────────────────────────────────────────
        try:
            w_res, h_res = [int(x) for x in resolucion.split("x")]
        except:
            w_res, h_res = 1920, 1080

        # ── Add transition overlap to all but last scene ───────────────────
        # extra NO se aplica globalmente — se aplica dentro de cada batch de imagen
        # para que el overlap interno del xfade lo consuma exactamente sin drift

        # ── Silent audio (Modal necesita audio_b64 válido por batch) ─────────
        _silent = os.path.join(tmp_dir, "silent.mp3")
        _run_cmd(["ffmpeg","-y","-f","lavfi","-i","anullsrc=r=44100:cl=mono",
                  "-t",str(duracion_total),"-b:a","32k",_silent], "No se pudo crear audio silencioso")
        _silent_b64 = base64.b64encode(
            open(_silent,"rb").read() if os.path.exists(_silent) else b"").decode()

        # ── Compressed audio para mezcla final ───────────────────────────────
        _asm = os.path.join(tmp_dir, "audio_s.mp3")
        _ra = subprocess.run(["ffmpeg","-y","-i",audio_path,"-ar","44100","-ac","1",
                               "-b:a","64k","-movflags","+faststart",_asm], capture_output=True, text=True, **_vf_no_window())
        audio_path_mix = (_asm if _ra.returncode==0 and os.path.exists(_asm)
                          and os.path.getsize(_asm)>1000 else audio_path)

        # ── _encode_img: JPEG 960px para enviar a Modal ───────────────────────
        def _encode_img(sc):
            try:
                from PIL import Image as _Im
                with _Im.open(sc["img_path"]) as im:
                    if im.mode != "RGB": im = im.convert("RGB")
                    ms = 960
                    if max(im.width, im.height) > ms:
                        r = ms / max(im.width, im.height)
                        im = im.resize((int(im.width*r), int(im.height*r)), _Im.BILINEAR)
                    buf = _io.BytesIO()
                    im.save(buf, format="JPEG", quality=78, optimize=True)
                    ib = base64.b64encode(buf.getvalue()).decode()
            except Exception:
                with open(sc["img_path"],"rb") as f: ib = base64.b64encode(f.read()).decode()
            return {"imagen_b64": ib, "duracion": sc["duracion"],
                    "movimiento": movimiento, "is_video": False}

        # ── _render_vid_clip: escala + letterbox un clip de video con FFmpeg ──
        def _render_vid_clip(sc, clip_idx):
            out = os.path.join(tmp_dir, f"vc_{sc['escena_idx']:05d}.mp4")
            dur = sc["duracion"]  # duración exacta del timestamp word-level
            src_d = 0.0
            try:
                src_d = float(_vf_ffprobe_duration(sc["vid_path"]))
            except Exception:
                src_d = 0.0

            # ── Generar clip con duración 100% EXACTA ────────────────────────────
            # Paso 1: ralentizar con setpts (se ve bien visualmente).
            # Paso 2: segundo pase con -frames:v + pts_rescale para garantizar
            #         que el output tenga EXACTAMENTE int(dur*24) frames @ 24fps.
            # Esto elimina TODO el drift acumulativo sin sacrificar la ralentización.
            _FPS = 24
            _n_frames_exact = int(round(dur * _FPS))
            _dur_exact = _n_frames_exact / _FPS   # duración real en frames exactos
            _t_exact = f"{_dur_exact:.6f}"
            _out_tmp = out.replace(".mp4", "_slow.mp4")

            if src_d > 0.05 and src_d < _dur_exact * 0.98:
                ratio = _dur_exact / src_d
                if ratio <= 1.60:
                    pts_expr = f"{ratio:.8f}*PTS"
                    log(f"  🎬 clip E{sc['escena_idx']+1}: {src_d:.2f}s --> {_dur_exact:.3f}s (x{ratio:.3f})")
                else:
                    pts_expr = "PTS"
                    log(f"  ⏱️ clip E{sc['escena_idx']+1}: {src_d:.2f}s < {_dur_exact:.3f}s --> freeze")
                _vf_s = (f"scale={w_res}:{h_res}:force_original_aspect_ratio=decrease,"
                         f"pad={w_res}:{h_res}:(ow-iw)/2:(oh-ih)/2:color=black,"
                         f"setsar=1,fps={_FPS},setpts={pts_expr}")
                if ratio > 1.60:
                    _vf_s += f",tpad=stop_mode=clone:stop_duration={(_dur_exact-src_d):.6f}"
                # Pase 1: ralentizar y generar clip temporal más largo que dur
                _r = subprocess.run([
                    "ffmpeg","-y","-threads",_ff_threads,"-i",sc["vid_path"],
                    "-map","0:v:0",
                    "-vf",_vf_s,
                    "-c:v","libx264","-preset","ultrafast","-crf","28",
                    "-x264-params",f"threads={_x264_thr}",
                    "-an","-pix_fmt","yuv420p",
                    "-movflags","+faststart", _out_tmp
                ], capture_output=True, text=True, **_vf_no_window())
            else:
                # Clip >= dur — solo escalar, sin ralentizar
                _vf_s = (f"scale={w_res}:{h_res}:force_original_aspect_ratio=decrease,"
                         f"pad={w_res}:{h_res}:(ow-iw)/2:(oh-ih)/2:color=black,"
                         f"setsar=1,fps={_FPS},setpts=PTS-STARTPTS")
                _r = subprocess.run([
                    "ffmpeg","-y","-threads",_ff_threads,"-i",sc["vid_path"],
                    "-map","0:v:0",
                    "-vf",_vf_s,
                    "-c:v","libx264","-preset","ultrafast","-crf","28",
                    "-x264-params",f"threads={_x264_thr}",
                    "-an","-pix_fmt","yuv420p",
                    "-movflags","+faststart", _out_tmp
                ], capture_output=True, text=True, **_vf_no_window())

            # Pase 2: cortar EXACTAMENTE _n_frames_exact frames del clip generado
            # Esto garantiza duración precisa al frame, sin drift acumulativo.
            if os.path.exists(_out_tmp) and os.path.getsize(_out_tmp) > 500:
                _r2 = subprocess.run([
                    "ffmpeg","-y","-threads",_ff_threads,"-i",_out_tmp,
                    "-frames:v",str(_n_frames_exact),
                    "-c:v","libx264","-preset","ultrafast","-crf","28",
                    "-x264-params",f"threads={_x264_thr}",
                    "-an","-pix_fmt","yuv420p","-r",str(_FPS),"-vsync","cfr",
                    "-movflags","+faststart", out
                ], capture_output=True, text=True, **_vf_no_window())
                try: os.remove(_out_tmp)
                except Exception: pass
            else:
                # fallback: usar el tmp directamente
                if os.path.exists(_out_tmp):
                    os.replace(_out_tmp, out)
            if not (os.path.exists(out) and os.path.getsize(out) > 500):
                _err = (_r.stderr or "")[-400:].strip()
                log(f"  [WARNING] _render_vid_clip E{sc['escena_idx']+1} fallback: {_err[-200:]}")
                _vf_fb = (f"scale={w_res}:{h_res}:force_original_aspect_ratio=decrease,"
                          f"pad={w_res}:{h_res}:(ow-iw)/2:(oh-ih)/2:color=black,"
                          f"setsar=1,fps={_FPS},setpts=PTS-STARTPTS")
                subprocess.run([
                    "ffmpeg","-y","-threads",_ff_threads,"-i",sc["vid_path"],
                    "-map","0:v:0","-vf",_vf_fb,
                    "-c:v","libx264","-preset","ultrafast","-crf","28",
                    "-x264-params",f"threads={_x264_thr}",
                    "-an","-r",str(_FPS),"-vsync","cfr","-pix_fmt","yuv420p",
                    "-frames:v",str(_n_frames_exact),
                    "-movflags","+faststart", out
                ], capture_output=True, text=True, **_vf_no_window())
            return out if (os.path.exists(out) and os.path.getsize(out) > 500) else None

        # ── _render_img_segment: llama a Modal con un segmento de imágenes ────
        def _render_img_segment(args, no_last_trans=False):
            seg_idx, img_scenes = args
            n_b      = max(1, _math.ceil(len(img_scenes) / BATCH_SIZE))
            batches  = [img_scenes[i*BATCH_SIZE:(i+1)*BATCH_SIZE] for i in range(n_b)]
            clips    = []
            _total_scenes = len(img_scenes)
            _scene_counter = [0]  # contador global de escenas procesadas
            for bi, batch in enumerate(batches):
                log(f"  seg{seg_idx} batch {bi+1}/{n_b}: preparando {len(batch)} escenas")
                # Añadir extra solo a scenes no-últimas del batch (overlap consume el extra)
                # Si no_last_trans=True, tampoco añadir extra a la última escena del último batch
                # (porque va seguida de un segmento de video — sin xfade entre tipos)
                batch_mod = []
                _is_last_batch = (bi == n_b - 1)
                for j, sc in enumerate(batch):
                    sc_m = _encode_img(sc)
                    _is_last_of_segment = _is_last_batch and (j == len(batch) - 1)
                    # Agregar trans_dur si: no es la última del batch
                    # Y si es la última del segmento, solo agregar si no está
                    # seguido de un segmento de video (no_last_trans=False)
                    _add_trans = (
                        transicion != "none" and
                        not _is_last_of_segment or
                        (transicion != "none" and _is_last_of_segment and not no_last_trans and not _is_last_batch)
                    )
                    if transicion != "none" and not _is_last_of_segment:
                        sc_m["duracion"] = round(sc["duracion"] + trans_dur, 3)
                    # última de segmento: no agregar trans_dur (ni si sigue video, ni si es el final)
                    batch_mod.append(sc_m)
                # Duración objetivo del clip que devuelve Modal para este batch.
                # Recortamos/normalizamos a este valor para evitar drift de PTS que
                # termina desincronizando cortes con el audio.
                expected_dur = 0.0
                try:
                    expected_dur = float(sum(float(x.get("duracion", 0.0)) for x in batch_mod))
                except Exception:
                    expected_dur = 0.0
                payload = {
                    "audio_b64":  _silent_b64,
                    "escenas":    batch_mod,
                    "resolucion": resolucion.replace("x",":"),
                    "transicion": transicion,
                    "trans_dur":  trans_dur,
                    "fade":       0,
                    "shake":      "false",
                }
                d = None
                last_err = None
                for _attempt in range(_modal_max_retries):
                    try:
                        log(
                            f"  seg{seg_idx} batch {bi+1}/{n_b}: enviando a Modal "
                            f"(intento {_attempt+1}/{_modal_max_retries})"
                        )
                        r = _modal_session().post(
                            _MODAL_URL, json=payload, timeout=(_modal_connect_timeout, _modal_read_timeout)
                        )
                        r.raise_for_status()
                        d = r.json()
                        log(f"  seg{seg_idx} batch {bi+1}/{n_b}: respuesta Modal OK")
                        last_err = None
                        break
                    except requests.exceptions.SSLError as ssl_err:
                        last_err = ssl_err
                        # SSLEOF suele ser transitorio: backoff corto + jitter
                        time.sleep(2.0 + _attempt * 2.0 + random.random() * 0.4)
                        continue
                    except (
                        requests.exceptions.ConnectionError,
                        requests.exceptions.ChunkedEncodingError,
                    ) as conn_err:
                        last_err = conn_err
                        # Renovar sesión para descartar socket/TLS roto en keep-alive.
                        try:
                            _modal_local.s = _mk_https_session(16)
                        except Exception:
                            _modal_local.s = requests.Session()
                        log(
                            f"  [WARNING] seg{seg_idx} batch {bi+1}/{n_b}: conexión Modal inestable, "
                            f"reintentando... ({str(conn_err)[:120]})"
                        )
                        time.sleep(1.5 + _attempt * 2.0 + random.random() * 0.35)
                        continue
                    except requests.exceptions.ReadTimeout as to_err:
                        last_err = to_err
                        log(
                            f"  [WARNING] seg{seg_idx} batch {bi+1}/{n_b}: timeout de Modal "
                            f"({_modal_read_timeout}s), reintentando..."
                        )
                        time.sleep(1.0 + _attempt * 1.5 + random.random() * 0.3)
                        continue
                    except requests.exceptions.HTTPError as http_err:
                        last_err = http_err
                        _st = getattr(getattr(http_err, "response", None), "status_code", None)
                        # 429/5xx suelen ser transitorios en servicios remotos.
                        if _st in (408, 409, 425, 429, 500, 502, 503, 504):
                            log(
                                f"  [WARNING] seg{seg_idx} batch {bi+1}/{n_b}: Modal HTTP {_st}, "
                                f"reintentando..."
                            )
                            time.sleep(1.5 + _attempt * 2.0 + random.random() * 0.3)
                            continue
                        break
                    except Exception as req_err:
                        last_err = req_err
                        break
                if last_err is not None:
                    body = ""
                    try:
                        body = (r.text or "")[:600]  # noqa: F821
                    except Exception:
                        pass
                    log(
                        f"  [WARNING] seg{seg_idx} batch {bi+1}/{n_b}: Modal no respondió, "
                        f"fallback local estático. {str(last_err)[:140]}"
                    )
                    _batch_clips = []
                    for _j, _sc in enumerate(batch):
                        _fb = os.path.join(tmp_dir, f"seg_{seg_idx:03d}_b{bi:02d}_fb_{_j:02d}.mp4")
                        _img_path = _sc.get("img_path", "")
                        if _img_path and os.path.exists(_img_path):
                            subprocess.run([
                                "ffmpeg","-y","-threads",_ff_threads,"-loop","1","-i",_img_path,
                                "-t",str(max(0.1, float(_sc.get("duracion", 1.0)))),
                                "-vf",f"scale={w_res}:{h_res}:force_original_aspect_ratio=decrease,"
                                      f"pad={w_res}:{h_res}:(ow-iw)/2:(oh-ih)/2:color=black,"
                                      f"setsar=1,fps=24,setpts=PTS-STARTPTS",
                                "-c:v","libx264","-preset","ultrafast","-crf","28",
                                "-x264-params",f"threads={_x264_thr}",
                                "-pix_fmt","yuv420p","-an","-movflags","+faststart", _fb
                            ], capture_output=True, text=True, **_vf_no_window())
                        if os.path.exists(_fb) and os.path.getsize(_fb) > 500:
                            _batch_clips.append(_fb)
                    if not _batch_clips:
                        raise Exception(f"Modal seg {seg_idx} batch {bi}: request error {last_err}. {body}")
                    if len(_batch_clips) == 1:
                        bp = _batch_clips[0]
                    else:
                        bp = os.path.join(tmp_dir, f"seg_{seg_idx:03d}_b{bi:02d}.mp4")
                        _cl = os.path.join(tmp_dir, f"seg_{seg_idx:03d}_b{bi:02d}_fb.txt")
                        _write_concat_list(_cl, _batch_clips)
                        _run_cmd([
                            "ffmpeg","-y","-threads",_ff_threads,"-f","concat","-safe","0","-i",_cl,
                            "-vf","setpts=PTS-STARTPTS",
                            "-c:v","libx264","-preset","ultrafast","-crf","28",
                            "-x264-params",f"threads={_x264_thr}",
                            "-pix_fmt","yuv420p","-r","24","-an","-movflags","+faststart",bp
                        ], f"Fallback local batch seg {seg_idx} falló")
                    clips.append(bp)
                    continue
                if not d.get("success"):
                    raise Exception(f"Modal seg {seg_idx} batch {bi}: {d.get('error','error')}")
                video_b64 = d.get("video_b64") or d.get("video_base64")
                if not isinstance(video_b64, str) or not video_b64.strip():
                    raise Exception(
                        f"Modal seg {seg_idx} batch {bi}: respuesta sin video_b64 válido. "
                        f"Claves: {list(d.keys())[:20]}"
                    )
                bp = os.path.join(tmp_dir, f"seg_{seg_idx:03d}_b{bi:02d}.mp4")
                try:
                    decoded_video = base64.b64decode(video_b64)
                except Exception as b64_err:
                    raise Exception(f"Modal seg {seg_idx} batch {bi}: base64 inválido ({b64_err})")
                with open(bp,"wb") as f:
                    f.write(decoded_video)
                if not os.path.exists(bp) or os.path.getsize(bp) <= 500:
                    raise Exception(f"Modal seg {seg_idx} batch {bi}: clip vacío o inválido")
                # Normalizar codec Modal --> libx264 ultrafast para compatibilidad con clips locales
                bp_n = bp.replace(".mp4","_n.mp4")
                _cmd = [
                    "ffmpeg", "-y", "-threads", _ff_threads, "-i", bp,
                ]
                if expected_dur:
                    _cmd += ["-t", str(max(0.1, expected_dur))]
                _cmd += [
                    "-c:v", "libx264", "-preset", "ultrafast", "-crf", "23",
                    "-x264-params", f"threads={_x264_thr}",
                    "-pix_fmt", "yuv420p", "-r", "24", "-an",
                    "-movflags", "+faststart", bp_n
                ]
                _nr = subprocess.run(_cmd, capture_output=True, text=True, **_vf_no_window())
                if os.path.exists(bp_n) and os.path.getsize(bp_n) > 500:
                    os.replace(bp_n, bp)
                clips.append(bp)
            if len(clips) == 1:
                return seg_idx, clips[0]
            # filter_complex con setpts=PTS-STARTPTS por batch — evita que el
            # PTS del batch 2 reinicie en 0 causando descuadre a partir de la
            # escena 21 (~4:39 en un video de 7 minutos).
            # ── Descartar clips con dimensiones inválidas (ej. 0×1) antes del
            #    concat — un clip así hace fallar todo el filter_complex.
            _clips_ok = []
            for _bi_v, _bp_v in enumerate(clips):
                try:
                    import json as _jv
                    _pr_v = subprocess.run(
                        ["ffprobe", "-v", "error", "-select_streams", "v:0",
                         "-show_entries", "stream=width,height",
                         "-of", "json", _bp_v],
                        capture_output=True, text=True, **_vf_no_window())
                    _st_v = _jv.loads(_pr_v.stdout).get("streams", [{}])
                    _bw_v = int((_st_v[0] if _st_v else {}).get("width", 0) or 0)
                    _bh_v = int((_st_v[0] if _st_v else {}).get("height", 0) or 0)
                    if _bw_v < 2 or _bh_v < 2:
                        log(f"  [WARNING] seg{seg_idx} batch{_bi_v} descartado: "
                            f"dim inválida {_bw_v}×{_bh_v} --> {os.path.basename(_bp_v)}")
                        continue
                except Exception:
                    pass  # ante la duda conservar el clip
                _clips_ok.append(_bp_v)
            if not _clips_ok:
                raise Exception(
                    f"seg {seg_idx}: todos los batches tienen dimensiones inválidas — abortando")
            clips = _clips_ok
            if len(clips) == 1:
                return seg_idx, clips[0]
            co = os.path.join(tmp_dir, f"seg_{seg_idx:03d}.mp4")
            n_c = len(clips)
            # Log duración real de cada batch antes de concatenar
            for _bi, _bp in enumerate(clips):
                try:
                    _pr = subprocess.run(["ffprobe","-v","error","-show_entries",
                        "format=duration","-of","json",_bp],capture_output=True, text=True, **_vf_no_window())
                    import json as _j
                    _bd = float(_j.loads(_pr.stdout).get("format",{}).get("duration",0))
                    log(f"  batch{_bi}: {os.path.basename(_bp)} dur={_bd:.3f}s")
                except Exception: pass
            fc_inputs = []
            for cp in clips:
                fc_inputs += ["-i", cp]
            # Normalizar resolución de cada batch antes de concatenar.
            # Sin esto, si Modal devuelve clips con dimensiones distintas
            # (o un lote fallback en resolución diferente) FFmpeg falla
            # con "Stream #1:0 0x1" / dimension mismatch en concat filter.
            fp = "".join(
                f"[{k}:v]scale={w_res}:{h_res}:force_original_aspect_ratio=decrease,"
                f"pad={w_res}:{h_res}:(ow-iw)/2:(oh-ih)/2:color=black,"
                f"setsar=1,fps=24,setpts=PTS-STARTPTS[v{k}];"
                for k in range(n_c)
            )
            fp += "".join(f"[v{k}]" for k in range(n_c))
            fp += f"concat=n={n_c}:v=1:a=0[vout]"
            _run_cmd(["ffmpeg","-y","-threads",_ff_threads] + fc_inputs + [
                "-filter_complex", fp, "-map", "[vout]",
                "-c:v","libx264","-preset","ultrafast","-crf","23",
                "-x264-params",f"threads={_x264_thr}",
                "-pix_fmt","yuv420p","-r","24","-an",
                "-movflags","+faststart", co
            ], f"No se pudo concatenar batches de imagen seg {seg_idx}")
            # Log duración del segmento resultante
            try:
                _pr2 = subprocess.run(["ffprobe","-v","error","-show_entries",
                    "format=duration","-of","json",co],capture_output=True, text=True, **_vf_no_window())
                _sd = float(_j.loads(_pr2.stdout).get("format",{}).get("duration",0))
                _esp = sum(sc["duracion"] for sc in img_scenes)
                log(f"  seg{seg_idx} concat: dur={_sd:.3f}s esperado={_esp:.3f}s Δ={_sd-_esp:+.3f}s")
            except Exception: pass
            return seg_idx, co

        # ── _render_vid_segment: procesa clips de video en paralelo con FFmpeg
        def _render_vid_segment(args):
            seg_idx, vid_scenes = args
            # Procesar en paralelo pero ordenar por escena_idx para garantizar orden correcto
            def _render_one(sc):
                return sc["escena_idx"], _render_vid_clip(sc, sc["escena_idx"])
            with _TPE(max_workers=min(len(vid_scenes), _vid_clip_par)) as _ex:
                _res_vid = list(_ex.map(_render_one, vid_scenes))
            _res_vid.sort(key=lambda x: x[0])
            _sc_map = {sc["escena_idx"]: sc for sc in vid_scenes}
            clip_paths = []
            for _eidx, _path in _res_vid:
                if _path and os.path.exists(_path) and os.path.getsize(_path) > 500:
                    clip_paths.append(_path)
                else:
                    _sc = _sc_map[_eidx]
                    _fb = os.path.join(tmp_dir, f"vc_{_eidx:05d}_fb.mp4")
                    log(f"  [WARNING] clip E{_eidx+1} falló — usando imagen estática como fallback")
                    # Intentar usar la imagen correspondiente (img_XXXXX.jpg/png/webp)
                    _img_path = _sc.get("img_path", "")
                    _img_ok = _img_path and os.path.exists(_img_path)
                    if _img_ok:
                        _fr = subprocess.run([
                            "ffmpeg","-y","-threads",_ff_threads,"-loop","1","-i",_img_path,
                            "-t",str(_sc["duracion"]),
                            "-vf",f"scale={w_res}:{h_res}:force_original_aspect_ratio=decrease,"
                                  f"pad={w_res}:{h_res}:(ow-iw)/2:(oh-ih)/2:color=black,"
                                  f"setsar=1,fps=24,setpts=PTS-STARTPTS",
                            "-c:v","libx264","-preset","ultrafast","-crf","28",
                            "-x264-params",f"threads={_x264_thr}",
                            "-pix_fmt","yuv420p","-an","-movflags","+faststart", _fb
                        ], capture_output=True, **_vf_no_window())
                    if not _img_ok or not (os.path.exists(_fb) and os.path.getsize(_fb) > 500):
                        # Último recurso: clip negro
                        subprocess.run([
                            "ffmpeg","-y","-threads",_ff_threads,"-f","lavfi",
                            "-i",f"color=c=black:s={w_res}x{h_res}:r=24:d={_sc['duracion']}",
                            "-c:v","libx264","-preset","ultrafast","-crf","28",
                            "-x264-params",f"threads={_x264_thr}",
                            "-pix_fmt","yuv420p","-an","-movflags","+faststart", _fb
                        ], capture_output=True, **_vf_no_window())
                    if os.path.exists(_fb) and os.path.getsize(_fb) > 500:
                        clip_paths.append(_fb)
            if not clip_paths:
                raise Exception(f"Segmento video {seg_idx}: ningún clip generado")
            if len(clip_paths) == 1:
                return seg_idx, clip_paths[0]
            cl = os.path.join(tmp_dir, f"seg_{seg_idx:03d}_cl.txt")
            _write_concat_list(cl, clip_paths)
            co = os.path.join(tmp_dir, f"seg_{seg_idx:03d}.mp4")
            # Calcular frames totales exactos del segmento para forzar duración precisa
            _seg_dur_exact = sum(sc["duracion"] for sc in vid_scenes)
            _seg_frames_exact = int(round(_seg_dur_exact * 24))
            _run_cmd(["ffmpeg","-y","-threads",_ff_threads,"-f","concat","-safe","0","-i",cl,
                      "-vf","setpts=PTS-STARTPTS","-c:v","libx264","-preset","ultrafast","-crf","28",
                      "-x264-params",f"threads={_x264_thr}",
                      "-pix_fmt","yuv420p","-r","24","-vsync","cfr","-an",
                      "-frames:v",str(_seg_frames_exact),
                      "-movflags","+faststart",
                      co], f"No se pudo concatenar clips de video seg {seg_idx}")
            # Medir drift real y corregir si es necesario
            try:
                import json as _jv
                _prv = subprocess.run(["ffprobe","-v","error","-show_entries",
                    "format=duration","-of","json",co],capture_output=True, text=True, **_vf_no_window())
                _vd = float(_jv.loads(_prv.stdout).get("format",{}).get("duration",0))
                _drift = _vd - _seg_dur_exact
                log(f"  seg{seg_idx} video concat: {len(vid_scenes)} clips, dur={_vd:.3f}s esperado={_seg_dur_exact:.3f}s Δ={_drift:+.3f}s")
                # Si hay drift > 1 frame, corregir con setpts proporcional
                if abs(_drift) > 0.042 and _vd > 0.1:
                    _corr_ratio = _seg_dur_exact / _vd
                    _co_corr = co.replace(".mp4", "_corr.mp4")
                    subprocess.run([
                        "ffmpeg","-y","-threads",_ff_threads,"-i",co,
                        "-vf",f"setpts={_corr_ratio:.8f}*PTS-STARTPTS",
                        "-c:v","libx264","-preset","ultrafast","-crf","28",
                        "-x264-params",f"threads={_x264_thr}",
                        "-pix_fmt","yuv420p","-r","24","-vsync","cfr","-an",
                        "-frames:v",str(_seg_frames_exact),
                        "-movflags","+faststart", _co_corr
                    ], capture_output=True, **_vf_no_window())
                    if os.path.exists(_co_corr) and os.path.getsize(_co_corr) > 500:
                        os.replace(_co_corr, co)
                        log(f"  [OK] seg{seg_idx} drift corregido: {_drift:+.3f}s --> 0.000s")
            except Exception: pass
            return seg_idx, co

        # ── Agrupar escenas en segmentos consecutivos por tipo ────────────────
        segments = []
        cur_type, cur_batch = None, []
        for sc in scenes:
            if sc["type"] != cur_type:
                if cur_batch: segments.append((cur_type, cur_batch))
                cur_type, cur_batch = sc["type"], [sc]
            else:
                cur_batch.append(sc)
        if cur_batch: segments.append((cur_type, cur_batch))

        # Marcar si cada segmento imagen es seguido por un segmento de video.
        # En ese caso su última escena NO debe tener trans_dur extra —
        # el overlap de xfade no ocurre entre segmentos de distinto tipo.
        _seg_followed_by_video = []
        for _si, (st, _) in enumerate(segments):
            if st == "image" and _si + 1 < len(segments) and segments[_si+1][0] == "video":
                _seg_followed_by_video.append(_si)

        n_img_segs = sum(1 for t,_ in segments if t == "image")
        n_vid_segs = sum(1 for t,_ in segments if t == "video")
        log(f"🔀 {len(segments)} segmentos — {n_img_segs} imagen-->Modal · {n_vid_segs} video-->FFmpeg", 30)

        # ── Procesar todos los segmentos EN PARALELO ──────────────────────────
        log("⚡ Procesando segmentos en paralelo...", 35)
        def _process_segment(args):
            seg_idx, (seg_type, seg_scenes) = args
            if seg_type == "image":
                # Si este segmento imagen va seguido de video, su última escena
                # no debe tener trans_dur — pasar flag para que _render_img_segment lo sepa
                _no_last_trans = seg_idx in _seg_followed_by_video
                return _render_img_segment((seg_idx, seg_scenes), no_last_trans=_no_last_trans)
            else:
                return _render_vid_segment((seg_idx, seg_scenes))

        with _TPE(max_workers=min(_seg_par, len(segments))) as ex:
            results = list(ex.map(_process_segment, enumerate(segments)))
        results.sort(key=lambda x: x[0])
        log(f"✓ {len(results)} segmentos listos", 82)

        # ── Stitch todos los segmentos en orden ───────────────────────────────
        results.sort(key=lambda x: x[0])
        seg_paths_raw = [(idx, p) for idx, p in results if p and os.path.exists(p)]
        log(f"🔗 Segmentos para stitch: {len(seg_paths_raw)}/{len(results)}")
        for idx, p in seg_paths_raw:
            try:
                _pr = subprocess.run(["ffprobe","-v","error","-show_entries",
                    "format=duration,stream=codec_name,width,height,r_frame_rate",
                    "-of","json", p], capture_output=True, text=True, **_vf_no_window())
                log(f"  seg{idx}: {os.path.basename(p)} — {_pr.stdout[:200].strip()}")
            except Exception:
                log(f"  seg{idx}: {os.path.basename(p)}")
        if not seg_paths_raw:
            raise Exception("No se generaron clips de segmentos")

        # Limpiar archivos temporales intermedios antes del concat para liberar espacio en disco
        log("🧹 Liberando espacio temporal...", 84)
        seg_finals = set(p for _, p in seg_paths_raw)
        for _f in os.listdir(tmp_dir):
            _fp = os.path.join(tmp_dir, _f)
            if _fp not in seg_finals and _f not in ("silent.mp3", "audio_s.mp3"):
                try: os.remove(_fp)
                except Exception: pass

        # Unir segmentos con filter_complex: normaliza specs en un solo paso.
        # CRF 28 para reducir uso de disco (~4x menos que CRF 18, calidad suficiente).
        log("🔗 Uniendo y normalizando segmentos con filter_complex...", 85)
        concat_out = os.path.join(tmp_dir, "concat_final.mp4")
        n_segs = len(seg_paths_raw)
        inputs = []
        for _, p in seg_paths_raw:
            inputs += ["-i", p]
        vf = (f"scale={w_res}:{h_res}:force_original_aspect_ratio=decrease,"
              f"pad={w_res}:{h_res}:(ow-iw)/2:(oh-ih)/2:color=black,"
              f"setsar=1,fps=24,setpts=PTS-STARTPTS")
        # Calcular frames totales exactos del video completo
        _total_frames_exact = int(round(duracion_total * 24))
        filter_parts = "".join(f"[{i}:v]{vf}[v{i}];" for i in range(n_segs))
        concat_inputs = "".join(f"[v{i}]" for i in range(n_segs))
        filter_str = f"{filter_parts}{concat_inputs}concat=n={n_segs}:v=1:a=0[vout]"
        _run_cmd(
            ["ffmpeg","-y","-threads",_ff_threads] + inputs + [
                "-filter_complex", filter_str,
                "-map", "[vout]",
                "-c:v","libx264","-preset","ultrafast","-crf","28",
                "-x264-params",f"threads={_x264_thr}",
                "-pix_fmt","yuv420p","-r","24","-vsync","cfr","-an",
                "-frames:v",str(_total_frames_exact),
                "-movflags","+faststart", concat_out
            ], "No se pudo unir segmentos finales"
        )

        # ── Mezcla de audio final (alineado a duración del audio maestro; sin -shortest) ──
        log("🎵 Mezclando audio...", 90)
        video_final = os.path.join(out_dir, f"render_{job_id}.mp4")
        try:
            _vf_final_mux_aligned(concat_out, audio_path_mix, video_final, duracion_total, log=log)
        except Exception as _mux_e:
            raise Exception(f"No se pudo mezclar audio final: {_mux_e}") from _mux_e

        if not os.path.exists(video_final):
            raise Exception("FFmpeg no generó el video final")

        size_mb = os.path.getsize(video_final) / (1024*1024)
        log(f"[OK] Video listo — {size_mb:.1f} MB", 100)
        jobs[job_id].update({
            "estado":    "completado",
            "video_url": f"/api/descargar_render/{job_id}",
            "video_path": video_final,
            "size_mb":   round(size_mb,1),
            "duracion":  round(duracion_total,1),
            "escenas":   len(scenes),
        })
        _abrir_carpeta(video_final)

    except Exception as e:
        try:
            import traceback as _tb4
            print(_tb4.format_exc().encode('ascii', 'replace').decode('ascii'))
        except Exception:
            pass
        _e_safe = str(e).encode('ascii', 'replace').decode('ascii')
        log(f"Error: {_e_safe}")
        jobs[job_id].update({"estado":"error","error":_e_safe})
    finally:
        _sh.rmtree(tmp_dir, ignore_errors=True)




@app.route("/api/descargar_render/<job_id>")
def descargar_render(job_id):
    if job_id not in jobs: return jsonify({"error":"no encontrado"}),404
    path = jobs[job_id].get("video_path","")
    if not path or not os.path.exists(path): return jsonify({"error":"video no listo"}),404
    import re as _re
    proj = re.sub(r"[^\w\-]","_",jobs[job_id].get("mensaje","render"))[:30]
    return send_file(path, as_attachment=True, download_name=f"render_{job_id}.mp4")


@app.route("/api/proyectos/borrar", methods=["POST"])
def borrar_proyecto():
    import shutil as _shutil, re as _r
    data = request.get_json(force=True, silent=True) or {}
    raw = (data.get("nombre") or data.get("name") or "").strip()
    name = _r.sub(r"[^\w\-]", "_", raw)[:60]
    if not name:
        return jsonify({"error": "Nombre invalido"}), 400
    from pathlib import Path as _P
    jobs = _P(JOBS_FOLDER)
    proj = jobs / name
    if not proj.exists():
        return jsonify({"ok": True, "msg": "not_found"})
    try:
        proj.resolve().relative_to(jobs.resolve())
    except ValueError:
        return jsonify({"error": "Ruta invalida"}), 400
    if not proj.is_dir():
        return jsonify({"error": "No es directorio"}), 400
    _shutil.rmtree(str(proj))
    return jsonify({"ok": True, "nombre": name})


# --- Mismo dominio «proyectos»: salidas en video_final/ (tras el job de render) ---

@app.route("/api/proyectos/videos_final")
def proyecto_videos_final():
    proj_name = request.args.get("project","")
    if not proj_name: return jsonify({"videos":[]}), 200
    from pathlib import Path as _P
    vf_dir = _P(JOBS_FOLDER) / proj_name / "video_final"
    if not vf_dir.exists(): return jsonify({"videos":[]}), 200
    videos = sorted([f.name for f in vf_dir.glob("*.mp4")])
    return jsonify({"videos": videos})

@app.route("/api/proyectos/video_final")
def proyecto_video_final():
    proj_name = request.args.get("project","")
    fname     = request.args.get("file","")
    dl        = request.args.get("dl","0") == "1"
    if not proj_name or not fname: return jsonify({"error":"missing params"}),400
    from pathlib import Path as _P
    path = _P(JOBS_FOLDER) / proj_name / "video_final" / fname
    if not path.exists(): return jsonify({"error":"not found"}),404
    return send_file(
        str(path),
        as_attachment=dl,
        download_name=fname,
        mimetype="video/mp4",
        conditional=True,
    )


@app.route("/api/proyectos/abrir_video_final", methods=["POST"])
def proyecto_abrir_video_final():
    """Abre en el explorador de archivos la carpeta video_final del proyecto (cross-platform)."""
    data = request.get_json(force=True, silent=True) or {}
    proj_name = re.sub(r"[^\w\-]", "_", (data.get("project") or "").strip())
    if not proj_name:
        return jsonify(ok=False, error="Falta el nombre del proyecto"), 400
    from pathlib import Path as _P
    d = _P(JOBS_FOLDER) / proj_name / "video_final"
    try:
        d.mkdir(parents=True, exist_ok=True)
    except OSError as e:
        return jsonify(ok=False, error=str(e)), 400
    try:
        _abrir_carpeta(str(d))
    except Exception as e:
        return jsonify(ok=False, error=str(e)), 500
    return jsonify(ok=True, path=str(d))


