# 9. VOZ — /api/voz/* (webhooks n8n)
# ══════════════════════════════════════════════════════════════════

_N8N_HOST_CANON = "n8n-n8n.y9c1cn.easypanel.host"

def _n8n_fix_url(url: str) -> str:
    """Normaliza host n8n por typo común y alias."""
    if not url:
        return url
    return str(url).replace("y9clcn", "y9c1cn").replace("y9C1cn", "y9c1cn")

def _n8n_request(method: str, url: str, *, json_payload=None, timeout=120, attempts=3):
    """Request con reintentos robustos para n8n.

    Usa una sesión NUEVA en cada intento para evitar reutilizar sockets
    keep-alive ya cerrados por el servidor (ConnectionResetError 10054 en
    Windows / BrokenPipeError en Linux). El header Connection:close le indica
    al servidor que no mantenga el socket abierto, eliminando la fuente del
    reset en solicitudes largas como merge-audio.
    """
    import time as _t, random as _rnd
    _url = _n8n_fix_url(url)
    # Errores de red que se pueden reintentar con una sesión limpia
    _retryable = (
        requests.exceptions.ConnectionError,
        requests.exceptions.ChunkedEncodingError,
        requests.exceptions.Timeout,
    )
    last = None
    for i in range(max(1, int(attempts))):
        # Sesión nueva en cada intento — no reutiliza sockets muertos
        _s = requests.Session()
        _s.headers.update({"Connection": "close"})
        try:
            resp = _s.request(
                method.upper(),
                _url,
                json=json_payload,
                timeout=timeout,
            )
            return resp
        except _retryable as e:
            last = e
            if i < attempts - 1:
                # Backoff exponencial con jitter: 1s, ~2.5s, ~5s …
                _t.sleep((2 ** i) + _rnd.uniform(0.2, 0.8))
        except Exception as e:
            # Error no reintentable (p. ej. JSON inválido, SSL roto sin recuperación)
            last = e
            if i < attempts - 1:
                _t.sleep(1.2 * (i + 1))
        finally:
            try:
                _s.close()
            except Exception:
                pass
    raise RuntimeError(
        "No se pudo conectar con el servidor de voces. "
        "Verifica Internet o n8n y vuelve a intentar."
    ) from last

@app.route("/api/voz/voces")
def voz_get_voces():
    try:
        r = _n8n_request("GET", "https://n8n-n8n.y9c1cn.easypanel.host/webhook/voces-videoforge", timeout=20, attempts=3)
        if r.status_code >= 400:
            return Response(
                r.text, status=r.status_code, content_type="application/json; charset=utf-8"
            )
        try:
            data = r.json()
        except Exception:
            return Response(
                r.text, status=r.status_code, content_type="application/json; charset=utf-8"
            )
        out = None
        if isinstance(data, list):
            out = data
            # n8n a veces devuelve [{voices:[...]}] — desenvuelve si los items no son voces
            if out and isinstance(out[0], dict) and not out[0].get("voice_id") and not out[0].get("ID Voz"):
                for key in ("data", "voces", "voices", "items", "results", "rows", "list"):
                    v = out[0].get(key)
                    if isinstance(v, list):
                        out = v
                        break
        elif isinstance(data, dict):
            for key in ("data", "voces", "voices", "items", "results", "rows", "list"):
                v = data.get(key)
                if isinstance(v, list):
                    out = v
                    break
        if out is not None:
            # Normaliza para que cada item tenga "ID Voz" y "Nombre Voz" como espera el frontend
            _skip_keys = {"ID Voz", "Nombre Voz", "row_number", "id", "voice_id"}
            normed = []
            for item in out:
                if isinstance(item, dict):
                    item = dict(item)
                    # Si no tiene "ID Voz", mapear desde campos ElevenLabs estándar
                    if "ID Voz" not in item:
                        vid = item.get("voice_id") or item.get("id") or ""
                        if vid:
                            item["ID Voz"] = vid
                    # Si tiene "ID Voz" pero no "Nombre Voz", buscar el nombre en cualquier otra columna string
                    if item.get("ID Voz") and "Nombre Voz" not in item:
                        vname = item.get("name") or item.get("voice_name") or ""
                        if not vname:
                            # Tomar el primer campo string que no sea ID ni metadato
                            for k, v in item.items():
                                if k not in _skip_keys and isinstance(v, str) and v.strip():
                                    vname = v.strip()
                                    break
                        item["Nombre Voz"] = vname or item["ID Voz"]
                    if item.get("ID Voz"):
                        normed.append(item)
            out = normed
            return Response(
                json.dumps(out, ensure_ascii=False),
                status=200,
                content_type="application/json; charset=utf-8",
            )
        return Response(
            r.text, status=r.status_code, content_type="application/json; charset=utf-8"
        )
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route("/api/voz/generar", methods=["POST"])
def voz_generar():
    """
    Sends text to n8n in safe chunks.
    Sanitizes text so n8n's JSON expression {{ $json.data }} never breaks.
    """
    import re as _re, time as _t
    from pathlib import Path as _P

    data     = request.get_json() or {}
    pn       = data.pop("project_name", "")
    voice_id = data.get("voice_id", "")
    text     = data.get("data", "").strip()

    # ── Verificación de límite de voz (server-side, siempre desde la BD) ──
    _vg_user = _current_username()
    if _vg_user:
        _vg_chars = len(text)
        _vg_ok, _vg_msg, _vg_extra = check_limit(_vg_user, "tts", _vg_chars)
        if not _vg_ok:
            return jsonify({
                "error": _vg_msg,
                "limit_reached": True,
                "limit_type": "tts",
                "extra": _vg_extra,
            }), 429

    N8N_URL   = "https://n8n-n8n.y9c1cn.easypanel.host/webhook/541b2f00-1fbb-443f-8225-25dd5969da01"
    MAX_CHARS = 900

    def _sanitize(t):
        """Remove chars that break n8n JSON expressions."""
        t = t.replace("\r\n", " ").replace("\n", " ").replace("\r", " ")
        t = t.replace('"', "'").replace("\\", " ")
        t = " ".join(t.split())   # collapse multiple spaces
        return t.strip()

    def _split(txt, max_c):
        """Split at sentence boundaries, max max_c chars each."""
        chunks, start = [], 0
        while start < len(txt):
            end_pos = start + max_c
            if end_pos >= len(txt):
                chunk = txt[start:].strip()
                if chunk: chunks.append(chunk)
                break
            cut = -1
            for i in range(end_pos, start + max_c // 2, -1):
                if txt[i] in ".!?": cut = i + 1; break
            if cut == -1:
                for i in range(end_pos, start + max_c // 2, -1):
                    if txt[i] == " ": cut = i; break
            if cut == -1: cut = end_pos
            chunk = txt[start:cut].strip()
            if chunk: chunks.append(chunk)
            start = cut
        return chunks

    clean  = _sanitize(text)
    chunks = _split(clean, MAX_CHARS) if len(clean) > MAX_CHARS else [clean]

    all_fragments = []
    for chunk in chunks:
        try:
            r = _n8n_request(
                "POST",
                N8N_URL,
                json_payload={"data": chunk, "voice_id": voice_id},
                timeout=300,
                attempts=3
            )
            result = r.json()
            _res   = result[0] if isinstance(result, list) else result
            if isinstance(_res, dict) and _res.get("fragments"):
                for _frag in _res["fragments"]: _frag["chunkText"] = chunk; all_fragments.append(_frag)
            else:
                err = _res.get("message", str(_res)[:120]) if isinstance(_res, dict) else str(_res)[:120]
                return jsonify({"error": f"n8n error: {err}"}), 500
        except Exception as e:
            return jsonify({"error": str(e)}), 500

    if not all_fragments:
        return jsonify({"error": "No se generaron fragmentos"}), 500

    # ── Registrar uso de TTS en la BD ────────────────────────────
    if _vg_user:
        try:
            _vg_uid = (_get_user_full(_vg_user) or {}).get("id")
            if _vg_uid:
                record_usage(_vg_uid, tts_chars=_vg_chars)
        except Exception:
            pass  # nunca bloquear la respuesta por fallo de registro

    return jsonify({"fragments": all_fragments})


@app.route("/api/voz/fusionar", methods=["POST"])
def voz_fusionar():
    data=request.get_json() or {}
    pn=data.pop("project_name","")
    try:
        r=_n8n_request("POST", "https://n8n-n8n.y9c1cn.easypanel.host/webhook/merge-audio", json_payload=data, timeout=360, attempts=5)
        if r.status_code >= 400:
            return jsonify({"error": f"n8n merge-audio respondio {r.status_code}: {r.text[:300]}"}), 502
        try:
            result=r.json()
        except Exception:
            return jsonify({"error": f"Respuesta invalida de merge-audio: {r.text[:200]}"}), 502
        raw=result[0] if isinstance(result,list) else result
        if pn and raw.get("finalAudio"):
            from pathlib import Path as _P; import re as _r; import time as _t
            ad=_P(JOBS_FOLDER)/_r.sub(r"[^\w\-]","_",pn)/"audio"; ad.mkdir(parents=True,exist_ok=True)
            s=raw["finalAudio"]
            if s.startswith("data:"):
                _,b=s.split(",",1)
                ts=int(_t.time())
                (ad/f"voz_completa_{ts}.wav").write_bytes(base64.b64decode(b))
        return Response(r.text,status=r.status_code,content_type="application/json")
    except Exception as e: return jsonify({"error":str(e)}),500

