@app.route("/api/guion/guardar", methods=["POST"])
def guion_guardar():
    data      = request.get_json() or {}
    proj_name = data.get("project_name", "").strip()
    texto     = data.get("texto", "").strip()
    prompts   = data.get("prompts", "").strip()
    if not proj_name or not texto:
        return jsonify({"error": "Faltan datos"}), 400
    import re as _re
    from pathlib import Path as _P
    proj_name = _re.sub(r"[^\w\-]", "_", proj_name)
    guion_dir = _P(JOBS_FOLDER) / proj_name / "guion"
    guion_dir.mkdir(parents=True, exist_ok=True)
    (guion_dir / "guion_fragmentado.txt").write_text(texto, encoding="utf-8")
    if prompts:
        (guion_dir / "prompts_imagen.txt").write_text(prompts, encoding="utf-8")
    return jsonify({"ok": True})

@app.route("/api/guion/cargar")
def guion_cargar():
    proj_name = request.args.get("project", "").strip()
    if not proj_name:
        return jsonify({"texto": "", "prompts": "", "existe": False})
    import re as _re
    from pathlib import Path as _P
    proj_name = _re.sub(r"[^\w\-]", "_", proj_name)
    guion_dir = _P(JOBS_FOLDER) / proj_name / "guion"
    path_g    = guion_dir / "guion_fragmentado.txt"
    path_p    = guion_dir / "prompts_imagen.txt"
    if path_g.exists():
        pts = path_p.read_text(encoding="utf-8") if path_p.exists() else ""
        return jsonify({"texto": path_g.read_text(encoding="utf-8"), "prompts": pts, "existe": True})
    return jsonify({"texto": "", "prompts": "", "existe": False})


@app.route("/api/audio/cargar")
def audio_cargar():
    proj_name = request.args.get("project", "").strip()
    if not proj_name:
        return jsonify({"existe": False, "archivos": []})
    import re as _re
    from pathlib import Path as _P
    proj_name = _re.sub(r"[^\w\-]", "_", proj_name)
    audio_dir = _P(JOBS_FOLDER) / proj_name / "audio"
    if not audio_dir.exists():
        return jsonify({"existe": False, "archivos": []})
    exts = {".mp3", ".wav", ".m4a", ".ogg", ".aac"}
    files = [f for f in audio_dir.iterdir() if f.is_file() and f.suffix.lower() in exts]
    if not files:
        return jsonify({"existe": False, "archivos": []})
    # Sort by modification time (newest first)
    files.sort(key=lambda f: f.stat().st_mtime, reverse=True)
    archivos = [f.name for f in files]
    return jsonify({"existe": True, "archivos": archivos, "principal": archivos[0]})

@app.route("/api/audio/archivo")
def audio_archivo():
    proj_name = request.args.get("project", "").strip()
    fname     = request.args.get("file", "").strip()
    if not proj_name or not fname:
        return jsonify({"error": "missing params"}), 400
    import re as _re
    from pathlib import Path as _P
    proj_name = _re.sub(r"[^\w\-]", "_", proj_name)
    path = _P(JOBS_FOLDER) / proj_name / "audio" / fname
    if not path.exists():
        return jsonify({"error": "not found"}), 404
    # Detectar mimetype correcto según extensión para evitar "failed to fetch"
    _ext = path.suffix.lower()
    _mime_map = {
        ".mp3": "audio/mpeg", ".wav": "audio/wav",
        ".m4a": "audio/mp4", ".aac": "audio/aac",
        ".ogg": "audio/ogg", ".flac": "audio/flac",
    }
    _mime = _mime_map.get(_ext, "audio/mpeg")
    return send_file(str(path), mimetype=_mime,
                     download_name=fname, as_attachment=False)



