".tl-lr{height:20px;flex-shrink:0;border-bottom:1px solid var(--b)}\n"
".tl-tl{height:64px;display:flex;align-items:center;gap:5px;\n"
"  padding:0 6px 0 8px;border-bottom:1px solid var(--b);flex-shrink:0}\n"
".tl-tl.ir{height:56px}\n"
".tl-tl.audio{height:48px}\n"
