".tl-arow{height:48px;flex-shrink:0;position:relative;border-bottom:1px solid var(--b);\n"
"  background:rgba(34,211,160,.025)}\n"
".tl-seg{position:absolute;top:4px;bottom:4px;border-radius:6px;\n"
"  border:1.5px solid rgba(124,106,255,.4);background:rgba(124,106,255,.18);\n"
