".tl-tmark{position:absolute;top:4px;bottom:4px;width:12px;\n"
"  background:rgba(168,139,250,.6);border-radius:3px;cursor:pointer;z-index:2;\n"
"  display:flex;align-items:center;justify-content:center}\n"
".tl-tmark:hover{background:rgba(168,139,250,.9)}\n"
".tl-tmark span{font-size:7px;color:#fff;writing-mode:vertical-rl}\n"
".tl-ablk{position:absolute;top:4px;bottom:4px;border-radius:6px;\n"
"  border:1.5px solid rgba(34,211,160,.4);background:rgba(34,211,160,.12);\n"
"  overflow:hidden;cursor:pointer;min-width:20px}\n"
".tl-ablk.sel{border-color:var(--c3);background:rgba(34,211,160,.22)}\n"
".tl-albl{position:absolute;top:2px;left:6px;font-family:var(--mono);\n"
"  font-size:7px;color:var(--c3);white-space:nowrap;pointer-events:none;z-index:2}\n"
".tl-awc{width:100%;height:100%;display:block;opacity:.8}\n"
".tl-hdl{position:absolute;top:0;bottom:0;width:8px;cursor:ew-resize;\n"
"  background:rgba(255,255,255,.15);z-index:3;transition:.1s}\n"
".tl-hdl:hover,.tl-hdl.drg{background:rgba(255,255,255,.45)}\n"
".tl-hdl.L{left:0;border-radius:4px 0 0 4px}\n"
".tl-hdl.R{right:0;border-radius:0 4px 4px 0}\n"
"#tl-ph{position:absolute;top:0;bottom:0;width:2px;\n"
"  background:var(--cer);z-index:20;pointer-events:auto;cursor:ew-resize;\n"
"  box-shadow:0 0 6px rgba(244,114,134,.6)}\n"
"#tl-ph::before{content:'';position:absolute;top:0;left:-4px;\n"
"  width:10px;height:10px;background:var(--cer);border-radius:50%}\n"
"#tl-ph::after{content:'';position:absolute;top:0;bottom:0;left:-6px;width:14px;cursor:ew-resize}\n"
"#transcript-list{padding:8px}\n"
".tr-seg{display:flex;align-items:flex-start;gap:8px;padding:7px 8px;\n"
"  border-radius:8px;cursor:pointer;margin-bottom:4px;transition:.15s;\n"
"  border:1px solid transparent}\n"
".tr-seg:hover{background:var(--p);border-color:var(--b2)}\n"
".tr-seg.active{background:rgba(124,106,255,.15);border-color:rgba(124,106,255,.4)}\n"
".tr-time{font-family:var(--mono);font-size:9px;color:var(--m);min-width:34px;margin-top:2px}\n"
".tr-text{font-size:11px;color:var(--t);flex:1;line-height:1.4}\n"
"#btn-transcribe{display:flex;align-items:center;justify-content:center;gap:8px;\n"
"  width:100%;padding:10px;border:1px dashed var(--c3);border-radius:9px;\n"
"  background:transparent;color:var(--c3);font-size:12px;cursor:pointer;transition:.15s}\n"
"#btn-transcribe:hover{background:rgba(34,211,160,.1)}\n"
"#btn-transcribe:disabled{opacity:.5;cursor:not-allowed}\n"
".tl-ovrow{height:36px;flex-shrink:0;position:relative;border-bottom:1px solid var(--b);background:rgba(124,106,255,.02)}\n"
".tl-irrow{height:56px;flex-shrink:0;position:relative;border-bottom:1px solid var(--b);background:rgba(245,158,11,.02)}\n"
".tl-tl.ov,.tl-tl.ir{height:36px}\n"
".tl-ovblk{position:absolute;top:4px;bottom:4px;border-radius:5px;border:1.5px solid rgba(124,106,255,.6);background:rgba(124,106,255,.25);cursor:pointer;overflow:hidden;min-width:12px;display:flex;align-items:center;user-select:none}\n"
".tl-ovblk:hover,.tl-ovblk.sel{border-color:var(--c2);background:rgba(168,139,250,.4)}\n"
".tl-iblk{position:absolute;top:4px;bottom:4px;border-radius:5px;border:1.5px solid rgba(245,158,11,.6);\n"
"  background:rgba(245,158,11,.2);cursor:pointer;overflow:hidden;min-width:12px;\n"
"  display:flex;flex-direction:column;background-size:cover;background-position:center}\n"
".tl-iblk:hover{border-color:var(--ce)}\n"
".tl-iblk-overlay{position:absolute;inset:0;background:rgba(245,158,11,.25);pointer-events:none}\n"
".tl-iblk:hover .tl-iblk-overlay{background:rgba(245,158,11,.38)}\n"
".tl-blbl{font-family:var(--mono);font-size:6px;color:rgba(255,255,255,.85);padding:0 3px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;pointer-events:none;flex:1}\n"
".tl-hdl2{position:absolute;top:0;bottom:0;width:6px;cursor:ew-resize;background:rgba(255,255,255,.2);z-index:3}\n"
".tl-hdl2:hover{background:rgba(255,255,255,.55)}\n"
".tl-hdl2.L{left:0;border-radius:4px 0 0 4px}.tl-hdl2.R{right:0;border-radius:0 4px 4px 0}\n"
"@keyframes spin{to{transform:rotate(360deg)}}\n"
"#loading-overlay{position:fixed;inset:0;background:var(--bg);display:flex;align-items:center;\n"
"  justify-content:center;flex-direction:column;gap:14px;z-index:9999}\n"
"#loading-overlay.hidden{display:none}\n"
".ld-ring{width:44px;height:44px;border:3px solid var(--b2);border-top-color:var(--c1);\n"
"  border-radius:50%;animation:spin .7s linear infinite}\n"
".ld-txt{font-family:var(--mono);font-size:11px;color:var(--m)}\n"
"#render-modal{position:fixed;inset:0;background:rgba(0,0,0,.7);z-index:500;\n"
"  display:none;align-items:center;justify-content:center}\n"
"#render-modal.open{display:flex}\n"
"#render-box{background:var(--s);border:1px solid var(--b2);border-radius:14px;\n"
"  width:520px;max-width:92vw;padding:22px;display:flex;flex-direction:column;gap:12px}\n"
"#render-box h3{font-size:14px;font-weight:700}\n"
"#render-pbar{height:6px;background:var(--b2);border-radius:99px;overflow:hidden}\n"
"#render-pfill{height:100%;width:0%;background:linear-gradient(90deg,var(--c1),var(--c3));\n"
"  border-radius:99px;transition:width .4s}\n"
"#render-log{height:180px;background:var(--bg);border-radius:8px;padding:10px;\n"
"  overflow-y:auto;font-family:var(--mono);font-size:10px;color:var(--m);line-height:1.6}\n"
"#render-btns{display:flex;gap:8px;justify-content:flex-end}\n"
".btn-pri{padding:8px 18px;border:none;border-radius:8px;font-size:12px;font-weight:600;\n"
"  cursor:pointer;background:var(--c1);color:#fff;transition:.15s;text-decoration:none;\n"
"  display:inline-flex;align-items:center;gap:6px}\n"
".btn-sec{padding:8px 18px;border:none;border-radius:8px;font-size:12px;font-weight:600;\n"
"  cursor:pointer;background:var(--b2);color:var(--t);transition:.15s}\n"
".btn-pri:hover,.btn-sec:hover{opacity:.85}\n"
"</style>\n"
"</head>\n<body>\n\n"
"<div id='loading-overlay'><div class='ld-ring'></div><div class='ld-txt'>Cargando&#8230;</div></div>\n\n"
"<div id='render-modal'><div id='render-box'>\n"
"  <h3>&#127916; Renderizando&#8230;</h3>\n"
"  <div id='render-pbar'><div id='render-pfill'></div></div>\n"
"  <div id='render-log'></div>\n"
"  <div id='render-btns'><button class='btn-sec' onclick='closeRenderModal()'>Cerrar</button></div>\n"
"</div></div>\n\n"
"<div id='toolbar'>\n"
"  <div class='tb-logo'>\n"
"    <svg width='20' height='20' viewBox='0 0 24 24' fill='none' stroke='#7c6aff' stroke-width='2.2' stroke-linecap='round' stroke-linejoin='round'><polygon points='23 7 16 12 23 17 23 7'/><rect x='1' y='5' width='15' height='14' rx='2'/></svg>\n"
"    <span>Studio IVR</span>\n"
"  </div>\n"
"  <div class='tb-sep'></div>\n"
"  <span id='proj-title'>" + pn + "</span>\n"
"  <div class='tb-sep'></div>\n"
"  <div class='tb-tools'>\n"
"    <button class='tb-tool active' id='tool-select' title='Mover imagen (V)' onclick=\"setTool('select')\">\n"
"      <svg width='13' height='13' viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2.2'><path d='M5 3l14 9-7 1-4 6z'/></svg></button>\n"
"    <button class='tb-tool' id='tool-text' title='Texto (T)' onclick=\"setTool('text');switchTab('text')\">\n"
"      <svg width='13' height='13' viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2.2'><polyline points='4 7 4 4 20 4 20 7'/><line x1='9' y1='20' x2='15' y2='20'/><line x1='12' y1='4' x2='12' y2='20'/></svg></button>\n"
"    <button class='tb-tool' id='tool-trans' title='Transiciones' onclick=\"setTool('trans');switchTab('transitions')\">\n"
"      <svg width='13' height='13' viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2.2'><path d='M5 12h14M12 5l7 7-7 7'/></svg></button>\n"
"    <button class='tb-tool' id='tool-audio' title='Audio' onclick=\"setTool('audio');switchTab('audio')\">\n"
"      <svg width='13' height='13' viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2.2'><path d='M9 18V5l12-2v13'/><circle cx='6' cy='18' r='3'/><circle cx='18' cy='16' r='3'/></svg></button>\n"
"  </div>\n"
"  <div class='tb-spacer'></div>\n"
"  <button id='btn-render' onclick='startRender()' disabled>\n"
"    <svg width='13' height='13' viewBox='0 0 24 24' fill='currentColor'><polygon points='5 3 19 12 5 21 5 3'/></svg> Renderizar\n"
"  </button>\n"
"</div>\n\n"
"<div id='workspace'>\n"
"  <!-- ── Media Panel ── -->\n"
"  <div id='media-panel'>\n"
"    <div id='mp-header'>\n"
"      <svg width='12' height='12' viewBox='0 0 24 24' fill='none' stroke='var(--c2)' stroke-width='2'><rect x='3' y='3' width='18' height='18' rx='2'/><polyline points='21 15 16 10 5 21'/></svg>\n"
"      <span id='mp-title'>Media</span>\n"
"      <button class='tl-tbtn' onclick='toggleMediaPanel()' title='Cerrar' style='padding:1px 6px;font-size:11px'>&#10005;</button>\n"
"    </div>\n"
"    <!-- Import drop zone -->\n"
"    <div id='mp-import-zone' onclick='document.getElementById(\"mp-file-input\").click()'>\n"
"      <input type='file' id='mp-file-input' multiple accept='image/*,audio/*,video/*' onchange='mpHandleFiles(this.files)'/>\n"
"      <div class='mp-import-icon'>\n"
"        <svg width='22' height='22' viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='1.5'><path d='M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4'/><polyline points='17 8 12 3 7 8'/><line x1='12' y1='3' x2='12' y2='15'/></svg>\n"
"      </div>\n"
"      <div class='mp-import-txt'>Arrastra archivos aquí<br/>o haz clic para importar</div>\n"
"    </div>\n"
"    <div id='mp-tabs'>\n"
"      <div class='mp-tab active' id='mpt-images' onclick=\"switchMpTab('images')\">Imágenes</div>\n"
"      <div class='mp-tab' id='mpt-audio' onclick=\"switchMpTab('audio')\">Audio</div>\n"
"      <div class='mp-tab' id='mpt-video' onclick=\"switchMpTab('video')\">Video</div>\n"
"    </div>\n"
"    <div id='mp-body'>\n"
"      <div id='mp-pane-images'>\n"
"        <div class='mp-grid' id='mp-img-grid'></div>\n"
"      </div>\n"
"      <div id='mp-pane-audio' style='display:none'>\n"
"        <div id='mp-aud-list'></div>\n"
"      </div>\n"
"      <div id='mp-pane-video' style='display:none'>\n"
"        <div class='mp-grid' id='mp-vid-grid'></div>\n"
"      </div>\n"
"    </div>\n"
"  </div>\n"
"  <!-- ── Toggle button (outside panel so stays visible when collapsed) ── -->\n"
"  <button id='mp-toggle' onclick='toggleMediaPanel()' title='Panel de medios'>\n"
"    <svg id='mp-toggle-icon' width='8' height='10' viewBox='0 0 8 12' fill='currentColor'><path d='M0 0l8 6-8 6z'/></svg>\n"
"  </button>\n"
"  <div id='center'>\n"
"    <div id='canvas-area'>\n"
"      <canvas id='preview-canvas'></canvas>\n"
"      <div id='canvas-hint'>Clic en lienzo para colocar texto</div>\n"
"      <div id='canvas-scene-badge'></div>\n"
"    </div>\n"
"    <div id='playback-bar'>\n"
"      <button class='pb-btn' onclick='seekDelta(-5)' title='-5s'>\n"
"        <svg width='13' height='13' viewBox='0 0 24 24' fill='currentColor'><polygon points='19 20 9 12 19 4'/><line x1='5' y1='19' x2='5' y2='5' stroke='currentColor' stroke-width='2.5'/></svg></button>\n"
"      <button class='pb-btn big' id='btn-play' onclick='togglePlay()'>\n"
"        <svg id='play-icon' width='15' height='15' viewBox='0 0 24 24' fill='currentColor'><polygon points='5 3 19 12 5 21 5 3'/></svg>\n"
"        <svg id='pause-icon' width='15' height='15' viewBox='0 0 24 24' fill='currentColor' style='display:none'><rect x='6' y='4' width='4' height='16'/><rect x='14' y='4' width='4' height='16'/></svg></button>\n"
"      <button class='pb-btn' onclick='seekDelta(5)' title='+5s'>\n"
"        <svg width='13' height='13' viewBox='0 0 24 24' fill='currentColor'><polygon points='5 4 15 12 5 20'/><line x1='19' y1='5' x2='19' y2='19' stroke='currentColor' stroke-width='2.5'/></svg></button>\n"
"      <span id='pb-time' style='margin-left:6px'>0:00 / 0:00</span>\n"
"      <input type='range' id='pb-seek' min='0' max='100' value='0' step='0.05' oninput='onSeek(this.value)' style='margin:0 8px'/>\n"
"      <svg width='13' height='13' viewBox='0 0 24 24' fill='none' stroke='var(--m)' stroke-width='2' style='flex-shrink:0'><polygon points='11 5 6 9 2 9 2 15 6 15 11 19 11 5'/><path d='M15.54 8.46a5 5 0 0 1 0 7.07'/></svg>\n"
"      <input type='range' id='pb-vol' min='0' max='1' step='0.05' value='0.8' oninput='setVol(this.value)'/>\n"
"      <select id='pb-speed' onchange='setSpeed(this.value)'>\n"
"        <option value='0.5'>0.5x</option><option value='1' selected>1x</option>\n"
"        <option value='1.5'>1.5x</option><option value='2'>2x</option>\n"
"      </select>\n"
"    </div>\n"
"  </div>\n\n"
"  <div id='right-panel'>\n"
"    <div id='rp-tabs'>\n"
"      <div class='rp-tab active' id='tab-scene' onclick=\"switchTab('scene')\">Imagen</div>\n"
"      <div class='rp-tab' id='tab-text' onclick=\"switchTab('text')\">Texto</div>\n"
"      <div class='rp-tab' id='tab-transitions' onclick=\"switchTab('transitions')\">Trans.</div>\n"
"      <div class='rp-tab' id='tab-audio' onclick=\"switchTab('audio')\">Audio</div>\n"
"    </div>\n\n"
"    <div class='rp-pane active' id='pane-scene'>\n"
"      <div id='scene-empty' style='padding:24px 14px;text-align:center;font-size:11px;color:var(--m2)'>\n"
"        Selecciona una escena en la l&#237;nea de tiempo\n"
"      </div>\n"
"      <div id='scene-info' style='display:none'>\n"
"        <div class='rp-section'>\n"
"          <div class='rp-title'>Segmento</div>\n"
"          <div id='si-title' style='font-weight:600;font-size:12px;color:var(--t);margin-bottom:4px;word-break:break-word'></div>\n"
"          <div id='si-sub' style='font-size:10px;color:var(--m);font-family:var(--mono)'></div>\n"
"          <div id='rp-ref-wrap' style='display:none;margin-top:8px;border-radius:7px;overflow:hidden;border:1px solid var(--b);position:relative'>\n"
"            <div id='rp-ref-badge'>Imagen referencia</div>\n"
"            <img id='rp-ref-thumb' style='width:100%;display:block;max-height:100px;object-fit:cover' src='' alt='ref'/>\n"
"          </div>\n"
"          <div style='display:flex;align-items:center;gap:8px;margin-top:10px'>\n"
"            <span style='font-size:11px;color:var(--m)'>Imagen</span>\n"
"            <select class='rp-input' id='seg-img-sel' onchange='updateSegImg(this.value)' style='font-size:11px'></select>\n"
"          </div>\n"
"        </div>\n"
"        <div class='rp-section'>\n"
"          <div class='rp-title'>Transformar imagen &mdash; <span style='color:var(--c3);font-size:9px'>arrastra el lienzo para mover</span></div>\n"
"          <div class='rp-row'><span class='rp-label'>Escala</span>\n"
"            <input type='range' class='rp-input' id='img-scale' min='100' max='400' value='100'\n"
"                   oninput=\"updateImgT('scale',this.value)\"/>\n"
"            <span class='rp-vval' id='img-scale-v'>100%</span></div>\n"
"          <div class='rp-row'><span class='rp-label'>Pan X</span>\n"
"            <input type='range' class='rp-input' id='img-panx' min='0' max='100' value='50'\n"
"                   oninput=\"updateImgT('px',this.value)\"/>\n"
"            <span class='rp-vval' id='img-panx-v'>50</span></div>\n"
"          <div class='rp-row'><span class='rp-label'>Pan Y</span>\n"
"            <input type='range' class='rp-input' id='img-pany' min='0' max='100' value='50'\n"
"                   oninput=\"updateImgT('py',this.value)\"/>\n"
"            <span class='rp-vval' id='img-pany-v'>50</span></div>\n"
"          <div class='rp-row' style='margin-top:4px'>\n"
"            <button class='rp-btn' onclick='resetImgT()' style='font-size:10px'>&#8635; Restablecer</button>\n"
"          </div>\n"
"        </div>\n"
"        <div class='rp-section'>\n"
"          <div class='rp-title'>Texto de escena</div>\n"
"          <div id='si-trans-txt' style='font-size:11px;color:var(--m);line-height:1.5;word-break:break-word'></div>\n"
"          <button onclick=\"setTool('text');switchTab('text')\" style='width:100%;margin-top:8px;padding:7px;border:1px dashed var(--c1);border-radius:8px;background:transparent;color:var(--c2);font-size:11px;cursor:pointer'>+ Agregar overlay de texto</button>\n"
"        </div>\n"
"      </div>\n"
"    </div>\n\n"
"    <div class='rp-pane' id='pane-text'>\n"
"      <div id='text-empty' style='padding:20px 14px;text-align:center;font-size:11px;color:var(--m2)'>\n"
"        Activa la herramienta de texto y haz clic en el lienzo.<br><br>\n"
"        <button onclick=\"setTool('text')\" style='padding:7px 14px;background:var(--c1);color:#fff;border:none;border-radius:7px;font-size:11px;cursor:pointer'>Activar herramienta texto</button>\n"
"      </div>\n"
"      <div id='text-props' style='display:none'>\n"
"        <div class='rp-section'><div class='rp-title'>Contenido</div>\n"
"          <textarea class='rp-input' id='ov-text' rows='3' style='resize:vertical;min-height:56px;width:100%' oninput=\"updateOv('text',this.value)\"></textarea>\n"
"        </div>\n"
"        <div class='rp-section'><div class='rp-title'>Fuente</div>\n"
"          <div class='rp-row'><span class='rp-label'>Tipo</span>\n"
"            <select class='rp-input' id='ov-font' onchange=\"updateOv('font',this.value)\">\n"
"              <option>Arial</option><option>Georgia</option><option>Impact</option>\n"
"              <option>Trebuchet MS</option><option>Verdana</option>\n"
"              <option>Times New Roman</option><option>Courier New</option>\n"
"            </select></div>\n"
"          <div class='rp-row'><span class='rp-label'>Tama&#241;o</span>\n"
"            <input type='range' class='rp-input' id='ov-size' min='12' max='140' value='40'\n"
"                   oninput=\"updateOv('size',this.value);document.getElementById('ov-sz-v').textContent=this.value\"/>\n"
"            <span class='rp-vval' id='ov-sz-v'>40</span></div>\n"
"          <div class='rp-row'><span class='rp-label'>Color</span>\n"
"            <input type='color' class='rp-input' id='ov-color' value='#ffffff' oninput=\"updateOv('color',this.value)\"/></div>\n"
"          <div class='rp-row'><span class='rp-label'>Sombra</span>\n"
"            <input type='color' class='rp-input' id='ov-shadow' value='#000000' oninput=\"updateOv('shadow',this.value)\"/></div>\n"
"          <div class='rp-row'><span class='rp-label'>Contorno</span>\n"
"            <input type='color' class='rp-input' id='ov-stroke' value='#000000' oninput=\"updateOv('stroke',this.value)\"/>\n"
"            <input type='range' style='width:40px;accent-color:var(--c1)' id='ov-sw' min='0' max='8' value='0' step='0.5' oninput=\"updateOv('strokeW',this.value)\"/></div>\n"
"          <div class='rp-row'><span class='rp-label'>Opacidad</span>\n"
"            <input type='range' class='rp-input' id='ov-opacity' min='0' max='1' step='0.05' value='1' oninput=\"updateOv('opacity',this.value)\"/></div>\n"
"          <div class='rp-row'><span class='rp-label'>Estilo</span>\n"
"            <div class='rp-btn-group'>\n"
"              <button class='rp-btn' id='ov-bold' onclick=\"toggleOv('bold')\"><b>N</b></button>\n"
"              <button class='rp-btn' id='ov-italic' onclick=\"toggleOv('italic')\"><i>K</i></button></div></div>\n"
"          <div class='rp-row'><span class='rp-label'>Alinear</span>\n"
"            <div class='rp-btn-group'>\n"
"              <button class='rp-btn' id='ov-al-left' onclick=\"updateOv('align','left')\">L</button>\n"
"              <button class='rp-btn active' id='ov-al-center' onclick=\"updateOv('align','center')\">C</button>\n"
"              <button class='rp-btn' id='ov-al-right' onclick=\"updateOv('align','right')\">R</button></div></div>\n"
"        </div>\n"
"        <div class='rp-section'><div class='rp-title'>Posici&#243;n en lienzo</div>\n"
"          <div class='rp-row'><span class='rp-label'>X</span>\n"
"            <input type='range' class='rp-input' id='ov-px' min='0' max='100' value='50' oninput=\"updateOv('px',this.value)\"/></div>\n"
"          <div class='rp-row'><span class='rp-label'>Y</span>\n"
"            <input type='range' class='rp-input' id='ov-py' min='0' max='100' value='80' oninput=\"updateOv('py',this.value)\"/></div>\n"
"          <div style='margin-top:8px'>\n"
"            <button class='btn-sec' style='width:100%;font-size:11px;padding:6px' onclick='deleteOv()'>&#128465; Eliminar overlay</button></div>\n"
"        </div>\n"
"      </div>\n"
"    </div>\n\n"
"    <div class='rp-pane' id='pane-transitions'>\n"
"      <div style='padding:12px 14px 6px'>\n"
"        <div class='rp-title'>Transici&#243;n de entrada</div>\n"
"        <p style='font-size:11px;color:var(--m);margin-bottom:10px'>Selecciona un segmento y elige su transici&#243;n.</p>\n"
"        <div id='trans-grid'>" + tbns + "</div>\n"
"        <div style='margin-top:10px'>\n"
"          <div class='rp-row'><span class='rp-label'>Duraci&#243;n</span>\n"
"            <input type='range' class='rp-input' id='trans-dur' min='0.2' max='2' step='0.1' value='0.5'\n"
"                   oninput=\"updateTD(this.value);document.getElementById('trans-dur-v').textContent=this.value+'s'\"/>\n"
"            <span class='rp-vval' id='trans-dur-v'>0.5s</span></div>\n"
"        </div>\n"
"      </div>\n"
"    </div>\n\n"
"    <div class='rp-pane' id='pane-audio'>\n"
"      <div style='padding:12px 14px'>\n"
"        <div class='rp-title'>Transcripci&#243;n Whisper</div>\n"
"        <button id='btn-transcribe' onclick='runTranscription()'>&#127908; Transcribir audio</button>\n"
"        <div id='transcript-list' style='margin-top:8px'></div>\n"
"      </div>\n"
"      <div style='padding:0 14px 12px;border-top:1px solid var(--b)'>\n"
"        <div class='rp-title' style='margin-top:12px;margin-bottom:8px'>Pista de audio</div>\n"
"        <div id='audio-track-name' style='font-size:12px;color:var(--t);margin-bottom:10px;word-break:break-all'>Sin selecci&#243;n</div>\n"
"        <div class='rp-row'><span class='rp-label'>Volumen</span>\n"
"          <input type='range' class='rp-input' id='aud-vol' min='0' max='2' step='0.05' value='1' oninput='updateAudVol(this.value)'/>\n"
"          <span class='rp-vval' id='aud-vol-v'>100%</span></div>\n"
"        <div class='rp-row'><span class='rp-label'>Corte ini.</span>\n"
"          <input type='number' class='rp-input' id='aud-ts' min='0' step='0.1' value='0' style='width:60px' onchange=\"updateAudTrim('start',this.value)\"/> s</div>\n"
"        <div class='rp-row'><span class='rp-label'>Corte fin.</span>\n"
"          <input type='number' class='rp-input' id='aud-te' min='0' step='0.1' value='0' style='width:60px' onchange=\"updateAudTrim('end',this.value)\"/> s</div>\n"
"        <div class='rp-row'><span class='rp-label'>Fade in</span>\n"
"          <input type='range' class='rp-input' id='aud-fi' min='0' max='5' step='0.1' value='0' oninput=\"updateAudProp('fadeIn',this.value)\"/></div>\n"
"        <div class='rp-row'><span class='rp-label'>Fade out</span>\n"
"          <input type='range' class='rp-input' id='aud-fo' min='0' max='5' step='0.1' value='0' oninput=\"updateAudProp('fadeOut',this.value)\"/></div>\n"
"        <button class='btn-sec' style='width:100%;font-size:11px;padding:6px;margin-top:8px' onclick='deleteAud()'>&#128465; Eliminar pista</button>\n"
"        <label style='display:block;margin-top:8px;padding:9px;border:1px dashed var(--c3);border-radius:8px;background:transparent;color:var(--c3);font-size:11px;cursor:pointer;text-align:center'>\n"
"          + M&#250;sica / Efecto de sonido\n"
"          <input type='file' accept='audio/*' style='display:none' onchange='addAudFile(this)'/>\n"
"        </label>\n"
"      </div>\n"
"    </div>\n"
"  </div>\n"
"</div>\n\n"
"<div id='tl-resize-handle' title='Arrastra para cambiar altura de la línea de tiempo'></div>\n"
"<div id='timeline'>\n"
"  <div id='tl-toolbar'>\n"
"    <span id='tl-toolbar-label'>L&#237;nea de tiempo</span>\n"
"    <span id='tl-total-dur' style='font-family:var(--mono);font-size:9px;color:var(--m2);margin-left:8px'></span>\n"
"    <div style='flex:1'></div>\n"
"    <button class='tl-tbtn' id='btn-anchor' onclick='toggleAnchor()' title='Anclar pistas (mover/escalar todas juntas)' style='font-size:13px;padding:2px 7px;opacity:0.45'>&#128279;</button>\n"
"    <button class='tl-tbtn' onclick='zoomOut()'>&#8722;</button>\n"
"    <span id='zoom-val'>40px/s</span>\n"
"    <button class='tl-tbtn' onclick='zoomIn()'>+</button>\n"
"  </div>\n"
"  <div id='tl-body'>\n"
"    <div id='tl-labels'>\n"
"      <div class='tl-lr'></div>\n"
"      <div id='tl-labels-scroll'>\n"
"        <div id='ov-lbl-wrap'></div>\n"
"        <div id='ir-lbl-wrap'></div>\n"
"        <div class='tl-tl' id='lbl-video'>\n"
"          <svg width='11' height='11' viewBox='0 0 24 24' fill='none' stroke='var(--m)' stroke-width='2'><polygon points='23 7 16 12 23 17 23 7'/><rect x='1' y='5' width='15' height='14' rx='2'/></svg>\n"
"          <span class='tl-lt'>Video</span></div>\n"
"        <div id='aud-lbl-wrap'></div>\n"
"      </div>\n"
"    </div>\n"
"    <div id='tl-scroll'>\n"
"      <div id='tl-inner'>\n"
"        <div id='tl-ruler'><canvas id='ruler-canvas'></canvas></div>\n"
"        <div id='tl-ovrows'></div>\n"
"        <div id='tl-irrows'></div>\n"
"        <div class='tl-vrow' id='tl-vrow'></div>\n"
"        <div id='tl-arows'></div>\n"
"        <div id='tl-ph'></div>\n"
"        <div id='tl-newtrack-zone' style='display:none;min-height:40px;border-top:1px dashed rgba(124,106,255,.15);display:none;align-items:center;justify-content:center'><span style='font-family:var(--mono);font-size:9px;color:rgba(255,255,255,.2);pointer-events:none'>+ Soltar aquí para nueva pista</span></div>\n"
"      </div>\n"
"    </div>\n"
"  </div>\n"
"</div>\n\n"
"<script>\n"
"var PROJECT=" + pnjs + ";\n"
"var segs=[];var images=[];var audioTracks=[];\n"
"var curSeg=0,audEl=null,isPlaying=false,playSpeed=1;\n"
"var curTime=0; // current preview time (updated by rafTick and selSeg)\n"
"var activeTool='select',selOvId=null,selAudId=null;\n"
"var renderJobId=null,pxPerSec=40;\n"
"var ovDragState=null;\n"
"var tlAnchor=false;\n"
"var segDragState=null;\n"
"var canvasW=0,canvasH=0,dragState=null,audDragState=null;\n"
"var imgCache={},audBufCache={},audioCtx=null;\n"
"var TRANS_DUR=0.5;\n"
"var canvas=document.getElementById('preview-canvas');\n"
"var ctx=canvas.getContext('2d');\n"
"\n"
"function calcSz(){\n"
"  var a=document.getElementById('canvas-area');\n"
"  var aw=a.clientWidth-32,ah=a.clientHeight-24,ratio=16/9,w,h;\n"
"  if(aw/ah>ratio){h=ah;w=Math.round(h*ratio);}else{w=aw;h=Math.round(w/ratio);}\n"
"  canvas.width=w;canvas.height=h;canvas.style.width=w+'px';canvas.style.height=h+'px';\n"
"  canvasW=w;canvasH=h;\n"
"}\n"
"\n"
"function getImg(src){\n"
"  if(!src)return null;\n"
"  if(imgCache[src])return imgCache[src];\n"
"  var img=new Image();img.crossOrigin='anonymous';\n"
"  img.onload=function(){imgCache[src]=img;drawFrame();};\n"
"  img.src=src;return null;\n"
"}\n"
"\n"
"// Draw image with pan/zoom transforms\n"
"function drawImgTransformed(c2d,img,seg,w,h){\n"
"  var scale=(seg.imgScale||100)/100;\n"
"  var ir=img.naturalWidth/img.naturalHeight,cr=w/h;\n"
"  var baseW,baseH;\n"
"  if(ir>cr){baseH=h;baseW=baseH*ir;}else{baseW=w;baseH=baseW/ir;}\n"
"  var sw=baseW*scale,sh=baseH*scale;\n"
"  var panX=(seg.imgPanX!=null?seg.imgPanX:50)/100;\n"
"  var panY=(seg.imgPanY!=null?seg.imgPanY:50)/100;\n"
"  var dx=(w-sw)/2+(0.5-panX)*(sw-w);\n"
"  var dy=(h-sh)/2+(0.5-panY)*(sh-h);\n"
"  c2d.drawImage(img,dx,dy,sw,sh);\n"
"}\n"
"\n"
"function drawSceneOn(c2d,seg,w,h){\n"
"  c2d.fillStyle='#000';c2d.fillRect(0,0,w,h);\n"
"  if(seg&&seg.src){\n"
"    var img=getImg(seg.src);\n"
"    if(img&&img.complete)drawImgTransformed(c2d,img,seg,w,h);\n"
"  }\n"
"}\n"
"\n"
"// Collect ALL overlays whose ovStart/ovDur window covers time t\n"
"function getActiveOverlays(t){\n"
"  var result=[];\n"
"  segs.forEach(function(s){\n"
"    if(!s.overlays||!s.overlays.length)return;\n"
"    var os=s.ovStart!=null?s.ovStart:s.start;\n"
"    var oe=os+(s.ovDur!=null?s.ovDur:s.dur);\n"
"    if(t>=os&&t<oe){\n"
"      s.overlays.forEach(function(ov){result.push(ov);});\n"
"    }\n"
"  });\n"
"  return result;\n"
"}\n"
"\n"
"// Reference types that show the ref/Google image FULLSCREEN as primary visual\n"
"var REF_FULLSCREEN_TIPOS={'google_fullscreen':1,'ref_lugar':1,'broll':1,'ref_persona':1};\n"
"\n"
"// Find the segment whose img-track window covers time t (for reference image compositing)\n"
"// Returns {src, imgScale, imgPanX, imgPanY} for the first active imgTrackItem at time t,\n"
"// OR falls back to scanning segs for REF_FULLSCREEN_TIPOS scenes.\n"
"function getActiveRefSeg(t){\n"
"  // imgTrackItems are the authoritative positions (may have been moved by user)\n"
"  for(var ii=0;ii<imgTrackItems.length;ii++){\n"
"    var it=imgTrackItems[ii];\n"
"    if(t>=it.start&&t<it.start+it.dur){\n"
"      // Resolve src: item may carry it directly or via its linked seg\n"
"      var src=it.src\n"
"        ||(it._sc&&it._sc.refSrc)\n"
"        ||(it._sc&&it._sc.escena&&(it._sc.escena.ref_image_b64||it._sc.escena.ref_image_url))\n"
"        ||null;\n"
"      var sc2=it._sc||null;\n"
"      return {\n"
"        refSrc:src,\n"
"        imgScale:(sc2&&sc2.imgScale!=null)?sc2.imgScale:100,\n"
"        imgPanX:(sc2&&sc2.imgPanX!=null)?sc2.imgPanX:50,\n"
"        imgPanY:(sc2&&sc2.imgPanY!=null)?sc2.imgPanY:50,\n"
"        _sc:sc2, _it:it, tipo:'google_fullscreen'\n"
"      };\n"
"    }\n"
"  }\n"
"  // Fallback: only for segs NOT already covered by an imgTrackItem\n"
"  for(var i=0;i<segs.length;i++){\n"
"    var s=segs[i];\n"
"    if(!REF_FULLSCREEN_TIPOS[s.tipo])continue;\n"
"    if(!s.escena&&!s.refSrc)continue;\n"
"    if(s.escena&&!s.escena.ref_image_url&&!s.escena.ref_image_b64&&!s.refSrc)continue;\n"
"    // Skip if this seg is already tracked in imgTrackItems (user may have moved it)\n"
"    var tracked=false;\n"
"    for(var j=0;j<imgTrackItems.length;j++){if(imgTrackItems[j].segIdx===i){tracked=true;break;}}\n"
"    if(tracked)continue;\n"
"    var is2=s.imgStart!=null?s.imgStart:s.start;\n"
"    var ie2=is2+(s.imgDur!=null?s.imgDur:s.dur);\n"
"    if(t>=is2&&t<ie2)return s;\n"
"  }\n"
"  return null;\n"
"}\n"
"\n"
"function drawFrame(){\n"
"  if(!segs.length)return;\n"
"  ctx.clearRect(0,0,canvasW,canvasH);\n"
"  var sc=segs[curSeg];\n"
"\n"
"  // Check if a reference/Google image should be shown fullscreen at curTime\n"
"  var refSeg=getActiveRefSeg(curTime);\n"
"  var drawnRef=false;\n"
"  if(refSeg){\n"
"    // Ensure ref image is loaded (triggers async load --> drawFrame callback)\n"
"    // When refSeg came from getActiveRefSeg for an imgTrackItem, the real seg is in _sc\n"
"    if(!refSeg.refSrc&&!refSeg._refLoading){\n"
"      var _loadTarget=refSeg._sc||refSeg;\n"
"      if(!_loadTarget._refLoading)loadRefImageForSeg(_loadTarget);\n"
"      // Also propagate refSrc back once loaded\n"
"      if(_loadTarget.refSrc){refSeg.refSrc=_loadTarget.refSrc;if(refSeg._it)refSeg._it.src=_loadTarget.refSrc;}\n"
"    }\n"
"    if(refSeg.refSrc){\n"
"      var rImg=getImg(refSeg.refSrc);\n"
"      if(rImg&&rImg.complete&&rImg.naturalWidth>0){\n"
"        ctx.fillStyle='#000';ctx.fillRect(0,0,canvasW,canvasH);\n"
"        drawImgTransformed(ctx,rImg,{imgScale:refSeg.imgScale||100,imgPanX:refSeg.imgPanX!=null?refSeg.imgPanX:50,imgPanY:refSeg.imgPanY!=null?refSeg.imgPanY:50},canvasW,canvasH);\n"
"        drawnRef=true;\n"
"      }\n"
"    }\n"
"  }\n"
"  if(!drawnRef){\n"
"    drawSceneOn(ctx,sc,canvasW,canvasH);\n"
"  }\n"
"\n"
"  // Draw overlays from all scenes whose timeline window includes curTime\n"
"  getActiveOverlays(curTime).forEach(function(ov){\n"
"    drawOvOn(ctx,ov,ov.id===selOvId,canvasW,canvasH);\n"
"  });\n"
"}\n"
"\n"
"function drawOvOn(c2d,ov,sel,w,h){\n"
"  c2d.save();\n"
"  c2d.globalAlpha=ov.opacity!=null?ov.opacity:1;\n"
"  var accent=ov.accentColor||'#00cfff';\n"
"  if(ov._type==='enfasis_panel'){\n"
"    var bh=Math.round(h*0.24),by=Math.round(h*0.38);\n"
"    c2d.fillStyle='rgba(0,0,0,0.85)';c2d.fillRect(0,by,w,bh);\n"
"    c2d.fillStyle=accent;c2d.fillRect(0,by,w,5);c2d.fillRect(0,by+bh-5,w,5);\n"
"    var lines=(ov.text||'').split('\\n');\n"
"    var sz=Math.round(h*0.082);\n"
"    c2d.font='bold '+sz+'px Impact';c2d.textAlign='center';c2d.textBaseline='middle';\n"
"    c2d.shadowColor='rgba(0,0,0,0.9)';c2d.shadowBlur=10;c2d.shadowOffsetX=2;c2d.shadowOffsetY=2;\n"
"    lines.forEach(function(ln,li){\n"
"      var cy=by+bh/2+(li-(lines.length-1)/2)*sz*1.15;\n"
"      c2d.fillStyle='rgba(0,0,0,0.6)';c2d.fillText(ln,w/2+2,cy+2);\n"
"      c2d.fillStyle='#ffffff';c2d.fillText(ln,w/2,cy);\n"
"    });\n"
"    c2d.restore();return;\n"
"  }\n"
"  if(ov._type==='intro_panel'){\n"
"    var ph=Math.round(h*0.28),py2=h-ph;\n"
"    c2d.fillStyle='rgba(0,0,0,0.72)';c2d.fillRect(0,py2,w,ph);\n"
"    c2d.fillStyle=accent;c2d.fillRect(0,py2,w,6);\n"
"    c2d.shadowColor='rgba(0,0,0,0.9)';c2d.shadowBlur=6;c2d.shadowOffsetX=1;c2d.shadowOffsetY=1;\n"
"    var lns=(ov.text||'').split('\\n');\n"
"    var lineY=py2+14;\n"
"    lns.forEach(function(ln,li){\n"
"      var isT=(li===0);\n"
"      var fsz=isT?Math.round(h*0.062):Math.round(h*0.044);\n"
"      c2d.font=(isT?'bold ':'')+fsz+'px '+(isT?'Impact':'Arial');\n"
"      c2d.textAlign='center';c2d.textBaseline='top';\n"
"      c2d.fillStyle=isT?accent:'rgba(255,255,255,0.95)';\n"
"      c2d.fillText(ln,w/2,lineY);\n"
"      lineY+=fsz*1.3;\n"
"    });\n"
"    c2d.restore();return;\n"
"  }\n"
"  var x=(ov.px/100)*w,y=(ov.py/100)*h,sz=ov.size||40;\n"
"  var fs=(ov.italic?'italic ':'')+(ov.bold?'bold ':'')+sz+'px '+(ov.font||'Arial');\n"
"  c2d.font=fs;c2d.textAlign=ov.align||'center';c2d.textBaseline='middle';\n"
"  c2d.shadowColor=ov.shadow||'rgba(0,0,0,.85)';c2d.shadowBlur=8;c2d.shadowOffsetX=2;c2d.shadowOffsetY=2;\n"
"  var lines=(ov.text||'').split('\\n');\n"
"  var sw=ov.strokeW||0;\n"
"  lines.forEach(function(ln,li){\n"
"    var yy=y+li*sz*1.2-((lines.length-1)*sz*0.6);\n"
"    if(sw>0){c2d.shadowBlur=0;c2d.strokeStyle=ov.stroke||'#000';c2d.lineWidth=sw*2;c2d.strokeText(ln,x,yy);c2d.shadowBlur=8;}\n"
"    c2d.fillStyle=ov.color||'#fff';c2d.fillText(ln,x,yy);\n"
"  });\n"
"  if(sel){\n"
"    c2d.shadowBlur=0;c2d.shadowOffsetX=0;c2d.shadowOffsetY=0;\n"
"    var tw=c2d.measureText(lines[0]||'').width+24,th=lines.length*sz*1.2+16;\n"
"    var bx=(ov.align==='center')?x-tw/2:(ov.align==='right')?x-tw:x;\n"
"    c2d.strokeStyle='#7c6aff';c2d.lineWidth=2;c2d.setLineDash([4,3]);c2d.globalAlpha=.8;\n"
"    c2d.strokeRect(bx-8,y-th/2,tw,th);c2d.setLineDash([]);\n"
"  }\n"
"  c2d.restore();\n"
"}\n"
"\n"
"function setTool(t){\n"
"  activeTool=t;\n"
"  document.querySelectorAll('.tb-tool').forEach(function(b){b.classList.remove('active');});\n"
"  var el=document.getElementById('tool-'+t);if(el)el.classList.add('active');\n"
"  canvas.style.cursor=t==='text'?'crosshair':(t==='select'?'grab':'default');\n"
"  document.getElementById('canvas-hint').style.display=t==='text'?'':'none';\n"
"}\n"
"\n"
"function switchTab(id){\n"
"  document.querySelectorAll('.rp-tab').forEach(function(t){t.classList.remove('active');});\n"
"  document.querySelectorAll('.rp-pane').forEach(function(p){p.classList.remove('active');});\n"
"  var t=document.getElementById('tab-'+id);if(t)t.classList.add('active');\n"
"  var p=document.getElementById('pane-'+id);if(p)p.classList.add('active');\n"
"}\n"
"\n"
"function cXY(e){var r=canvas.getBoundingClientRect();return{x:e.clientX-r.left,y:e.clientY-r.top};}\n"
"function hitOv(pos){\n"
"  // Check active overlays (time-based) in reverse order\n"
"  var active=getActiveOverlays(curTime);\n"
"  for(var i=active.length-1;i>=0;i--){\n"
"    var ov=active[i],ox=(ov.px/100)*canvasW,oy=(ov.py/100)*canvasH,sz=ov.size||40;\n"
"    var lines=(ov.text||'').split('\\n'),tw=(ov.text||'').length*sz*.55+24,th=lines.length*sz*1.2+16;\n"
"    var bx=(ov.align==='center')?ox-tw/2:(ov.align==='right')?ox-tw:ox;\n"
"    if(pos.x>=bx-12&&pos.x<=bx+tw+12&&pos.y>=oy-th/2-8&&pos.y<=oy+th/2+8)return ov.id;\n"
"  }return null;\n"
"}\n"
"\n"
"canvas.addEventListener('mousedown',function(e){\n"
"  var pos=cXY(e);\n"
"  if(activeTool==='text'){addOv(pos.x,pos.y);switchTab('text');return;}\n"
"  var hit=hitOv(pos);\n"
"  if(hit){\n"
"    selOv(hit);\n"
"    var ov=getOv(hit);\n"
"    if(ov)dragState={type:'ov',id:hit,ox:(ov.px/100)*canvasW-pos.x,oy:(ov.py/100)*canvasH-pos.y};\n"
"  }else{\n"
"    selOv(null);\n"
"    if(segs.length&&activeTool==='select'){\n"
"      var seg=segs[curSeg];\n"
"      dragState={type:'img',sx:e.clientX,sy:e.clientY,\n"
"        px:seg.imgPanX!=null?seg.imgPanX:50,py:seg.imgPanY!=null?seg.imgPanY:50,\n"
"        scale:seg.imgScale||100};\n"
"      canvas.style.cursor='grabbing';\n"
"    }\n"
"  }\n"
"});\n"
"\n"
"window.addEventListener('mousemove',function(e){\n"
"  if(dragState&&dragState.type==='ov'){\n"
"    var r=canvas.getBoundingClientRect(),x=e.clientX-r.left+dragState.ox,y=e.clientY-r.top+dragState.oy;\n"
"    var ov=getOv(dragState.id);\n"
"    if(ov){\n"
"      ov.px=Math.max(0,Math.min(100,(x/canvasW)*100));\n"
"      ov.py=Math.max(0,Math.min(100,(y/canvasH)*100));\n"
"      document.getElementById('ov-px').value=ov.px;\n"
"      document.getElementById('ov-py').value=ov.py;\n"
"      drawFrame();\n"
"    }\n"
"  }\n"
"  if(dragState&&dragState.type==='img'&&segs.length){\n"
"    var seg=segs[curSeg];\n"
"    var scale=dragState.scale/100;\n"
"    var ir=(imgCache[seg.src]&&imgCache[seg.src].naturalWidth/imgCache[seg.src].naturalHeight)||1.78;\n"
"    var cr=canvasW/canvasH;\n"
"    var baseW,baseH;\n"
"    if(ir>cr){baseH=canvasH;baseW=baseH*ir;}else{baseW=canvasW;baseH=baseW/ir;}\n"
"    var sw=baseW*scale,sh=baseH*scale;\n"
"    var rangW=Math.max(1,sw-canvasW),rangH=Math.max(1,sh-canvasH);\n"
"    var dx=(e.clientX-dragState.sx),dy=(e.clientY-dragState.sy);\n"
"    seg.imgPanX=Math.max(0,Math.min(100,dragState.px-dx/rangW*100));\n"
"    seg.imgPanY=Math.max(0,Math.min(100,dragState.py-dy/rangH*100));\n"
"    document.getElementById('img-panx').value=seg.imgPanX.toFixed(1);\n"
"    document.getElementById('img-pany').value=seg.imgPanY.toFixed(1);\n"
"    document.getElementById('img-panx-v').textContent=Math.round(seg.imgPanX);\n"
"    document.getElementById('img-pany-v').textContent=Math.round(seg.imgPanY);\n"
"    drawFrame();\n"
"  }\n"
"  if(audDragState){\n"
"    var dx2=(e.clientX-audDragState.sx)/pxPerSec;\n"
"    var tr=audioTracks.find(function(a){return a.id===audDragState.id;});if(!tr)return;\n"
"    if(audDragState.side==='L')tr.trimStart=Math.max(0,audDragState.st+dx2);\n"
"    else tr.trimEnd=Math.max(0,audDragState.st-dx2);\n"
"    buildTimeline();\n"
"  }\n"
"});\n"
"\n"
"window.addEventListener('mouseup',function(){\n"
"  if(dragState&&dragState.type==='img')canvas.style.cursor='grab';\n"
"  dragState=null;\n"
"  if(audDragState){document.querySelectorAll('.tl-hdl.drg').forEach(function(h){h.classList.remove('drg');});audDragState=null;}\n"
"});\n"
"\n"
"var oidC=1;\n"
"function addOv(cx,cy){\n"
"  if(!segs.length)return;\n"
"  var sc=segs[curSeg];if(!sc.overlays)sc.overlays=[];\n"
"  var id='ov_'+(oidC++);\n"
"  sc.overlays.push({id:id,text:'Texto',px:(cx/canvasW)*100,py:(cy/canvasH)*100,\n"
"    size:40,font:'Arial',color:'#ffffff',shadow:'#000000',stroke:'#000000',strokeW:0,\n"
"    bold:false,italic:false,align:'center',opacity:1});\n"
"  selOv(id);setTool('select');drawFrame();\n"
"}\n"
"function getOv(id){\n"
"  if(!segs.length||!id)return null;\n"
"  // Search across all segments (overlays can be time-shifted to cover other scenes)\n"
"  for(var i=0;i<segs.length;i++){\n"
"    var found=(segs[i].overlays||[]).find(function(o){return o.id===id;});\n"
"    if(found)return found;\n"
"  }\n"
"  return null;\n"
"}\n"
"function selOv(id){\n"
"  selOvId=id;var ov=id?getOv(id):null;\n"
"  document.getElementById('text-props').style.display=ov?'':'none';\n"
"  document.getElementById('text-empty').style.display=ov?'none':'';\n"
"  if(ov)loadOvUI(ov);drawFrame();\n"
"}\n"
"function loadOvUI(ov){\n"
"  document.getElementById('ov-text').value=ov.text||'';\n"
"  document.getElementById('ov-font').value=ov.font||'Arial';\n"
"  document.getElementById('ov-size').value=ov.size||40;\n"
"  document.getElementById('ov-sz-v').textContent=ov.size||40;\n"
"  document.getElementById('ov-color').value=ov.color||'#ffffff';\n"
"  document.getElementById('ov-shadow').value=ov.shadow||'#000000';\n"
"  document.getElementById('ov-stroke').value=ov.stroke||'#000000';\n"
"  document.getElementById('ov-sw').value=ov.strokeW||0;\n"
"  document.getElementById('ov-opacity').value=ov.opacity!=null?ov.opacity:1;\n"
"  document.getElementById('ov-bold').classList.toggle('active',!!ov.bold);\n"
"  document.getElementById('ov-italic').classList.toggle('active',!!ov.italic);\n"
"  document.getElementById('ov-px').value=ov.px||50;\n"
"  document.getElementById('ov-py').value=ov.py||80;\n"
"  ['left','center','right'].forEach(function(a){\n"
"    document.getElementById('ov-al-'+a).classList.toggle('active',(ov.align||'center')===a);});\n"
"}\n"
"function updateOv(prop,val){\n"
"  var ov=selOvId?getOv(selOvId):null;if(!ov)return;\n"
"  if(prop==='text')ov.text=val;\n"
"  else if(prop==='font')ov.font=val;\n"
"  else if(prop==='size')ov.size=parseInt(val);\n"
"  else if(prop==='color')ov.color=val;\n"
"  else if(prop==='shadow')ov.shadow=val;\n"
"  else if(prop==='stroke')ov.stroke=val;\n"
"  else if(prop==='strokeW')ov.strokeW=parseFloat(val);\n"
"  else if(prop==='opacity')ov.opacity=parseFloat(val);\n"
"  else if(prop==='align'){\n"
"    ov.align=val;['left','center','right'].forEach(function(a){\n"
"      document.getElementById('ov-al-'+a).classList.toggle('active',a===val);});}\n"
"  else if(prop==='px')ov.px=parseFloat(val);\n"
"  else if(prop==='py')ov.py=parseFloat(val);\n"
"  drawFrame();\n"
"}\n"
"function toggleOv(prop){\n"
"  var ov=selOvId?getOv(selOvId):null;if(!ov)return;\n"
"  ov[prop]=!ov[prop];document.getElementById('ov-'+prop).classList.toggle('active',ov[prop]);drawFrame();\n"
"}\n"
"function deleteOv(){\n"
"  if(!selOvId||!segs.length)return;\n"
"  var _did=selOvId;\n"
"  segs.forEach(function(s){\n"
"    s.overlays=(s.overlays||[]).filter(function(o){return o.id!==_did;});\n"
"  });\n"
"  selOv(null);buildTimeline();drawFrame();\n"
"}\n"
"\n"
"// Image transform controls\n"
"function updateImgT(prop,val){\n"
"  if(!segs.length)return;\n"
"  var seg=segs[curSeg];\n"
"  if(prop==='scale'){seg.imgScale=parseInt(val);document.getElementById('img-scale-v').textContent=val+'%';}\n"
"  else if(prop==='px'){seg.imgPanX=parseFloat(val);document.getElementById('img-panx-v').textContent=Math.round(val);}\n"
"  else if(prop==='py'){seg.imgPanY=parseFloat(val);document.getElementById('img-pany-v').textContent=Math.round(val);}\n"
"  drawFrame();\n"
"}\n"
"function resetImgT(){\n"
"  if(!segs.length)return;\n"
"  var seg=segs[curSeg];seg.imgScale=100;seg.imgPanX=50;seg.imgPanY=50;\n"
"  document.getElementById('img-scale').value=100;document.getElementById('img-scale-v').textContent='100%';\n"
"  document.getElementById('img-panx').value=50;document.getElementById('img-panx-v').textContent='50';\n"
"  document.getElementById('img-pany').value=50;document.getElementById('img-pany-v').textContent='50';\n"
"  drawFrame();\n"
"}\n"
"function syncImgUI(seg){\n"
"  document.getElementById('img-scale').value=seg.imgScale||100;\n"
"  document.getElementById('img-scale-v').textContent=(seg.imgScale||100)+'%';\n"
"  document.getElementById('img-panx').value=seg.imgPanX!=null?seg.imgPanX:50;\n"
"  document.getElementById('img-panx-v').textContent=Math.round(seg.imgPanX!=null?seg.imgPanX:50);\n"
"  document.getElementById('img-pany').value=seg.imgPanY!=null?seg.imgPanY:50;\n"
"  document.getElementById('img-pany-v').textContent=Math.round(seg.imgPanY!=null?seg.imgPanY:50);\n"
"}\n"
"\n"
"// Transitions\n"
"function applyTrans(type){\n"
"  if(!segs.length)return;segs[curSeg].transition=type;\n"
"  document.querySelectorAll('.tb2').forEach(function(b){b.classList.remove('active');});\n"
"  var btn=document.getElementById('tb-'+type);if(btn)btn.classList.add('active');\n"
"  buildTimeline();\n"
"}\n"
"function updateTD(val){TRANS_DUR=parseFloat(val);if(segs.length)segs[curSeg].transDur=TRANS_DUR;}\n"
"function syncTransUI(){\n"
"  var sc=segs[curSeg],t=sc?(sc.transition||'none'):'none';\n"
"  document.querySelectorAll('.tb2').forEach(function(b){b.classList.remove('active');});\n"
"  var btn=document.getElementById('tb-'+t);if(btn)btn.classList.add('active');\n"
"  var dur=sc&&sc.transDur?sc.transDur:0.5;\n"
"  document.getElementById('trans-dur').value=dur;\n"
"  document.getElementById('trans-dur-v').textContent=dur+'s';TRANS_DUR=dur;\n"
"}\n"
"\n"
"function selSeg(idx){\n"
"  if(idx<0||idx>=segs.length)return;\n"
"  curSeg=idx;selOvId=null;\n"
"  var _sc0=segs[idx];curTime=(_sc0.start+_sc0.end)/2;\n"
"  document.querySelectorAll('.tl-seg').forEach(function(el,i){el.classList.toggle('active',i===idx);});\n"
"  document.querySelectorAll('.tr-seg').forEach(function(el,i){el.classList.toggle('active',i===idx);});\n"
"  var sc=segs[idx];\n"
"  document.getElementById('scene-empty').style.display='none';\n"
"  document.getElementById('scene-info').style.display='';\n"
"  var tipoLabel=sc.tipo&&sc.tipo!=='normal'?(' ['+sc.tipo+']'):'  ';\n"
"  document.getElementById('si-title').textContent=(sc.escena&&sc.escena.texto_overlay?sc.escena.texto_overlay:('Escena '+(idx+1)))+tipoLabel;\n"
"  document.getElementById('si-sub').textContent=fmt(sc.start)+' – '+fmt(sc.end)+' ('+sc.dur.toFixed(1)+'s)';\n"
"  // Update canvas scene badge\n"
"  var badge=document.getElementById('canvas-scene-badge');\n"
"  if(badge){\n"
"    var tmap={normal:'',intro:'INTRO',ref:'REF',texto:'TEXTO',cita:'CITA',google:'GOOGLE'};\n"
"    var tname=tmap[sc.tipo]||sc.tipo||'';\n"
"    badge.textContent='E'+(idx+1)+(tname?' · '+tname:'');\n"
"    badge.style.display='';\n"
"  }\n"
"  document.getElementById('si-trans-txt').textContent=sc.text||'';\n"
"  var sel=document.getElementById('seg-img-sel');sel.innerHTML='';\n"
"  images.forEach(function(src,i){\n"
"    var o=document.createElement('option');\n"
"    o.value=i;o.textContent='Imagen '+(i+1);if(sc.imgIdx===i)o.selected=true;\n"
"    sel.appendChild(o);});\n"
"  syncImgUI(sc);syncTransUI();updatePH();\n"
"  // Load reference image for this scene if needed\n"
"  loadRefImageForSeg(sc);\n"
"  drawFrame();\n"
"}\n"
"function loadRefImageForSeg(sc){\n"
"  if(!sc||!sc.escena)return;\n"
"  var esc=sc.escena;\n"
"  // Show ref image ONLY in the right-panel thumbnail — NEVER replace the main canvas src\n"
"  var refThumb=document.getElementById('rp-ref-thumb');\n"
"  var refWrap=document.getElementById('rp-ref-wrap');\n"
"  if(!refThumb){return;}\n"
"  // Hide if no ref image\n"
"  var rawSrc=esc.ref_image_b64||esc.ref_image_url||null;\n"
"  if(!rawSrc){if(refWrap)refWrap.style.display='none';return;}\n"
"  // Already loaded --> just show\n"
"  if(sc.refSrc){\n"
"    refThumb.src=sc.refSrc;if(refWrap)refWrap.style.display='';\n"
"    return;\n"
"  }\n"
"  // b64 already in plan — use directly\n"
"  if(esc.ref_image_b64&&esc.ref_image_b64.length>100){\n"
"    sc.refSrc=esc.ref_image_b64;\n"
"    if(refThumb)refThumb.src=sc.refSrc;\n"
"    if(refWrap)refWrap.style.display='';\n"
"    buildRefImgTrack();drawFrame();setTimeout(buildMediaPanel,0);\n"
"    return;\n"
"  }\n"
"  // URL reference — fetch via proxy\n"
"  var url=esc.ref_image_url;\n"
"  if(!url){if(refWrap)refWrap.style.display='none';return;}\n"
"  sc._refLoading=true; // prevent duplicate fetches\n"
"  fetch('/api/editor/proxy_imagen',{\n"
"    method:'POST',headers:{'Content-Type':'application/json'},\n"
"    body:JSON.stringify({url:url})\n"
"  }).then(function(r){return r.json();})\n"
"  .then(function(d){\n"
"    sc._refLoading=false;\n"
"    if(d.b64){\n"
"      sc.refSrc=d.b64;\n"
"      if(refThumb)refThumb.src=d.b64;\n"
"      if(refWrap)refWrap.style.display='';\n"
"      buildRefImgTrack();drawFrame();setTimeout(buildMediaPanel,0);\n"
"    }\n"
"  }).catch(function(){sc._refLoading=false;});\n"
"}\n"
"function updateSegImg(val){\n"
"  var idx=parseInt(val);if(isNaN(idx)||!segs.length)return;\n"
"  segs[curSeg].imgIdx=idx;segs[curSeg].src=images[idx]||null;\n"
"  buildVideoRow();drawFrame();\n"
"}\n"
"\n"
"// Playback\n"
"var fbTimer=null;\n"
"function rafTick(){\n"
"  if(!isPlaying||!audEl)return;\n"
"  var t=audEl.currentTime;\n"
"  curTime=t;\n"
"  for(var i=0;i<segs.length;i++){\n"
"    if(t>=segs[i].start&&t<segs[i].end){if(curSeg!==i)selSeg(i);break;}\n"
"  }\n"
"  drawFrame();\n"
"  var tot=audEl.duration||1;\n"
"  document.getElementById('pb-time').textContent=fmt(t)+' / '+fmt(tot);\n"
"  document.getElementById('pb-seek').value=(t/tot)*100;\n"
"  updatePH();\n"
"  if(t>=tot-0.05)stopPlay();\n"
"  else requestAnimationFrame(rafTick);\n"
"}\n"
"function togglePlay(){if(isPlaying)stopPlay();else startPlay();}\n"
"function startPlay(){\n"
"  if(!audEl){isPlaying=true;fallbackPlay();return;}\n"
"  audEl.playbackRate=playSpeed;\n"
"  audEl.volume=parseFloat(document.getElementById('pb-vol').value);\n"
"  audEl.play().catch(function(){});\n"
"  isPlaying=true;\n"
"  document.getElementById('play-icon').style.display='none';\n"
"  document.getElementById('pause-icon').style.display='';\n"
"  requestAnimationFrame(rafTick);\n"
"}\n"
"function stopPlay(){\n"
"  isPlaying=false;if(audEl)audEl.pause();\n"
"  clearTimeout(fbTimer);\n"
"  document.getElementById('play-icon').style.display='';\n"
"  document.getElementById('pause-icon').style.display='none';\n"
"}\n"
"function fallbackPlay(){\n"
"  document.getElementById('play-icon').style.display='none';\n"
"  document.getElementById('pause-icon').style.display='';\n"
"  function advance(){\n"
"    if(!isPlaying)return;\n"
"    if(curSeg+1>=segs.length){stopPlay();return;}\n"
"    selSeg(curSeg+1);\n"
"    fbTimer=setTimeout(advance,segs[curSeg].dur*1000/playSpeed);\n"
"  }\n"
"  clearTimeout(fbTimer);\n"
"  fbTimer=setTimeout(advance,(segs[curSeg]?segs[curSeg].dur:3)*1000/playSpeed);\n"
"}\n"
"function seekDelta(dt){\n"
"  if(audEl)audEl.currentTime=Math.max(0,Math.min(audEl.duration,audEl.currentTime+dt));\n"
"}\n"
"function onSeek(val){\n"
"  if(!audEl){var idx=Math.round((parseFloat(val)/100)*segs.length);selSeg(Math.min(idx,segs.length-1));return;}\n"
"  audEl.currentTime=(parseFloat(val)/100)*audEl.duration;\n"
"}\n"
"function setVol(v){if(audEl)audEl.volume=Math.max(0,Math.min(1,parseFloat(v)));}\n"
"function setSpeed(v){playSpeed=parseFloat(v);if(audEl)audEl.playbackRate=playSpeed;}\n"
"\n"
"function totalDur(){\n"
"  if(audEl&&audEl.duration)return audEl.duration;\n"
"  return segs.reduce(function(a,s){return a+s.dur;},0);\n"
"}\n"
"function fmt(s){var m=Math.floor(s/60);return m+':'+('0'+Math.floor(s%60)).slice(-2);}\n"
"function updateTotalDur(){document.getElementById('tl-total-dur').textContent=fmt(totalDur());}\n"
"\n"
"// Audio tracks\n"
"var aidC=1;\n"
"function addAudTrack(src,name,dur){\n"
"  var id='a_'+(aidC++);\n"
"  audioTracks.push({id:id,name:name,src:src,start:0,duration:dur,\n"
"    volume:1,muted:false,fadeIn:0,fadeOut:0,trimStart:0,trimEnd:0});\n"
"  buildTimeline();selAudTrack(id);\n"
"  setTimeout(function(){loadWaveform(id);},80);\n"
"}\n"
"function selAudTrack(id){\n"
"  selAudId=id;var tr=audioTracks.find(function(a){return a.id===id;});\n"
"  document.getElementById('audio-track-name').textContent=tr?tr.name:'Sin selección';\n"
"  if(tr){\n"
"    document.getElementById('aud-vol').value=tr.volume;\n"
"    document.getElementById('aud-vol-v').textContent=Math.round(tr.volume*100)+'%';\n"
"    document.getElementById('aud-ts').value=tr.trimStart||0;\n"
"    document.getElementById('aud-te').value=tr.trimEnd||0;\n"
"    document.getElementById('aud-fi').value=tr.fadeIn||0;\n"
"    document.getElementById('aud-fo').value=tr.fadeOut||0;\n"
"  }\n"
"  document.querySelectorAll('.tl-ablk').forEach(function(el){el.classList.toggle('sel',el.dataset.id===id);});\n"
"  switchTab('audio');\n"
"}\n"
"function updateAudVol(v){\n"
"  var tr=audioTracks.find(function(a){return a.id===selAudId;});if(!tr)return;\n"
"  tr.volume=parseFloat(v);document.getElementById('aud-vol-v').textContent=Math.round(tr.volume*100)+'%';\n"
"}\n"
"function updateAudTrim(which,val){\n"
"  var tr=audioTracks.find(function(a){return a.id===selAudId;});if(!tr)return;\n"
"  if(which==='start')tr.trimStart=parseFloat(val)||0;else tr.trimEnd=parseFloat(val)||0;buildTimeline();\n"
"}\n"
"function updateAudProp(prop,val){\n"
"  var tr=audioTracks.find(function(a){return a.id===selAudId;});if(!tr)return;tr[prop]=parseFloat(val);\n"
"}\n"
"function deleteAud(){\n"
"  if(!selAudId)return;audioTracks=audioTracks.filter(function(a){return a.id!==selAudId;});\n"
"  selAudId=null;document.getElementById('audio-track-name').textContent='Sin selección';buildTimeline();\n"
"}\n"
"function addAudFile(input){\n"
"  var file=input.files[0];if(!file)return;\n"
"  var url=URL.createObjectURL(file);var a=new Audio();a.src=url;\n"
"  a.onloadedmetadata=function(){addAudTrack(url,file.name,a.duration);};\n"
"  input.value='';\n"
"}\n"
"\n"
"function loadWaveform(tid){\n"
"  var tr=audioTracks.find(function(a){return a.id===tid;});if(!tr||!tr.src)return;\n"
"  if(!audioCtx)audioCtx=new(window.AudioContext||window.webkitAudioContext)();\n"
"  if(audBufCache[tid]){renderWC(tid,audBufCache[tid]);return;}\n"
"  fetch(tr.src).then(function(r){return r.arrayBuffer();})\n"
"  .then(function(ab){return audioCtx.decodeAudioData(ab);})\n"
"  .then(function(buf){audBufCache[tid]=buf;renderWC(tid,buf);})\n"
"  .catch(function(e){console.warn('waveform',e);});\n"
"}\n"
"function renderWC(tid,buf){\n"
"  if(!buf)return;\n"
"  var el=document.querySelector('.tl-ablk[data-id=\"'+tid+'\"] .tl-awc');if(!el)return;\n"
"  var w=el.offsetWidth||200,h=el.offsetHeight||40;el.width=w;el.height=h;\n"
"  var c=el.getContext('2d');c.clearRect(0,0,w,h);\n"
"  var data=buf.getChannelData(0),step=Math.max(1,Math.ceil(data.length/w));\n"
"  c.fillStyle='rgba(34,211,160,.75)';\n"
"  for(var i=0;i<w;i++){\n"
"    var mn=0,mx=0;\n"
"    for(var j=0;j<step;j++){var s=data[i*step+j]||0;if(s<mn)mn=s;if(s>mx)mx=s;}\n"
"    var yT=(1+mn)*h/2,yB=(1+mx)*h/2;\n"
"    c.fillRect(i,Math.min(yT,yB),1,Math.max(1,Math.abs(yB-yT)));\n"
"  }\n"
"}\n"
"function renderNarrWC(el,src){\n"
"  if(!el||!src)return;\n"
"  if(!audioCtx)audioCtx=new(window.AudioContext||window.webkitAudioContext)();\n"
"  fetch(src).then(function(r){return r.arrayBuffer();})\n"
"  .then(function(ab){return audioCtx.decodeAudioData(ab);})\n"
"  .then(function(buf){\n"
"    var w=el.offsetWidth||400,h=el.offsetHeight||36;el.width=w;el.height=h;\n"
"    var c=el.getContext('2d');c.clearRect(0,0,w,h);\n"
"    var data=buf.getChannelData(0),step=Math.max(1,Math.ceil(data.length/w));\n"
"    var g=c.createLinearGradient(0,0,0,h);\n"
"    g.addColorStop(0,'rgba(34,211,160,.9)');g.addColorStop(1,'rgba(34,211,160,.3)');\n"
"    c.fillStyle=g;\n"
"    for(var i=0;i<w;i++){\n"
"      var mn=0,mx=0;\n"
"      for(var j=0;j<step;j++){var s=data[i*step+j]||0;if(s<mn)mn=s;if(s>mx)mx=s;}\n"
"      var yT2=(1+mn)*h/2,yB2=(1+mx)*h/2;\n"
"      c.fillRect(i,Math.min(yT2,yB2),1,Math.max(1,Math.abs(yB2-yT2)));\n"
"    }\n"
"  }).catch(function(){});\n"
"}\n"
"\n"
"// Timeline\n"
"function zoomIn(){pxPerSec=Math.min(200,Math.round(pxPerSec*1.5));document.getElementById('zoom-val').textContent=pxPerSec+'px/s';buildTimeline();}\n"
"function zoomOut(){pxPerSec=Math.max(8,Math.round(pxPerSec/1.5));document.getElementById('zoom-val').textContent=pxPerSec+'px/s';buildTimeline();}\n"
"\n"
"function buildTimeline(){\n"
"  var tot=Math.max(totalDur(),10);var iw=Math.round(tot*pxPerSec)+120;\n"
"  document.getElementById('tl-inner').style.width=iw+'px';\n"
"  buildRuler(iw,tot);buildVideoRow();buildAudRows();buildOvTrack();buildRefImgTrack();updateTotalDur();\n"
"  attachDropToNewTrack();initPhDrag();\n"
"}\n"
"function buildRuler(w,tot){\n"
"  var c=document.getElementById('ruler-canvas');c.width=w;c.height=20;c.style.width=w+'px';\n"
"  var g=c.getContext('2d');g.clearRect(0,0,w,20);\n"
"  var step=1;if(pxPerSec<15)step=10;else if(pxPerSec<30)step=5;else if(pxPerSec<60)step=2;\n"
"  for(var t=0;t<=tot+step;t+=step){\n"
"    var x=Math.round(t*pxPerSec);if(x>=w)break;\n"
"    g.fillStyle='#3a3a55';g.fillRect(x,12,1,8);\n"
"    g.fillStyle='#5a5a80';g.font='8px monospace';if(x+20<w)g.fillText(fmt(t),x+2,10);\n"
"  }\n"
"}\n"
"function buildVideoRow(){\n"
"  var row=document.getElementById('tl-vrow');row.innerHTML='';\n"
"  attachDropToRow(row,'video');\n"
"  segs.forEach(function(sc,i){\n"
"    var x=Math.round(sc.start*pxPerSec),w2=Math.max(20,Math.round(sc.dur*pxPerSec));\n"
"    var el=document.createElement('div');\n"
"    el.className='tl-seg'+(i===curSeg?' active':'');\n"
"    el.style.left=x+'px';el.style.width=w2+'px';el.dataset.idx=i;\n"
"    if(sc.src){var im=document.createElement('img');im.src=sc.src;im.loading='lazy';el.appendChild(im);}\n"
"    var nm=document.createElement('div');nm.className='tl-seg-txt';\n"
"    nm.textContent=(i+1)+'. '+(sc.tipo!=='normal'?'['+sc.tipo+'] ':'')+'Esc'+(i+1);el.appendChild(nm);\n"
"    var hL=document.createElement('div');hL.className='tl-hdl L';hL.dataset.idx=i;hL.dataset.side='L';\n"
"    var hR=document.createElement('div');hR.className='tl-hdl R';hR.dataset.idx=i;hR.dataset.side='R';\n"
"    el.appendChild(hL);el.appendChild(hR);\n"
"    el.addEventListener('mousedown',function(e){\n"
"      if(e.target.classList.contains('tl-hdl'))return;\n"
"      stopPlay();selSeg(parseInt(this.dataset.idx));\n"
"      var ii=parseInt(this.dataset.idx);\n"
"      segDragState={idx:ii,side:'M',sx:e.clientX,os:segs[ii].start,oe:segs[ii].end};\n"
"      document.body.style.cursor='grabbing';\n"
"      e.stopPropagation();\n"
"    });\n"
"    (function(h2,side){\n"
"      h2.addEventListener('mousedown',function(e){\n"
"        e.stopPropagation();e.preventDefault();\n"
"        var ii2=parseInt(h2.dataset.idx);\n"
"        segDragState={idx:ii2,side:side,sx:e.clientX,os:segs[ii2].start,oe:segs[ii2].end};\n"
"        document.body.style.cursor='ew-resize';\n"
"      });\n"
"    })(hL,'L');\n"
"    (function(h2,side){\n"
"      h2.addEventListener('mousedown',function(e){\n"
"        e.stopPropagation();e.preventDefault();\n"
"        var ii2=parseInt(h2.dataset.idx);\n"
"        segDragState={idx:ii2,side:side,sx:e.clientX,os:segs[ii2].start,oe:segs[ii2].end};\n"
"        document.body.style.cursor='ew-resize';\n"
"      });\n"
"    })(hR,'R');\n"
"    row.appendChild(el);\n"
"    if(i<segs.length-1&&sc.transition&&sc.transition!=='none'){\n"
"      var tdur=sc.transDur||TRANS_DUR,tx=Math.round((sc.start+sc.dur-tdur/2)*pxPerSec)-6;\n"
"      var tm=document.createElement('div');tm.className='tl-tmark';tm.style.left=tx+'px';\n"
"      tm.title=sc.transition;\n"
"      tm.innerHTML='<span>'+sc.transition.charAt(0).toUpperCase()+'</span>';\n"
"      tm.addEventListener('click',function(e){e.stopPropagation();switchTab('transitions');});\n"
"      row.appendChild(tm);\n"
"    }\n"
"  });\n"
"}\n"
"function buildAudRows(){\n"
"  var container=document.getElementById('tl-arows');container.innerHTML='';\n"
"  var lblWrap=document.getElementById('aud-lbl-wrap');lblWrap.innerHTML='';\n"
"  var narrSrc=audEl?audEl.src:null;\n"
"  if(narrSrc){\n"
"    var lbl=document.createElement('div');lbl.className='tl-tl audio';\n"
"    lbl.innerHTML='<svg width=\"10\" height=\"10\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"var(--c3)\" stroke-width=\"2\"><path d=\"M9 18V5l12-2v13\"/><circle cx=\"6\" cy=\"18\" r=\"3\"/><circle cx=\"18\" cy=\"16\" r=\"3\"/></svg><span class=\"tl-lt\">Narración</span>';\n"
"    lblWrap.appendChild(lbl);\n"
"    var narrRow=document.createElement('div');narrRow.className='tl-arow';\n"
"    var dur=audEl.duration||totalDur();\n"
"    var w=Math.round(dur*pxPerSec);\n"
"    var blk=document.createElement('div');blk.className='tl-ablk';blk.style.left='0';blk.style.width=Math.max(30,w)+'px';\n"
"    var lbl2=document.createElement('div');lbl2.className='tl-albl';lbl2.textContent='Narración';\n"
"    var wc=document.createElement('canvas');wc.className='tl-awc';\n"
"    blk.appendChild(lbl2);blk.appendChild(wc);\n"
"    narrRow.appendChild(blk);container.appendChild(narrRow);\n"
"    setTimeout(function(){renderNarrWC(wc,narrSrc);},60);\n"
"  }\n"
"  audioTracks.forEach(function(tr){\n"
"    var lbl3=document.createElement('div');lbl3.className='tl-tl audio';\n"
"    lbl3.innerHTML='<svg width=\"10\" height=\"10\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"var(--c3)\" stroke-width=\"2\"><path d=\"M9 18V5l12-2v13\"/><circle cx=\"6\" cy=\"18\" r=\"3\"/><circle cx=\"18\" cy=\"16\" r=\"3\"/></svg><span class=\"tl-lt\">'+tr.name+'</span>';\n"
"    lblWrap.appendChild(lbl3);\n"
"    var row2=document.createElement('div');row2.className='tl-arow';\n"
"    var eff=Math.max(0,tr.duration-(tr.trimStart||0)-(tr.trimEnd||0));\n"
"    var xr=Math.round((tr.start||0)*pxPerSec),wr=Math.round(eff*pxPerSec);\n"
"    var blk2=document.createElement('div');\n"
"    blk2.className='tl-ablk'+(tr.id===selAudId?' sel':'');\n"
"    blk2.style.left=xr+'px';blk2.style.width=Math.max(20,wr)+'px';blk2.dataset.id=tr.id;\n"
"    blk2.innerHTML='<div class=\"tl-albl\">'+tr.name+'</div><canvas class=\"tl-awc\"></canvas>'\n"
"      +'<div class=\"tl-hdl L\" data-id=\"'+tr.id+'\" data-side=\"L\"></div>'\n"
"      +'<div class=\"tl-hdl R\" data-id=\"'+tr.id+'\" data-side=\"R\"></div>';\n"
"    blk2.addEventListener('click',function(){selAudTrack(this.dataset.id);});\n"
"    row2.appendChild(blk2);container.appendChild(row2);\n"
"    setTimeout(function(){renderWC(tr.id,audBufCache[tr.id]||null);},60);\n"
"  });\n"
"  document.querySelectorAll('.tl-hdl').forEach(function(h){\n"
"    h.addEventListener('mousedown',function(e){\n"
"      e.stopPropagation();\n"
"      var sid=h.dataset.side;\n"
"      var tr2=audioTracks.find(function(a){return a.id===h.dataset.id;});\n"
"      audDragState={id:h.dataset.id,side:sid,sx:e.clientX,\n"
"        st:sid==='L'?(tr2?tr2.trimStart:0):(tr2?tr2.trimEnd:0)};\n"
"      h.classList.add('drg');\n"
"    });\n"
"  });\n"
"}\n"
"\n"
"function buildOvTrack(){\n"
"  var container=document.getElementById('tl-ovrows');\n"
"  var lblWrap=document.getElementById('ov-lbl-wrap');\n"
"  if(!container||!lblWrap)return;\n"
"  container.innerHTML='';lblWrap.innerHTML='';\n"
"  var hasOvs=segs.some(function(s){return s.overlays&&s.overlays.length>0;});\n"
"  if(!hasOvs)return;\n"
"  var lbl=document.createElement('div');lbl.className='tl-tl ov';\n"
"  lbl.innerHTML='<svg width=\"10\" height=\"10\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"var(--c2)\" stroke-width=\"2\"><rect x=\"3\" y=\"3\" width=\"18\" height=\"18\" rx=\"2\"/><line x1=\"8\" y1=\"12\" x2=\"16\" y2=\"12\"/></svg><span class=\"tl-lt\" style=\"color:var(--c2)\">Texto</span>';\n"
"  lblWrap.appendChild(lbl);\n"
"  var row=document.createElement('div');row.className='tl-ovrow';\n"
"  attachDropToRow(row,'ov');\n"
"  segs.forEach(function(sc,si){\n"
"    if(!sc.overlays||!sc.overlays.length)return;\n"
"    var ovS=sc.ovStart!=null?sc.ovStart:sc.start,ovD=sc.ovDur!=null?sc.ovDur:sc.dur;\n"
"    var x=Math.round(ovS*pxPerSec),bw=Math.max(14,Math.round(ovD*pxPerSec));\n"
"    var blk=document.createElement('div');\n"
"    blk.className='tl-ovblk'+(si===curSeg?' sel':'');\n"
"    blk.style.left=x+'px';blk.style.width=bw+'px';blk.dataset.si=si;\n"
"    var fo=sc.overlays[0];\n"
"    var lbl2=document.createElement('div');lbl2.className='tl-blbl';\n"
"    lbl2.textContent=(fo.text||(fo._type?'['+fo._type+']':'ov')).substring(0,20);\n"
"    blk.appendChild(lbl2);\n"
"    var hL=document.createElement('div');hL.className='tl-hdl2 L';hL.dataset.si=si;hL.dataset.side='L';\n"
"    var hR=document.createElement('div');hR.className='tl-hdl2 R';hR.dataset.si=si;hR.dataset.side='R';\n"
"    blk.appendChild(hL);blk.appendChild(hR);\n"
"    blk.addEventListener('click',function(e){\n"
"      if(e.target.classList.contains('tl-hdl2'))return;\n"
"      stopPlay();selSeg(parseInt(this.dataset.si));\n"
"    });\n"
"    (function(h2,side){\n"
"      h2.addEventListener('mousedown',function(e){\n"
"        e.stopPropagation();e.preventDefault();\n"
"        var idx=parseInt(h2.dataset.si);\n"
"        var sc2=segs[idx];var os=sc2.ovStart!=null?sc2.ovStart:sc2.start;\n"
"        ovDragState={si:idx,track:'ov',side:side,sx:e.clientX,os:os,oe:os+(sc2.ovDur!=null?sc2.ovDur:sc2.dur)};\n"
"        document.body.style.cursor='ew-resize';\n"
"      });\n"
"    })(hL,'L');\n"
"    (function(h2,side){\n"
"      h2.addEventListener('mousedown',function(e){\n"
"        e.stopPropagation();e.preventDefault();\n"
"        var idx=parseInt(h2.dataset.si);\n"
"        var sc2=segs[idx];var os=sc2.ovStart!=null?sc2.ovStart:sc2.start;\n"
"        ovDragState={si:idx,track:'ov',side:side,sx:e.clientX,os:os,oe:os+(sc2.ovDur!=null?sc2.ovDur:sc2.dur)};\n"
"        document.body.style.cursor='ew-resize';\n"
"      });\n"
"    })(hR,'R');\n"
"    row.appendChild(blk);\n"
"  });\n"
"  container.appendChild(row);\n"
"}\n"
"// Build an image track block element\n"
"function makeIBlk(it,si_or_null){\n"
"  var x=Math.round(it.start*pxPerSec),bw=Math.max(14,Math.round(it.dur*pxPerSec));\n"
"  var blk=document.createElement('div');\n"
"  blk.className='tl-iblk';blk.style.left=x+'px';blk.style.width=bw+'px';\n"
"  if(si_or_null!=null)blk.dataset.si=si_or_null;\n"
"  blk.dataset.iid=it.id;\n"
"  var thumbSrc=it.src||(it._sc&&it._sc.refSrc?it._sc.refSrc:null);\n"
"  if(thumbSrc){\n"
"    blk.style.backgroundImage='url('+thumbSrc+')';\n"
"    blk.style.backgroundSize='cover';blk.style.backgroundPosition='center';\n"
"  }\n"
"  var ovDiv=document.createElement('div');ovDiv.className='tl-iblk-overlay';blk.appendChild(ovDiv);\n"
"  var lbl2=document.createElement('div');lbl2.className='tl-blbl';\n"
"  lbl2.textContent=it.name||'img';lbl2.style.position='relative';lbl2.style.zIndex='1';\n"
"  blk.appendChild(lbl2);\n"
"  // Resize handles\n"
"  var hL2=document.createElement('div');hL2.className='tl-hdl2 L';hL2.dataset.iid=it.id;hL2.dataset.side='L';\n"
"  var hR2=document.createElement('div');hR2.className='tl-hdl2 R';hR2.dataset.iid=it.id;hR2.dataset.side='R';\n"
"  blk.appendChild(hL2);blk.appendChild(hR2);\n"
"  blk.addEventListener('click',function(e){\n"
"    if(e.target.classList.contains('tl-hdl2'))return;\n"
"    if(it.segIdx!=null){stopPlay();selSeg(it.segIdx);}\n"
"  });\n"
"  // Move drag on block body\n"
"  blk.addEventListener('mousedown',function(e){\n"
"    if(e.target.classList.contains('tl-hdl2'))return;\n"
"    e.stopPropagation();e.preventDefault();\n"
"    ovDragState={iid:it.id,track:'imgItem',side:'M',sx:e.clientX,os:it.start,oe:it.start+it.dur};\n"
"    document.body.style.cursor='grabbing';\n"
"  });\n"
"  function hdlDown(side){\n"
"    return function(e){e.stopPropagation();e.preventDefault();\n"
"      ovDragState={iid:it.id,track:'imgItem',side:side,sx:e.clientX,os:it.start,oe:it.start+it.dur};\n"
"      document.body.style.cursor='ew-resize';\n"
"    };\n"
"  }\n"
"  hL2.addEventListener('mousedown',hdlDown('L'));\n"
"  hR2.addEventListener('mousedown',hdlDown('R'));\n"
"  return blk;\n"
"}\n"
"function buildRefImgTrack(){\n"
"  var container=document.getElementById('tl-irrows');\n"
"  var lblWrap=document.getElementById('ir-lbl-wrap');\n"
"  if(!container||!lblWrap)return;\n"
"  container.innerHTML='';lblWrap.innerHTML='';\n"
"  if(!imgTrackItems.length)return;\n"
"  // Find max lane\n"
"  var maxLane=0;\n"
"  imgTrackItems.forEach(function(it){if(it.lane>maxLane)maxLane=it.lane;});\n"
"  // One label row spanning all lanes\n"
"  var lbl=document.createElement('div');lbl.className='tl-tl ir';\n"
"  lbl.style.height=((maxLane+1)*56)+'px';\n"
"  lbl.style.alignItems='flex-start';lbl.style.paddingTop='16px';\n"
"  lbl.innerHTML='<svg width=\"10\" height=\"10\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"var(--ce)\" stroke-width=\"2\"><rect x=\"3\" y=\"3\" width=\"18\" height=\"18\" rx=\"2\"/><polyline points=\"21 15 16 10 5 21\"/></svg><span class=\"tl-lt\" style=\"color:var(--ce)\">Imágenes</span>';\n"
"  lblWrap.appendChild(lbl);\n"
"  // One row per lane\n"
"  for(var lane=0;lane<=maxLane;lane++){\n"
"    var row=document.createElement('div');row.className='tl-irrow';\n"
"    attachDropToRow(row,'img');\n"
"    var laneItems=imgTrackItems.filter(function(it){return it.lane===lane;});\n"
"    laneItems.forEach(function(it){\n"
"      row.appendChild(makeIBlk(it,it.segIdx!=null?it.segIdx:null));\n"
"    });\n"
"    container.appendChild(row);\n"
"  }\n"
"}\n"
"window.addEventListener('mousemove',function(e){\n"
"  if(!segDragState)return;\n"
"  var dx=(e.clientX-segDragState.sx)/pxPerSec;\n"
"  var sc=segs[segDragState.idx];if(!sc)return;\n"
"  if(segDragState.side==='M'){\n"
"    var ns2=Math.max(0,segDragState.os+dx);\n"
"    sc.start=ns2;sc.end=ns2+(segDragState.oe-segDragState.os);\n"
"  } else if(segDragState.side==='L'){\n"
"    var ns3=Math.max(0,segDragState.os+dx),nd2=segDragState.oe-ns3;\n"
"    if(nd2>=0.2){sc.start=ns3;sc.dur=nd2;sc.end=sc.start+sc.dur;}\n"
"  } else {\n"
"    var ne2=Math.max(segDragState.os+0.2,segDragState.oe+dx);\n"
"    sc.end=ne2;sc.dur=ne2-sc.start;\n"
"  }\n"
"  curTime=sc.start+sc.dur/2;\n"
"  fastUpdateBlks();drawFrame();\n"
"});\n"
"window.addEventListener('mouseup',function(){\n"
"  if(segDragState){segDragState=null;document.body.style.cursor='';buildTimeline();drawFrame();}\n"
"});\n"
"\n"
"\n"
"function toggleAnchor(){\n"
"  tlAnchor=!tlAnchor;\n"
"  var btn=document.getElementById('btn-anchor');\n"
"  if(btn){btn.style.opacity=tlAnchor?'1':'0.45';btn.style.background=tlAnchor?'rgba(255,200,0,0.25)':'';}\n"
"}\n"
"window.addEventListener('mousemove',function(e){\n"
"  if(!ovDragState)return;\n"
"  var dx=(e.clientX-ovDragState.sx)/pxPerSec;\n"
"  var trk=ovDragState.track||'ov';\n"
"  if(trk==='imgItem'){\n"
"    // Resize an imgTrackItem directly\n"
"    var it=imgTrackItems.find(function(x){return x.id===ovDragState.iid;});\n"
"    if(!it){buildTimeline();drawFrame();return;}\n"
"    if(ovDragState.side==='M'){it.start=Math.max(0,ovDragState.os+dx);}\n"
"    else if(ovDragState.side==='L'){var ns=Math.max(0,ovDragState.os+dx),nd=ovDragState.oe-ns;if(nd>=0.2){it.start=ns;it.dur=nd;}}\n"
"    else{it.dur=Math.max(0.2,ovDragState.oe-ovDragState.os+dx);}\n"
"    curTime=it.start+it.dur/2;\n"
"    fastUpdateBlks();drawFrame();return;\n"
"  }\n"
"  var sc=segs[ovDragState.si];if(!sc)return;\n"
"  function applyToTrack(s,t,side,os,oe){\n"
"    if(t==='ov'){\n"
"      if(side==='L'){var ns=Math.max(0,os+dx),nd=oe-ns;if(nd>=0.2){s.ovStart=ns;s.ovDur=nd;}}\n"
"      else{var ne=Math.max(os+0.2,oe+dx);s.ovDur=ne-s.ovStart;}\n"
"    } else {\n"
"      if(side==='L'){var ns=Math.max(0,os+dx),nd=oe-ns;if(nd>=0.2){s.imgStart=ns;s.imgDur=nd;}}\n"
"      else{var ne=Math.max(os+0.2,oe+dx);s.imgDur=ne-s.imgStart;}\n"
"    }\n"
"  }\n"
"  applyToTrack(sc,trk,ovDragState.side,ovDragState.os,ovDragState.oe);\n"
"  if(tlAnchor){\n"
"    var otherT=trk==='ov'?'img':'ov';\n"
"    var delta=dx;\n"
"    if(ovDragState.side==='L'){\n"
"      if(otherT==='ov'){var os2=sc.ovStart,nd2=(sc.ovStart+sc.ovDur)-(os2+delta);if(nd2>=0.2){sc.ovStart=Math.max(0,os2+delta);sc.ovDur=nd2;}}\n"
"      else{var os2=sc.imgStart,nd2=(sc.imgStart+sc.imgDur)-(os2+delta);if(nd2>=0.2){sc.imgStart=Math.max(0,os2+delta);sc.imgDur=nd2;}}\n"
"    } else {\n"
"      if(otherT==='ov'){sc.ovDur=Math.max(0.2,sc.ovDur+delta);}\n"
"      else{sc.imgDur=Math.max(0.2,sc.imgDur+delta);}\n"
"    }\n"
"  }\n"
"  fastUpdateBlks();drawFrame();\n"
"});\n"
"window.addEventListener('mouseup',function(){\n"
"  if(ovDragState){\n"
"    // After moving an imgItem, reassign its lane based on new position\n"
"    if(ovDragState.track==='imgItem'&&ovDragState.side==='M'){\n"
"      var movedIt=imgTrackItems.find(function(x){return x.id===ovDragState.iid;});\n"
"      if(movedIt){\n"
"        // Temporarily remove from list to avoid self-collision\n"
"        var others=imgTrackItems.filter(function(x){return x.id!==movedIt.id;});\n"
"        var tmpItems=imgTrackItems;imgTrackItems=others;\n"
"        movedIt.lane=assignImgLane(movedIt.start,movedIt.start+movedIt.dur);\n"
"        imgTrackItems=tmpItems;\n"
"      }\n"
"    }\n"
"    ovDragState=null;document.body.style.cursor='';buildTimeline();drawFrame();\n"
"  }\n"
"});\n"
"\n"
"\n"
"function updatePH(){\n"
"  var t=audEl?audEl.currentTime:segs.slice(0,curSeg).reduce(function(a,s){return a+s.dur;},0);\n"
"  var x=Math.round(t*pxPerSec);\n"
"  document.getElementById('tl-ph').style.left=x+'px';\n"
"  var sc=document.getElementById('tl-scroll');\n"
"  if(x<sc.scrollLeft||x>sc.scrollLeft+sc.clientWidth-40)sc.scrollLeft=Math.max(0,x-sc.clientWidth/3);\n"
"}\n"
"\n"
"// Fast DOM-only update during drag (no full rebuild)\n"
"function fastUpdateBlks(){\n"
"  // Update video seg blocks\n"
"  var vrow=document.getElementById('tl-vrow');\n"
"  if(vrow){Array.from(vrow.querySelectorAll('.tl-seg')).forEach(function(el){\n"
"    var i=parseInt(el.dataset.idx);if(isNaN(i))return;\n"
"    var sc=segs[i];if(!sc)return;\n"
"    el.style.left=Math.round(sc.start*pxPerSec)+'px';\n"
"    el.style.width=Math.max(20,Math.round(sc.dur*pxPerSec))+'px';\n"
"  });}\n"
"  // Update img track blocks\n"
"  var irrows=document.getElementById('tl-irrows');\n"
"  if(irrows){Array.from(irrows.querySelectorAll('.tl-iblk')).forEach(function(el){\n"
"    var iid=el.dataset.iid;if(!iid)return;\n"
"    var it=imgTrackItems.find(function(x){return x.id===iid;});if(!it)return;\n"
"    el.style.left=Math.round(it.start*pxPerSec)+'px';\n"
"    el.style.width=Math.max(14,Math.round(it.dur*pxPerSec))+'px';\n"
"  });}\n"
"  // Update ov track blocks\n"
"  var ovrow=document.getElementById('tl-ovrow');\n"
"  if(ovrow){Array.from(ovrow.querySelectorAll('.tl-ovblk')).forEach(function(el){\n"
"    var si=parseInt(el.dataset.si);if(isNaN(si))return;\n"
"    var sc=segs[si];if(!sc)return;\n"
"    var os=sc.ovStart!=null?sc.ovStart:sc.start;\n"
"    var od=sc.ovDur!=null?sc.ovDur:sc.dur;\n"
"    el.style.left=Math.round(os*pxPerSec)+'px';\n"
"    el.style.width=Math.max(14,Math.round(od*pxPerSec))+'px';\n"
"  });}\n"
"  // Update playhead\n"
"  var ph=document.getElementById('tl-ph');\n"
"  if(ph){ph.style.left=Math.round(curTime*pxPerSec)+'px';}\n"
"}\n"
"\n"
"// Playhead scrub drag\n"
"var _phDrag=false;\n"
"function scrubTo(clientX){\n"
"  var sc2=document.getElementById('tl-scroll');\n"
"  var rx=clientX-sc2.getBoundingClientRect().left+sc2.scrollLeft;\n"
"  var t=Math.max(0,rx/pxPerSec);\n"
"  curTime=t;\n"
"  var ph=document.getElementById('tl-ph');if(ph)ph.style.left=Math.round(t*pxPerSec)+'px';\n"
"  if(audEl&&isFinite(audEl.duration)){audEl.currentTime=Math.min(audEl.duration,t);}\n"
"  var acc2=0;\n"
"  for(var i=0;i<segs.length;i++){if(acc2+segs[i].dur>t){if(i!==curSeg){curSeg=i;selSeg(i);}break;}acc2+=segs[i].dur;}\n"
"  drawFrame();\n"
"}\n"
"function initPhDrag(){\n"
"  var ph=document.getElementById('tl-ph');if(!ph||ph._phWired)return;\n"
"  ph._phWired=true;\n"
"  // pointer-events and cursor already set via CSS\n"
"  ph.addEventListener('mousedown',function(e){\n"
"    _phDrag=true;e.stopPropagation();e.preventDefault();document.body.style.cursor='ew-resize';\n"
"  });\n"
"}\n"
"window.addEventListener('mousemove',function(e){if(!_phDrag)return;scrubTo(e.clientX);});\n"
"window.addEventListener('mouseup',function(){if(_phDrag){_phDrag=false;document.body.style.cursor='';}});\n"
"\n"
"document.getElementById('tl-scroll').addEventListener('click',function(e){\n"
"  if(e.target.classList.contains('tl-hdl'))return;\n"
"  if(e.target.id==='tl-ph'||e.target.closest&&e.target.closest('#tl-ph'))return;\n"
"  var r=this.getBoundingClientRect(),x=e.clientX-r.left+this.scrollLeft,t=x/pxPerSec;\n"
"  if(audEl&&isFinite(audEl.duration)){audEl.currentTime=Math.max(0,Math.min(audEl.duration,t));curTime=t;drawFrame();return;}\n"
"  var acc=0;\n"
"  for(var i=0;i<segs.length;i++){if(acc+segs[i].dur>t){stopPlay();selSeg(i);return;}acc+=segs[i].dur;}\n"
"});\n"
"\n"
"// Mouse wheel: horizontal scroll on timeline (normal) or zoom (ctrl)\n"
"document.getElementById('tl-scroll').addEventListener('wheel',function(e){\n"
"  e.preventDefault();\n"
"  if(e.ctrlKey||e.metaKey){\n"
"    // Ctrl+wheel --> zoom\n"
"    if(e.deltaY<0)zoomIn();else zoomOut();\n"
"  } else {\n"
"    // Normal wheel --> scroll horizontally\n"
"    this.scrollLeft+=e.deltaY*2;\n"
"  }\n"
"},{passive:false});\n"
"\n"
"// Timeline resize handle: drag to change height\n"
"(function(){\n"
"  var handle=document.getElementById('tl-resize-handle');\n"
"  var tl=document.getElementById('timeline');\n"
"  var _dragging=false,_startY=0,_startH=0;\n"
"  var MIN_H=120,MAX_H=600;\n"
"  handle.addEventListener('mousedown',function(e){\n"
"    _dragging=true;_startY=e.clientY;_startH=tl.offsetHeight;\n"
"    handle.classList.add('dragging');\n"
"    document.body.style.cursor='ns-resize';document.body.style.userSelect='none';\n"
"    e.preventDefault();\n"
"  });\n"
"  window.addEventListener('mousemove',function(e){\n"
"    if(!_dragging)return;\n"
"    var dy=_startY-e.clientY; // drag up = bigger\n"
"    var nh=Math.max(MIN_H,Math.min(MAX_H,_startH+dy));\n"
"    tl.style.height=nh+'px';\n"
"  });\n"
"  window.addEventListener('mouseup',function(){\n"
"    if(!_dragging)return;\n"
"    _dragging=false;handle.classList.remove('dragging');\n"
"    document.body.style.cursor='';document.body.style.userSelect='';\n"
"  });\n"
"})();\n"
"\n"
"// ── Media Panel ──────────────────────────────────────────────\n"
"var mpTab='images';\n"
"var mpOpen=true;\n"
"var _mpDragData=null; // {type,src,name,idx}\n"
"// Multi-lane image track items: [{id,src,name,start,dur,lane,segIdx}]\n"
"var imgTrackItems=[];\n"
"var _imgItemIdC=1;\n"
"\n"
"function toggleMediaPanel(){\n"
"  mpOpen=!mpOpen;\n"
"  var p=document.getElementById('media-panel');\n"
"  var btn=document.getElementById('mp-toggle');\n"
"  var icon=document.getElementById('mp-toggle-icon');\n"
"  if(mpOpen){\n"
"    p.classList.remove('collapsed');\n"
"    if(btn)btn.style.left='260px';\n"
"    if(icon)icon.setAttribute('d','M8 0L0 6l8 6z');\n"
"  } else {\n"
"    p.classList.add('collapsed');\n"
"    if(btn)btn.style.left='0px';\n"
"    if(icon)icon.setAttribute('d','M0 0l8 6-8 6z');\n"
"  }\n"
"}\n"
"function switchMpTab(t){\n"
"  mpTab=t;\n"
"  ['images','audio','video'].forEach(function(x){\n"
"    document.getElementById('mp-pane-'+x).style.display=x===t?'':'none';\n"
"    document.getElementById('mpt-'+x).classList.toggle('active',x===t);\n"
"  });\n"
"}\n"
"// Create a draggable media item element\n"
"function makeMpItem(src,label,typeClass,typeLabel,dragData){\n"
"  var item=document.createElement('div');item.className='mp-item';\n"
"  item.draggable=true;\n"
"  if(src){\n"
"    var img=document.createElement('img');img.src=src;img.loading='lazy';\n"
"    item.appendChild(img);\n"
"  } else {\n"
"    var ph=document.createElement('div');ph.className='mp-item-no-img';\n"
"    ph.textContent=typeLabel==='AUD'?'🎵':'📄';\n"
"    item.appendChild(ph);\n"
"  }\n"
"  var lbl=document.createElement('div');lbl.className='mp-item-lbl';lbl.textContent=label;\n"
"  var typ=document.createElement('div');typ.className='mp-item-type '+typeClass;typ.textContent=typeLabel;\n"
"  item.appendChild(lbl);item.appendChild(typ);\n"
"  item.addEventListener('dragstart',function(e){\n"
"    _mpDragData=dragData;\n"
"    item.classList.add('dragging');\n"
"    e.dataTransfer.effectAllowed='copy';\n"
"    e.dataTransfer.setData('text/plain',JSON.stringify(dragData));\n"
"  });\n"
"  item.addEventListener('dragend',function(){item.classList.remove('dragging');setTimeout(function(){_mpDragData=null;},0);});\n"
"  return item;\n"
"}\n"
"function buildMediaPanel(){\n"
"  var grid=document.getElementById('mp-img-grid');if(!grid)return;\n"
"  grid.innerHTML='';\n"
"  // Project images\n"
"  images.forEach(function(src,i){\n"
"    grid.appendChild(makeMpItem(src,'Img '+(i+1),'img','IMG',{type:'image',src:src,name:'Img '+(i+1),idx:i}));\n"
"  });\n"
"  // Ref images from imgTrackItems + segs\n"
"  var seenRefs={};\n"
"  imgTrackItems.forEach(function(it){\n"
"    if(!it.src||seenRefs[it.src])return;\n"
"    seenRefs[it.src]=1;\n"
"    grid.appendChild(makeMpItem(it.src,it.name||'Ref','ref','REF',{type:'ref',src:it.src,name:it.name||'Ref'}));\n"
"  });\n"
"  segs.forEach(function(sc,i){\n"
"    if(!sc.refSrc||seenRefs[sc.refSrc])return;\n"
"    seenRefs[sc.refSrc]=1;\n"
"    grid.appendChild(makeMpItem(sc.refSrc,(sc.tipo||'ref')+' E'+(i+1),'ref','REF',{type:'ref',src:sc.refSrc,name:(sc.tipo||'ref')+' E'+(i+1),segIdx:i}));\n"
"  });\n"
"  // Audio\n"
"  var audList=document.getElementById('mp-aud-list');if(audList){audList.innerHTML='';}\n"
"  if(audEl&&audEl.src){\n"
"    if(audList)audList.appendChild(mpAudItem('Narración',audEl.src,'narr'));\n"
"  }\n"
"  audioTracks.forEach(function(tr){\n"
"    if(audList)audList.appendChild(mpAudItem(tr.name,tr.src||'',tr.id));\n"
"  });\n"
"  // Video tab — scene thumbnails\n"
"  var vgrid=document.getElementById('mp-vid-grid');if(vgrid){vgrid.innerHTML='';}\n"
"  segs.forEach(function(sc,i){\n"
"    if(!sc.src||!vgrid)return;\n"
"    vgrid.appendChild(makeMpItem(sc.src,'E'+(i+1),'vid','VID',{type:'video',src:sc.src,name:'E'+(i+1),segIdx:i}));\n"
"  });\n"
"  // Wire import zone drag-and-drop\n"
"  var iz=document.getElementById('mp-import-zone');\n"
"  if(iz&&!iz._wired){\n"
"    iz._wired=true;\n"
"    iz.addEventListener('dragover',function(e){\n"
"      // Only accept file drops from outside, not from media panel items\n"
"      if(!e.dataTransfer.types.includes('Files'))return;\n"
"      e.preventDefault();iz.classList.add('drag-over');\n"
"    });\n"
"    iz.addEventListener('dragleave',function(){iz.classList.remove('drag-over');});\n"
"    iz.addEventListener('drop',function(e){\n"
"      e.preventDefault();iz.classList.remove('drag-over');\n"
"      if(e.dataTransfer.files&&e.dataTransfer.files.length)mpHandleFiles(e.dataTransfer.files);\n"
"    });\n"
"  }\n"
"}\n"
"function mpAudItem(name,src,id){\n"
"  var d=document.createElement('div');d.className='mp-aud-item';d.draggable=true;\n"
"  d.innerHTML='<svg class=\"mp-aud-icon\" width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M9 18V5l12-2v13\"/><circle cx=\"6\" cy=\"18\" r=\"3\"/><circle cx=\"18\" cy=\"16\" r=\"3\"/></svg>'\n"
"    +'<span class=\"mp-aud-name\">'+name+'</span>';\n"
"  d.addEventListener('dragstart',function(e){\n"
"    _mpDragData={type:'audio',src:src,name:name,id:id};\n"
"    d.style.opacity='.5';\n"
"    e.dataTransfer.effectAllowed='copy';\n"
"    e.dataTransfer.setData('text/plain',JSON.stringify(_mpDragData));\n"
"  });\n"
"  d.addEventListener('dragend',function(){d.style.opacity='';setTimeout(function(){_mpDragData=null;},0);});\n"
"  return d;\n"
"}\n"
"\n"
"// ── Import files from disk into media panel ──────────────────\n"
"function mpHandleFiles(files){\n"
"  Array.from(files).forEach(function(f){\n"
"    var type=f.type||'';\n"
"    var reader=new FileReader();\n"
"    reader.onload=function(ev){\n"
"      var dataUrl=ev.target.result;\n"
"      if(type.startsWith('image/')){\n"
"        // Add to images array\n"
"        images.push(dataUrl);\n"
"        // Also add as imgTrackItem so it shows in img track section\n"
"        buildMediaPanel();\n"
"        buildTimeline();\n"
"      } else if(type.startsWith('audio/')){\n"
"        var id='imp_'+(Date.now());\n"
"        var tr={id:id,src:dataUrl,name:f.name.replace(/\\.\\w+$/,''),\n"
"          start:0,duration:0,trimStart:0,trimEnd:0,vol:0.8,fadeIn:0,fadeOut:0};\n"
"        var tmp=new Audio(dataUrl);\n"
"        tmp.onloadedmetadata=function(){tr.duration=tmp.duration||10;buildTimeline();};\n"
"        audioTracks.push(tr);\n"
"        buildMediaPanel();\n"
"        buildTimeline();\n"
"      }\n"
"    };\n"
"    reader.readAsDataURL(f);\n"
"  });\n"
"}\n"
"\n"
"// ── Multi-lane image track helpers ───────────────────────────\n"
"// Compute lane assignment for a new item given existing items on same row\n"
"function assignImgLane(newStart,newEnd){\n"
"  var laneMax=0;\n"
"  imgTrackItems.forEach(function(it){if(it.lane>laneMax)laneMax=it.lane;});\n"
"  for(var lane=0;lane<=laneMax+1;lane++){\n"
"    var conflict=false;\n"
"    imgTrackItems.forEach(function(it){\n"
"      if(it.lane===lane&&newStart<it.start+it.dur&&newEnd>it.start)conflict=true;\n"
"    });\n"
"    if(!conflict)return lane;\n"
"  }\n"
"  return laneMax+1;\n"
"}\n"
"// Initialize imgTrackItems from segs (called on load)\n"
"function initImgTrackItems(){\n"
"  imgTrackItems=[];\n"
"  segs.forEach(function(sc,i){\n"
"    if(!sc.refSrc&&!(sc.escena&&(sc.escena.ref_image_b64||sc.escena.ref_image_url))&&!REF_FULLSCREEN_TIPOS[sc.tipo])return;\n"
"    var s=sc.imgStart!=null?sc.imgStart:sc.start;\n"
"    var d2=sc.imgDur!=null?sc.imgDur:sc.dur;\n"
"    var lane=assignImgLane(s,s+d2);\n"
"    imgTrackItems.push({id:'iti_'+(++_imgItemIdC),src:sc.refSrc||null,\n"
"      name:(sc.tipo||'ref')+' E'+(i+1),start:s,dur:d2,lane:lane,segIdx:i,_sc:sc});\n"
"  });\n"
"}\n"
"\n"
"// ── Timeline drag-drop ───────────────────────────────────────\n"
"// Attach dragover/drop to timeline track rows (called from buildTimeline)\n"
"function attachDropToRow(rowEl,rowType){\n"
"  rowEl.addEventListener('dragover',function(e){\n"
"    var hasData=_mpDragData||(e.dataTransfer.types&&(e.dataTransfer.types.includes?e.dataTransfer.types.includes('text/plain'):Array.from(e.dataTransfer.types).indexOf('text/plain')>=0));\n"
"    if(!hasData)return;\n"
"    e.preventDefault();e.dataTransfer.dropEffect='copy';\n"
"    rowEl.classList.add('tl-drop-over');\n"
"  });\n"
"  rowEl.addEventListener('dragleave',function(){rowEl.classList.remove('tl-drop-over');});\n"
"  rowEl.addEventListener('drop',function(e){\n"
"    e.preventDefault();rowEl.classList.remove('tl-drop-over');\n"
"    var drag=_mpDragData;\n"
"    if(!drag){try{var raw=e.dataTransfer.getData('text/plain');if(raw)drag=JSON.parse(raw);}catch(ex){}}\n"
"    if(!drag)return;\n"
"    var sc2=document.getElementById('tl-scroll');\n"
"    var rx=e.clientX-sc2.getBoundingClientRect().left+sc2.scrollLeft;\n"
"    var dropTime=rx/pxPerSec;\n"
"    handleTimelineDrop(drag,rowType,dropTime);\n"
"  });\n"
"}\n"
"\n"
"// Attach to the empty area below all tracks for new track creation\n"
"function attachDropToNewTrack(){\n"
"  var zone=document.getElementById('tl-newtrack-zone');if(!zone)return;\n"
"  if(zone._wired)return;zone._wired=true;\n"
"  // Show zone only while user is dragging a media item\n"
"  document.addEventListener('dragstart',function(e){\n"
"    if(!e.dataTransfer||!e.dataTransfer.types)return;\n"
"    var hasText=e.dataTransfer.types.includes?e.dataTransfer.types.includes('text/plain'):Array.from(e.dataTransfer.types).indexOf('text/plain')>=0;\n"
"    if(hasText){zone.style.display='flex';}\n"
"  });\n"
"  document.addEventListener('dragend',function(){zone.style.display='none';});\n"
"  zone.addEventListener('dragover',function(e){\n"
"    var hasData=_mpDragData||(e.dataTransfer.types&&(e.dataTransfer.types.includes?e.dataTransfer.types.includes('text/plain'):Array.from(e.dataTransfer.types).indexOf('text/plain')>=0));\n"
"    if(!hasData)return;\n"
"    e.preventDefault();zone.style.borderColor='var(--c1)';\n"
"    zone.querySelector('span').textContent='+ Soltar para nueva pista';\n"
"  });\n"
"  zone.addEventListener('dragleave',function(){\n"
"    zone.style.borderColor='';\n"
"    var sp=zone.querySelector('span');if(sp)sp.textContent='+ Soltar aquí para nueva pista';\n"
"  });\n"
"  zone.addEventListener('drop',function(e){\n"
"    e.preventDefault();zone.style.borderColor='';zone.style.display='none';\n"
"    var drag=_mpDragData;\n"
"    if(!drag){try{var raw=e.dataTransfer.getData('text/plain');if(raw)drag=JSON.parse(raw);}catch(ex){}}\n"
"    if(!drag)return;\n"
"    var sc2=document.getElementById('tl-scroll');\n"
"    var rx=e.clientX-sc2.getBoundingClientRect().left+sc2.scrollLeft;\n"
"    var dropTime=rx/pxPerSec;\n"
"    handleNewTrackDrop(drag,dropTime);\n"
"  });\n"
"}\n"
"\n"
"// Check collision: does [ns, ne] overlap any existing block in the same row?\n"
"// blocks: array of {start, end}\n"
"function hasCollision(blocks,ns,ne){\n"
"  for(var i=0;i<blocks.length;i++){\n"
"    if(ns<blocks[i].end&&ne>blocks[i].start)return true;\n"
"  }\n"
"  return false;\n"
"}\n"
"\n"
"function handleTimelineDrop(drag,rowType,dropTime){\n"
"  if(rowType==='video'){\n"
"    // Drop image/video onto video row --> find scene at that time and replace its src\n"
"    if(drag.type!=='image'&&drag.type!=='video'&&drag.type!=='ref')return;\n"
"    var targetSeg=null;\n"
"    for(var i=0;i<segs.length;i++){\n"
"      if(dropTime>=segs[i].start&&dropTime<segs[i].end){targetSeg=segs[i];break;}\n"
"    }\n"
"    if(!targetSeg){targetSeg=segs[segs.length-1];}\n"
"    if(targetSeg){\n"
"      targetSeg.src=drag.src;\n"
"      if(drag.type==='image'&&drag.idx!=null)targetSeg.imgIdx=drag.idx;\n"
"      getImg(drag.src);\n"
"      buildTimeline();drawFrame();\n"
"    }\n"
"  } else if(rowType==='img'){\n"
"    if(drag.type!=='image'&&drag.type!=='ref')return;\n"
"    var dropDur=5;\n"
"    for(var j=0;j<segs.length;j++){if(dropTime>=segs[j].start&&dropTime<segs[j].end){dropDur=segs[j].dur;break;}}\n"
"    // Auto-assign lane: new lane if collision\n"
"    var newLane=assignImgLane(dropTime,dropTime+dropDur);\n"
"    var newItem={id:'iti_'+(++_imgItemIdC),src:drag.src,\n"
"      name:drag.name||'img',start:dropTime,dur:dropDur,lane:newLane,segIdx:null};\n"
"    imgTrackItems.push(newItem);\n"
"    buildTimeline();drawFrame();\n"
"  } else if(rowType==='ov'){\n"
"    // Drop image onto text/overlay row --> add text overlay at that time\n"
"    // (skip — text overlays are canvas-based not image-based)\n"
"  } else if(rowType==='audio'){\n"
"    // Drop audio --> add new audio track at dropTime\n"
"    if(drag.type!=='audio')return;\n"
"    addAudioAtTime(drag.src,drag.name,dropTime);\n"
"  }\n"
"}\n"
"\n"
"function handleNewTrackDrop(drag,dropTime){\n"
"  if(drag.type==='audio'){\n"
"    addAudioAtTime(drag.src,drag.name,dropTime);\n"
"  } else if(drag.type==='image'||drag.type==='ref'){\n"
"    var dropDur=5;\n"
"    for(var k=0;k<segs.length;k++){if(dropTime>=segs[k].start&&dropTime<segs[k].end){dropDur=segs[k].dur;break;}}\n"
"    var newLane2=assignImgLane(dropTime,dropTime+dropDur);\n"
"    imgTrackItems.push({id:'iti_'+(++_imgItemIdC),src:drag.src,\n"
"      name:drag.name||'img',start:dropTime,dur:dropDur,lane:newLane2,segIdx:null});\n"
"    buildTimeline();drawFrame();\n"
"  }\n"
"}\n"
"\n"
"function addAudioAtTime(src,name,t){\n"
"  var id='aud_'+(Date.now());\n"
"  var tr={id:id,src:src,name:name,start:t,duration:5,trimStart:0,trimEnd:0,vol:0.8,fadeIn:0,fadeOut:0};\n"
"  // Try to get actual duration\n"
"  var tmp=new Audio(src);\n"
"  tmp.addEventListener('loadedmetadata',function(){\n"
"    tr.duration=tmp.duration||5;\n"
"    buildTimeline();\n"
"  });\n"
"  audioTracks.push(tr);\n"
"  buildTimeline();\n"
"}\n"
"\n"
"// Y-scroll sync: labels follow tl-scroll vertical scroll\n"
"document.getElementById('tl-scroll').addEventListener('scroll',function(){\n"
"  var ls=document.getElementById('tl-labels-scroll');\n"
"  if(ls)ls.scrollTop=this.scrollTop;\n"
"});\n"
"\n"
"// Transcription\n"
"async function runTranscription(){\n"
"  var btn=document.getElementById('btn-transcribe');\n"
"  btn.disabled=true;btn.textContent='Transcribiendo…';\n"
"  try{\n"
"    var r=await fetch('/api/editor/transcribir/'+encodeURIComponent(PROJECT));\n"
"    var d=await r.json();\n"
"    if(!r.ok)throw new Error(d.error||'Error');\n"
"    var tsegs=d.segments||[];\n"
"    if(!tsegs.length)throw new Error('No se obtuvieron segmentos');\n"
"    var oldSegs=segs.slice();\n"
"    segs=tsegs.map(function(s,i){\n"
"      var imgIdx=oldSegs[i]?oldSegs[i].imgIdx:Math.min(i,images.length-1);\n"
"      var oldOvs=oldSegs[i]?oldSegs[i].overlays:[];\n"
"      // Keep existing overlays; update the auto text overlay text if it exists\n"
"      var oldEsc=oldSegs[i]?oldSegs[i].escena:null;\n"
"      // Rebuild overlays with new Whisper text but preserving plan_edicion tipo\n"
"      var newEsc=oldEsc?Object.assign({},oldEsc,{texto:s.text}):null;\n"
"      var newOvs=buildOverlaysFromEscena(newEsc,i);\n"
"      // Merge any manually added overlays (not auto-generated)\n"
"      var manualOvs=(oldOvs||[]).filter(function(o){return o.id&&!o.id.match(/^(sub_|enf_|lt_|tit_|cap_|nom_|nom2_|qt_|sp1_|sp2_|int_|gq_|ov_|auto_)/);});\n"
"      newOvs=newOvs.concat(manualOvs);\n"
"      return{src:images[imgIdx]||null,imgIdx:imgIdx,imgScale:100,imgPanX:50,imgPanY:50,\n"
"        title:'Segmento '+(i+1),text:s.text,tipo:oldSegs[i]?oldSegs[i].tipo:'normal',\n"
"        escena:newEsc,start:s.start,end:s.end,dur:s.end-s.start,\n"
"        overlays:newOvs,transition:'none',transDur:0.5};\n"
"    });\n"
"    buildTimeline();buildTranscriptList();\n"
"    if(segs.length)selSeg(0);\n"
"    buildMediaPanel();\n"
"    btn.textContent='&#127908; Re-transcribir';\n"
"  }catch(e){\n"
"    alert('Error: '+e.message);\n"
"    btn.textContent='&#127908; Transcribir audio';\n"
"  }\n"
"  btn.disabled=false;\n"
"}\n"
"\n"
"function buildTranscriptList(){\n"
"  var list=document.getElementById('transcript-list');list.innerHTML='';\n"
"  segs.forEach(function(s,i){\n"
"    var div=document.createElement('div');\n"
"    div.className='tr-seg'+(i===curSeg?' active':'');\n"
"    div.dataset.idx=i;\n"
"    div.innerHTML='<span class=\"tr-time\">'+fmt(s.start)+'</span><span class=\"tr-text\">'+s.text+'</span>';\n"
"    div.addEventListener('click',function(){stopPlay();selSeg(parseInt(this.dataset.idx));});\n"
"    list.appendChild(div);\n"
"  });\n"
"}\n"
"\n"
"// Keyboard\n"
"document.addEventListener('keydown',function(e){\n"
"  if(e.target.tagName==='INPUT'||e.target.tagName==='TEXTAREA'||e.target.tagName==='SELECT')return;\n"
"  if(e.code==='Space'){e.preventDefault();togglePlay();}\n"
"  if(e.code==='KeyV')setTool('select');\n"
"  if(e.code==='KeyT'){setTool('text');switchTab('text');}\n"
"  if(e.code==='ArrowRight'&&!isPlaying){selSeg(Math.min(segs.length-1,curSeg+1));}\n"
"  if(e.code==='ArrowLeft'&&!isPlaying){selSeg(Math.max(0,curSeg-1));}\n"
"  if((e.code==='Delete'||e.code==='Backspace')&&selOvId){e.preventDefault();deleteOv();}\n"
"});\n"
"\n"
"// Build canvas overlays from plan_edicion escena metadata\n"
"// NOTE: narration text (esc.texto) is NOT shown on screen — only visual overlays\n"
"function buildOverlaysFromEscena(esc,i){\n"
"  var ovs=[];\n"
"  if(!esc)return ovs;\n"
"  var tipo=esc.tipo||'normal';\n"
"  var rawAccent=esc.color_accent||'00cfff';\n"
"  var accent='#'+rawAccent.replace(/^#/,'');\n"
"  var ovTxt=esc.texto_overlay||null;\n"
"  var txt2=esc.texto_secundario||null;\n"
"  var refLbl=esc.ref_label||null;\n"
"\n"
"  if(tipo==='texto_enfasis'&&ovTxt){\n"
