@app.route("/api/editor/transcribir/<proj_name>")
def editor_transcribir(proj_name):
    """Transcribes with WhisperX and uses asignar_timestamps() — SAME algorithm as the render pipeline.
    Produces contiguous per-scene timestamps and saves to timestamps_escenas.json.
    """
    from pathlib import Path as _P
    import re as _re, json as _json

    proj_name = _re.sub(r"[^\w\-]", "_", proj_name.strip())
    if not proj_name:
        return jsonify({"error": "proyecto requerido"}), 400

    proj_dir = _P(JOBS_FOLDER) / proj_name
    if not proj_dir.exists():
        return jsonify({"error": "proyecto no encontrado"}), 404

    # ── Check for a VALID cached timestamps_escenas.json ─────────────────────
    # (good = contiguous, avg duration >= 2s — not the raw 1:1 whisper mapping)
    for _tsp in [proj_dir/"editor"/"timestamps_escenas.json",
                 proj_dir/"timestamps_escenas.json",
                 proj_dir/"guion"/"timestamps_escenas.json"]:
        if _tsp.exists():
            try:
                _ts_raw = _json.loads(_tsp.read_text("utf-8"))
                if _ts_raw:
                    _avg = sum(t.get("duracion", 0) for t in _ts_raw) / len(_ts_raw)
                    _gaps = sum(1 for i in range(1, len(_ts_raw))
                                if _ts_raw[i].get("inicio", 0) - _ts_raw[i-1].get("fin", 0) > 0.4)
                    if _avg >= 2.0 and _gaps / max(1, len(_ts_raw) - 1) < 0.15:
                        print(f"[editor_transcribir] Cache OK: n={len(_ts_raw)} avg={_avg:.2f}s gaps={_gaps}")
                        _segs_out = [{"start": float(t.get("inicio", 0)),
                                      "end":   float(t.get("fin", 0)),
                                      "text":  t.get("texto", ""),
                                      "seg_idx": t.get("escena", 1) - 1}
                                     for t in _ts_raw]
                        resp = jsonify({"segments": _segs_out, "total": len(_segs_out), "source": "cache"})
                        resp.headers["Access-Control-Allow-Origin"] = "*"
                        return resp
                    else:
                        print(f"[editor_transcribir] Cache BAD avg={_avg:.2f}s gaps={_gaps} — eliminando y re-transcribiendo")
                        try: _tsp.unlink()
                        except Exception: pass
            except Exception:
                pass

    # ── Find audio ────────────────────────────────────────────────────────────
    audio_path = None
    for _af in sorted((proj_dir / "audio").iterdir()) if (proj_dir / "audio").exists() else []:
        if _af.suffix.lower() in {".mp3", ".wav", ".m4a", ".aac", ".ogg"}:
            audio_path = str(_af)
            break
    if not audio_path:
        return jsonify({"error": "no se encontró audio en el proyecto"}), 404

    # ── Read guion lines (same files the render pipeline uses) ───────────────
    guion_lines = []
    for _gp in [proj_dir/"guion"/"guion_fragmentado.txt",
                proj_dir/"guion"/"guion_render.txt",
                proj_dir/"guion"/"guion.txt",
                proj_dir/"guion.txt"]:
        if _gp.exists():
            try:
                guion_lines = [l.strip() for l in _gp.read_text("utf-8").splitlines() if l.strip()]
                print(f"[editor_transcribir] Guion: {len(guion_lines)} líneas desde {_gp.name}")
            except Exception:
                pass
            if guion_lines:
                break

    if not guion_lines:
        return jsonify({"error": "No se encontró guion en el proyecto"}), 404

    # ── Get audio duration ────────────────────────────────────────────────────
    try:
        duracion_total = _vf_ffprobe_duration(audio_path) or 0.0
    except Exception:
        duracion_total = 0.0
    if duracion_total <= 0:
        # fallback: estimate from guion word count
        duracion_total = sum(max(1.5, len(l.split()) / 2.5) for l in guion_lines)
    print(f"[editor_transcribir] Audio duration: {duracion_total:.2f}s")

    # ── Transcribe ────────────────────────────────────────────────────────────
    try:
        segmentos_raw = []
        all_words = []
        source = "unknown"

        # 1. WhisperX via Replicate (word-level, best quality)
        try:
            segmentos_raw, all_words = _transcribir_whisperx_runpod(audio_path, language=None)
            source = "whisperx_replicate"
            print(f"[editor_transcribir] WhisperX OK --> {len(segmentos_raw)} segs, {len(all_words)} words")
        except Exception as _e1:
            print(f"[editor_transcribir] WhisperX falló ({_e1}), probando faster-whisper…")

            # 2. faster-whisper (local, word-level)
            try:
                from faster_whisper import WhisperModel as _FWM
                _fwm = _FWM("medium", device="cpu", compute_type="int8")
                _segs_iter, _ = _fwm.transcribe(
                    audio_path, language=None, word_timestamps=True,
                    beam_size=1, vad_filter=True)
                for _s in _segs_iter:
                    _wds = [{"word": w.word, "start": w.start, "end": w.end}
                            for w in (_s.words or [])]
                    segmentos_raw.append({"start": _s.start, "end": _s.end,
                                          "text": _s.text.strip(), "words": _wds})
                    all_words.extend(_wds)
                source = "faster_whisper"
                print(f"[editor_transcribir] faster-whisper OK --> {len(segmentos_raw)} segs")
            except ImportError:

                # 3. openai-whisper (local, word-level)
                try:
                    import whisper as _wh
                    _res = _wh.load_model("medium").transcribe(
                        audio_path, language=None, word_timestamps=True)
                    segmentos_raw = _res.get("segments", [])
                    for _s in segmentos_raw:
                        all_words.extend(_s.get("words", []))
                    source = "openai_whisper"
                    print(f"[editor_transcribir] openai-whisper OK --> {len(segmentos_raw)} segs")
                except ImportError:
                    # No Whisper at all — use guion estimate
                    source = "guion_estimate"
                    print("[editor_transcribir] Sin Whisper — estimación por guión")

        # ── Assign timestamps using the SAME algorithm as the render pipeline ─
        if source == "guion_estimate" or not segmentos_raw:
            timestamps = _proporcional(guion_lines, duracion_total)
        elif all_words:
            # Try word-level first
            timestamps = asignar_timestamps_words(guion_lines, all_words, duracion_total)
            _unmatched = sum(1 for t in timestamps if t.get("score", 0) == 0)
            _last_ok   = max((t["fin"] for t in timestamps if t.get("score", 0) > 0), default=0.0)
            if (_unmatched / max(1, len(timestamps)) > 0.40
                    and _last_ok > duracion_total * 0.85):
                print(f"[editor_transcribir] Word-level anómalo ({_unmatched}/{len(timestamps)} sin match) --> segment-level fallback")
                timestamps = asignar_timestamps(guion_lines, segmentos_raw, duracion_total)
            else:
                print(f"[editor_transcribir] Word-level OK ({len(timestamps) - _unmatched}/{len(timestamps)} matched)")
        else:
            timestamps = asignar_timestamps(guion_lines, segmentos_raw, duracion_total)

        print(f"[editor_transcribir] ✓ {len(timestamps)} timestamps ({source})")
        for _i, _t in enumerate(timestamps[:5]):
            print(f"  E{_i+1:02d}: {_t['inicio']:.2f}s --> {_t['fin']:.2f}s ({_t['duracion']:.2f}s) score={_t.get('score',0):.2f}")

        # ── Build final records ────────────────────────────────────────────────
        ts_records = []
        for _i, _t in enumerate(timestamps):
            ts_records.append({
                "escena":    _i + 1,
                "seg_idx":   _i,
                "texto":     guion_lines[_i] if _i < len(guion_lines) else "",
                "inicio":    _t["inicio"],
                "fin":       _t["fin"],
                "duracion":  _t["duracion"],
                "score":     _t.get("score", 1.0),
                "source":    source,
            })

        # ── Save to timestamps_escenas.json ───────────────────────────────────
        _ts_save = proj_dir / "timestamps_escenas.json"
        _ts_save.write_text(_json.dumps(ts_records, ensure_ascii=False, indent=2), "utf-8")
        print(f"[editor_transcribir] Guardado: {_ts_save} ({len(ts_records)} escenas)")

        # ── Return in segments format the editor JS expects ───────────────────
        segs_out = [{"start": t["inicio"], "end": t["fin"],
                     "text": t["texto"], "seg_idx": _i}
                    for _i, t in enumerate(ts_records)]
        result = {"segments": segs_out, "total": len(segs_out), "source": source}
        resp = jsonify(result)
        resp.headers["Access-Control-Allow-Origin"] = "*"
        return resp

    except Exception as e:
        import traceback
        traceback.print_exc()
        return jsonify({"error": str(e)}), 500




@app.route("/api/editor/renderizar", methods=["POST", "OPTIONS"])
def editor_renderizar():
    """El editor llama aquí para disparar el render final en el launcher."""
    if request.method == "OPTIONS":
        resp = Response("", 204)
        resp.headers["Access-Control-Allow-Origin"] = "*"
        resp.headers["Access-Control-Allow-Methods"] = "POST, OPTIONS"
        resp.headers["Access-Control-Allow-Headers"] = "Content-Type"
        return resp

    data = request.get_json(force=True, silent=True) or {}
    proj_name = re.sub(r"[^\w\-]", "_", (data.get("project") or "").strip())
    if not proj_name:
        return jsonify({"error": "proyecto requerido"}), 400

    guion      = data.get("guion", "")
    resolucion = data.get("resolucion", "1920x1080")
    transicion = data.get("transicion", "xfade")
    trans_dur  = float(data.get("trans_dur", 0.6))
    movimiento = data.get("movimiento", "none")
    modelo     = data.get("modelo", "base")
    render_mode = data.get("render_mode", "smart")

    from pathlib import Path as _P
    proj_dir  = _P(JOBS_FOLDER) / proj_name
    audio_dir = proj_dir / "audio"
    img_dir   = proj_dir / "imagen"
    vid_dir   = proj_dir / "video"
    out_dir   = proj_dir / "video_final"
    out_dir.mkdir(parents=True, exist_ok=True)

    # Audio
    audios = list(audio_dir.glob("*")) if audio_dir.exists() else []
    audios = [a for a in audios if a.suffix.lower() in {".mp3",".wav",".m4a",".aac",".ogg"}]
    if not audios:
        return jsonify({"error": "Sin audio en el proyecto"}), 400
    audio_path = str(audios[0])

    # Imágenes
    def _ord2(p):
        m = re.match(r"^(?:img|flow)_(\d+)$", p.stem, flags=re.I)
        return (0, int(m.group(1))) if m else (1, p.stat().st_mtime)
    images = []
    if img_dir.exists():
        images = sorted(
            [f for f in img_dir.iterdir() if f.suffix.lower().lstrip(".") in {"jpg","jpeg","png","webp"}],
            key=_ord2,
        )
    videos = sorted(vid_dir.glob("*.mp4"), key=_ord2) if vid_dir.exists() else []
    if not images and not videos:
        return jsonify({"error": "Sin imágenes ni videos en el proyecto"}), 400
    vid_index = {v.stem: v for v in videos}

    guion_path = None
    if guion:
        guion_path = str(proj_dir / "guion" / "guion_editor.txt")
        import os as _os2
        _os2.makedirs(str(proj_dir / "guion"), exist_ok=True)
        open(guion_path, "w", encoding="utf-8").write(guion)

    job_id = str(uuid.uuid4())[:8]
    jobs[job_id] = {
        "id": job_id, "estado": "procesando", "progreso": 0,
        "mensaje": "Iniciando render desde editor...", "logs": [],
        "video_url": None, "inicio": time.time(), "tipo": "render",
        "proyecto": proj_name,
    }

    threading.Thread(
        target=procesar_render_inteligente,
        args=(job_id, images, vid_index, audio_path, guion,
              resolucion, modelo, transicion, trans_dur, movimiento,
              False, render_mode, str(out_dir), "whisperx", guion_path, None),
        daemon=True,
    ).start()

    resp = jsonify({"job_id": job_id})
    resp.headers["Access-Control-Allow-Origin"] = "*"
    return resp


@app.route("/api/editor/estado/<job_id>")
def editor_estado(job_id):
    """Polling de estado para el editor."""
    if job_id not in jobs:
        return jsonify({"error": "no encontrado"}), 404
    resp = jsonify(jobs[job_id])
    resp.headers["Access-Control-Allow-Origin"] = "*"
    return resp


