# DOCUMENTACIÓN — vf_docs
# ══════════════════════════════════════════════════════════════════
import re as _re_docs

def _docs_conn():
    from auth_module import _get_db_connection as _gdbc
    return _gdbc()

def _docs_init_table():
    try:
        conn = _docs_conn()
        with conn.cursor() as cur:
            cur.execute("""
                CREATE TABLE IF NOT EXISTS vf_docs (
                    id            INT AUTO_INCREMENT PRIMARY KEY,
                    type          ENUM('video','text') NOT NULL DEFAULT 'video',
                    category      VARCHAR(100) NOT NULL DEFAULT 'General',
                    title         VARCHAR(255) NOT NULL DEFAULT '',
                    description   TEXT,
                    url           VARCHAR(1000) DEFAULT '',
                    content       LONGTEXT,
                    thumbnail_url VARCHAR(500)  DEFAULT '',
                    duration_label VARCHAR(20)  DEFAULT '',
                    tags          VARCHAR(500)  DEFAULT '',
                    sort_order    INT           DEFAULT 0,
                    is_published  TINYINT(1)    DEFAULT 1,
                    created_at    TIMESTAMP     DEFAULT CURRENT_TIMESTAMP,
                    updated_at    TIMESTAMP     DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
                    created_by    VARCHAR(100)  DEFAULT ''
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS vf_help_reports (
                    id          INT AUTO_INCREMENT PRIMARY KEY,
                    username    VARCHAR(255),
                    email       VARCHAR(255),
                    type        VARCHAR(50),
                    category    VARCHAR(100),
                    title       VARCHAR(500),
                    description TEXT,
                    status      VARCHAR(50) DEFAULT 'pending',
                    priority    VARCHAR(20) DEFAULT 'normal',
                    admin_notes TEXT,
                    created_at  DATETIME DEFAULT CURRENT_TIMESTAMP,
                    updated_at  DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
                    INDEX idx_type (type), INDEX idx_status (status),
                    INDEX idx_user (username), INDEX idx_created (created_at)
                ) ENGINE=InnoDB CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci
            """)
        conn.commit()
        conn.close()
        print("[DOCS] Tablas vf_docs / vf_help_reports OK")
    except Exception as _de:
        print(f"[DOCS] init error: {_de}")

try:
    _docs_init_table()
except Exception:
    pass

def _docs_yt_embed(url):
    m = _re_docs.search(r'(?:v=|youtu\.be/|embed/)([A-Za-z0-9_-]{11})', url or '')
    if m:
        return f'https://www.youtube.com/embed/{m.group(1)}?rel=0&modestbranding=1'
    return url or ''

def _docs_is_admin(username):
    try:
        u = _get_user_full(username)
        return bool(u and u.get('role') == 'admin')
    except Exception:
        return False

@app.route("/api/docs", methods=["GET"])
def api_docs_public():
    try:
        conn = _docs_conn()
        with conn.cursor() as cur:
            cur.execute(
                "SELECT id,type,category,title,description,url,content,"
                "thumbnail_url,duration_label,tags,sort_order "
                "FROM vf_docs WHERE is_published=1 ORDER BY category,sort_order,id"
            )
            rows = cur.fetchall()
        conn.close()
    except Exception as e:
        return jsonify({"error": str(e)}), 500
    cats = {}
    for r in rows:
        d = {"id":r[0],"type":r[1],"category":r[2],"title":r[3],"description":r[4],
             "url":r[5],"content":r[6],"thumbnail_url":r[7],"duration_label":r[8],
             "tags":r[9],"sort_order":r[10]}
        cats.setdefault(d["category"] or "General", []).append(d)
    return jsonify({"categories": dict(sorted(cats.items()))})

@app.route("/api/help", methods=["POST"])
def api_help_submit():
    u = _current_username()
    try:
        data = request.get_json(force=True) or {}
    except Exception:
        data = {}
    report_type = (data.get("type") or "")[:50]
    category    = (data.get("category") or "")[:100]
    title       = (data.get("title") or "")[:500]
    description = (data.get("description") or "")[:5000]
    email_client= (data.get("email") or "")[:255]
    if not title:
        return jsonify({"ok": False, "error": "title required"}), 400
    user_email = email_client
    try:
        conn = _docs_conn()
        with conn.cursor() as cur:
            if not user_email and u:
                cur.execute("SELECT user_mail FROM vf_users WHERE username=%s LIMIT 1", (u,))
                row = cur.fetchone()
                if row:
                    user_email = row[0] or ""
            cur.execute(
                "INSERT INTO vf_help_reports "
                "(username, email, type, category, title, description) "
                "VALUES (%s, %s, %s, %s, %s, %s)",
                (u or "anonymous", user_email, report_type, category, title, description)
            )
            conn.commit()
        conn.close()
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500
    return jsonify({"ok": True})

# ─── Idea --> Video: generador de guión ──────────────────────────────────────
def _xi2v_template(idea, dur_sec, style, tone, audience):
    n_scenes  = max(4, min(40, round(dur_sec / 7)))
    dur_label = f"{dur_sec//60}m{dur_sec%60:02d}s" if dur_sec >= 60 else f"{dur_sec}s"

    STYLES = {
        "cinematic"  : [
            ("Gran angular, luz dramática de amanecer", "Orquesta épica, arranca en el primer frame"),
            ("Primer plano, bokeh profundo, cámara lenta", "Tema orquestal tenso"),
            ("Travelling lateral fluido", "Cuerdas en crescendo"),
            ("Plano cenital, perspectiva aérea", "Climax instrumental"),
        ],
        "tutorial"   : [
            ("Pantalla con UI, anotaciones visuales animadas", "Música ligera, discreta"),
            ("Demostración paso a paso, zoom en detalles", "Ambiente neutro, clean"),
            ("Comparativa side-by-side", "Transición suave"),
            ("Infografía animada", "Tono claro e informativo"),
        ],
        "documental" : [
            ("Plano medio, entrevista, iluminación natural", "Narración sobria en off"),
            ("Archivo histórico / material de época", "Sonido ambiente auténtico"),
            ("Exterior, cámara en mano", "Sonido directo, sin música"),
            ("Datos y gráficos animados", "Fondo documental, discreto"),
        ],
        "viral"      : [
            ("Corte rápido, ángulo dinámico", "Beat electrónico, crescendo"),
            ("Split screen, ritmo acelerado", "Drop de impacto"),
            ("POV cámara, inmersivo", "Efecto sonoro de golpe"),
            ("Texto animado sobre imagen", "Beat viral trending"),
        ],
        "corporativo": [
            ("Oficina moderna, equipo colaborando", "Música corporativa positiva"),
            ("Presentación limpia, minimalista", "Fondo profesional"),
            ("Reunión de equipo, diversidad", "Motivador corporativo"),
            ("Producto en uso, contexto real", "Música positiva de fondo"),
        ],
    }

    TONE_DATA = {
        "inspirador" : {
            "hook"   : f"Hay momentos que lo cambian todo. Este es uno de ellos.",
            "bridge" : f"Lo que viene a continuación no es teoría. Es la realidad.",
            "climax" : f"Juntos, lo imposible se vuelve posible.",
            "cta"    : f"Comparte. Inspira. Transforma.",
        },
        "profesional": {
            "hook"   : f"Los datos son contundentes. El análisis no deja lugar a dudas.",
            "bridge" : f"La evidencia respalda una sola conclusión.",
            "climax" : f"La eficiencia y el conocimiento son la ventaja decisiva.",
            "cta"    : f"Actúa con información. Decide con claridad.",
        },
        "casual"     : {
            "hook"   : f"¿Y si te dijera que hay algo que la mayoría no sabe sobre esto?",
            "bridge" : f"Seré directo contigo, sin rodeos.",
            "climax" : f"Es más simple de lo que parece. Solo hay que verlo.",
            "cta"    : f"Dale like si esto te hizo pensar. Comenta qué opinas.",
        },
        "tecnico"    : {
            "hook"   : f"El sistema opera bajo parámetros específicos. Vamos a analizarlos.",
            "bridge" : f"Cada variable tiene un impacto medible en el resultado.",
            "climax" : f"Los patrones revelan una dirección inequívoca.",
            "cta"    : f"Implementa. Mide. Itera.",
        },
        "urgente"    : {
            "hook"   : f"No hay tiempo que perder. Cada segundo de inacción tiene un costo.",
            "bridge" : f"La ventana de oportunidad no estará abierta para siempre.",
            "climax" : f"El que actúa hoy define las reglas del mañana.",
            "cta"    : f"Actúa ahora. No mañana. Ahora.",
        },
    }

    sv_list = STYLES.get(style, STYLES["cinematic"])
    td      = TONE_DATA.get(tone, TONE_DATA["inspirador"])
    topic   = idea.strip()
    title   = topic[:60] + ("..." if len(topic) > 60 else "")

    def sv(i):
        return sv_list[i % len(sv_list)]

    ANGLES = [
        ("CONTEXTO",
         f"Para entender {topic}, hay que ver el panorama completo.\n"
         f"No basta con la superficie: cada capa que se descubre\n"
         f"revela dimensiones que cambian por completo la perspectiva."),
        ("PROFUNDIDAD",
         f"¿Qué hay realmente detrás de {topic}?\n"
         f"Los detalles que la mayoría pasa por alto\n"
         f"son precisamente los que marcan la diferencia definitiva."),
        ("IMPACTO REAL",
         f"{topic} tiene consecuencias concretas, no abstractas.\n"
         f"No en un futuro lejano: ahora mismo, hoy.\n"
         f"Quienes lo entienden ya llevan una ventaja decisiva."),
        ("PERSPECTIVA",
         f"Visto desde otro ángulo, {topic} revela patrones\n"
         f"que no son evidentes a primera vista.\n"
         f"La información más valiosa raramente está en la superficie."),
        ("LO QUE NADIE DICE",
         f"Hay aspectos de {topic} que pocas veces se mencionan.\n"
         f"No porque no sean importantes,\n"
         f"sino porque requieren un nivel más profundo de análisis."),
        ("MOMENTO ACTUAL",
         f"{topic} es más relevante hoy que en cualquier otro momento.\n"
         f"Las circunstancias actuales crean una convergencia única.\n"
         f"Este tipo de alineación no se repite con frecuencia."),
        ("EL FACTOR DECISIVO",
         f"De todos los elementos que rodean a {topic},\n"
         f"hay uno que lo determina todo.\n"
         f"Identificarlo es la diferencia entre el acierto y el error."),
        ("EVIDENCIA",
         f"Los hechos sobre {topic} son elocuentes.\n"
         f"No se trata de opiniones ni interpretaciones subjetivas.\n"
         f"Las tendencias apuntan de forma inequívoca en una dirección."),
    ]

    sections = []
    visual0, audio0 = sv(0)

    # Scene 1 – Hook
    sections.append(
        f"[ESCENA 1 — GANCHO | ~7 seg]\n"
        f"[Visual: {visual0}. Impacto inmediato, sin texto en pantalla.]\n"
        f"[Audio: {audio0}]\n\n"
        f"{td['hook']}\n"
        f"{topic}.\n"
        f"Esto es lo que necesitas saber."
    )

    # Middle scenes
    dev_n = n_scenes - 3
    for i in range(dev_n):
        sc = i + 2
        angle_name, angle_body = ANGLES[i % len(ANGLES)]
        visual_i, audio_i = sv(i + 1)
        sections.append(
            f"[ESCENA {sc} — {angle_name} | ~7 seg]\n"
            f"[Visual: {visual_i}. Mantiene tensión, ritmo sostenido.]\n"
            f"[Audio: {audio_i}]\n\n"
            f"{angle_body}"
        )

    # Climax
    cl = n_scenes - 1
    visual_cl, audio_cl = sv(cl)
    sections.append(
        f"[ESCENA {cl} — PUNTO DE INFLEXIÓN | ~10 seg]\n"
        f"[Visual: {visual_cl}. Máxima intensidad. El momento más memorable.]\n"
        f"[Audio: Pico musical. Clímax emocional.]\n\n"
        f"{td['bridge']}\n"
        f"{topic} define un antes y un después.\n"
        f"Las decisiones de hoy construyen el mañana.\n"
        f"{td['climax']}"
    )

    # CTA
    sections.append(
        f"[ESCENA {n_scenes} — CIERRE Y LLAMADA A LA ACCIÓN | ~8 seg]\n"
        f"[Visual: Logo y tagline. Fade out elegante.]\n"
        f"[Audio: Resolución musical. Remate definitivo.]\n\n"
        f"El momento es ahora. No mañana.\n"
        f"{td['cta']}\n\n"
        f"[{title}]"
    )

    script = "\n\n".join(sections)
    return {
        "title"  : title,
        "script" : script,
        "scenes" : n_scenes,
        "words"  : len(script.split()),
        "dur"    : dur_label,
    }


def _xi2v_call_claude(idea, dur_sec, style, tone, audience, api_key):
    try:
        import urllib.request, json as _json2, ssl
        n_sc = max(4, round(dur_sec / 7))
        dur_s = f"{dur_sec//60}:{dur_sec%60:02d}" if dur_sec >= 60 else f"{dur_sec}s"
        prompt = (
            f"Genera un guión profesional para video de {dur_s} en español.\n"
            f"IDEA: {idea}\nESTILO: {style}\nTONO: {tone}\nAUDIENCIA: {audience}\n"
            f"ESCENAS: ~{n_sc}\n\n"
            f"Usa este formato para cada escena:\n"
            f"[ESCENA N - NOMBRE | ~X seg]\n"
            f"[Visual: descripcion]\n[Audio: indicacion]\n\nNarracion aqui...\n\n"
            f"Incluye: gancho impactante, desarrollo, climax, CTA al cierre. "
            f"Solo el guion, sin explicaciones."
        )
        payload = _json2.dumps({
            "model": "claude-haiku-4-5-20251001",
            "max_tokens": 4096,
            "messages": [{"role": "user", "content": prompt}]
        }).encode()
        ctx = ssl.create_default_context()
        req = urllib.request.Request(
            "https://api.anthropic.com/v1/messages",
            data=payload,
            headers={
                "Content-Type": "application/json",
                "x-api-key": api_key,
                "anthropic-version": "2023-06-01",
            },
            method="POST"
        )
        with urllib.request.urlopen(req, context=ctx, timeout=30) as resp:
            rdata = _json2.loads(resp.read().decode())
        script = rdata["content"][0]["text"].strip()
        n_found = max(1, script.count("[ESCENA"))
        return {
            "title"  : idea[:60].rstrip(),
            "script" : script,
            "scenes" : n_found,
            "words"  : len(script.split()),
            "dur"    : dur_s,
        }
    except Exception:
        return None


@app.route("/api/idea2video/script", methods=["POST"])
def api_idea2video_script():
    try:
        data = request.get_json(force=True) or {}
    except Exception:
        data = {}
    idea     = (data.get("idea") or "").strip()[:3000]
    dur_sec  = max(15, min(1200, int(data.get("dur") or 60)))
    style    = (data.get("style")    or "cinematic").strip()
    tone     = (data.get("tone")     or "inspirador").strip()
    audience = (data.get("audience") or "general").strip()
    if not idea:
        return jsonify({"ok": False, "error": "idea requerida"}), 400
    import os as _osi
    api_key = _osi.environ.get("ANTHROPIC_API_KEY") or _osi.environ.get("CLAUDE_API_KEY")
    if api_key:
        result = _xi2v_call_claude(idea, dur_sec, style, tone, audience, api_key)
        if result:
            return jsonify({"ok": True, **result})
    result = _xi2v_template(idea, dur_sec, style, tone, audience)
    return jsonify({"ok": True, **result})



# ══════════════════════════════════════════════════════════════════
# IDEA --> VIDEO  AUTOPILOT  ─  job engine
# ══════════════════════════════════════════════════════════════════
_i2v_ap_jobs = {}   # job_id --> job dict

def _i2v_parse_scenes_ap(script):
    import re as _re
    parts = _re.split(r'\n\s*\n', script.strip())
    return [p.strip() for p in parts if p.strip() and len(p.strip()) > 15]

def _i2v_extract_prompts_ap(scenes):
    import re as _re
    out = []
    for s in scenes:
        m = _re.search(r'\[Visual:\s*([^\]]{5,})\]', s, _re.I)
        if m:
            out.append(m.group(1).strip())
        else:
            txt = _re.sub(r'\[[^\]]*\]', '', s).strip()
            first = txt.split('.')[0].strip()[:120]
            if len(first) > 10:
                out.append(first)
    return [p for p in out if p][:20]

def _i2v_extract_narration_ap(script):
    import re as _re
    t = _re.sub(r'\[ESCENA[^\]]*\]', '', script, flags=_re.I)
    t = _re.sub(r'\[\w+:[^\]]*\]', '', t)
    t = _re.sub(r'\n{2,}', '\n', t.strip())
    return ' '.join(t.split())[:8000]

def _i2v_ap_scan_images(job, img_dir):
    import glob as _g, os as _o
    patterns = ['*.jpg', '*.jpeg', '*.png', '*.webp']
    imgs = []
    for pat in patterns:
        imgs.extend(_g.glob(_o.path.join(img_dir, pat)))
    imgs = sorted(set(imgs))
    proj = job['project_name']
    urls = [f'/api/idea2video/ap_imagen?project={proj}&file={_o.path.basename(p)}'
            for p in imgs]
    job['images'] = urls

def _i2v_ap_worker(job_id, script, voice_id):
    import time as _t, re as _re, threading as _th
    from pathlib import Path as _P

    job = _i2v_ap_jobs[job_id]
    ref_image = job.get('ref_image')
    _ap_render_mode = job.get('mode', 'rapido')

    def upd(phase, status, detail=''):
        job['phase'] = phase
        job['phases'][phase] = status
        if detail:
            job['current_detail'] = detail
            job['log'].append(detail)

    try:
        # ── 1. Preparar recursos ─────────────────────────────────────
        upd('recursos', 'active', 'Creando estructura del proyecto...')
        proj_name = job['project_name']
        proj_dir  = _P(JOBS_FOLDER) / proj_name
        for sub in ('guion', 'imagenes', 'audio'):
            (proj_dir / sub).mkdir(parents=True, exist_ok=True)
        (proj_dir / 'guion' / 'guion.txt').write_text(script, encoding='utf-8')
        _t.sleep(0.4)
        upd('recursos', 'done', f'Proyecto "{proj_name}" listo')

        # ── 2. Fragmentar guión ──────────────────────────────────────
        upd('fragmentar', 'active', 'Dividiendo guión en escenas...')
        scenes  = _i2v_parse_scenes_ap(script)
        prompts = _i2v_extract_prompts_ap(scenes)
        job['scenes']  = len(scenes)
        job['prompts'] = prompts
        _t.sleep(0.6)
        upd('fragmentar', 'done', f'{len(scenes)} escenas · {len(prompts)} prompts extraídos')

        # ── 3. Generar prompts ───────────────────────────────────────
        upd('prompts', 'active', 'Guardando prompts...')
        _prompts_dir = proj_dir / 'prompts'
        _prompts_dir.mkdir(exist_ok=True)
        (_prompts_dir / 'prompts.txt').write_text(
            '\n'.join(f'{i+1}. {p}' for i, p in enumerate(prompts)), encoding='utf-8')
        _t.sleep(0.6)
        upd('prompts', 'done', f'{len(prompts)} prompts guardados')

        # ── 4. Voz ───────────────────────────────────────────────────
        upd('voz', 'active', 'Iniciando síntesis de voz...')
        narration  = _i2v_extract_narration_ap(script)
        char_count = len(narration)
        job['char_count'] = char_count
        upd('voz', 'active', f'Procesando {char_count} caracteres de narración...')

        voz_ok = False
        if voice_id and narration:
            try:
                _VOZ_N8N       = "https://n8n-n8n.y9c1cn.easypanel.host/webhook/541b2f00-1fbb-443f-8225-25dd5969da01"
                _VOZ_MERGE_N8N = "https://n8n-n8n.y9c1cn.easypanel.host/webhook/merge-audio"
                _MAX_CHARS     = 900

                def _san(t):
                    t = t.replace("\r\n"," ").replace("\n"," ").replace("\r"," ")
                    t = t.replace('"',"'").replace("\\"," ")
                    return " ".join(t.split()).strip()

                def _chnk(txt, mx):
                    parts, s = [], 0
                    while s < len(txt):
                        e = s + mx
                        if e >= len(txt):
                            c = txt[s:].strip()
                            if c: parts.append(c)
                            break
                        cut = -1
                        for i in range(e, s+mx//2, -1):
                            if txt[i] in ".!?": cut=i+1; break
                        if cut == -1:
                            for i in range(e, s+mx//2, -1):
                                if txt[i] == " ": cut=i; break
                        if cut == -1: cut = e
                        c = txt[s:cut].strip()
                        if c: parts.append(c)
                        s = cut
                    return parts

                clean      = _san(narration)
                v_chunks   = _chnk(clean, _MAX_CHARS) if len(clean) > _MAX_CHARS else [clean]
                all_frags  = []
                for _ch in v_chunks:
                    upd('voz', 'active', f'Sintetizando fragmento ({len(all_frags)+1}/{len(v_chunks)})...')
                    _rv  = _n8n_request("POST", _VOZ_N8N,
                                        json_payload={"data": _ch, "voice_id": voice_id},
                                        timeout=300, attempts=3)
                    _rd  = _rv.json()
                    _rr  = _rd[0] if isinstance(_rd, list) else _rd
                    if isinstance(_rr, dict) and _rr.get("fragments"):
                        for _f in _rr["fragments"]:
                            _f["chunkText"] = _ch
                            all_frags.append(_f)
                    else:
                        raise Exception(str(_rr)[:120])

                if all_frags:
                    upd('voz', 'active', f'Fusionando {len(all_frags)} fragmentos de audio...')
                    _rm   = _n8n_request("POST", _VOZ_MERGE_N8N,
                                         json_payload={"fragments": all_frags, "voice_id": voice_id},
                                         timeout=360, attempts=5)
                    _rmd  = _rm.json()
                    _raw  = _rmd[0] if isinstance(_rmd, list) else _rmd
                    if _raw.get("finalAudio"):
                        import base64 as _b64, time as _ti2
                        _fa = _raw["finalAudio"]
                        if _fa.startswith("data:"):
                            _, _b = _fa.split(",", 1)
                            (proj_dir / "audio" / f"voz_completa_{int(_ti2.time())}.wav").write_bytes(
                                _b64.b64decode(_b))
                    voz_ok = True
            except Exception as ev:
                job['log'].append(f'Voz: {str(ev)[:120]}')

        if voz_ok:
            upd('voz', 'done', 'Voz sintetizada · fusionando audio...')
        elif voice_id:
            upd('voz', 'partial', 'Voz en proceso (revisar n8n/ElevenLabs)')
        else:
            upd('voz', 'skip', 'Sin voz seleccionada (omitido)')

        # ── 5. Imágenes (Flow) ────────────────────────────────────────
        img_dir = str(proj_dir / 'imagenes')
        if prompts:
            upd('imagenes', 'active', f'Iniciando generación de {len(prompts)} imágenes...')
            # Verificar si Flow ya está corriendo otro batch
            with _flow_lock:
                already_flow = _flow_state.get('running', False)
            if not already_flow:
                _ap_model = 'IMAGE_GENERATION_001_IMAGEN4' if ref_image else 'NANO_BANANA_2'
                img_th = _th.Thread(
                    target=_flow_run_batch,
                    args=(prompts, img_dir, 5,
                          'IMAGE_ASPECT_RATIO_LANDSCAPE',
                          _ap_model, 2, ref_image),
                    kwargs={'auto_open': True},
                    daemon=True
                )
                img_th.start()
                deadline = _t.time() + 600
                while _t.time() < deadline:
                    with _flow_lock:
                        saved   = _flow_state.get('images_saved', 0)
                        total   = _flow_state.get('total', len(prompts))
                        running = _flow_state.get('running', False)
                    job['current_detail'] = f'Flow: {saved}/{total} imágenes generadas'
                    _i2v_ap_scan_images(job, img_dir)
                    if not running and not img_th.is_alive():
                        break
                    _t.sleep(2)
            else:
                _t.sleep(2)
                job['log'].append('[Flow] Generación en curso en otro proceso — esperando')

            _i2v_ap_scan_images(job, img_dir)
            n_img = len(job['images'])
            if n_img > 0:
                upd('imagenes', 'done', f'{n_img} imágenes generadas con Flow')
            else:
                upd('imagenes', 'partial', 'Sin imágenes — verifica cuentas Flow y que los browsers estén conectados')
        else:
            upd('imagenes', 'skip', 'Sin prompts de imagen')

        # ── 6. Ensamblar ─────────────────────────────────────────────
        upd('ensamblar', 'active', 'Ensamblando video final...')
        import glob as _gl, subprocess as _sp, os as _os
        try:
            _imgs = sorted(
                _gl.glob(str(proj_dir / 'imagenes' / '*.png')) +
                _gl.glob(str(proj_dir / 'imagenes' / '*.jpg')) +
                _gl.glob(str(proj_dir / 'imagenes' / '*.webp')),
                key=lambda p: _os.path.basename(p)
            )
            if not _imgs:
                raise Exception('Sin imágenes para ensamblar')

            _aud_files = sorted(
                _gl.glob(str(proj_dir / 'audio' / '*.wav')) +
                _gl.glob(str(proj_dir / 'audio' / '*.mp3'))
            )
            _audio = _aud_files[0] if _aud_files else None
            _vf_dir = proj_dir / 'video_final'
            _vf_dir.mkdir(exist_ok=True)
            _final_mp4 = str(_vf_dir / 'video_autopilot.mp4')

            if _ap_render_mode == 'profesional':
                # ── Modo profesional: WhisperX timing + FFmpeg local (sin Modal) ──
                upd('ensamblar', 'active', 'Analizando audio con WhisperX...')
                _scenes_txt = [s.get('texto', '') for s in job.get('_scenes_raw', [])]
                if not _scenes_txt:
                    _scenes_txt = [p for p in script.split('\n\n') if p.strip()]
                _aud_dur_pro = _vf_ffprobe_duration(_audio) if _audio else 0.0
                _all_words_pro = None
                try:
                    job['current_detail'] = 'WhisperX: alineando palabras...'
                    _segs_pro, _all_words_pro = _transcribir_whisperx_runpod(_audio)
                    job['current_detail'] = f'WhisperX: {len(_all_words_pro)} palabras alineadas'
                except Exception as _wex:
                    job['log'].append(f'WhisperX falló ({_wex}), usando duración igual por escena')
                if _all_words_pro and _scenes_txt and _aud_dur_pro > 0:
                    _ts_pro = asignar_timestamps_words(_scenes_txt, _all_words_pro, _aud_dur_pro)
                else:
                    _n_s = max(1, len(_scenes_txt) or len(_imgs))
                    _d_s = _aud_dur_pro / _n_s if _aud_dur_pro > 0 else 3.0
                    _ts_pro = [{'inicio': i * _d_s, 'fin': (i+1) * _d_s,
                                'duracion': _d_s, 'scene_idx': i} for i in range(_n_s)]
                upd('ensamblar', 'active', f'Renderizando {len(_ts_pro)} escenas con FFmpeg...')
                _n_imgs = len(_imgs)
                _cl_path_pro = str(_vf_dir / '_concat_pro.txt')
                _tmp_vid_pro = str(_vf_dir / '_pro_tmp.mp4')
                with open(_cl_path_pro, 'w', encoding='utf-8') as _clf:
                    for _i, _ts in enumerate(_ts_pro):
                        _sidx = min(_ts.get('scene_idx', _i), _n_imgs - 1)
                        _dur  = max(0.1, _ts.get('duracion', 1.0))
                        _pp   = _imgs[_sidx].replace('\\', '/').replace("'", "'\\''")
                        _clf.write(f"file '{_pp}'\nduration {_dur:.3f}\n")
                    _last_sidx = min((_ts_pro[-1].get('scene_idx', _n_imgs-1) if _ts_pro else _n_imgs-1), _n_imgs-1)
                    _pp_last = _imgs[_last_sidx].replace('\\', '/').replace("'", "'\\''")
                    _clf.write(f"file '{_pp_last}'\n")
                _nw = _vf_no_window()
                _r1 = _sp.run([
                    'ffmpeg', '-y', '-f', 'concat', '-safe', '0', '-i', _cl_path_pro,
                    '-vf', ('scale=1920:1080:force_original_aspect_ratio=decrease,'
                            'pad=1920:1080:(ow-iw)/2:(oh-ih)/2:color=black,'
                            'format=yuv420p'),
                    '-c:v', 'libx264', '-preset', 'fast', '-crf', '18',
                    '-r', '24', '-an', '-movflags', '+faststart', _tmp_vid_pro
                ], capture_output=True, text=True, **_nw)
                if _r1.returncode != 0:
                    raise Exception(f'FFmpeg profesional falló: {_r1.stderr[-300:]}')
                _r2 = _sp.run([
                    'ffmpeg', '-y', '-i', _tmp_vid_pro, '-i', _audio,
                    '-c:v', 'copy', '-c:a', 'aac', '-b:a', '192k',
                    '-shortest', '-movflags', '+faststart', _final_mp4
                ], capture_output=True, text=True, **_nw)
                if _r2.returncode != 0:
                    raise Exception(f'FFmpeg mux profesional falló: {_r2.stderr[-300:]}')
                _wx_label = f'WhisperX · {len(_all_words_pro)} palabras' if _all_words_pro else 'timing proporcional'
                upd('ensamblar', 'done', f'Video profesional listo · {len(_ts_pro)} escenas · {_wx_label}')

            else:
                # ── Modo rápido: FFmpeg slideshow ──────────────────────
                _aud_dur = _vf_ffprobe_duration(_audio) if _audio else 0.0
                _n_imgs  = len(_imgs)
                _dur_per = max(1.5, _aud_dur / _n_imgs) if _aud_dur > 1.0 else 3.0

                upd('ensamblar', 'active',
                    f'Creando slideshow: {_n_imgs} imágenes × {_dur_per:.1f}s...')

                _cl_path = str(_vf_dir / '_concat.txt')
                _tmp_vid = str(_vf_dir / '_slideshow_tmp.mp4')

                with open(_cl_path, 'w', encoding='utf-8') as _clf:
                    for _img in _imgs:
                        _pp = _img.replace('\\', '/').replace("'", "'\\''")
                        _clf.write(f"file '{_pp}'\nduration {_dur_per:.3f}\n")
                    _pp = _imgs[-1].replace('\\', '/').replace("'", "'\\''")
                    _clf.write(f"file '{_pp}'\n")

                _nw = _vf_no_window()
                _r1 = _sp.run([
                    'ffmpeg', '-y', '-f', 'concat', '-safe', '0', '-i', _cl_path,
                    '-vf', ('scale=1280:720:force_original_aspect_ratio=decrease,'
                            'pad=1280:720:(ow-iw)/2:(oh-ih)/2:color=black,'
                            'setsar=1,fps=24,setpts=PTS-STARTPTS'),
                    '-c:v', 'libx264', '-preset', 'ultrafast', '-crf', '26',
                    '-pix_fmt', 'yuv420p', '-an', '-movflags', '+faststart', _tmp_vid
                ], capture_output=True, text=True, **_nw)

                if _r1.returncode != 0 or not _os.path.exists(_tmp_vid):
                    raise Exception(f'FFmpeg slideshow: {(_r1.stderr or "")[-300:]}')

                if _audio and _os.path.exists(_audio):
                    upd('ensamblar', 'active', 'Mezclando video con audio...')
                    _r2 = _sp.run([
                        'ffmpeg', '-y', '-i', _tmp_vid, '-i', _audio,
                        '-c:v', 'copy', '-c:a', 'aac', '-b:a', '192k',
                        '-shortest', '-movflags', '+faststart', _final_mp4
                    ], capture_output=True, text=True, **_nw)
                    if _r2.returncode == 0 and _os.path.exists(_final_mp4):
                        try: _os.remove(_tmp_vid)
                        except: pass
                    else:
                        _os.rename(_tmp_vid, _final_mp4)
                        job['log'].append(f'Audio mux falló: {(_r2.stderr or "")[-150:]}')
                else:
                    _os.rename(_tmp_vid, _final_mp4)

                try: _os.remove(_cl_path)
                except: pass

                _total_s = int(_aud_dur or _n_imgs * _dur_per)
                upd('ensamblar', 'done', f'Video listo · {_n_imgs} imágenes · {_total_s}s')

            _vid_url = f'/api/proyectos/video_final?project={proj_name}&file=video_autopilot.mp4'
            _vid_dl  = f'/api/proyectos/video_final?project={proj_name}&file=video_autopilot.mp4&dl=1'
            job['video_url'] = _vid_url
            job['video_dl']  = _vid_dl

        except Exception as _ev:
            job['log'].append(f'Ensamblar: {str(_ev)[:200]}')
            upd('ensamblar', 'partial', f'Error ensamblando: {str(_ev)[:80]}')

        job['status'] = 'done'

    except Exception as ex:
        job['status'] = 'error'
        job['error']  = str(ex)[:300]
        if job.get('phase'):
            job['phases'][job['phase']] = 'error'
        job['log'].append(f'ERROR: {str(ex)[:200]}')


@app.route("/api/idea2video/autopilot", methods=["POST"])
def api_i2v_autopilot_run():
    import uuid as _uuid, time as _ti, re as _re
    data      = request.get_json() or {}
    script    = data.get('script', '').strip()
    title     = (data.get('title', '') or 'video_autopilot').strip()
    voice_id  = data.get('voice_id', '')
    ref_image = data.get('ref_image') or None
    mode      = data.get('mode', 'rapido')  # 'rapido' | 'profesional'
    if mode not in ('rapido', 'profesional'):
        mode = 'rapido'
    if not script:
        return jsonify({'error': 'Sin guión'}), 400
    job_id    = str(_uuid.uuid4())[:8]
    safe      = _re.sub(r'[^\w\-]', '_', title[:40]) + '_' + job_id
    _i2v_ap_jobs[job_id] = {
        'status': 'running',
        'phase': '',
        'phases': {k: 'pending' for k in ('recursos','fragmentar','prompts','voz','imagenes','ensamblar')},
        'images': [],
        'log': [],
        'title': title,
        'project_name': safe,
        'current_detail': '',
        'scenes': 0,
        'char_count': 0,
        'started': _ti.time(),
        'ref_image': ref_image,
        'mode': mode,
    }
    import threading as _th2
    _th2.Thread(target=_i2v_ap_worker, args=(job_id, script, voice_id), daemon=True).start()
    return jsonify({'ok': True, 'job_id': job_id})


@app.route("/api/idea2video/autopilot/<job_id>", methods=["GET"])
def api_i2v_autopilot_status(job_id):
    import time as _ti2
    if job_id not in _i2v_ap_jobs:
        return jsonify({'error': 'not found'}), 404
    job    = _i2v_ap_jobs[job_id]
    result = dict(job)
    result['elapsed'] = int(_ti2.time() - job['started'])
    return jsonify(result)


@app.route("/api/idea2video/autopilot/<job_id>/abrir_carpeta", methods=["POST"])
def i2v_ap_abrir_carpeta(job_id):
    if job_id not in _i2v_ap_jobs:
        return jsonify({"error": "not found"}), 404
    from pathlib import Path as _P
    proj = _i2v_ap_jobs[job_id].get("project_name", "")
    if not proj:
        return jsonify({"error": "no project"}), 400
    folder = str(_P(JOBS_FOLDER) / proj)
    _abrir_carpeta(folder)
    return jsonify({"ok": True})


@app.route("/api/idea2video/ap_imagen")
def i2v_ap_imagen():
    import re as _re
    from pathlib import Path as _P
    proj  = _re.sub(r"[^\w\-]", "_", request.args.get("project", "").strip())
    fname = request.args.get("file", "").strip().replace("..", "")
    if not proj or not fname:
        return jsonify({"error": "missing"}), 400
    path = _P(JOBS_FOLDER) / proj / "imagenes" / fname
    if not path.exists():
        return "", 404
    ext  = path.suffix.lower()
    mime = {".jpg": "image/jpeg", ".jpeg": "image/jpeg",
            ".png": "image/png", ".webp": "image/webp"}.get(ext, "image/png")
    resp = send_file(str(path), mimetype=mime)
    resp.headers["Cache-Control"] = "no-store, no-cache"
    return resp


@app.route("/api/admin/docs", methods=["GET"])
def api_admin_docs_list():
    u = _current_username()
    try:
        conn = _docs_conn()
        with conn.cursor() as cur:
            cur.execute(
                "SELECT id,type,category,title,description,url,content,thumbnail_url,"
                "duration_label,tags,sort_order,is_published,"
                "DATE_FORMAT(created_at,'%%Y-%%m-%%d'),created_by "
                "FROM vf_docs ORDER BY category,sort_order,id"
            )
            rows = cur.fetchall()
        conn.close()
    except Exception as e:
        return jsonify({"error": str(e)}), 500
    return jsonify([{"id":r[0],"type":r[1],"category":r[2],"title":r[3],"description":r[4],
                     "url":r[5],"content":r[6],"thumbnail_url":r[7],"duration_label":r[8],
                     "tags":r[9],"sort_order":r[10],"is_published":bool(r[11]),
                     "created_at":r[12] or "","created_by":r[13] or ""} for r in rows])

@app.route("/api/admin/docs", methods=["POST"])
def api_admin_docs_create():
    u = _current_username() or "admin"
    d = request.get_json() or {}
    url_val = _docs_yt_embed(d.get("url","")) if d.get("type")=="video" else d.get("url","")
    try:
        conn = _docs_conn()
        with conn.cursor() as cur:
            cur.execute(
                "INSERT INTO vf_docs(type,category,title,description,url,content,"
                "thumbnail_url,duration_label,tags,sort_order,is_published,created_by) "
                "VALUES(%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                (d.get("type","video"), d.get("category","General"), d.get("title","Sin título"),
                 d.get("description",""), url_val, d.get("content",""),
                 d.get("thumbnail_url",""), d.get("duration_label",""), d.get("tags",""),
                 int(d.get("sort_order",0)), 1 if d.get("is_published",True) else 0, u)
            )
            new_id = cur.lastrowid
        conn.commit()
        conn.close()
        return jsonify({"id": new_id}), 201
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route("/api/admin/docs/<int:doc_id>", methods=["PUT"])
def api_admin_docs_update(doc_id):
    u = _current_username() or "admin"
    d = request.get_json() or {}
    url_val = _docs_yt_embed(d.get("url","")) if d.get("type")=="video" else d.get("url","")
    try:
        conn = _docs_conn()
        with conn.cursor() as cur:
            cur.execute(
                "UPDATE vf_docs SET type=%s,category=%s,title=%s,description=%s,url=%s,"
                "content=%s,thumbnail_url=%s,duration_label=%s,tags=%s,"
                "sort_order=%s,is_published=%s WHERE id=%s",
                (d.get("type","video"), d.get("category","General"), d.get("title",""),
                 d.get("description",""), url_val, d.get("content",""),
                 d.get("thumbnail_url",""), d.get("duration_label",""), d.get("tags",""),
                 int(d.get("sort_order",0)), 1 if d.get("is_published",True) else 0, doc_id)
            )
        conn.commit()
        conn.close()
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route("/api/admin/docs/<int:doc_id>", methods=["DELETE"])
def api_admin_docs_delete(doc_id):
    u = _current_username() or "admin"
    try:
        conn = _docs_conn()
        with conn.cursor() as cur:
            cur.execute("DELETE FROM vf_docs WHERE id=%s", (doc_id,))
        conn.commit()
        conn.close()
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"error": str(e)}), 500

