def abrir_navegador():
    time.sleep(1.5)
    webbrowser.open("http://127.0.0.1:8080/shell")


def _iniciar_flask():
    app.run(host="0.0.0.0", port=8080, debug=False, threaded=True, use_reloader=False)


def _flask_ready(url="http://127.0.0.1:8080/", max_wait=20, intervalo=0.25):
    """Espera hasta que Flask responda (polling con timeout)."""
    import urllib.request as _ur
    for _ in range(int(max_wait / intervalo)):
        try:
            _ur.urlopen(url, timeout=1)
            return True
        except Exception:
            time.sleep(intervalo)
    return False


if __name__ == "__main__":
# ============================================
    # INICIAR WEBSOCKET BRIDGE (SIN INTERRUMPIR)
    # ============================================
    import threading
    import time
    
    def _start_bridge_auto():
        try:
            # Esperar a que Flask arranque primero
            time.sleep(3)
            _flow_start_ws_server()
            print("[Bridge] [OK] WebSocket corriendo en ws://127.0.0.1:5557")
        except Exception as e:
            print(f"[Bridge] [WARNING]  No se pudo iniciar: {e}")
    
    # Iniciar bridge en hilo DAEMON (no bloquea la app)
    threading.Thread(target=_start_bridge_auto, daemon=True).start()
    

    _mostrar_splash()
    print("\n" + "═"*52)
    print("  🎬  Studio IVR — Pipeline de Video con IA")
    print("  -->   http://127.0.0.1:8080/shell  (ventana principal)")
    print("  -->   Jobs guardados en:", JOBS_FOLDER)
    print("═"*52 + "\n")

    # ── pywebview: ventana nativa independiente ───────────────────────────
    # Instalar:  pip install pywebview
    # Forzar navegador clásico: python launcher.py --browser
    _use_webview = "--browser" not in sys.argv
    if _use_webview:
        try:
            import webview as _wv
        except (ImportError, Exception):
            _use_webview = False
            print("[Studio IVR] pywebview no instalado -> abre en navegador.")
            print("             Ventana nativa:  pip install pywebview")

    if _use_webview:
        # Flask en hilo secundario; pywebview necesita el hilo principal
        _flask_t = threading.Thread(
            target=_iniciar_flask, daemon=True, name="VF-Flask"
        )
        _flask_t.start()

        print("[Studio IVR] Esperando que Flask inicie...", end="", flush=True)
        if _flask_ready():
            print(" listo.")
        else:
            print(" timeout.")

        # Calcular dimensiones de pantalla como fallback si maximized no funciona
        try:
            import tkinter as _tk_sz
            _r_sz = _tk_sz.Tk(); _r_sz.withdraw()
            _sw = _r_sz.winfo_screenwidth()
            _sh = _r_sz.winfo_screenheight()
            _r_sz.destroy()
        except Exception:
            _sw, _sh = 1920, 1080

        _wv_kw = dict(
            title="Studio IVR",
            url="http://127.0.0.1:8080/shell",
            width=_sw,
            height=_sh,
            resizable=True,
            min_size=(960, 640),
            text_select=True,
            maximized=True,
        )
        if sys.platform == "darwin":
            _wv_kw["fullscreen"] = False

        try:
            # Si la versión de pywebview no acepta 'maximized' en create_window,
            # lo quitamos y recurrimos a maximize() en el callback de inicio.
            try:
                _win = _wv.create_window(**_wv_kw)
            except TypeError:
                _wv_kw.pop("maximized", None)
                _win = _wv.create_window(**_wv_kw)

            def _on_closed():
                print("[Studio IVR] Ventana cerrada. Saliendo.")
                os._exit(0)

            def _on_shown():
                try:
                    _win.maximize()
                except Exception:
                    pass

            _win.events.closed += _on_closed
            try:
                _wv.start(debug=False, http_server=False, func=_on_shown)
            except TypeError:
                _wv.start(debug=False, http_server=False)
        except Exception as _we:
            print(f"[Studio IVR] Error pywebview ({_we}) --> fallback navegador.")
            webbrowser.open("http://127.0.0.1:8080/shell")
            _flask_t.join()
    else:
        threading.Thread(target=abrir_navegador, daemon=True).start()
        _iniciar_flask()
